-- Poems batch 19
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2b7ae190-430b-47fa-99a4-3c5dfaf383df','悟禪三首寄胡果 二','元稹','唐','唐诗','tang','','[]','百年都幾日，何事苦囂然。',48,'全唐诗/poet.tang.21000.json','["百年都幾日，何事苦囂然。", "晚歲倦爲學，閑心易到禪。", "病宜多宴坐，貧似少攀緣。", "自笑無名字，因名自在天。"]'),
('6d6865db-c817-450d-9c4f-42b95c941275','悟禪三首寄胡果 三','元稹','唐','唐诗','tang','','[]','近見新章句，因知見在心。',48,'全唐诗/poet.tang.21000.json','["近見新章句，因知見在心。", "春游晉祠水，晴上霍山岑。", "問法僧當偈，還丹客贈金。", "莫驚頭欲白，禪觀老彌深。"]'),
('97b21fcf-2c71-4ade-b6dd-744e6618accf','東臺去','元稹','唐','唐诗','tang','','[]','陶君喜不遇，予每爲君言。',48,'全唐诗/poet.tang.21000.json','["陶君喜不遇，予每爲君言。", "今日東臺去，澄心在陸渾。", "旋抽隨日俸，幷買近山園。", "千萬崔兼白，殷勤承主恩。"]'),
('b1764691-f3e8-453a-b9c8-ec3dfa2e27c8','戴光弓','元稹','唐','唐诗','tang','','[]','潞府筋角勁，戴光因合成。',48,'全唐诗/poet.tang.21000.json','["潞府筋角勁，戴光因合成。", "因君懷膽氣，贈我定交情。", "不擬閑穿葉，那能枉始生。", "唯調一隻箭，飛入破聊城。"]'),
('89403a0f-4a7e-496f-980b-ab261d5a1d0e','劉頗詩','元稹','唐','唐诗','tang','','[]','一言感激士，三世義忠臣。',48,'全唐诗/poet.tang.21000.json','["一言感激士，三世義忠臣。", "破甕嫌妨路，燒莊恥屬人。", "迥分遼海氣，閑蹋洛陽塵。", "儻使權由我，還君白馬津。"]'),
('cd9d3425-7ad3-42c0-aca0-c8328a19d8c7','夜飲','元稹','唐','唐诗','tang','','[]','燈火隔簾明，竹梢風雨聲。',48,'全唐诗/poet.tang.21000.json','["燈火隔簾明，竹梢風雨聲。", "詩篇隨意贈，杯酒越巡行。", "漫唱江朝曲，閑徵藥草名。", "莫辭終夜飲，朝起又營營。"]'),
('80c921a7-8d8a-4e92-9952-49bf6e5654d3','襃城驛','元稹','唐','唐诗','tang','','[]','嚴秦修此驛，兼漲驛前池。',48,'全唐诗/poet.tang.21000.json','["嚴秦修此驛，兼漲驛前池。", "已種千竿竹，又栽千樹棃。", "四年三月半，新筍晚花時。", "悵望東川去，等閑題作詩。"]'),
('c91be134-8bc6-4a1b-8577-021ce2f8abc4','閑二首 一','元稹','唐','唐诗','tang','','[]','晻澹洲煙白，籬篩日脚紅。',48,'全唐诗/poet.tang.21000.json','["晻澹洲煙白，籬篩日脚紅。", "江喧過雲雨，船泊打頭風。", "艇子收魚市，鴉兒噪荻叢。", "不堪堤上立，滿眼是蚊蟲。"]'),
('259c50f9-2131-4404-a442-35bd3b70e6c3','閑二首 二','元稹','唐','唐诗','tang','','[]','青衫經夏黕，白髮望鄉稠。',48,'全唐诗/poet.tang.21000.json','["青衫經夏黕，白髮望鄉稠。", "雨冷新秋簟，星稀欲曙樓。", "連鴻盡南去，雙鯉本東流。", "北信無人寄，蟬聲滿樹頭。"]'),
('873d6894-bc6d-447d-8042-7a8847e0f44a','欲曙','元稹','唐','唐诗','tang','','[]','江隄閱暗流，漏鼓急殘籌。',53,'全唐诗/poet.tang.21000.json','["江隄閱暗流，漏鼓急殘籌。", "片月低城堞，稀星轉角樓。", "鶴媒華表上，{篦𥫗+鳥}鵊柳枝頭。", "不爲來趨府，何因欲曙遊。"]'),
('fcd7ec50-36c9-4c76-bba5-d1abc18c15cd','寄胡靈之','元稹','唐','唐诗','tang','','[]','早歲顛狂伴，城中共幾年。',48,'全唐诗/poet.tang.21000.json','["早歲顛狂伴，城中共幾年。", "有時潛步出，連夜小亭眠。", "月影侵牀上，花叢在眼前。", "今宵正風雨，空宅楚江邊。"]'),
('64167d4a-dae8-4bd9-8725-6f2a2fd0334b','夜雨','元稹','唐','唐诗','tang','','[]','水怪潛幽草，江雲擁廢居。',48,'全唐诗/poet.tang.21000.json','["水怪潛幽草，江雲擁廢居。", "雷驚空屋柱，電照滿牀書。", "竹瓦風頻裂，茅檐雨漸疎。", "平生滄海意，此去怯爲魚。"]'),
('7a1f6e57-20f4-4ff9-922d-8aac1a118229','酬李六醉後見寄口號','元稹','唐','唐诗','tang','','[]','頓愈頭風疾，因吟口號詩。',72,'全唐诗/poet.tang.21000.json','["頓愈頭風疾，因吟口號詩。", "文章紛似繡，珠玉布如棊。", "健羨觥飛酒，蒼黃日映籬。", "命童寒色倦，撫穉晚啼飢。", "潦倒慙相識，平生頗自奇。", "明公將有問，林下是靈龜。"]'),
('4e0acb89-0bc3-4682-87a2-701cc0494fbc','歸田','元稹','唐','唐诗','tang','','[]','陶君三十七，挂綬出都門。',48,'全唐诗/poet.tang.21000.json','["陶君三十七，挂綬出都門。", "我亦今年去，商山淅岸邨。", "冬修方丈室，春種桔橰園。", "千萬人間事，從茲不復言。"]'),
('7642989a-74c8-4e46-8ab1-3c0b3b97aa95','緣路','元稹','唐','唐诗','tang','','[]','總是玲瓏竹，兼藏淺漫溪。',48,'全唐诗/poet.tang.21000.json','["總是玲瓏竹，兼藏淺漫溪。", "沙平深見底，石亂不成泥。", "煙火遙邨落，桑麻隔稻畦。", "此中如有問，甘被到頭迷。"]'),
('39b96ab4-54a6-4083-bd94-3147ec1b07e6','誚盧戡與予數約遊三寺戡獨沈醉而不行','元稹','唐','唐诗','tang','','[]','乘興無羈束，閑行信馬蹄。',48,'全唐诗/poet.tang.21000.json','["乘興無羈束，閑行信馬蹄。", "路幽穿竹遠，野迥望雲低。", "素帚茅花亂，圓珠稻實齊。", "如何盧進士，空戀醉如泥。"]'),
('f918b6f5-8cd9-468c-b3a9-0e192436a66f','遣春三首 一','元稹','唐','唐诗','tang','','[]','楊公三不惑，我惑兩般全。',48,'全唐诗/poet.tang.21000.json','["楊公三不惑，我惑兩般全。", "逢酒判身病，拈花盡意憐。", "水生低岸沒，梅蹙小珠連。", "千萬紅顏輩，須驚又一年。"]'),
('e1630277-c5c5-42d3-b5c9-190f346c00ce','遣春三首 二','元稹','唐','唐诗','tang','','[]','柳眼開渾盡，梅心動已闌。',48,'全唐诗/poet.tang.21000.json','["柳眼開渾盡，梅心動已闌。", "風光好時少，杯酒病中難。", "學問慵都廢，聲名老更判。", "唯餘看花伴，未免憶長安。"]'),
('4ac218bc-c596-4eba-822c-e42344cf124f','遣春三首 三','元稹','唐','唐诗','tang','','[]','失却遊花伴，因風浪引將。',48,'全唐诗/poet.tang.21000.json','["失却遊花伴，因風浪引將。", "柳堤遙認馬，梅徑誤尋香。", "晚景行看謝，春心漸欲狂。", "園林都不到，何處枉風光。"]'),
('da350090-e297-4f80-8fd3-3d440b97f166','歲日','元稹','唐','唐诗','tang','','[]','一日今年始，一年前事空。',24,'全唐诗/poet.tang.21000.json','["一日今年始，一年前事空。", "淒涼百年事，應與一年同。"]'),
('a7dcb73d-37ac-4df5-858b-ea11bfcab662','湘南登臨湘樓','元稹','唐','唐诗','tang','','[]','高處望瀟湘，花時萬井香。',48,'全唐诗/poet.tang.21000.json','["高處望瀟湘，花時萬井香。", "雨餘憐日嫩，歲閏覺春長。", "霞剎分危牓，煙波透遠光。", "情知樓上好，不是仲宣鄉。"]'),
('f01afb00-59b5-484a-b2f3-e76bb1717686','晚宴湘亭','元稹','唐','唐诗','tang','','[]','晚日宴清湘，晴空走豔陽。',48,'全唐诗/poet.tang.21000.json','["晚日宴清湘，晴空走豔陽。", "花低愁露醉，絮起覺春狂。", "舞旋紅裙急，歌垂碧袖長。", "甘心出童羖，須一盡時荒。"]'),
('2a3cb0d0-89e9-4dc4-bca0-da2bc61718f7','酒醒','元稹','唐','唐诗','tang','','[]','飲醉日將盡，醒時夜已闌。',48,'全唐诗/poet.tang.21000.json','["飲醉日將盡，醒時夜已闌。", "暗燈風燄曉，春席水窗寒。", "未解縈身帶，猶傾墜枕冠。", "呼兒問狼藉，疑是夢中歡。"]'),
('7dc2316f-aced-4ab3-a30a-41e8c1b5d6e0','獨遊','元稹','唐','唐诗','tang','','[]','遠地難逢侶，閑人且獨行。',48,'全唐诗/poet.tang.21000.json','["遠地難逢侶，閑人且獨行。", "上山隨老鶴，接酒待殘鸎。", "花當西施面，泉勝衛玠清。", "鵜鶘滿春野，無限好同聲。"]'),
('67c3da71-0821-41bf-a3db-ca498688fb4b','洞庭湖','元稹','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','人生除泛海，便到洞庭波。',48,'全唐诗/poet.tang.21000.json','["人生除泛海，便到洞庭波。", "駕浪沉西日，吞空接曙河。", "虞巡竟安在，軒樂詎曾過。", "唯有君山下，狂風萬古多。"]'),
('51974ef1-b8d8-4166-baca-7d4b9e8c147b','雪天','元稹','唐','唐诗','tang','','[]','故鄉千里夢，往事萬重悲。',48,'全唐诗/poet.tang.21000.json','["故鄉千里夢，往事萬重悲。", "小雪沈陰夜，閑窗老病時。", "獨聞歸去鴈，偏詠別來詩。", "慚愧紅妝女，頻驚兩鬢絲。"]'),
('f9cb9e32-4eac-41f3-a19a-52a4f044a04c','贈熊士登','元稹','唐','唐诗','tang','','[]','平生本多思，況復老逢春。',24,'全唐诗/poet.tang.21000.json','["平生本多思，況復老逢春。", "今日梅花下，他鄉值故人。"]'),
('30cc1776-1373-48e5-b49d-c67fde633d71','別嶺南熊判官','元稹','唐','唐诗','tang','','[]','十年常遠道，不忍別離聲。',48,'全唐诗/poet.tang.21000.json','["十年常遠道，不忍別離聲。", "況復三巴外，仍逢萬里行。", "桐花新雨氣，梨葉晚春晴。", "到海知何日，風波從此生。"]'),
('ca73e2e5-6e5a-438e-a481-372a8831d7ce','水上寄樂天','元稹','唐','唐诗','tang','','[]','眼前明月水，先入漢江流。',48,'全唐诗/poet.tang.21000.json','["眼前明月水，先入漢江流。", "漢水流江海，西江過庾樓。", "庾樓今夜月，君豈在樓頭。", "萬一樓頭望，還應望我愁。"]'),
('93def192-bc98-416c-9057-3664a224bede','夏陽亭臨望寄河陽侍御堯','元稹','唐','唐诗','tang','','[]','望遠音書絕，臨川意緒長。',24,'全唐诗/poet.tang.21000.json','["望遠音書絕，臨川意緒長。", "殷勤眼前水，千里到河陽。"]'),
('1351b044-b89a-4fc3-85e3-d9e17297f0ed','日高睡','元稹','唐','唐诗','tang','','[]','隔是身如夢，頻來不爲名。',24,'全唐诗/poet.tang.21000.json','["隔是身如夢，頻來不爲名。", "憐君近南住，時得到山行。"]'),
('2360a884-4907-4da4-93e1-3ebc4dc3c053','輞川','元稹','唐','唐诗','tang','','[]','世累爲身累，閑忙不自由。',24,'全唐诗/poet.tang.21000.json','["世累爲身累，閑忙不自由。", "殷勤輞川水，何事出山流。"]'),
('8ba94648-c512-4152-b3a1-3a5f4e53b4d5','天壇歸','元稹','唐','唐诗','tang','','[]','爲結區中累，因辭洞裏花。',24,'全唐诗/poet.tang.21000.json','["爲結區中累，因辭洞裏花。", "還來舊城郭，煙火萬人家。"]'),
('716d0de3-1d63-44c7-adc2-6632a34c7857','雨後','元稹','唐','唐诗','tang','','[]','倦寢數殘更，孤燈暗又明。',24,'全唐诗/poet.tang.21000.json','["倦寢數殘更，孤燈暗又明。", "竹梢餘雨重，時復拂簾驚。"]'),
('d715a486-a4c6-4694-b408-9dae3ecd8707','晴日','元稹','唐','唐诗','tang','','[]','多病苦虛羸，晴明強展眉。',24,'全唐诗/poet.tang.21000.json','["多病苦虛羸，晴明強展眉。", "讀書心緒少，閑臥日長時。"]'),
('12ad9a59-b634-4fd1-a0f5-eeefc89443d9','直臺','元稹','唐','唐诗','tang','','[]','麋入神羊隊，烏驚海鷺眠。',24,'全唐诗/poet.tang.21000.json','["麋入神羊隊，烏驚海鷺眠。", "仍教百餘日，迎送直廳前。"]'),
('02943f6d-2c91-4d9c-9690-247eab9ae3ec','行宮','元稹','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u53e4", "\u5bab\u6028", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u7edd\u53e5"]','寥落古行宮，宮花寂寞紅。',24,'全唐诗/poet.tang.21000.json','["寥落古行宮，宮花寂寞紅。", "白頭宮女在，閑坐說玄宗。"]'),
('5f99986f-0c0c-4efa-b660-5160aa94dea4','醉行','元稹','唐','唐诗','tang','','[]','秋風方索漠，霜貌足暌攜。',24,'全唐诗/poet.tang.21000.json','["秋風方索漠，霜貌足暌攜。", "今日騎驄馬，街中醉蹋泥。"]'),
('6f0b2bc8-134b-460f-8a7d-b7540d063e9b','指巡胡','元稹','唐','唐诗','tang','','[]','遣悶多憑酒，公心只仰胡。',24,'全唐诗/poet.tang.21000.json','["遣悶多憑酒，公心只仰胡。", "挺身唯直指，無意獨欺愚。"]'),
('bca9c210-fdbf-4b02-9bef-bf9bc3acbaae','飲新酒','元稹','唐','唐诗','tang','','[]','聞君新酒熟，況值菊花秋。',24,'全唐诗/poet.tang.21000.json','["聞君新酒熟，況值菊花秋。", "莫怪平生志，圖銷盡日愁。"]'),
('59577abf-ce99-4aa1-a172-0af65d1c00c7','香毬','元稹','唐','唐诗','tang','','[]','順俗唯團轉，居中莫動搖。',24,'全唐诗/poet.tang.21000.json','["順俗唯團轉，居中莫動搖。", "愛君心不惻，猶訝火長燒。"]'),
('5d842a27-5a1a-48d8-87bf-b6bf55304f93','景申秋八首 一','元稹','唐','唐诗','tang','','[]','年年秋意緒，多向雨中生。',48,'全唐诗/poet.tang.21000.json','["年年秋意緒，多向雨中生。", "漸欲煙火近，稍憐衣服輕。", "詠詩閑處立，憶事夜深行。", "濩落尋常慣，淒涼別爲情。"]'),
('d54a89ca-a73e-442b-98e9-0ad6df390d48','景申秋八首 二','元稹','唐','唐诗','tang','','[]','蚊幌雨來卷，燭蛾燈上稀。',48,'全唐诗/poet.tang.21000.json','["蚊幌雨來卷，燭蛾燈上稀。", "啼兒冷秋簟，思婦問寒衣。", "簾斷螢火入，窗明蝙蝠飛。", "良辰日夜去，漸與壯心違。"]'),
('408db686-9dc4-42b9-b417-6e6f3109e980','景申秋八首 三','元稹','唐','唐诗','tang','','[]','嗢嗢簷霤凝，丁丁窗雨繁。',48,'全唐诗/poet.tang.21000.json','["嗢嗢簷霤凝，丁丁窗雨繁。", "枕傾筒簟滑，幔颭案燈翻。", "喚魘兒難覺，吟詩婢苦煩。", "強眠終不著，閑臥暗消魂。"]'),
('cfc8e033-081e-4cea-bd80-fabc0ab807de','景申秋八首 四','元稹','唐','唐诗','tang','','[]','瓶瀉高簷雨，窗來激箭風。',48,'全唐诗/poet.tang.21000.json','["瓶瀉高簷雨，窗來激箭風。", "病憎燈火暗，寒覺薄幃空。", "婢報樵蘇竭，妻愁院落通。", "老夫慵計數，教想蔡城東。"]'),
('380e9a6b-777e-4842-877b-50d2b0b91641','景申秋八首 五','元稹','唐','唐诗','tang','','[]','風頭難著枕，病眼厭看書。',48,'全唐诗/poet.tang.21000.json','["風頭難著枕，病眼厭看書。", "無酒銷長夜，回燈照小餘。", "三元推廢王，九曜入乘除。", "廊廟應多算，參差斡太虛。"]'),
('008ea4f5-5596-4c20-a485-3195084c2686','景申秋八首 六','元稹','唐','唐诗','tang','','[]','經雨籬落壞，入秋田地荒。',48,'全唐诗/poet.tang.21000.json','["經雨籬落壞，入秋田地荒。", "竹垂哀折節，蓮敗惜空房。", "小片慈菇白，低叢柚子黃。", "眼前撩亂輩，無不是同鄉。"]'),
('edf23bd7-766e-4427-8b6a-39419e902624','景申秋八首 七','元稹','唐','唐诗','tang','','[]','雨柳枝枝弱，風光片片斜。',48,'全唐诗/poet.tang.21000.json','["雨柳枝枝弱，風光片片斜。", "蜻蜓憐曉露，蛺蝶戀秋花。", "飢啅空籬雀，寒棲滿樹鴉。", "荒涼池館內，不似有人家。"]'),
('ab1dc725-a463-466a-bb8b-a70ff7eee1f9','景申秋八首 八','元稹','唐','唐诗','tang','','[]','病苦十年後，連陰十日餘。',48,'全唐诗/poet.tang.21000.json','["病苦十年後，連陰十日餘。", "人方教作鼠，天豈遣爲魚。", "鮫綻酆城劒，蟲凋鬼火書。", "出聞泥濘盡，何地不摧車。"]'),
('c45a54fc-1535-4029-b28e-d8b230e01109','遣行十首 一','元稹','唐','唐诗','tang','','[]','慘切風雨夕，沉吟離別情。',48,'全唐诗/poet.tang.21000.json','["慘切風雨夕，沉吟離別情。", "燕辭前日社，蟬是每年聲。", "暗淚深相感，危心亦自驚。", "不如元不識，俱作路人行。"]'),
('172ba709-45f7-4228-933b-cad93131e78c','遣行十首 二','元稹','唐','唐诗','tang','','[]','十五年前事，恓惶無限情。',48,'全唐诗/poet.tang.21000.json','["十五年前事，恓惶無限情。", "病僮更借出，羸馬共馳聲。", "射葉楊纔破，聞弓鴈已驚。", "小年辛苦學，求得苦辛行。"]'),
('abea8f2d-9e51-46ad-b122-fdaf1c004361','遣行十首 三','元稹','唐','唐诗','tang','','[]','徙倚簷宇下，思量去住情。',48,'全唐诗/poet.tang.21000.json','["徙倚簷宇下，思量去住情。", "暗螢穿竹見，斜雨隔窗聲。", "就枕回轉數，聞雞撩亂驚。", "一家同草草，排比送君行。"]'),
('88b9cf01-87da-4ac1-abb8-e4ddcc62e941','遣行十首 四','元稹','唐','唐诗','tang','','[]','已愴朋交別，復懷兒女情。',48,'全唐诗/poet.tang.21000.json','["已愴朋交別，復懷兒女情。", "相兄亦相舊，同病又同聲。", "白髮年年剩，秋蓬處處驚。", "不堪身漸老，頻送異鄉行。"]'),
('26f55d2e-80e3-44c4-9269-f37ce0720105','遣行十首 五','元稹','唐','唐诗','tang','','[]','塞上風雨思，城中兄弟情。',48,'全唐诗/poet.tang.21000.json','["塞上風雨思，城中兄弟情。", "北隨鵷立位，南送鴈來聲。", "遇適尤兼恨，聞書喜復驚。", "唯應遙料得，知我伴君行。"]'),
('2813ccde-f3e5-4eb9-b1e7-6fa273b30143','遣行十首 六','元稹','唐','唐诗','tang','','[]','暮欲歌吹樂，暗衝泥水情。',48,'全唐诗/poet.tang.21000.json','["暮欲歌吹樂，暗衝泥水情。", "稻花秋雨氣，江石夜灘聲。", "犬吠穿籬出，鷗眠起水驚。", "愁君明月夜，獨自入山行。"]'),
('d89a661a-974b-4215-b831-beb3479417f1','遣行十首 七','元稹','唐','唐诗','tang','','[]','七過襃城驛，回回各爲情。',48,'全唐诗/poet.tang.21000.json','["七過襃城驛，回回各爲情。", "八年身世夢，一種水風聲。", "尋覓詩章在，思量歲月驚。", "更悲西塞別，終夜繞池行。"]'),
('1890307f-3123-4b81-aed9-b32600e5f84f','遣行十首 八','元稹','唐','唐诗','tang','','[]','襃縣驛前境，曲江池上情。',48,'全唐诗/poet.tang.21000.json','["襃縣驛前境，曲江池上情。", "南堤衰柳意，西寺晚鐘聲。", "雲水興方遠，風波心已驚。", "可憐皆老大，不得自由行。"]'),
('26d65a96-fa9b-4df4-bd9b-752927d7957e','遣行十首 九','元稹','唐','唐诗','tang','','[]','見說巴風俗，都無漢性情。',48,'全唐诗/poet.tang.21000.json','["見說巴風俗，都無漢性情。", "猿聲蘆管調，羌笛竹雞聲。", "迎候人應少，平安火莫驚。", "每逢危棧處，須作貫魚行。"]'),
('8ac61d90-5ce4-4999-90c9-a969abb9c978','遣行十首 十','元稹','唐','唐诗','tang','','[]','聞道陰平郡，翛然古戍情。',48,'全唐诗/poet.tang.21000.json','["聞道陰平郡，翛然古戍情。", "橋兼麋鹿蹋，山應鼓鼙聲。", "羌婦梳頭緊，蕃牛護尾驚。", "憐君閑悶極，只傍白江行。"]'),
('f5170856-6ead-4edf-b076-f7378a593959','生春二十首 一','元稹','唐','唐诗','tang','','[]','何處生春早，春生雲色中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生雲色中。", "籠蔥閑著水，晻淡欲隨風。", "度曉分霞態，餘光庇雪融。", "晚來低漠漠，渾欲泥幽叢。"]'),
('9a4ef431-d432-4382-8bcc-ba64a8352846','生春二十首 二','元稹','唐','唐诗','tang','','[]','何處生春早，春生漫雪中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生漫雪中。", "渾無到地片，唯逐入樓風。", "屋上些些薄，池心旋旋融。", "自悲銷散盡，誰假入蘭叢。"]'),
('ee3cdbe7-145e-48ac-995a-77ca43f2d81e','生春二十首 三','元稹','唐','唐诗','tang','','[]','何處生春早，春生霽色中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生霽色中。", "遠林橫返照，高樹亞東風。", "水凍霜威庇，泥新地氣融。", "漸知殘雪薄，杪近最憐叢。"]'),
('c31dfe5e-f537-41fc-8e29-865ecf856220','生春二十首 四','元稹','唐','唐诗','tang','','[]','何處生春早，春生曙火中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生曙火中。", "星圍分暗陌，煙氣滿晴風。", "宮樹棲鵶亂，城樓帶雪融。", "競排閶闔側，珂傘自相叢。"]'),
('82b5aad9-2e43-4717-9aab-04da6afd869c','生春二十首 五','元稹','唐','唐诗','tang','','[]','何處生春早，春生曉禁中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生曉禁中。", "殿階龍斾日，漏閣寶箏風。", "藥樹香煙重，天顏瑞氣融。", "柳梅渾未覺，青紫已叢叢。"]'),
('a8fc8df0-c6ac-4f7b-8476-8eb464b2c1a0','生春二十首 六','元稹','唐','唐诗','tang','','[]','何處生春早，春生江路中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生江路中。", "雨移臨浦市，晴候過湖風。", "蘆筍錐猶短，凌澌玉漸融。", "數宗船載足，商婦兩眉叢。"]'),
('d62d3a70-1742-45fd-a08d-0be5ba5733f9','生春二十首 七','元稹','唐','唐诗','tang','','[]','何處生春早，春生野墅中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生野墅中。", "病翁閑向日，征婦嬾成風。", "斫筤天雖暖，穿區凍未融。", "鞭牛縣門外，爭土蓋蠶叢。"]'),
('76206acd-40e7-41bc-a957-12a30e59dd7e','生春二十首 八','元稹','唐','唐诗','tang','','[]','何處生春早，春生冰岸中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生冰岸中。", "尚憐扶臘雪，漸覺受東風。", "織女雲橋斷，波神玉貌融。", "便成嗚咽去，流恨與蓮叢。"]'),
('c746891e-189b-49e8-8459-459317031476','生春二十首 九','元稹','唐','唐诗','tang','','[]','何處生春早，春生柳眼中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生柳眼中。", "芽新纔綻日，茸短未含風。", "綠誤眉心重，黃驚蠟淚融。", "碧條殊未合，愁緒已先叢。"]'),
('fb1e142c-039f-4630-aa60-ea6c311ecbe0','生春二十首 十','元稹','唐','唐诗','tang','','[]','何處生春早，春生梅援中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生梅援中。", "蘂排難犯雪，香乞擬來風。", "隴迥羌聲怨，江遙客思融。", "年年最相惱，緣未有諸叢。"]'),
('14140e43-736f-4e66-94e3-77a7297124b7','生春二十首 十一','元稹','唐','唐诗','tang','','[]','何處生春早，春生鳥思中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生鳥思中。", "鵲巢移舊歲，䳒羽旋高風。", "鴻鴈驚沙暖，鴛鴦愛水融。", "最憐雙翡翠，飛入小梅叢。"]'),
('9077071d-8e11-463f-b540-cd3e65bd328c','生春二十首 十二','元稹','唐','唐诗','tang','','[]','何處生春早，春生池榭中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生池榭中。", "鏤瓊冰陷日，文縠水廻風。", "柳愛和身動，梅愁合樹融。", "草芽猶未出，挑得小萱叢。"]'),
('62991599-6a5c-46c4-b197-4f07e39893ad','生春二十首 十三','元稹','唐','唐诗','tang','','[]','何處生春早，春生稚戲中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生稚戲中。", "亂騎殘爆竹，爭唾小旋風。", "駡雨愁妨走，呵冰喜旋融。", "女兒針線盡，偷學五辛叢。"]'),
('4579fbab-df7b-4e90-ba1d-35bb35b4db41','生春二十首 十四','元稹','唐','唐诗','tang','','[]','何處生春早，春生人意中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生人意中。", "曉妝雖近火，晴戲漸憐風。", "暗入心情嬾，先添酒思融。", "預知花好惡，偏在最深叢。"]'),
('55542850-61a0-4958-9f15-a65ca013f0b6','生春二十首 十五','元稹','唐','唐诗','tang','','[]','何處生春早，春生半睡中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生半睡中。", "見燈如見霧，聞雨似聞風。", "開眼猶殘夢，擡身便恐融。", "却成雙翅蝶，還繞庳花叢。"]'),
('5c69fb38-d8a5-4dc1-a713-c17d084adcd0','生春二十首 十六','元稹','唐','唐诗','tang','','[]','何處生春早，春生曉鏡中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生曉鏡中。", "手寒勻面粉，鬟動倚簾風。", "宿霧梅心滴，朝光幕上融。", "思牽梳洗嬾，空拔綠絲叢。"]'),
('7f22aec4-e20a-47f2-b637-6c81be69f2b6','生春二十首 十七','元稹','唐','唐诗','tang','','[]','何處生春早，春生綺戶中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生綺戶中。", "玉櫳穿細日，羅幔張輕風。", "柳軟腰支嫩，梅香密氣融。", "獨眠傍妬物，偷鏟合歡叢。"]'),
('c6203fcb-4ab3-4af2-9b2a-4fa906d6cc94','生春二十首 十八','元稹','唐','唐诗','tang','','[]','何處生春早，春生老病中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生老病中。", "土膏蒸足腫，天暖癢頭風。", "似覺肌膚展，潛知血氣融。", "又添新一歲，衰白轉成叢。"]'),
('f0a8c0eb-fbe9-478d-9e65-a6e9370a4b54','生春二十首 十九','元稹','唐','唐诗','tang','','[]','何處生春早，春生客思中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生客思中。", "旅魂驚北鴈，鄉信是東風。", "縱有心灰動，無由鬢雪融。", "未知開眼日，空繞未開叢。"]'),
('3605d246-f841-4fc9-9af4-81e50af7ff21','生春二十首 二十','元稹','唐','唐诗','tang','','[]','何處生春早，春生濛雨中。',48,'全唐诗/poet.tang.21000.json','["何處生春早，春生濛雨中。", "裛塵微有氣，拂面細如風。", "柳誤啼珠密，梅驚粉汗融。", "滿空愁淡淡，應豫憶芳叢。"]'),
('3ceee809-a65a-4eac-91d7-8b2859b4fa4e','嘉陵水','元稹','唐','唐诗','tang','','[]','爾是無心水，東流有恨無。',24,'全唐诗/poet.tang.21000.json','["爾是無心水，東流有恨無。", "我心無說處，也共爾何殊。"]'),
('2070aa40-e05d-4f56-8cd5-81dc52349125','漫天嶺贈僧','元稹','唐','唐诗','tang','','[]','五上兩漫天，因師懺業緣。',24,'全唐诗/poet.tang.21000.json','["五上兩漫天，因師懺業緣。", "漫天無盡日，浮世有窮年。"]'),
('3a5a05fc-b27d-4506-afb8-6a1e6aebeff0','百牢關','元稹','唐','唐诗','tang','','[]','天上無窮路，生期七十間。',24,'全唐诗/poet.tang.21000.json','["天上無窮路，生期七十間。", "那堪九年內，五度百牢關。"]'),
('8d86248a-1761-4971-bdf8-ee2ed0ed10a6','二月十九日酬王十八全素','元稹','唐','唐诗','tang','','[]','君念世上川，嗟予老瘴天。',24,'全唐诗/poet.tang.21000.json','["君念世上川，嗟予老瘴天。", "那堪十日內，又長白頭年。"]'),
('90d7fd77-5000-4cfd-8d58-0d1f0c8c6006','滎陽鄭公以稹寓居嚴茅有池塘之勝寄詩四首因有意獻','元稹','唐','唐诗','tang','','[]','激射分流闊，灣環此地多。',48,'全唐诗/poet.tang.21000.json','["激射分流闊，灣環此地多。", "暫停隨梗浪，猶閱敗霜荷。", "恨阻還江勢，思深到海波。", "自傷才畎澮，其奈贈珠何。"]'),
('27ac6dc5-8146-4d05-a26e-2b751770184f','酬樂天寄蘄州簟','元稹','唐','唐诗','tang','','[]','蘄簟未經春，君先拭翠筠。',72,'全唐诗/poet.tang.21000.json','["蘄簟未經春，君先拭翠筠。", "知爲熱時物，預與瘴中人。", "碾玉連心潤，編牙小片珍。", "霜凝青汗簡，冰透碧游鱗。", "水魄輕涵黛，琉璃薄帶塵。", "夢成傷冷滑，驚臥老龍身。"]'),
('df9de0ac-2b78-433f-ac3c-e86dfbb9b2ee','酬李浙西先因從事見寄之作','元稹','唐','唐诗','tang','','[]','近日金鑾直，親於漢珥貂。',48,'全唐诗/poet.tang.21000.json','["近日金鑾直，親於漢珥貂。", "內人傳帝命，丞相讓吾僚。", "浙郡懸旌遠，長安諭日遙。", "因君蘂珠贈，還一夢煙霄。"]'),
('d9eab0f2-9bea-4065-b574-ec7bcae31f25','酬周從事望海亭見寄','元稹','唐','唐诗','tang','','[]','年老無流輩，行稀足薜蘿。',48,'全唐诗/poet.tang.21000.json','["年老無流輩，行稀足薜蘿。", "熱時憐水近，高處見山多。", "衣袖長堪舞，喉嚨轉解歌。", "不辭狂復醉，人世有風波。"]'),
('9a0cdeca-65bb-4e52-9a40-f1a1a037b5d9','代杭民答樂天','元稹','唐','唐诗','tang','','[]','翠幕籠斜日，朱衣儼別筵。',48,'全唐诗/poet.tang.21000.json','["翠幕籠斜日，朱衣儼別筵。", "管弦淒欲罷，城郭望依然。", "路溢新城市，農開舊廢田。", "春坊幸無事，何惜借三年。"]'),
('ed96672b-c89f-47c1-983b-c7bf78e34ce1','杏園','元稹','唐','唐诗','tang','','[]','浩浩長安車馬塵，狂風吹送每年春。',32,'全唐诗/poet.tang.21000.json','["浩浩長安車馬塵，狂風吹送每年春。", "門前本是虛空界，何事栽花誤世人。"]'),
('8085e498-9420-4bf8-93ac-c407eca63f03','菊花','元稹','唐','唐诗','tang','','["\u548f\u7269", "\u83ca\u82b1", "\u6292\u6000", "\u548f\u7269\u8bd7"]','秋叢繞舍似陶家，遍繞籬邊日漸斜。',32,'全唐诗/poet.tang.21000.json','["秋叢繞舍似陶家，遍繞籬邊日漸斜。", "不是花中偏愛菊，此花開盡更無花。"]'),
('0cb447c4-43a5-4f22-8a48-b1e0a823a08c','酬哥舒大少府寄同年科第','元稹','唐','唐诗','tang','','[]','前年科第偏年少，未解知羞最愛狂。',64,'全唐诗/poet.tang.21000.json','["前年科第偏年少，未解知羞最愛狂。", "九陌爭馳好鞍馬，八人同著綵衣裳。", "自言行樂朝朝是，豈料浮生漸漸忙。", "賴得官閑且疎散，到君花下憶諸郎。"]'),
('0b864ee4-2a60-4408-88bb-cae317fc78c1','幽棲','元稹','唐','唐诗','tang','','[]','野人自愛幽棲所，近對長松遠是山。',64,'全唐诗/poet.tang.21000.json','["野人自愛幽棲所，近對長松遠是山。", "盡日望雲心不繫，有時看月夜方閑。", "壺中天地乾坤外，夢裏身名旦暮間。", "遼海若思千歲鶴，且留城市會飛還。"]'),
('b328e435-0a88-46e0-b4cc-28c87753b6f1','清都春霽寄胡三吳十一','元稹','唐','唐诗','tang','','[]','蘂珠宮殿經微雨，草樹無塵耀眼光。',64,'全唐诗/poet.tang.21000.json','["蘂珠宮殿經微雨，草樹無塵耀眼光。", "白日當空天氣暖，好風飄樹柳陰涼。", "蜂憐宿露攢芳久，燕得新泥拂戶忙。", "時節催年春不住，武陵花謝憶諸郎。"]'),
('f4e9e77c-3ae0-4c64-80ce-73d705d4a835','華嶽寺','元稹','唐','唐诗','tang','','["\u534e\u5c71"]','山前古寺臨長道，來往淹留爲愛山。',64,'全唐诗/poet.tang.21000.json','["山前古寺臨長道，來往淹留爲愛山。", "雙燕營巢始西別，百花成子又東還。", "暝驅羸馬頻看堠，曉聽鳴雞欲度關。", "羞見竇師無外役，竹窗依舊老身閑。"]'),
('b7f0f6a5-d9aa-4474-9a47-1632823cf119','天壇上境','元稹','唐','唐诗','tang','','[]','野人性僻窮深僻，芸署官閑不似官。',64,'全唐诗/poet.tang.21000.json','["野人性僻窮深僻，芸署官閑不似官。", "萬里洞中朝玉帝，九光霞外宿天壇。", "洪漣浩渺東溟曙，白日低回上境寒。", "因爲南昌檢仙籍，馬君家世奉還丹。"]'),
('8ef4954c-9fcf-4f13-ae95-18c6f94853f4','尋西明寺僧不在','元稹','唐','唐诗','tang','','[]','春來日日到西林，飛錫經行不可尋。',32,'全唐诗/poet.tang.21000.json','["春來日日到西林，飛錫經行不可尋。", "蓮池舊是無波水，莫逐狂風起浪心。"]'),
('80d07f27-f539-44f0-a402-00e3a59a0691','與吳侍御春遊','元稹','唐','唐诗','tang','','[]','蒼龍闕下陪驄馬，紫閣峰頭見白雲。',32,'全唐诗/poet.tang.21000.json','["蒼龍闕下陪驄馬，紫閣峰頭見白雲。", "滿眼流光隨日度，今朝花落更紛紛。"]'),
('0a0f8ea1-9ba7-4c4d-a85c-9f1df1e8065d','晚春','元稹','唐','唐诗','tang','','[]','晝靜簾疎燕語頻，雙雙鬬雀動階塵。',32,'全唐诗/poet.tang.21000.json','["晝靜簾疎燕語頻，雙雙鬬雀動階塵。", "柴扉日暮隨風掩，落盡閑花不見人。"]'),
('94824a5c-c555-449f-96e3-8dbdab954b28','先醉','元稹','唐','唐诗','tang','','[]','今日樽前敗飲名，三桮未盡不能傾。',32,'全唐诗/poet.tang.21000.json','["今日樽前敗飲名，三桮未盡不能傾。", "怪來花下長先醉，半是春風蕩酒情。"]'),
('1486d94d-a8a6-4c71-88ec-221c17920dab','獨醉','元稹','唐','唐诗','tang','','[]','一樹芳菲也當春，漫隨車馬擁行塵。',32,'全唐诗/poet.tang.21000.json','["一樹芳菲也當春，漫隨車馬擁行塵。", "桃花解笑鶯能語，自醉自眠那藉人。"]'),
('2499282a-00c2-4327-9891-e5949d06373b','宿醉','元稹','唐','唐诗','tang','','[]','風引春心不自由，等閑衝席飲多籌。',32,'全唐诗/poet.tang.21000.json','["風引春心不自由，等閑衝席飲多籌。", "朝來始向花前覺，度却醒時一夜愁。"]'),
('249ef03d-725c-4f4f-bc02-ab39171d4945','懼醉','元稹','唐','唐诗','tang','','[]','聞道秋來怯夜寒，不辭泥水爲桮盤。',32,'全唐诗/poet.tang.21000.json','["聞道秋來怯夜寒，不辭泥水爲桮盤。", "殷勤懼醉有深意，愁到醒時燈火闌。"]'),
('9a3e3b6f-f6c3-495c-b5e7-f5d4b36e64d1','羨醉','元稹','唐','唐诗','tang','','[]','綺陌高樓競醉眠，共期顦顇不相憐。',32,'全唐诗/poet.tang.21000.json','["綺陌高樓競醉眠，共期顦顇不相憐。", "也應自有尋春日，虛度而今正少年。"]'),
('f9e0cca7-70dd-4d08-954b-72fdd42aae28','憶醉','元稹','唐','唐诗','tang','','[]','自歎旅人行意速，每嫌桮酒緩歸期。',32,'全唐诗/poet.tang.21000.json','["自歎旅人行意速，每嫌桮酒緩歸期。", "今朝偏遇醒時別，淚落風前憶醉時。"]'),
('29467c48-ba36-40cf-8ef6-3d9c92de5150','病醉','元稹','唐','唐诗','tang','','[]','醉伴見儂因病酒，道儂無酒不相窺。',32,'全唐诗/poet.tang.21000.json','["醉伴見儂因病酒，道儂無酒不相窺。", "那知下藥還沽底，人去人來剩一巵。"]'),
('6959f1b1-0404-44a4-99cf-7834fee41a28','擬醉','元稹','唐','唐诗','tang','','[]','九月閑宵初向火，一尊清酒始行桮。',32,'全唐诗/poet.tang.21000.json','["九月閑宵初向火，一尊清酒始行桮。", "憐君城外遙相憶，冒雨衝泥黑地來。"]'),
('65635820-9d48-4902-b107-ef280fcacb67','勸醉','元稹','唐','唐诗','tang','','[]','竇家能釀銷愁酒，但是愁人便與銷。',32,'全唐诗/poet.tang.21000.json','["竇家能釀銷愁酒，但是愁人便與銷。", "願我共君俱寂寞，只應連夜復連朝。"]'),
('4f444942-bb38-42c9-bc82-c8e908b04d31','任醉','元稹','唐','唐诗','tang','','[]','本怕酒醒渾不飲，因君相勸覺情來。',32,'全唐诗/poet.tang.21000.json','["本怕酒醒渾不飲，因君相勸覺情來。", "殷勤滿酌從聽醉，乍可欲醒還一桮。"]'),
('9cad7c85-58ea-4593-bbb7-00e74fe24bd4','同醉','元稹','唐','唐诗','tang','','[]','柏樹臺中推事人，杏花壇上鍊形真。',32,'全唐诗/poet.tang.21000.json','["柏樹臺中推事人，杏花壇上鍊形真。", "心源一種閑如水，同醉櫻桃林下春。"]'),
('d18e7036-1278-442b-b849-c2ee42ca8522','狂醉','元稹','唐','唐诗','tang','','[]','一自柏臺爲御史，二年辜負兩京春。',32,'全唐诗/poet.tang.21000.json','["一自柏臺爲御史，二年辜負兩京春。", "峴亭今日顛狂醉，舞引紅娘亂打人。"]'),
('f29311e8-c609-423a-973a-5c70f9578f51','伴僧行','元稹','唐','唐诗','tang','','[]','春來求事百無成，因向愁中識道情。',32,'全唐诗/poet.tang.21000.json','["春來求事百無成，因向愁中識道情。", "花滿杏園千萬樹，幾人能伴老僧行。"]'),
('4b53f8e5-9021-431f-997b-2d50fd290a1a','古寺','元稹','唐','唐诗','tang','','[]','古寺春餘日半斜，竹風蕭爽勝人家。',32,'全唐诗/poet.tang.21000.json','["古寺春餘日半斜，竹風蕭爽勝人家。", "花時不到有花院，意在尋僧不在花。"]'),
('a59bdc6e-6a2a-4759-8592-10a3724e0a69','定僧','元稹','唐','唐诗','tang','','[]','落魄閑行不著家，徧尋春寺賞年華。',32,'全唐诗/poet.tang.21000.json','["落魄閑行不著家，徧尋春寺賞年華。", "野僧偶向花前定，滿樹狂風滿樹花。"]'),
('9991d806-3930-408e-a943-54a3d69e56db','觀心處','元稹','唐','唐诗','tang','','[]','滿坐喧喧笑語頻，獨憐方丈了無塵。',32,'全唐诗/poet.tang.21000.json','["滿坐喧喧笑語頻，獨憐方丈了無塵。", "燈前便是觀心處，要似觀心有幾人。"]'),
('9b696659-42b7-4695-8251-971a0cf706e2','智度師二首 一','元稹','唐','唐诗','tang','','[]','四十年前馬上飛，功名藏盡擁禪衣。',32,'全唐诗/poet.tang.21000.json','["四十年前馬上飛，功名藏盡擁禪衣。", "石榴園下擒生處，獨自閑行獨自歸。"]'),
('f801df9d-6ccc-42bb-998a-3772c86e3077','智度師二首 二','元稹','唐','唐诗','tang','','[]','三陷思明三突圍，鐵衣拋盡衲禪衣。',32,'全唐诗/poet.tang.21000.json','["三陷思明三突圍，鐵衣拋盡衲禪衣。", "天津橋上無人識，閑凭欄干望落暉。"]'),
('f1409f02-1aa8-4837-a92a-7a0b5c8c86ff','西明寺牡丹','元稹','唐','唐诗','tang','','[]','花向琉璃地上生，光風炫轉紫雲英。',32,'全唐诗/poet.tang.21000.json','["花向琉璃地上生，光風炫轉紫雲英。", "自從天女盤中見，直至今朝眼更明。"]'),
('a328d410-7fbb-4727-bfd9-9f15129a7241','憶楊十二','元稹','唐','唐诗','tang','','[]','去時芍藥纔堪贈，看却殘花已度春。',32,'全唐诗/poet.tang.21000.json','["去時芍藥纔堪贈，看却殘花已度春。", "只爲情深偏愴別，等閑相見莫相親。"]'),
('0f813a11-a3a7-4612-b48d-69ee1a234bbd','送復夢赴韋令幕','元稹','唐','唐诗','tang','','[]','世上於今重檢身，吾徒耽酒作狂人。',32,'全唐诗/poet.tang.21000.json','["世上於今重檢身，吾徒耽酒作狂人。", "西曹舊事多持法，慎莫吐他丞相茵。"]'),
('7c11ab39-c2d2-40f6-8487-b849f20a15e1','送劉太白','元稹','唐','唐诗','tang','','[]','洛陽大底居人少，從善坊西最寂寥。',32,'全唐诗/poet.tang.21000.json','["洛陽大底居人少，從善坊西最寂寥。", "想得劉君獨騎馬，古堤愁樹隔中橋。"]'),
('bd719b17-e5f3-45ac-ba44-8caa8b298024','奉誠園','元稹','唐','唐诗','tang','','[]','蕭相深誠奉至尊，舊居求作奉誠園。',32,'全唐诗/poet.tang.21000.json','["蕭相深誠奉至尊，舊居求作奉誠園。", "秋來古巷無人掃，樹滿空牆閉戟門。"]'),
('4d68459e-3fac-4968-99fd-e0c1e3e7509c','與太白同之東洛至櫟陽太白染疾駐行予九月二十五日至華嶽寺雪後望山','元稹','唐','唐诗','tang','','["\u534e\u5c71"]','共作洛陽千里伴，老劉因疾駐行軒。',32,'全唐诗/poet.tang.21000.json','["共作洛陽千里伴，老劉因疾駐行軒。", "今朝獨自山前立，雪滿三峰倚寺門。"]'),
('7cc954d2-0b6b-4fc5-aec8-1841b8ea46bc','野狐泉柳林','元稹','唐','唐诗','tang','','[]','去日野狐泉上柳，紫牙初綻拂眉低。',32,'全唐诗/poet.tang.21000.json','["去日野狐泉上柳，紫牙初綻拂眉低。", "秋來寥落驚風雨，葉滿空林踏作泥。"]'),
('9cdfbdae-79ce-462c-ab32-37f809b326fa','酬胡三憑人問牡丹','元稹','唐','唐诗','tang','','[]','竊見胡三問牡丹，爲言依舊滿西欄。',32,'全唐诗/poet.tang.21000.json','["竊見胡三問牡丹，爲言依舊滿西欄。", "花時何處偏相憶，寥落衰紅雨後看。"]'),
('31791a22-6ec0-47c8-a3b6-1a207d69e749','酬樂天秋興見贈本句云莫怪獨吟秋興苦比君校近二毛年','元稹','唐','唐诗','tang','','[]','勸君休作悲秋賦，白髮如星也任垂。',32,'全唐诗/poet.tang.21000.json','["勸君休作悲秋賦，白髮如星也任垂。", "畢竟百年同是夢，長年何異少何爲。"]'),
('26f406cf-90f0-4aa2-b594-1473ced4856b','雪後宿同軌店上法護寺鐘樓望月','元稹','唐','唐诗','tang','','[]','滿山殘雪滿山風，野寺無門院院空。',32,'全唐诗/poet.tang.21000.json','["滿山殘雪滿山風，野寺無門院院空。", "煙火漸稀孤店靜，月明深夜古樓中。"]'),
('2acc06f6-6da2-4b71-8d57-95fe33b3af30','陪韋尚書丈歸履信宅因贈韋氏兄弟','元稹','唐','唐诗','tang','','[]','紫垣騶騎入華居，公子文衣護錦輿。',32,'全唐诗/poet.tang.21000.json','["紫垣騶騎入華居，公子文衣護錦輿。", "眠閣書生復何事，也騎羸馬從尚書。"]'),
('33d01690-c6e7-449b-964d-d3cbfb8de2b2','永貞二年正月二日上御丹鳳樓赦天下予與李公垂庾順之閑行曲江不及盛觀','元稹','唐','唐诗','tang','','[]','春來饒夢慵朝起，不看千官擁御樓。',32,'全唐诗/poet.tang.21000.json','["春來饒夢慵朝起，不看千官擁御樓。", "却著閑行是忙事，數人同傍曲江頭。"]'),
('7d314c99-5469-4867-8969-9990cbdabf54','韋居守晚歲常言退休之志因署其居曰大隱洞命予賦詩因贈絕句','元稹','唐','唐诗','tang','','[]','謝公潛有東山意，已向朱門啓洞門。',32,'全唐诗/poet.tang.21000.json','["謝公潛有東山意，已向朱門啓洞門。", "大隱猶疑戀朝市，不如名作罷歸園。"]'),
('13202e47-9430-4789-89b8-f3bdc623e49e','贈李十二牡丹花片因以餞行','元稹','唐','唐诗','tang','','[]','鸎澁餘聲絮墮風，牡丹花盡葉成叢。',32,'全唐诗/poet.tang.21000.json','["鸎澁餘聲絮墮風，牡丹花盡葉成叢。", "可憐顏色經年別，收取朱闌一片紅。"]'),
('35388b3e-a98a-479d-aee4-e22a573cbb0c','題李十一修行里居壁','元稹','唐','唐诗','tang','','[]','雲闕朝迴塵騎合，杏花春盡曲江閑。',32,'全唐诗/poet.tang.21000.json','["雲闕朝迴塵騎合，杏花春盡曲江閑。", "憐君雖在城中住，不隔人家便是山。"]'),
('069ab4ed-53f7-4d02-bb5b-5ea859971f72','靖安窮居','元稹','唐','唐诗','tang','','[]','喧靜不由居遠近，大都車馬就權門。',32,'全唐诗/poet.tang.21000.json','["喧靜不由居遠近，大都車馬就權門。", "野人住處無名利，草滿空階樹滿園。"]'),
('4a59963b-3551-4e86-8016-4391234956bd','贈樂天','元稹','唐','唐诗','tang','','[]','等閑相見銷長日，也有閑時更學琴。',32,'全唐诗/poet.tang.21000.json','["等閑相見銷長日，也有閑時更學琴。", "不是眼前無外物，不關心事不經心。"]'),
('86f6f93a-4705-4416-994b-f0bed8471193','使東川 駱口驛二首 一','元稹','唐','唐诗','tang','','[]','郵亭壁上數行字，崔李題名王白詩。',32,'全唐诗/poet.tang.21000.json','["郵亭壁上數行字，崔李題名王白詩。", "盡日無人共言語，不離牆下至行時。"]'),
('5515d6a8-272d-4a16-827b-ed8d3d8448e4','使東川 駱口驛二首 二','元稹','唐','唐诗','tang','','[]','二星徼外通蠻服，五夜燈前草御文。',32,'全唐诗/poet.tang.21000.json','["二星徼外通蠻服，五夜燈前草御文。", "我到東川恰相半，向南看月北看雲。"]'),
('d6854aa9-80fd-4b31-9e7e-802cfcbee4f9','使東川 清明日','元稹','唐','唐诗','tang','','[]','常年寒食好風輕，觸處相隨取次行。',32,'全唐诗/poet.tang.21000.json','["常年寒食好風輕，觸處相隨取次行。", "今日清明漢江上，一身騎馬縣官迎。"]'),
('6fe16304-7de7-4383-9501-eab14dedd165','使東川 亞枝紅','元稹','唐','唐诗','tang','','[]','平陽池上亞枝紅，悵望山郵事事同。',32,'全唐诗/poet.tang.21000.json','["平陽池上亞枝紅，悵望山郵事事同。", "還向萬竿深竹裏，一枝渾臥碧流中。"]'),
('103e1b52-b0b7-412b-9b76-02a4b834848f','使東川 梁州夢','元稹','唐','唐诗','tang','','[]','夢君同繞曲江頭，也向慈恩院院遊。',32,'全唐诗/poet.tang.21000.json','["夢君同繞曲江頭，也向慈恩院院遊。", "亭吏呼人排去馬，忽驚身在古梁州。"]'),
('581d09df-97be-40e5-af0c-88be3c8dfd6f','使東川 南秦雪','元稹','唐','唐诗','tang','','[]','帝城寒盡臨寒食，駱谷春深未有春。',64,'全唐诗/poet.tang.21000.json','["帝城寒盡臨寒食，駱谷春深未有春。", "纔見嶺頭雲似蓋，已驚巖下雪如塵。", "千峰筍石千株玉，萬樹松蘿萬朵銀。", "飛鳥不飛猿不動，青驄御史上南秦。"]'),
('b5133a5c-8a3b-4200-87c0-1e5bb03e3de9','使東川 江樓月','元稹','唐','唐诗','tang','','[]','嘉陵江岸驛樓中，江在樓前月在空。',64,'全唐诗/poet.tang.21000.json','["嘉陵江岸驛樓中，江在樓前月在空。", "月色滿牀兼滿地，江聲如鼓復如風。", "誠知遠近皆三五，但恐陰晴有異同。", "萬一帝鄉還潔白，幾人潛傍杏園東。"]'),
('caf88efc-7f27-44ce-bfd5-aebe4cb6468e','使東川 慙問囚','元稹','唐','唐诗','tang','','[]','司馬子微壇上頭，與君深結白雲儔。',64,'全唐诗/poet.tang.21000.json','["司馬子微壇上頭，與君深結白雲儔。", "尚平村落擬連買，王屋山泉爲別遊。", "各待陸渾求一尉，共資三徑便同休。", "那知今日蜀門路，帶月夜行緣問囚。"]'),
('5c7b9255-66db-4c4e-b2ae-73342be2502b','使東川 江上行','元稹','唐','唐诗','tang','','[]','悶見漢江流不息，悠悠漫漫竟何成。',32,'全唐诗/poet.tang.21000.json','["悶見漢江流不息，悠悠漫漫竟何成。", "江流不語意相問，何事遠來江上行。"]'),
('22a08255-3ae2-4d5c-9b54-bcfb48808ea7','使東川 漢江上笛','元稹','唐','唐诗','tang','','[]','小年爲寫遊梁賦，最說漢江聞笛愁。',32,'全唐诗/poet.tang.21000.json','["小年爲寫遊梁賦，最說漢江聞笛愁。", "今夜聽時在何處，月明西縣驛南樓。"]'),
('218da403-736a-4102-8308-09c22230e8a0','使東川 郵亭月','元稹','唐','唐诗','tang','','[]','君多務實我多情，大抵偏嗔步月明。',32,'全唐诗/poet.tang.21000.json','["君多務實我多情，大抵偏嗔步月明。", "今夜山郵與蠻嶂，君應堅臥我還行。"]'),
('6ac58dd5-d86a-49ca-bf31-08520f85d513','使東川 嘉陵驛二首 一','元稹','唐','唐诗','tang','','[]','嘉陵驛上空牀客，一夜嘉陵江水聲。',32,'全唐诗/poet.tang.21000.json','["嘉陵驛上空牀客，一夜嘉陵江水聲。", "仍對牆南滿山樹，野花撩亂月朧明。"]'),
('bb059bc3-708b-4a8a-a835-4060b9803c57','使東川 嘉陵驛二首 二','元稹','唐','唐诗','tang','','[]','牆外花枝壓短牆，月明還照半張牀。',32,'全唐诗/poet.tang.21000.json','["牆外花枝壓短牆，月明還照半張牀。", "無人會得此時意，一夜獨眠西畔廊。"]'),
('ccd386d2-a2d8-486d-bd99-4532e92530ca','使東川 百牢關','元稹','唐','唐诗','tang','','[]','嘉陵江上萬重山，何事臨江一破顏。',32,'全唐诗/poet.tang.21000.json','["嘉陵江上萬重山，何事臨江一破顏。", "自笑只緣任敬仲，等閑身度百牢關。"]'),
('53a82ea9-ce9f-40cc-800c-4e5032afb150','使東川 江花落','元稹','唐','唐诗','tang','','[]','日暮嘉陵江水東，棃花萬片逐江風。',32,'全唐诗/poet.tang.21000.json','["日暮嘉陵江水東，棃花萬片逐江風。", "江花何處最腸斷，半落江流半在空。"]'),
('5d55cbd0-897e-4c01-b618-0830269835cb','使東川 嘉陵江二首 一','元稹','唐','唐诗','tang','','[]','秦人惟識秦中水，長想吳江與蜀江。',32,'全唐诗/poet.tang.21000.json','["秦人惟識秦中水，長想吳江與蜀江。", "今日嘉川驛樓下，可憐如練繞明窗。"]'),
('c7ae908f-1310-4d18-8713-b2b712183b13','使東川 嘉陵江二首 二','元稹','唐','唐诗','tang','','[]','千里嘉陵江水聲，何年重繞此江行。',32,'全唐诗/poet.tang.21000.json','["千里嘉陵江水聲，何年重繞此江行。", "只應添得清宵夢，時見滿江流月明。"]'),
('9527fca2-6423-461d-a129-0f123026a333','使東川 西縣驛','元稹','唐','唐诗','tang','','[]','去時樓上清明夜，月照樓前撩亂花。',32,'全唐诗/poet.tang.21000.json','["去時樓上清明夜，月照樓前撩亂花。", "今日成陰復成子，可憐春盡未還家。"]'),
('5a03faa6-9ccc-4839-a2ee-c480b8fd861e','使東川 望喜驛','元稹','唐','唐诗','tang','','[]','滿眼文書堆案邊，眼昏偷得暫時眠。',32,'全唐诗/poet.tang.21000.json','["滿眼文書堆案邊，眼昏偷得暫時眠。", "子規驚覺燈又滅，一道月光橫枕前。"]'),
('e51736f4-8fe8-400e-92eb-8a1b9c1a6a16','使東川 好時節','元稹','唐','唐诗','tang','','[]','身騎驄馬峨眉下，面帶霜威卓氏前。',32,'全唐诗/poet.tang.21000.json','["身騎驄馬峨眉下，面帶霜威卓氏前。", "虛度東川好時節，酒樓元被蜀兒眠。"]'),
('319ecb16-94e3-4fad-9d34-437eca2ea1be','使東川 夜深行','元稹','唐','唐诗','tang','','[]','夜深猶自繞江行，震地江聲似鼓聲。',32,'全唐诗/poet.tang.21000.json','["夜深猶自繞江行，震地江聲似鼓聲。", "漸見戍樓疑近驛，百牢關吏火前迎。"]'),
('125359bd-6743-482e-9dcd-66c680233ca3','使東川 望驛臺','元稹','唐','唐诗','tang','','[]','可憐三月三旬足，悵望江邊望驛臺。',32,'全唐诗/poet.tang.21000.json','["可憐三月三旬足，悵望江邊望驛臺。", "料得孟光今日語，不曾春盡不歸來。"]'),
('25fb5507-0913-44d8-ab9e-b2e113537535','贈咸陽少府蕭郎','元稹','唐','唐诗','tang','','[]','莫怪逢君淚每盈，仲由多感有深情。',64,'全唐诗/poet.tang.21000.json','["莫怪逢君淚每盈，仲由多感有深情。", "陸家幼女託良壻，阮氏諸房無外生。", "顧我自傷爲弟拙，念渠能繼事姑名。", "別時何處最腸斷，日暮渭陽驅馬行。"]'),
('153d317f-8d14-4278-a8cb-781acb795453','贈呂三校書','元稹','唐','唐诗','tang','','[]','同年同拜校書郎，觸處潛行爛熳狂。',64,'全唐诗/poet.tang.21000.json','["同年同拜校書郎，觸處潛行爛熳狂。", "共占花園爭趙辟，競添錢貫定秋娘。", "七年浮世皆經眼，八月閑宵忽竝牀。", "語到欲明歡又泣，傍人相笑兩相傷。"]'),
('8583100a-bd5c-48c1-966f-9c28a73d0a43','封書','元稹','唐','唐诗','tang','','[]','鶴臺南望白雲關，城市猶存暫一還。',32,'全唐诗/poet.tang.21000.json','["鶴臺南望白雲關，城市猶存暫一還。", "書出步虛三百韻，蘂珠文字在人間。"]'),
('48a7d3fe-36c1-4654-b957-07ba14de0d58','仁風李著作園醉後寄李十','元稹','唐','唐诗','tang','','[]','朧明春月照花枝，花下音聲是管兒。',32,'全唐诗/poet.tang.21000.json','["朧明春月照花枝，花下音聲是管兒。", "却笑西京李員外，五更騎馬趁朝時。"]'),
('bcc75cc7-04a6-4599-81e8-48817a28a056','燈影','元稹','唐','唐诗','tang','','[]','洛陽晝夜無車馬，漫挂紅紗滿樹頭。',32,'全唐诗/poet.tang.21000.json','["洛陽晝夜無車馬，漫挂紅紗滿樹頭。", "見說平時燈影裏，玄宗潛伴太真游。"]'),
('46cb00e3-d659-463b-bff9-da3047e3eaa3','貶江陵途中寄樂天杓直杓直以員外郎判鹽鐵樂天以拾遺在翰林','元稹','唐','唐诗','tang','','[]','想到江陵無一事，酒杯書卷綴新文。',64,'全唐诗/poet.tang.21000.json','["想到江陵無一事，酒杯書卷綴新文。", "紫芽嫩茗和枝采，朱橘香苞數瓣分。", "暇日上山狂逐鹿，凌晨過寺飽看雲。", "算緡草詔終須解，不敢將心遠羨君。"]'),
('7fe83bb3-c791-47a4-a66b-b7f0d7551a94','渡漢江','元稹','唐','唐诗','tang','','[]','嶓冢去年尋漾水，襄陽今日渡江濆。',64,'全唐诗/poet.tang.21000.json','["嶓冢去年尋漾水，襄陽今日渡江濆。", "山遙遠樹纔成點，浦靜沈碑欲辨文。", "萬里朝宗誠可羨，百川流入渺難分。", "鯢鯨歸穴東溟溢，又作波濤隨伍員。"]'),
('065548d2-57c9-4735-b6cf-161f25c999d5','哀病驄呈致用','元稹','唐','唐诗','tang','','[]','櫪上病驄啼褭褭，江邊廢宅路迢迢。',96,'全唐诗/poet.tang.21000.json','["櫪上病驄啼褭褭，江邊廢宅路迢迢。", "自經梅雨長垂耳，乍食菰蔣欲折腰。", "金絡頭銜光未滅，玉花衫色瘦來燋。", "曾聽禁漏驚衙鼓，慣蹋康衢怕小橋。", "半夜雄嘶心不死，日高飢臥尾還搖。", "龍媒薄地天池遠，何事牽牛在碧霄。"]'),
('a97e8535-9ed3-43a2-b7a1-929399a49229','送嶺南崔侍御','元稹','唐','唐诗','tang','','[]','我是北人長北望，每嗟南雁更南飛。',160,'全唐诗/poet.tang.21000.json','["我是北人長北望，每嗟南雁更南飛。", "君今又作嶺南別，南雁北歸君未歸。", "洞主參承驚豸角，島夷安集慕霜威。", "黃家賊用鑹刀利，白水郎行旱地稀。", "蜃吐朝光樓隱隱，鼇吹細浪雨霏霏。", "毒龍蛻骨轟雷鼓，野象埋牙斸石磯。", "火布垢塵須火浣，木綿溫軟當綿衣。", "桄榔麪磣檳榔澀，海氣常昏海日微。", "蛟老變爲妖婦女，舶來多賣假珠璣。", "此中無限相憂事，請爲殷勤事事依。"]'),
('f754fbb8-3279-4407-a77e-2ac280c5d0df','酬樂天八月十五夜禁中獨直玩月見寄','元稹','唐','唐诗','tang','','[]','一年秋半月偏深，況就煙霄極賞心。',64,'全唐诗/poet.tang.21000.json','["一年秋半月偏深，況就煙霄極賞心。", "金鳳臺前波漾漾，玉鉤簾下影沈沈。", "宴移明處清蘭路，歌待新詞促翰林。", "何意枚臯正承詔，瞥然塵念到江陰。"]'),
('edfe9ceb-1e18-4799-af69-5829d529694c','予病瘴樂天寄通中散碧腴垂雲膏仍題四韻以慰遠懷開坼之間因有酬答','元稹','唐','唐诗','tang','','[]','紫河變鍊紅霞散，翠液煎研碧玉英。',64,'全唐诗/poet.tang.21000.json','["紫河變鍊紅霞散，翠液煎研碧玉英。", "金籍真人天上合，鹽車病驥軛前驚。", "愁腸欲轉蛟龍吼，醉眼初開日月明。", "唯有思君治不得，膏銷雪盡意還生。"]'),
('07f39e73-e021-4d61-99ba-ce3b1176262a','陪諸公游故江西韋大夫通德湖舊居有感題四韻兼呈李六侍御即韋大夫舊寮也','元稹','唐','唐诗','tang','','[]','高墉行馬接通湖，巨壑藏舟感大夫。',64,'全唐诗/poet.tang.21000.json','["高墉行馬接通湖，巨壑藏舟感大夫。", "塵壁暗埋悲舊札，風簾吹斷落殘珠。", "煙波漾日侵隤岸，狐兔奔叢拂坐隅。", "唯有滿園桃李下，膺門偏拜阮元瑜。"]'),
('44b7d6c5-3933-419e-aa66-612fdd30da63','送友封二首 一','元稹','唐','唐诗','tang','','[]','桃葉成陰燕引雛，南風吹浪颭檣烏。',64,'全唐诗/poet.tang.21000.json','["桃葉成陰燕引雛，南風吹浪颭檣烏。", "瘴雲拂地黃梅雨，明月滿帆青草湖。", "迢遞旅魂歸去遠，顛狂酒興病來孤。", "知君兄弟憐詩句，徧爲姑將惱大巫。"]'),
('401288e9-ef20-4c63-9fe0-53df908806b0','送友封二首 二','元稹','唐','唐诗','tang','','[]','惠和坊裏當時別，豈料江陵送上船。',64,'全唐诗/poet.tang.21000.json','["惠和坊裏當時別，豈料江陵送上船。", "鵬翼張風期萬里，馬頭無角已三年。", "甘將泥尾隨龜後，尚有雲心在鶴前。", "若見中丞忽相問，爲言腰折氣衝天。"]'),
('2f00f292-9d3f-4cc7-ab13-297aff196f5f','放言五首 一','元稹','唐','唐诗','tang','','[]','近來逢酒便高歌，醉舞詩狂漸欲魔。',64,'全唐诗/poet.tang.21000.json','["近來逢酒便高歌，醉舞詩狂漸欲魔。", "五斗解酲猶恨少，十分飛盞未嫌多。", "眼前讐敵都休問，身外功名一任他。", "死是等閑生也得，擬將何事奈吾何。"]'),
('b3d1d35a-bac6-495b-9e38-38d6846772d2','放言五首 二','元稹','唐','唐诗','tang','','[]','莫將心事厭長沙，雲到何方不是家。',64,'全唐诗/poet.tang.21000.json','["莫將心事厭長沙，雲到何方不是家。", "酒熟餔糟學漁父，飯來開口似神鵶。", "竹枝待鳳千莖直，柳樹迎風一向斜。", "總被天公霑雨露，等頭成長盡生涯。"]'),
('1e578601-f9a4-4e47-9734-821810766962','放言五首 三','元稹','唐','唐诗','tang','','[]','霆轟電烻數聲頻，不奈狂夫不藉身。',64,'全唐诗/poet.tang.21000.json','["霆轟電烻數聲頻，不奈狂夫不藉身。", "縱使被雷燒作燼，寧殊埋骨颺爲塵。", "得成蝴蝶尋花樹，儻化江魚掉錦鱗。", "必若乖龍在諸處，何須驚動自來人。"]'),
('5114e2e5-60fd-4ee2-aba2-8951729fa82a','放言五首 四','元稹','唐','唐诗','tang','','[]','安得心源處處安，何勞終日望林巒。',64,'全唐诗/poet.tang.21000.json','["安得心源處處安，何勞終日望林巒。", "玉英惟向火中冷，蓮葉元來水上乾。", "甯戚飯牛圖底事，陸通歌鳳也無端。", "孫登不語啓期樂，各自當情各自歡。"]'),
('a9c59af9-f28a-484d-a458-16a924ebf20f','放言五首 五','元稹','唐','唐诗','tang','','[]','三十年來世上行，也曾狂走趁浮名。',64,'全唐诗/poet.tang.21000.json','["三十年來世上行，也曾狂走趁浮名。", "兩廻左降須知命，數度登朝何處榮。", "乞我杯中松葉滿，遮渠肘上柳枝生。", "他時定葬燒缸地，賣與人家得酒盛。"]'),
('7fd8c120-42de-41c2-bb28-964055bc1b6b','劉二十八以文石枕見贈仍題絕句以將厚意因持壁州鞭酬謝兼廣爲四韻','元稹','唐','唐诗','tang','','[]','枕截文瓊珠綴篇，野人酬贈壁州鞭。',64,'全唐诗/poet.tang.21000.json','["枕截文瓊珠綴篇，野人酬贈壁州鞭。", "用長時節君須策，泥醉風雲我要眠。", "歌眄彩霞臨藥竈，執陪仙仗引爐煙。", "張騫却上知何日，隨會歸期在此年。"]'),
('04ecebb3-979f-4f9c-9a05-9478cc6f50c9','奉和嚴司空重陽日同崔常侍崔郎中及諸公登龍山落帽臺佳宴','元稹','唐','唐诗','tang','','[]','謝公愁思眇天涯，蠟屐登高爲菊花。',64,'全唐诗/poet.tang.21000.json','["謝公愁思眇天涯，蠟屐登高爲菊花。", "貴重近臣光綺席，笑憐從事落烏紗。", "萸房暗綻紅珠朵，茗椀寒供白露芽。", "詠碎龍山歸去號，馬奔流電妓奔車。"]'),
('17fc2b97-0137-4bfd-8b5e-21cbdb3c5c21','送王十一郎游剡中','元稹','唐','唐诗','tang','','[]','越州都在浙河灣，塵土消沈景象閑。',64,'全唐诗/poet.tang.21000.json','["越州都在浙河灣，塵土消沈景象閑。", "百里油盆鏡湖水，千峰鈿朵會稽山。", "軍城樓閣隨高下，禹廟煙霞自往還。", "想得玉郎乘畫舸，幾回明月墜雲間。"]'),
('bf2c3cef-2901-4358-bebc-9845c8934941','送友封','元稹','唐','唐诗','tang','','[]','輕風略略柳欣欣，晴色空濛遠似塵。',64,'全唐诗/poet.tang.21000.json','["輕風略略柳欣欣，晴色空濛遠似塵。", "斗柄未回猶帶閏，江痕潛上已生春。", "蘭成宅裏尋枯樹，宋玉亭前別故人。", "心斷洛陽三兩處，窈娘堤抱古天津。"]'),
('26fe9cf9-c9ce-4131-a8d0-0e744ee2e908','送致用','元稹','唐','唐诗','tang','','[]','淚霑雙袖血成文，不爲悲身爲別君。',64,'全唐诗/poet.tang.21000.json','["淚霑雙袖血成文，不爲悲身爲別君。", "望鶴眼穿期海外，待烏頭白老江濆。", "遙看逆浪愁翻雪，漸失征帆錯認雲。", "欲識九迴腸斷處，潯陽流水逐條分。"]'),
('bb061d4b-6db3-4bcc-8419-69675988fd83','早春登龍山靜勝寺時非休澣司空特許是行因贈幕中諸公','元稹','唐','唐诗','tang','','[]','謝傅知憐景氣新，許尋高寺望江春。',64,'全唐诗/poet.tang.21000.json','["謝傅知憐景氣新，許尋高寺望江春。", "龍文遠水吞平岸，羊角輕風旋細塵。", "山茗粉含鷹觜嫩，海榴紅綻錦窼勻。", "歸來笑問諸從事，占得閑行有幾人。"]'),
('8d5d0633-0c57-45ea-8371-936e27e3d34d','書樂天紙','元稹','唐','唐诗','tang','','[]','金鑾殿裏書殘紙，乞與荆州元判司。',32,'全唐诗/poet.tang.21000.json','["金鑾殿裏書殘紙，乞與荆州元判司。", "不忍拈將等閑用，半封京信半題詩。"]'),
('05e914dd-60fb-4791-8e0c-daf41541c420','酬孝甫見贈十首 一','元稹','唐','唐诗','tang','','[]','宋玉秋來續楚詞，陰鏗官漫足閑詩。',32,'全唐诗/poet.tang.21000.json','["宋玉秋來續楚詞，陰鏗官漫足閑詩。", "親情書札相安慰，多道蕭何作判司。"]'),
('bf4cfd02-1a4b-49f4-ad95-ca3ee133d8ef','酬孝甫見贈十首 二','元稹','唐','唐诗','tang','','[]','杜甫天材頗絕倫，每尋詩卷似情親。',32,'全唐诗/poet.tang.21000.json','["杜甫天材頗絕倫，每尋詩卷似情親。", "憐渠直道當時語，不著心源傍古人。"]'),
('e42d75a4-6cd5-462f-8c18-09b20caa551f','酬孝甫見贈十首 三','元稹','唐','唐诗','tang','','[]','十歲荒狂任博徒，挼莎五木擲梟盧。',32,'全唐诗/poet.tang.21000.json','["十歲荒狂任博徒，挼莎五木擲梟盧。", "野詩良輔偏憐假，長借金鞍迓酒胡。"]'),
('a961e6d4-fc6e-46e1-b212-bd73617410ef','酬孝甫見贈十首 四','元稹','唐','唐诗','tang','','[]','曾經綽立侍丹墀，綻蘂宮花拂面枝。',32,'全唐诗/poet.tang.21000.json','["曾經綽立侍丹墀，綻蘂宮花拂面枝。", "雉尾扇開朝日出，柘黃衫對碧霄垂。"]'),
('6c8ac34a-303a-4917-90d9-0c49999f58d6','酬孝甫見贈十首 五','元稹','唐','唐诗','tang','','[]','一自低心翰墨場，箭靫拋盡負書囊。',32,'全唐诗/poet.tang.21000.json','["一自低心翰墨場，箭靫拋盡負書囊。", "近來兼愛休糧藥，柏葉紗羅雜豆黃。"]'),
('89af457a-eed7-4f97-a704-56b86550b3c1','酬孝甫見贈十首 六','元稹','唐','唐诗','tang','','[]','莫笑風塵滿病顏，此生元在有無間。',32,'全唐诗/poet.tang.21000.json','["莫笑風塵滿病顏，此生元在有無間。", "卷舒蓮葉終難濕，去住雲心一種閑。"]'),
('0e690110-479a-4ae8-b56a-9236bc55a0a2','酬孝甫見贈十首 七','元稹','唐','唐诗','tang','','[]','無事拋棊侵虎口，幾時開眼復聯行。',32,'全唐诗/poet.tang.21000.json','["無事拋棊侵虎口，幾時開眼復聯行。", "終須殺盡緣邊敵，四面通同掩大荒。"]'),
('e855a15e-c329-4680-9618-cbb64093f207','酬孝甫見贈十首 八','元稹','唐','唐诗','tang','','[]','原憲甘貧每自開，子春傷足少人哀。',32,'全唐诗/poet.tang.21000.json','["原憲甘貧每自開，子春傷足少人哀。", "巷南唯有陳居士，時學文殊一問來。"]'),
('655caa56-0339-466e-8a64-c1bc18bee630','酬孝甫見贈十首 九','元稹','唐','唐诗','tang','','[]','每識閑人如未識，與君相識更相憐。',32,'全唐诗/poet.tang.21000.json','["每識閑人如未識，與君相識更相憐。", "經旬不解來過宿，忍見空牀夜夜眠。"]'),
('ecdaff64-1a61-4095-8f71-99cbb6894f03','酬孝甫見贈十首 十','元稹','唐','唐诗','tang','','[]','開坼新詩展大璆，明珠炫轉玉音浮。',32,'全唐诗/poet.tang.21000.json','["開坼新詩展大璆，明珠炫轉玉音浮。", "酬君十首三更坐，減却常時半夜愁。"]'),
('7866d1fc-c4ad-45aa-937d-8a4e56009551','和樂天招錢蔚章看山絕句','元稹','唐','唐诗','tang','','[]','碧落招邀閑曠望，黃金城外玉方壺。',32,'全唐诗/poet.tang.21000.json','["碧落招邀閑曠望，黃金城外玉方壺。", "人間還有大江海，萬里煙波天上無。"]'),
('780c74aa-ce85-4c49-9e83-76a4b6474239','折枝花贈行','元稹','唐','唐诗','tang','','[]','櫻桃花下送君時，一寸春心逐折枝。',32,'全唐诗/poet.tang.21000.json','["櫻桃花下送君時，一寸春心逐折枝。", "別後相思最多處，千株萬片繞林垂。"]'),
('3ce2c5fd-3ca4-482c-8233-75c3691accc6','寄劉頗二首 一','元稹','唐','唐诗','tang','','[]','平生嗜酒顛狂甚，不許諸公占丈夫。',32,'全唐诗/poet.tang.21000.json','["平生嗜酒顛狂甚，不許諸公占丈夫。", "唯愛劉君一片膽，近來還敢似人無。"]'),
('81d9ed58-6e83-464e-bce1-ec76a436d318','寄劉頗二首 二','元稹','唐','唐诗','tang','','[]','前年碣石煙塵起，共看官軍過洛城。',32,'全唐诗/poet.tang.21000.json','["前年碣石煙塵起，共看官軍過洛城。", "無限公卿因戰得，與君依舊綠衫行。"]'),
('3a2f0b5a-da02-4443-8116-881970a9a120','晨起送使病不行因過王十一館居二首 一','元稹','唐','唐诗','tang','','[]','自笑今朝誤夙興，逢他御史瘧相仍。',32,'全唐诗/poet.tang.21000.json','["自笑今朝誤夙興，逢他御史瘧相仍。", "過君未起房門掩，深映寒窗一盞燈。"]'),
('be42df12-c77c-4588-a356-80696925fd4f','晨起送使病不行因過王十一館居二首 二','元稹','唐','唐诗','tang','','[]','密宇深房小火爐，飯香魚熟近中廚。',32,'全唐诗/poet.tang.21000.json','["密宇深房小火爐，飯香魚熟近中廚。", "野人愛靜仍耽寢，自問黃昏肯去無。"]'),
('04f51dd4-f4d1-428f-a9ef-2a8766f08256','送孫勝','元稹','唐','唐诗','tang','','[]','桐花暗澹柳惺愡，池帶輕波柳帶風。',32,'全唐诗/poet.tang.21000.json','["桐花暗澹柳惺愡，池帶輕波柳帶風。", "今日與君臨水別，可憐春盡宋亭中。"]'),
('5502b4a1-0db6-47ba-a727-3acbf6c276f6','遊三寺回呈上府主嚴司空時因尋寺道出當陽縣奉命覆視縣囚牽於游行不暇詳究故以詩自誚爾','元稹','唐','唐诗','tang','','[]','謝公恣縱顛狂掾，觸處閑行許自由。',64,'全唐诗/poet.tang.21000.json','["謝公恣縱顛狂掾，觸處閑行許自由。", "舉板支頤對山色，當筵吹帽落臺頭。", "貪緣稽首他方佛，無暇精心滿縣囚。", "莫責尋常吐茵吏，書囊赤白報君侯。"]'),
('76da7844-78b3-4c64-881b-6a24eec3a700','遠望','元稹','唐','唐诗','tang','','[]','滿眼傷心冬景和，一山紅樹寺邊多。',32,'全唐诗/poet.tang.21000.json','["滿眼傷心冬景和，一山紅樹寺邊多。", "仲宣無限思鄉淚，漳水東流碧玉波。"]'),
('6897ce9e-24f0-418d-a07c-20e17c14591c','早春尋李校書','元稹','唐','唐诗','tang','','[]','款款春風澹澹雲，柳枝低作翠櫳帬。',64,'全唐诗/poet.tang.21000.json','["款款春風澹澹雲，柳枝低作翠櫳帬。", "梅含雞舌兼紅氣，江弄瓊花散綠紋。", "帶霧山鶯啼尚小，穿沙蘆筍葉纔分。", "今朝何事偏相覓，撩亂芳情最是君。"]'),
('32a2f6dd-30f5-4709-8155-1533c76a9522','過襄陽樓呈上府主嚴司空樓在江陵節度使宅北隅','元稹','唐','唐诗','tang','','[]','襄陽樓下樹陰成，荷葉如錢水面平。',64,'全唐诗/poet.tang.21000.json','["襄陽樓下樹陰成，荷葉如錢水面平。", "拂水柳花千萬點，隔林鶯舌兩三聲。", "有時水畔看雲立，每日樓前信馬行。", "早晚暫教王粲上，庾公應待月分明。"]'),
('2a770646-a61f-4d9d-a4db-aa90da365787','八月六日與僧如展前松滋主簿韋戴同游碧澗寺賦得扉字韻寺臨蜀江內有碧澗穿注兩廊又有龍女洞能興雲雨詩中噴字以平聲韻','元稹','唐','唐诗','tang','','["\u957f\u6c5f"]','空闊長江礙鐵圍，高低行樹倚巖扉。',64,'全唐诗/poet.tang.21000.json','["空闊長江礙鐵圍，高低行樹倚巖扉。", "穿廊玉澗噴紅旭，踴墖金輪拆翠微。", "草引風輕馴虎睡，洞驅雲入毒龍歸。", "他生莫忘靈山別，滿壁人名後會稀。"]'),
('e4b26c8c-4996-4cf3-8ea6-a689b3cb53eb','奉和竇容州','元稹','唐','唐诗','tang','','[]','明公莫訝容州遠，一路瀟湘景氣濃。',64,'全唐诗/poet.tang.21000.json','["明公莫訝容州遠，一路瀟湘景氣濃。", "斑竹初成二妃廟，碧蓮遙聳九疑峰。", "禁林聞道長傾鳳，池水那能久滯龍。", "自歎風波去無極，不知何日又相逢。"]'),
('a44847c0-440e-4262-b8bc-3e0dc78fb775','盧頭陀詩','元稹','唐','唐诗','tang','','[]','盧師深話出家由，剃盡心花始剃頭。',64,'全唐诗/poet.tang.21000.json','["盧師深話出家由，剃盡心花始剃頭。", "馬哭青山別車匿，鵲飛螺髻見羅睺。", "還來舊日經過處，似隔前身夢寐游。", "爲向八龍兄弟說，他生緣會此生休。"]'),
('2b9ed22b-117c-4c0e-8fd6-06c4cf4758ba','醉別盧頭陀','元稹','唐','唐诗','tang','','[]','醉迷狂象別吾師，夢覺觀空始自悲。',64,'全唐诗/poet.tang.21000.json','["醉迷狂象別吾師，夢覺觀空始自悲。", "盡日笙歌人散後，滿江風雨獨醒時。", "心超幾地行無處，雲到何天住有期。", "頓見佛光身上出，已蒙衣內綴摩尼。"]'),
('66398840-9533-4dfb-bf03-e694729d116d','陪張湖南宴望岳樓稹爲監察御史張中丞知雜事','元稹','唐','唐诗','tang','','[]','觀象樓前奉末班，絳峰只似殿庭間。',32,'全唐诗/poet.tang.21000.json','["觀象樓前奉末班，絳峰只似殿庭間。", "今日高樓重陪宴，雨籠衡岳是南山。"]'),
('f48c31bd-d6da-4078-84d7-adf90f3faa30','岳陽樓','元稹','唐','唐诗','tang','','["\u5cb3\u9633\u697c", "\u5199\u666f", "\u548f\u7269", "\u6292\u60c5", "\u548f\u7269\u8bd7", "\u6005\u7136"]','岳陽樓上日銜窗，影到深潭赤玉幢。',32,'全唐诗/poet.tang.21000.json','["岳陽樓上日銜窗，影到深潭赤玉幢。", "悵望殘春萬般意，滿櫺湖水入西江。"]'),
('bcfc31e8-1e68-41b0-abec-a57bd13cd7e7','寄庾敬休','元稹','唐','唐诗','tang','','[]','小來同在曲江頭，不省春時不共游。',32,'全唐诗/poet.tang.21000.json','["小來同在曲江頭，不省春時不共游。", "今日江風好暄煖，可憐春盡古湘州。"]'),
('d0107f56-3bd9-4b0b-aa6f-a3f032b924a4','花栽二首 一','元稹','唐','唐诗','tang','','[]','買得山花一兩栽，離鄉別土易摧隤。',32,'全唐诗/poet.tang.21000.json','["買得山花一兩栽，離鄉別土易摧隤。", "欲知北客居南意，看取南花北地來。"]'),
('8f400052-1671-4b2f-ac66-9698274a449a','花栽二首 二','元稹','唐','唐诗','tang','','[]','南花北地種應難，且向船中盡日看。',32,'全唐诗/poet.tang.21000.json','["南花北地種應難，且向船中盡日看。", "縱使將來眼前死，猶勝拋擲在空欄。"]'),
('99df8155-2ebe-4971-96a2-27e762843ff4','宿石磯','元稹','唐','唐诗','tang','','[]','石磯江水夜潺湲，半夜江風引杜鵑。',32,'全唐诗/poet.tang.21000.json','["石磯江水夜潺湲，半夜江風引杜鵑。", "燈暗酒醒顛倒枕，五更斜月入空船。"]'),
('d28bcf11-8e69-47a8-8848-8a0606eeff9a','遭風二十韻','元稹','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭瀰漫接天廻，一點君山似措杯。',320,'全唐诗/poet.tang.21000.json','["洞庭瀰漫接天廻，一點君山似措杯。", "暝色已籠秋竹樹，夕陽猶帶舊樓臺。", "湘南賈伴乘風信，夏口篙工厄泝洄。", "後侶逢灘方拽𥮘，前宗到浦已眠桅。", "俄驚四面雲屏合，坐見千峰雪浪堆。", "罔象睢盱頻逞怪，石尤翻動忽成災。", "勝凌豈但河宮溢，坱軋渾憂地軸摧。", "疑是陰兵致昏黑，果聞靈鼓借喧豗。", "龍歸窟穴深潭漩，蜃作波濤古岸隤。", "水客暗遊燒野火，楓人夜長吼春雷。", "浸淫沙市兒童亂，汩沒汀洲雁鶩哀。", "自歎生涯看轉燭，更悲商旅哭沈財。", "檣烏斗折頭倉掉，水狗斜傾尾纜開。", "在昔詎慙橫海志，此時甘乏濟川才。", "歷陽舊事曾爲鼈，鮌穴相傳有化能。", "閉目唯愁滿空電，冥心真類不然灰。", "那知否極休徵至，漸覺宵分曙氣催。", "怪族潛收湖黯湛，幽妖盡走日崔嵬。", "紫衣將校臨船問，白馬君侯傍柳來。", "喚上驛亭還酩酊，兩行紅袖拂樽罍。"]'),
('2f3ce89d-d4ee-46f3-965a-c71c09f6be18','贈崔元儒','元稹','唐','唐诗','tang','','[]','殷勤夏口阮元瑜，二十年前舊飲徒。',64,'全唐诗/poet.tang.21000.json','["殷勤夏口阮元瑜，二十年前舊飲徒。", "最愛輕欺杏園客，也曾辜負酒家胡。", "些些風景閑猶在，事事顛狂老漸無。", "今日頭盤三兩擲，翠娥潛笑白髭鬚。"]'),
('1a301563-c053-427b-b3f0-a374bacd8568','鄂州寓館嚴澗宅','元稹','唐','唐诗','tang','','[]','鳳有高梧鶴有松，偶來江外寄行踪。',64,'全唐诗/poet.tang.21000.json','["鳳有高梧鶴有松，偶來江外寄行踪。", "花枝滿院空啼鳥，塵榻無人憶臥龍。", "心想夜閑唯足夢，眼看春盡不相逢。", "何時最是思君處，月入斜窗曉寺鐘。"]'),
('618d8ca7-54f4-4be9-aa45-81a110966efb','送杜元穎','元稹','唐','唐诗','tang','','[]','江上五年同送客，與君長羨北歸人。',32,'全唐诗/poet.tang.21000.json','["江上五年同送客，與君長羨北歸人。", "今朝又送君先去，千里洛陽城裏塵。"]'),
('18891019-da60-4001-9f72-f2e0170954f1','貽蜀五首 病馬詩寄上李尚書','元稹','唐','唐诗','tang','','[]','萬里長鳴望蜀門，病身猶帶舊瘡痕。',64,'全唐诗/poet.tang.21000.json','["萬里長鳴望蜀門，病身猶帶舊瘡痕。", "遙看雲路心空在，久服鹽車力漸煩。", "尚有高懸雙鏡眼，何由竝駕兩朱轓。", "唯應夜識深山道，忽遇君侯一報恩。"]'),
('1290f2c0-886d-4d57-b4fb-695ddc211a3c','貽蜀五首 李中丞表臣','元稹','唐','唐诗','tang','','[]','韋門同是舊親賓，獨恨潘牀簟有塵。',64,'全唐诗/poet.tang.21000.json','["韋門同是舊親賓，獨恨潘牀簟有塵。", "十里花谿錦城麗，五年沙尾白頭新。", "倅戎何事勞專席，老掾甘心逐衆人。", "却待文星上天去，少分光影照沈淪。"]'),
('74a98565-5963-495b-9a8c-f50163242486','貽蜀五首 盧評事子蒙','元稹','唐','唐诗','tang','','[]','爲我殷勤盧子蒙，近來無復昔時同。',64,'全唐诗/poet.tang.21000.json','["爲我殷勤盧子蒙，近來無復昔時同。", "懶成積疹推難動，禪盡狂心鍊到空。", "老愛早眠虛夜月，病妨杯酒負春風。", "唯公兩弟閑相訪，往往潸然一望公。"]'),
('d254d6fe-12b2-4ddf-9f2d-972c788081ac','貽蜀五首 張校書元夫','元稹','唐','唐诗','tang','','[]','未面西川張校書，書來稠疊頗相於。',64,'全唐诗/poet.tang.21000.json','["未面西川張校書，書來稠疊頗相於。", "我聞聲價金應敵，衆道風姿玉不如。", "遠處從人須謹慎，少年爲事要舒徐。", "勸君便是酬君愛，莫比尋常贈鯉魚。"]'),
('139fb7e9-3caa-4b0f-98f1-210861bffdfb','貽蜀五首 韋兵曹臧文','元稹','唐','唐诗','tang','','[]','處處侯門可曳裙，人人爭事蜀尚書。',64,'全唐诗/poet.tang.21000.json','["處處侯門可曳裙，人人爭事蜀尚書。", "摩天氣直山曾拔，澈底心清水共虛。", "鵬翼已翻君好去，烏頭未變我何如。", "殷勤爲話深相感，不學馮諼待食魚。"]'),
('1a1c0b87-3c7f-410b-9e32-e018ec2cc25d','贈嚴童子','元稹','唐','唐诗','tang','','[]','衛瓘諸孫衛玠珍，可憐雛鳳好青春。',64,'全唐诗/poet.tang.21000.json','["衛瓘諸孫衛玠珍，可憐雛鳳好青春。", "解拈玉葉排新句，認得金環識舊身。", "十歲佩觿嬌稚子，八行飛札老成人。", "楊公莫訝清無業，家有驪珠不復貧。"]'),
('0765b10a-b9e0-4194-87c8-8e399e1899e7','桐孫詩','元稹','唐','唐诗','tang','','[]','去日桐花半桐葉，別來桐樹老桐孫。',32,'全唐诗/poet.tang.21000.json','["去日桐花半桐葉，別來桐樹老桐孫。", "城中過盡無窮事，白髮滿頭歸故園。"]'),
('bbc9ca99-a48d-4336-98e1-46c17d2c03b3','西歸絕句十二首 一','元稹','唐','唐诗','tang','','[]','雙堠頻頻減去程，漸知身得近京城。',32,'全唐诗/poet.tang.21000.json','["雙堠頻頻減去程，漸知身得近京城。", "春來愛有歸鄉夢，一半猶疑夢裏行。"]'),
('ac663770-d191-439c-bb7f-9317e53f98c9','西歸絕句十二首 二','元稹','唐','唐诗','tang','','[]','五年江上損容顏，今日春風到武關。',32,'全唐诗/poet.tang.21000.json','["五年江上損容顏，今日春風到武關。", "兩紙京書臨水讀，小桃花樹滿商山。"]'),
('5bb77b34-d37d-414e-b698-8078d9a66b84','西歸絕句十二首 三','元稹','唐','唐诗','tang','','[]','同歸諫院韋丞相，共貶河南亞大夫。',32,'全唐诗/poet.tang.21000.json','["同歸諫院韋丞相，共貶河南亞大夫。", "今日還鄉獨憔悴，幾人憐見白髭鬚。"]'),
('37358051-b1c7-4bac-ac27-7fe8da8fd095','西歸絕句十二首 四','元稹','唐','唐诗','tang','','[]','只去長安六日期，多應及得杏花時。',32,'全唐诗/poet.tang.21000.json','["只去長安六日期，多應及得杏花時。", "春明門外誰相待，不夢閑人夢酒巵。"]'),
('f6964340-3839-4970-bb5b-de894b310524','西歸絕句十二首 五','元稹','唐','唐诗','tang','','[]','白頭歸舍意如何，賀處無窮弔亦多。',32,'全唐诗/poet.tang.21000.json','["白頭歸舍意如何，賀處無窮弔亦多。", "左降去時裴相宅，舊來車馬幾人過。"]'),
('0b761aec-8aff-48d7-82c6-f5cd02bcd345','西歸絕句十二首 六','元稹','唐','唐诗','tang','','[]','還鄉何用淚沾襟，一半雲霄一半沈。',32,'全唐诗/poet.tang.21000.json','["還鄉何用淚沾襟，一半雲霄一半沈。", "世事漸多饒悵望，舊曾行處便傷心。"]'),
('8aebbcbe-9897-4b8b-bc8d-e817a9196cd7','西歸絕句十二首 七','元稹','唐','唐诗','tang','','[]','閑遊寺觀從容到，遍問親知次第尋。',32,'全唐诗/poet.tang.21000.json','["閑遊寺觀從容到，遍問親知次第尋。", "腸斷裴家光德宅，無人掃地戟門深。"]'),
('2d349709-b78c-47d2-8213-ea0e71863878','西歸絕句十二首 八','元稹','唐','唐诗','tang','','[]','一世營營死是休，生前無事定無由。',32,'全唐诗/poet.tang.21000.json','["一世營營死是休，生前無事定無由。", "不知山下東流水，何事長須日夜流。"]'),
('d6817d04-378a-446f-b00d-bafaee9f06ef','西歸絕句十二首 九','元稹','唐','唐诗','tang','','[]','今朝西渡丹河水，心寄丹河無限愁。',32,'全唐诗/poet.tang.21000.json','["今朝西渡丹河水，心寄丹河無限愁。", "若到莊前竹園下，殷勤爲遶故山流。"]'),
('5e3bbc34-4415-43fe-b07c-c2fb4f920d41','西歸絕句十二首 十','元稹','唐','唐诗','tang','','[]','寒窗風雪擁深爐，彼此相傷指白鬚。',32,'全唐诗/poet.tang.21000.json','["寒窗風雪擁深爐，彼此相傷指白鬚。", "一夜思量十年事，幾人強健幾人無。"]'),
('646e2ebb-bcca-4dd6-91ee-a67afce84122','西歸絕句十二首 十一','元稹','唐','唐诗','tang','','[]','雲覆藍橋雪滿溪，須臾便與碧峰齊。',32,'全唐诗/poet.tang.21000.json','["雲覆藍橋雪滿溪，須臾便與碧峰齊。", "風回麵市連天合，凍壓花枝著水低。"]'),
('b105e766-89f1-47ac-b213-bd1c52a67499','西歸絕句十二首 十二','元稹','唐','唐诗','tang','','[]','寒花帶雪滿山腰，著柳冰珠滿碧條。',32,'全唐诗/poet.tang.21000.json','["寒花帶雪滿山腰，著柳冰珠滿碧條。", "天色漸明回一望，玉塵隨馬度藍橋。"]'),
('ad007ffd-f419-4839-baf6-0a8f2108fb1f','留呈夢得子厚致用','元稹','唐','唐诗','tang','','[]','泉溜才通疑夜磬，燒煙餘暖有春泥。',64,'全唐诗/poet.tang.21000.json','["泉溜才通疑夜磬，燒煙餘暖有春泥。", "千層玉帳鋪松蓋，五出銀區印虎蹄。", "暗落金烏山漸黑，深埋粉堠路渾迷。", "心知魏闕無多地，十二瓊樓百里西。"]'),
('502fe27d-2c80-4e35-9f75-51d5e587059e','小碎','元稹','唐','唐诗','tang','','[]','小碎詩篇取次書，等閑題柱意何如。',32,'全唐诗/poet.tang.21000.json','["小碎詩篇取次書，等閑題柱意何如。", "諸郎到處應相問，留取三行代鯉魚。"]'),
('515b1986-7fb3-41e4-ad83-a5db9cbd1ce0','和樂天高相宅','元稹','唐','唐诗','tang','','[]','莫愁已去無窮事，漫苦如今有限身。',32,'全唐诗/poet.tang.21000.json','["莫愁已去無窮事，漫苦如今有限身。", "二百年來城裏宅，一家知換幾多人。"]'),
('b50413c4-6976-4b43-bf5e-fa1a9b8b2af7','和樂天仇家酒','元稹','唐','唐诗','tang','','[]','病嗟酒戶年年減，老覺塵機漸漸深。',32,'全唐诗/poet.tang.21000.json','["病嗟酒戶年年減，老覺塵機漸漸深。", "飲罷醒餘更惆悵，不如閒事不經心。"]'),
('29ddb49c-86d0-43b2-ad43-f56e2d1b3f83','和樂天贈雲寂僧','元稹','唐','唐诗','tang','','[]','欲離煩惱三千界，不在禪門八萬條。',32,'全唐诗/poet.tang.21000.json','["欲離煩惱三千界，不在禪門八萬條。", "心火自生還自滅，雲師無路與君銷。"]'),
('51b29661-bad2-4158-bfed-a346f386224e','灃西別樂天博載樊宗憲李景信兩秀才姪谷三月三十日相餞送','元稹','唐','唐诗','tang','','[]','今朝相送自同遊，酒語詩情替別愁。',32,'全唐诗/poet.tang.21000.json','["今朝相送自同遊，酒語詩情替別愁。", "忽到灃西總回去，一身騎馬向通州。"]'),
('7209d60e-019c-41c2-b070-8c5a2aac9b3d','寄曇嵩寂三上人','元稹','唐','唐诗','tang','','[]','長學對治思苦處，偏將死苦教人間。',32,'全唐诗/poet.tang.21000.json','["長學對治思苦處，偏將死苦教人間。", "今因爲說無生死，無可對治心更閑。"]'),
('fc5993dd-fd40-43af-8a0a-df2ba4a95baa','題漫天嶺智藏師蘭若僧云住此二十八年','元稹','唐','唐诗','tang','','[]','僧臨大道閱浮生，來往憧憧利與名。',32,'全唐诗/poet.tang.21000.json','["僧臨大道閱浮生，來往憧憧利與名。", "二十八年何限客，不曾閑見一人行。"]'),
('bb82a619-3e41-47f8-979a-a4c7dcdd6ecc','蒼溪縣寄揚州兄弟','元稹','唐','唐诗','tang','','[]','蒼溪縣下嘉陵水，入峽穿江到海流。',32,'全唐诗/poet.tang.21000.json','["蒼溪縣下嘉陵水，入峽穿江到海流。", "憑仗鯉魚將遠信，雁回時節到揚州。"]'),
('b4c141f1-3842-4897-9cba-d374f4184a64','贈吳渠州從姨兄士則','元稹','唐','唐诗','tang','','[]','憶昔分襟童子郎，白頭拋擲又他鄉。',64,'全唐诗/poet.tang.21000.json','["憶昔分襟童子郎，白頭拋擲又他鄉。", "三千里外巴南恨，二十年前城裏狂。", "甯氏舅甥俱寂寞，荀家兄弟半淪亡。", "淚因生別兼懷舊，廻首江山欲萬行。"]'),
('4e7382a5-4b76-4fd5-a057-5efff2e4769b','長灘夢李紳','元稹','唐','唐诗','tang','','[]','孤吟獨寢意千般，合眼逢君一夜歡。',32,'全唐诗/poet.tang.21000.json','["孤吟獨寢意千般，合眼逢君一夜歡。", "慙愧夢魂無遠近，不辭風雨到長灘。"]'),
('08ba2d6a-f60b-4a0d-bc4e-37cf030ce96f','新政縣','元稹','唐','唐诗','tang','','[]','新政縣前逢月夜，嘉陵江底看星辰。',64,'全唐诗/poet.tang.21000.json','["新政縣前逢月夜，嘉陵江底看星辰。", "已聞城上三更鼓，不見心中一箇人。", "鬚鬢暗添巴路雪，衣裳無復帝鄉塵。", "曾沾幾許名兼利，勞動生涯涉苦辛。"]'),
('0bcce198-75e6-4d7e-b0a3-e0f63da01585','南昌灘','元稹','唐','唐诗','tang','','["\u9ec4\u5c71"]','渠江明淨峽逶迤，船到明灘拽𥮘遲。',64,'全唐诗/poet.tang.21000.json','["渠江明淨峽逶迤，船到明灘拽𥮘遲。", "櫓窡動搖妨作夢，巴童指點笑吟詩。", "畬餘宿麥黃山腹，日背殘花白水湄。", "物色可憐心莫恨，此行都是獨行時。"]'),
('9a2bc8b9-7f81-42cb-ab91-f577ab6b9521','見樂天詩','元稹','唐','唐诗','tang','','[]','通州到日日平西，江館無人虎印泥。',32,'全唐诗/poet.tang.21000.json','["通州到日日平西，江館無人虎印泥。", "忽向破簷殘漏處，見君詩在柱心題。"]'),
('43e7d760-bd9f-4268-aecb-0fd3ff32cd5a','夜坐','元稹','唐','唐诗','tang','','[]','雨滯更愁南瘴毒，月明兼喜北風涼。',64,'全唐诗/poet.tang.21000.json','["雨滯更愁南瘴毒，月明兼喜北風涼。", "古城樓影橫空館，濕地蟲聲遶暗廊。", "螢火亂飛秋已近，星辰早沒夜初長。", "孩提萬里何時見，狼籍家書滿臥牀。"]'),
('e9aaced5-982b-499f-9ef0-f78eb2141d1d','聞樂天授江州司馬','元稹','唐','唐诗','tang','','["\u8d2c\u8c2a", "\u53cb\u60c5"]','殘燈無焰影幢幢，此夕聞君謫九江。',32,'全唐诗/poet.tang.21000.json','["殘燈無焰影幢幢，此夕聞君謫九江。", "垂死病中驚坐起，暗風吹雨入寒窗。"]'),
('085c00d9-01d2-4cc2-9bb3-2e8f4a478516','歲日贈拒非','元稹','唐','唐诗','tang','','[]','君思曲水嗟身老，我望通州感道窮。',32,'全唐诗/poet.tang.21000.json','["君思曲水嗟身老，我望通州感道窮。", "同入新年兩行淚，白頭翁坐說城中。"]'),
('ad6e82d6-6b30-4193-8329-c407719a1cbb','送盧戡','元稹','唐','唐诗','tang','','[]','紅樹蟬聲滿夕陽，白頭相送倍相傷。',64,'全唐诗/poet.tang.21000.json','["紅樹蟬聲滿夕陽，白頭相送倍相傷。", "老嗟去日光陰促，病覺今年晝夜長。", "顧我親情皆遠道，念君兄弟欲他鄉。", "紅旗滿眼襄州路，此別淚流千萬行。"]'),
('df23d825-4db8-4bd9-88dd-9f47cbe46e89','雨聲','元稹','唐','唐诗','tang','','[]','風吹竹葉休還動，雨點荷心暗復明。',32,'全唐诗/poet.tang.21000.json','["風吹竹葉休還動，雨點荷心暗復明。", "曾向西江船上宿，慣聞寒夜滴篷聲。"]'),
('2618397e-f65f-4680-9751-f0f1e2ce2533','奉和滎陽公離筵作','元稹','唐','唐诗','tang','','[]','南郡生徒辭絳帳，東山妓樂擁油旌。',32,'全唐诗/poet.tang.21000.json','["南郡生徒辭絳帳，東山妓樂擁油旌。", "鈞天排比簫韶待，猶顧人間有別情。"]'),
('14132406-bb4c-4479-8863-d2504d6073e9','嘉陵水','元稹','唐','唐诗','tang','','[]','古時應是山頭水，自古流來江路深。',32,'全唐诗/poet.tang.21000.json','["古時應是山頭水，自古流來江路深。", "若使江流會人意，也應知我遠來心。"]'),
('060f08fe-2bb0-4435-b83d-61930063de12','閬州開元寺壁題樂天詩','元稹','唐','唐诗','tang','','[]','憶君無計寫君詩，寫盡千行說向誰。',32,'全唐诗/poet.tang.21000.json','["憶君無計寫君詩，寫盡千行說向誰。", "題在閬州東寺壁，幾時知是見君時。"]'),
('ee493a91-1009-4b75-a338-e0e16dc7e866','憑李忠州寄書樂天','元稹','唐','唐诗','tang','','[]','萬里寄書將出峽，却憑巫峽寄江州。',32,'全唐诗/poet.tang.21000.json','["萬里寄書將出峽，却憑巫峽寄江州。", "傷心最是江頭月，莫把書將上庾樓。"]'),
('27388ed8-54ae-4da2-b390-b6db716d623e','得樂天書','元稹','唐','唐诗','tang','','["\u6292\u60c5"]','遠信入門先有淚，妻驚女哭問何如。',32,'全唐诗/poet.tang.21000.json','["遠信入門先有淚，妻驚女哭問何如。", "尋常不省曾如此，應是江州司馬書。"]'),
('4d44b19d-fe73-4bac-bac7-2d9ce37bae1e','寄樂天','元稹','唐','唐诗','tang','','[]','無身尚擬魂相就，身在那無夢往還。',32,'全唐诗/poet.tang.21000.json','["無身尚擬魂相就，身在那無夢往還。", "直到他生亦相覓，不能空記樹中環。"]'),
('32c72f22-c622-42dd-a194-6ad48342dc72','酬知退','元稹','唐','唐诗','tang','','[]','終須修到無修處，聞盡聲聞始不聞。',32,'全唐诗/poet.tang.21000.json','["終須修到無修處，聞盡聲聞始不聞。", "莫著妄心銷彼我，我心無我亦無君。"]'),
('e1715338-0fb2-4757-b961-44c30d377493','通州','元稹','唐','唐诗','tang','','[]','平生欲得山中住，天與通州遶郡山。',32,'全唐诗/poet.tang.21000.json','["平生欲得山中住，天與通州遶郡山。", "睡到日西無一事，月儲三萬買教閑。"]'),
('0bd2b921-b675-4367-9e6f-04f083579fd5','酬樂天書後三韻','元稹','唐','唐诗','tang','','[]','今日廬峰霞遶寺，昔時鸞殿鳳廻書。',48,'全唐诗/poet.tang.21000.json','["今日廬峰霞遶寺，昔時鸞殿鳳廻書。", "兩封相去八年後，一種俱云五夜初。", "漸覺此生都是夢，不能將淚滴雙魚。"]'),
('0ca87ea3-72e3-4281-ae8c-4a7af85562eb','相憶淚','元稹','唐','唐诗','tang','','[]','西江流水到江州，聞道分成九道流。',64,'全唐诗/poet.tang.21000.json','["西江流水到江州，聞道分成九道流。", "我滴兩行相憶淚，遣君何處遣人求。", "除非入海無由住，縱使逢灘未擬休。", "會向伍員潮上見，氣充頑石報心讎。"]'),
('9101cedd-dfbb-4b59-b3fd-69b95c6591cc','喜李十一景信到','元稹','唐','唐诗','tang','','[]','何事相逢翻有淚，念君緣我到通州。',32,'全唐诗/poet.tang.21000.json','["何事相逢翻有淚，念君緣我到通州。", "留君剩住君須住，我不自由君自由。"]'),
('18937f00-bf1f-485e-a5da-2d719a6b9ab4','與李十一夜飲','元稹','唐','唐诗','tang','','[]','寒夜燈前賴酒壺，與君相對興猶孤。',32,'全唐诗/poet.tang.21000.json','["寒夜燈前賴酒壺，與君相對興猶孤。", "忠州刺史應閑臥，江水猿聲睡得無。"]'),
('a82ad28f-e540-4280-8cd5-fe7ffe82b28c','贈李十一','元稹','唐','唐诗','tang','','[]','淮水連年起戰塵，油旌三換一何頻。',32,'全唐诗/poet.tang.21000.json','["淮水連年起戰塵，油旌三換一何頻。", "共君前後俱從事，羞見功名與別人。"]'),
('fa9621ac-9410-4629-b4ef-4c66150c4aeb','寒食日','元稹','唐','唐诗','tang','','[]','今年寒食好風流，此日一家同出游。',32,'全唐诗/poet.tang.21000.json','["今年寒食好風流，此日一家同出游。", "碧水青山無限思，莫將心道是涪州。"]'),
('3f2db908-c927-4d2d-a841-4bb340f0119c','三兄以白角巾寄遺髮不勝冠因有感歎','元稹','唐','唐诗','tang','','[]','病瘴年深渾禿盡，那能勝置角頭巾。',64,'全唐诗/poet.tang.21000.json','["病瘴年深渾禿盡，那能勝置角頭巾。", "暗梳蓬髮羞臨鏡，私戴蓮花恥見人。", "白髮過於冠色白，銀釘少校頷中銀。", "我身四十猶如此，何況吾兄六十身。"]'),
('a6d7ce58-acbe-4b70-a82b-1a4dee278b24','別李十一五絕 一','元稹','唐','唐诗','tang','','[]','巴南分與親情別，不料與君牀竝頭。',32,'全唐诗/poet.tang.21000.json','["巴南分與親情別，不料與君牀竝頭。", "爲我遠來休悵望，折君災難是通州。"]'),
('58a279dd-a328-4a09-a58d-5089c640546c','別李十一五絕 二','元稹','唐','唐诗','tang','','[]','京城每與閑人別，猶自傷心與白頭。',32,'全唐诗/poet.tang.21000.json','["京城每與閑人別，猶自傷心與白頭。", "今日別君心更苦，別君緣是在通州。"]'),
('b0d31706-816f-43ef-b537-3ebbaef4c1ca','別李十一五絕 三','元稹','唐','唐诗','tang','','[]','萬里尚能來遠道，一程那忍便分頭。',32,'全唐诗/poet.tang.21000.json','["萬里尚能來遠道，一程那忍便分頭。", "鳥籠猿檻君應會，十步向前非我州。"]'),
('fc87baf9-31fe-4235-a00a-e88d155a2007','別李十一五絕 四','元稹','唐','唐诗','tang','','[]','來時見我江南岸，今日送君江上頭。',32,'全唐诗/poet.tang.21000.json','["來時見我江南岸，今日送君江上頭。", "別後料添新夢寐，虎驚蛇伏是通州。"]'),
('b2ac5796-0feb-43a9-911a-7ca66f608d9d','別李十一五絕 五','元稹','唐','唐诗','tang','','[]','聞君欲去潛銷骨，一夜暗添新白頭。',32,'全唐诗/poet.tang.21000.json','["聞君欲去潛銷骨，一夜暗添新白頭。", "明朝別後應腸斷，獨櫂破船歸到州。"]'),
('9fe0c25a-d6bb-4325-97fc-0344e2b1bb86','酬樂天醉別','元稹','唐','唐诗','tang','','[]','前回一去五年別，此別又知何日回。',32,'全唐诗/poet.tang.21000.json','["前回一去五年別，此別又知何日回。", "好住樂天休悵望，匹如元不到京來。"]'),
('b341faad-2bb5-466f-83d5-e5719cb39b67','酬樂天雨後見憶','元稹','唐','唐诗','tang','','[]','雨滑危梁性命愁，差池一步一生休。',32,'全唐诗/poet.tang.21000.json','["雨滑危梁性命愁，差池一步一生休。", "黃泉便是通州郡，漸入深泥漸到州。"]'),
('dea31989-5102-4438-b6af-a792c98f1531','和樂天過祕閣書省舊廳','元稹','唐','唐诗','tang','','[]','聞君西省重徘徊，祕閣書房次第開。',64,'全唐诗/poet.tang.21000.json','["聞君西省重徘徊，祕閣書房次第開。", "壁記欲題三漏合，吏人驚問十年來。", "經排蠹簡憐初校，芸長陳根識舊栽。", "司馬見詩心最苦，滿身蚊蚋哭煙埃。"]'),
('67b27a0d-fa9f-4ff6-85b0-29bbde94d15d','和樂天贈楊祕書','元稹','唐','唐诗','tang','','[]','舊與楊郎在帝城，搜天斡地覓詩情。',64,'全唐诗/poet.tang.21000.json','["舊與楊郎在帝城，搜天斡地覓詩情。", "曾因竝句甘稱小，不爲論年便喚兄。", "刮骨直穿由苦鬬，夢腸翻出暫閑行。", "因君投贈還相和，老去那能競底名。"]'),
('f08f1763-5066-4130-8e59-ababbee17d32','和樂天題王家亭子','元稹','唐','唐诗','tang','','[]','風吹筍籜飄紅砌，雨打桐花蓋綠莎。',32,'全唐诗/poet.tang.21000.json','["風吹筍籜飄紅砌，雨打桐花蓋綠莎。", "都大資人無暇日，泛池全少買池多。"]'),
('405029da-b7b6-4bc6-a42c-1d774799d41a','酬樂天頻夢微之','元稹','唐','唐诗','tang','','["\u53cb\u60c5"]','山水萬重書斷絕，念君憐我夢相聞。',32,'全唐诗/poet.tang.21000.json','["山水萬重書斷絕，念君憐我夢相聞。", "我今因病魂顛倒，唯夢閑人不夢君。"]'),
('ed4e67c9-700f-4880-9d1e-596ba3860446','琵琶','元稹','唐','唐诗','tang','','[]','學語胡兒撼玉玲，甘州破裏最星星。',32,'全唐诗/poet.tang.21000.json','["學語胡兒撼玉玲，甘州破裏最星星。", "使君自恨常多事，不得工夫夜夜聽。"]'),
('cc86bac4-879d-47ae-942f-e680876f6a3b','春詞','元稹','唐','唐诗','tang','','[]','山翠湖光似欲流，蜂聲鳥思却堪愁。',32,'全唐诗/poet.tang.21000.json','["山翠湖光似欲流，蜂聲鳥思却堪愁。", "西施顏色今何在，但看春風百草頭。"]'),
('7c60ca2a-09d7-4c8d-8aac-564211636c2a','酬樂天春寄微之','元稹','唐','唐诗','tang','','[]','鸚心明黠雀幽蒙，何事相將盡入籠。',64,'全唐诗/poet.tang.21000.json','["鸚心明黠雀幽蒙，何事相將盡入籠。", "君避海鯨驚浪裏，我隨巴蟒瘴煙中。", "千山塞路音書絕，兩地知春曆日同。", "一樹梅花數升酒，醉尋江岸哭東風。"]'),
('7735b268-73d5-4da5-aa07-7a9b2f74f58c','酬樂天舟泊夜讀微之詩','元稹','唐','唐诗','tang','','[]','知君暗泊西江岸，讀我閑詩欲到明。',32,'全唐诗/poet.tang.21000.json','["知君暗泊西江岸，讀我閑詩欲到明。", "今夜通州還不睡，滿山風雨杜鵑聲。"]'),
('6cd822e2-77bd-4aff-814c-76e32d58ec94','酬樂天武關南見微之題山石榴花詩','元稹','唐','唐诗','tang','','[]','比因酬贈爲花時，不爲君行不復知。',32,'全唐诗/poet.tang.21000.json','["比因酬贈爲花時，不爲君行不復知。", "又更幾年還共到，滿牆塵土兩篇詩。"]'),
('467af7d6-7c0c-4982-9908-5f5caa9612db','酬樂天見寄','元稹','唐','唐诗','tang','','[]','三千里外巴虵穴，四十年來司馬官。',64,'全唐诗/poet.tang.21000.json','["三千里外巴虵穴，四十年來司馬官。", "瘴色滿身治不盡，瘡痕刮骨洗應難。", "常甘人向衰容薄，獨訝君將舊眼看。", "前日詩中高蓋字，至今脣舌遍長安。"]'),
('ccf1b76a-8334-48a3-9aed-928dc56ac5ba','酬樂天得稹所寄紵絲布白輕庸製成衣服以詩報之','元稹','唐','唐诗','tang','','[]','湓城萬里隔巴庸，紵薄綈輕共一封。',64,'全唐诗/poet.tang.21000.json','["湓城萬里隔巴庸，紵薄綈輕共一封。", "腰帶定知今瘦小，衣衫難作遠裁縫。", "唯愁書到炎涼變，忽見詩來意緒濃。", "春草綠茸雲色白，想君騎馬好儀容。"]'),
('a1bdea57-346d-498b-b799-20916336a3b9','和樂天尋郭道士不遇','元稹','唐','唐诗','tang','','[]','昔年我見杯中渡，今日人言鶴上逢。',64,'全唐诗/poet.tang.21000.json','["昔年我見杯中渡，今日人言鶴上逢。", "兩虎定隨千歲鹿，雙林添作幾株松。", "方瞳應是新燒藥，短脚知緣舊施舂。", "欲請僧繇遠相畫，苦愁頻變本形容。"]'),
('1f4576e2-e9bc-4709-9817-5bf233398ec1','酬樂天寄生衣','元稹','唐','唐诗','tang','','[]','秋茅處處流痎瘧，夜鳥聲聲哭瘴雲。',32,'全唐诗/poet.tang.21000.json','["秋茅處處流痎瘧，夜鳥聲聲哭瘴雲。", "羸骨不勝纖細物，欲將文服却還君。"]'),
('81e02909-ddc5-4308-9349-7e1613594a4f','酬樂天得微之詩知通州事因成四首 一','元稹','唐','唐诗','tang','','[]','茅簷屋舍竹籬州，虎怕偏蹄虵兩頭。',64,'全唐诗/poet.tang.21000.json','["茅簷屋舍竹籬州，虎怕偏蹄虵兩頭。", "暗蠱有時迷酒影，浮塵向日似波流。", "沙含水弩多傷骨，田仰畬刀少用牛。", "知得共君相見否，近來魂夢轉悠悠。"]'),
('dedc7b24-9ac7-44a4-8ee2-3fa3eb8157bd','酬樂天得微之詩知通州事因成四首 二','元稹','唐','唐诗','tang','','[]','平地才應一頃餘，閣欄都大似巢居。',64,'全唐诗/poet.tang.21000.json','["平地才應一頃餘，閣欄都大似巢居。", "入衙官吏聲疑鳥，下峽舟船腹似魚。", "市井無錢論尺丈，田疇付火罷耘鋤。", "此中愁殺須甘分，惟惜平生舊著書。"]'),
('881cb6a0-9019-490b-b763-91e6d1582d4e','酬樂天得微之詩知通州事因成四首 三','元稹','唐','唐诗','tang','','[]','哭鳥晝飛人少見，倀魂夜嘯虎行多。',64,'全唐诗/poet.tang.21000.json','["哭鳥晝飛人少見，倀魂夜嘯虎行多。", "滿身沙虱無防處，獨脚山魈不奈何。", "甘受鬼神侵骨髓，常憂岐路處風波。", "南歌未有東西分，敢唱滄浪一字歌。"]'),
('6af7eb8e-7528-4646-a437-d88bceb36b7d','酬樂天得微之詩知通州事因成四首 四','元稹','唐','唐诗','tang','','[]','荒蕪滿院不能鋤，甑有塵埃圃乏蔬。',64,'全唐诗/poet.tang.21000.json','["荒蕪滿院不能鋤，甑有塵埃圃乏蔬。", "定覺身將囚一種，未知生共死何如。", "飢搖困尾喪家狗，熱暴枯鱗失水魚。", "苦境萬般君莫問，自憐方寸本來虛。"]'),
('99660a0e-febc-47da-9d17-6713424fa287','酬樂天聞李尚書拜相以詩見賀','元稹','唐','唐诗','tang','','[]','初因彈劾死東川，又爲親情弄化權百口共經三峽水，一時重上兩漫天。',63,'全唐诗/poet.tang.21000.json','["初因彈劾死東川，又爲親情弄化權百口共經三峽水，一時重上兩漫天。", "尚書入用雖旬月，司馬銜冤已十年。", "若待更遭秋瘴後，便愁平地有重泉。"]'),
('a26eb899-f846-4194-8c47-964305503dca','酬樂天歎窮愁見寄','元稹','唐','唐诗','tang','','[]','病煎愁緒轉紛紛，百里何由說向君。',64,'全唐诗/poet.tang.21000.json','["病煎愁緒轉紛紛，百里何由說向君。", "老去心情隨日減，遠來書信隔年聞。", "三冬有電連春雨，九月無霜盡火雲。", "併與巴南終歲熱，四時誰道各平分。"]'),
('15cf8bec-a050-4001-89a1-4bc9ef1f19ff','酬樂天三月三日見寄','元稹','唐','唐诗','tang','','[]','當年此日花前醉，今日花前病裏銷。',32,'全唐诗/poet.tang.21000.json','["當年此日花前醉，今日花前病裏銷。", "獨倚破簾閑悵望，可憐虛度好春朝。"]'),
('7693bdaf-285f-4156-b251-4e4ee36cb9df','酬樂天歎損傷見寄','元稹','唐','唐诗','tang','','[]','前途何在轉茫茫，漸老那能不自傷。',64,'全唐诗/poet.tang.21000.json','["前途何在轉茫茫，漸老那能不自傷。", "病爲怕風多睡月，起因花藥暫扶牀。", "函關氣索迷真侶，峽水波翻礙故鄉。", "唯有秋來兩行淚，對君新贈遠詩章。"]'),
('ea561390-5c93-4cac-a95e-dcd37f78924b','瘴塞','元稹','唐','唐诗','tang','','[]','瘴塞巴山哭鳥悲，紅妝少婦斂啼眉。',32,'全唐诗/poet.tang.21000.json','["瘴塞巴山哭鳥悲，紅妝少婦斂啼眉。", "殷勤奉藥來相勸，云是前年欲病時。"]'),
('c3865968-bc9b-4a42-8191-ff3987321fe6','紅荆','元稹','唐','唐诗','tang','','[]','庭中栽得紅荆樹，十月花開不待春。',32,'全唐诗/poet.tang.21000.json','["庭中栽得紅荆樹，十月花開不待春。", "直到孩提盡驚怪，一家同是北來人。"]'),
('e3baebc1-a02d-4dbd-bcab-7aef6e5517d8','黃草峽聽柔之琴二首 一','元稹','唐','唐诗','tang','','[]','胡笳夜奏塞聲寒，是我鄉音聽漸難。',32,'全唐诗/poet.tang.21000.json','["胡笳夜奏塞聲寒，是我鄉音聽漸難。", "料得小來辛苦學，又因知向峽中彈。"]'),
('14a622f1-e6a2-45eb-b917-a273c33487e7','黃草峽聽柔之琴二首 二','元稹','唐','唐诗','tang','','[]','別鶴淒清覺露寒，離聲漸咽命雛難。',32,'全唐诗/poet.tang.21000.json','["別鶴淒清覺露寒，離聲漸咽命雛難。", "憐君伴我涪州宿，猶有心情徹夜彈。"]'),
('4eb36125-dfd3-4a34-94ff-3551e27cf68d','書劒','元稹','唐','唐诗','tang','','[]','渝工劒刃皆歐冶，巴吏書蹤盡子雲。',32,'全唐诗/poet.tang.21000.json','["渝工劒刃皆歐冶，巴吏書蹤盡子雲。", "唯我心知有來處，泊船黃草夜思君。"]'),
('3123c4e8-25a5-44db-ba9b-b3f65386e571','內狀詩寄楊白二員外','元稹','唐','唐诗','tang','','[]','天門暗闢玉琤鍧，晝送中樞曉禁清。',64,'全唐诗/poet.tang.21000.json','["天門暗闢玉琤鍧，晝送中樞曉禁清。", "彤管內人書細膩，金匳御印篆分明。", "衝街不避將軍令，跋勅兼題宰相名。", "南省郎官誰待詔，與君將向世間行。"]'),
('bbbd4c1d-576d-417c-a1c9-6595d7a8b55d','別毅郎 一','元稹','唐','唐诗','tang','','[]','爾爺只爲一杯酒，此別那知死與生。',32,'全唐诗/poet.tang.21000.json','["爾爺只爲一杯酒，此別那知死與生。", "兒有何辜才七歲，亦教兒作瘴江行。"]'),
('83826df1-8aff-4051-afed-89741cdcff29','別毅郎 二','元稹','唐','唐诗','tang','','[]','愛惜爾爺唯有我，我今顦顇望何人。',32,'全唐诗/poet.tang.21000.json','["愛惜爾爺唯有我，我今顦顇望何人。", "傷心自比籠中鶴，翦盡翅翎愁到身。"]'),
('f1f4b9b9-bb8f-4ed9-8564-6a86f8e0161c','自責','元稹','唐','唐诗','tang','','[]','犀帶金魚束紫袍，不能將命報分毫。',32,'全唐诗/poet.tang.21000.json','["犀帶金魚束紫袍，不能將命報分毫。", "他時得見牛常侍，爲爾君前捧佩刀。"]'),
('f2958e20-77ac-42a3-bf43-f9bfaf967288','送公度之福建','元稹','唐','唐诗','tang','','[]','棠陰猶在建溪磯，此去那論是與非。',32,'全唐诗/poet.tang.21000.json','["棠陰猶在建溪磯，此去那論是與非。", "若見白頭須盡敬，恐曾江岸識胡威。"]'),
('433b2b4d-1490-455c-b242-f751078e05ca','喜五兄自泗州至','元稹','唐','唐诗','tang','','[]','眼中三十年來淚，一望南雲一度垂。',32,'全唐诗/poet.tang.21000.json','["眼中三十年來淚，一望南雲一度垂。", "慚愧臨淮李常侍，遠教形影暫相隨。"]'),
('0844874f-28de-4901-bb53-811ef142d677','杏花','元稹','唐','唐诗','tang','','[]','常年出入右銀臺，每怪春光例早回。',32,'全唐诗/poet.tang.21000.json','["常年出入右銀臺，每怪春光例早回。", "慚愧杏園行在景，同州園裏也先開。"]'),
('14d8021d-9fbd-476f-8f61-3b5f3bb85ada','第三歲日詠春風憑楊員外寄長安柳','元稹','唐','唐诗','tang','','[]','三日春風已有情，拂人頭面稍憐輕。',32,'全唐诗/poet.tang.21000.json','["三日春風已有情，拂人頭面稍憐輕。", "殷勤爲報長安柳，莫惜枝條動軟聲。"]'),
('43b2cd4a-de59-4d02-9d34-a10657efef2c','贈別楊員外巨源','元稹','唐','唐诗','tang','','[]','憶昔西河縣下時，青山顦顇宦名卑。',64,'全唐诗/poet.tang.21000.json','["憶昔西河縣下時，青山顦顇宦名卑。", "揄揚陶令緣求酒，結託蕭娘只在詩。", "朱紫衣裳浮世重，蒼黃歲序長年悲。", "白頭後會知何日，一盞煩君不用辭。"]'),
('a55cf688-bed6-4a89-a271-7dda6ac16d7b','寄樂天二首 一','元稹','唐','唐诗','tang','','[]','榮辱升沈影與身，世情誰是舊雷陳。',64,'全唐诗/poet.tang.21000.json','["榮辱升沈影與身，世情誰是舊雷陳。", "唯應鮑叔猶憐我，自保曾參不殺人。", "山入白樓沙苑暮，潮生滄海野塘春。", "老逢佳景唯惆悵，兩地各傷何限神。"]'),
('29623661-eb54-4ac9-a23d-b969b860010e','寄樂天二首 二','元稹','唐','唐诗','tang','','[]','論才賦命不相干，鳳有文章雉有冠。',64,'全唐诗/poet.tang.21000.json','["論才賦命不相干，鳳有文章雉有冠。", "羸骨欲銷猶被刻，瘡痕未沒又遭彈。", "劒頭已折藏須蓋，丁字雖剛屈莫難。", "休學州前羅剎石，一生身敵海波瀾。"]'),
('d9b8bb2d-b3b2-4ef6-9433-357c981114db','聽妻彈別鶴操','元稹','唐','唐诗','tang','','[]','別鶴聲聲怨夜弦，聞君此奏欲潸然。',32,'全唐诗/poet.tang.21000.json','["別鶴聲聲怨夜弦，聞君此奏欲潸然。", "商瞿五十知無子，更付琴書與仲宣。"]'),
('64831176-2482-4e3a-b941-3540ad74f810','和王侍郎酬廣宣上人觀放牓後相賀','元稹','唐','唐诗','tang','','[]','渥洼徒自有權奇，伯樂書名世始知。',64,'全唐诗/poet.tang.21000.json','["渥洼徒自有權奇，伯樂書名世始知。", "競走牆前希得儁，高縣日下表無私。", "都中紙貴流傳後，海外金填姓字時。", "珍重劉繇因首薦，爲君送和碧雲詩。"]'),
('6a92c882-6091-4204-a665-276ea1007541','酬樂天喜鄰郡','元稹','唐','唐诗','tang','','[]','蹇驢瘦馬塵中伴，紫綬朱衣夢裏身。',64,'全唐诗/poet.tang.21000.json','["蹇驢瘦馬塵中伴，紫綬朱衣夢裏身。", "符竹偶因成對岸，文章虛被配爲鄰。", "湖翻白浪常看雪，火照紅妝不待春。", "老大那能更爭競，任君投募醉鄉人。"]'),
('24c527df-26c7-4fee-b2b9-3215bf6bc43a','再酬復言和前篇','元稹','唐','唐诗','tang','','[]','經過二郡逢賢牧，聚集諸郎宴老身。',64,'全唐诗/poet.tang.21000.json','["經過二郡逢賢牧，聚集諸郎宴老身。", "清夜漫勞紅燭會，白頭非是翠娥鄰。", "曾攜酒伴無端宿，自入朝行便別春。", "潦倒微之從不占，未知公議道何人。"]'),
('8f87a45a-6c36-41ed-a223-60fcf71df72e','贈樂天','元稹','唐','唐诗','tang','','[]','莫言鄰境易經過，彼此分符欲奈何。',32,'全唐诗/poet.tang.21000.json','["莫言鄰境易經過，彼此分符欲奈何。", "垂老相逢漸難別，白頭期限各無多。"]'),
('e3a5f32f-9e1b-47d7-811c-f94b24e270a6','重贈','元稹','唐','唐诗','tang','','[]','休遣玲瓏唱我詩，我詩多是別君詞。',32,'全唐诗/poet.tang.21000.json','["休遣玲瓏唱我詩，我詩多是別君詞。", "明朝又向江頭別，月落潮平是去時。"]'),
('138e0d16-ee85-4d75-9ae1-156bc57f1a58','別後西陵晚眺','元稹','唐','唐诗','tang','','[]','晚日未拋詩筆硯，夕陽空望郡樓臺。',32,'全唐诗/poet.tang.21000.json','["晚日未拋詩筆硯，夕陽空望郡樓臺。", "與君後會知何日，不似潮頭暮却廻。"]'),
('f051ef36-ede4-4af3-b167-699a70b268ed','以州宅夸於樂天','元稹','唐','唐诗','tang','','[]','州城迥遶拂雲堆，鏡水稽山滿眼來。',64,'全唐诗/poet.tang.21000.json','["州城迥遶拂雲堆，鏡水稽山滿眼來。", "四面常時對屏障，一家終日在樓臺。", "星河似向簷前落，鼓角驚從地底廻。", "我是玉皇香案吏，謫居猶得住蓬萊。"]'),
('f5d517fe-003f-4e06-9653-f1500f97b9c0','重夸州宅旦暮景色兼酬前篇末句','元稹','唐','唐诗','tang','','[]','仙都難畫亦難書，暫合登臨不合居。',64,'全唐诗/poet.tang.21000.json','["仙都難畫亦難書，暫合登臨不合居。", "繞郭煙嵐新雨後，滿山樓閣上燈初。", "人聲曉動千門闢，湖色宵涵萬象虛。", "爲問西州羅剎岸，濤頭衝突近何如。"]'),
('0c850801-7809-4363-80a7-2b7012e5c2df','酬樂天吟張員外詩見寄因思上京每與樂天於居敬兄升平里詠張新詩','元稹','唐','唐诗','tang','','[]','樂天書內重封到，居敬堂前共讀時。',64,'全唐诗/poet.tang.21000.json','["樂天書內重封到，居敬堂前共讀時。", "四友一爲泉路客，三人兩詠浙江詩。", "別無遠近皆難見，老減心情自各知。", "杯酒與他年少隔，不相酬贈欲何之。"]'),
('68c4faba-d4e1-4b89-b912-e4fc60977c6b','寄樂天','元稹','唐','唐诗','tang','','[]','閑夜思君坐到明，追尋往事倍傷情。',64,'全唐诗/poet.tang.21000.json','["閑夜思君坐到明，追尋往事倍傷情。", "同登科後心相合，初得官時髭未生。", "二十年來諳世路，三千里外老江城。", "猶應更有前途在，知向人間何處行。"]'),
('f354c1eb-9dbb-4c39-9c65-478cba9cbd35','戲贈樂天復言','元稹','唐','唐诗','tang','','[]','樂事難逢歲易徂，白頭光景莫令孤。',64,'全唐诗/poet.tang.21000.json','["樂事難逢歲易徂，白頭光景莫令孤。", "弄濤船更曾觀否，望市樓還有會無。", "眼力少將尋案牘，心情且強擲梟盧。", "孫園虎寺隨宜看，不必遙遙羨鏡湖。"]'),
('914a23fb-d48f-4c97-8d39-8ea9170b2374','重酬樂天','元稹','唐','唐诗','tang','','[]','紅塵擾擾日西徂，我興雲心兩共孤。',64,'全唐诗/poet.tang.21000.json','["紅塵擾擾日西徂，我興雲心兩共孤。", "暫出已遭千騎擁，故交求見一人無。", "百篇書判從饒白，八米詩章未伏盧。", "最笑近來黃叔度，自投名刺占陂湖。"]'),
('93e29bd7-032b-45e6-bcf4-3392ea55a58d','再酬復言','元稹','唐','唐诗','tang','','[]','繞郭笙歌夜景徂，稽山迥帶月輪孤。',64,'全唐诗/poet.tang.21000.json','["繞郭笙歌夜景徂，稽山迥帶月輪孤。", "休文欲詠心應破，道子雖來畫得無。", "顧我小才同培塿，知君險鬬敵都盧。", "不然豈有姑蘇郡，擬著陂塘比鏡湖。"]'),
('397f644b-719f-4800-9e18-88f4106fe711','郡務稍簡因得整比舊詩幷連綴焚削封章委篋僅逾百軸偶成自歎因寄樂天','元稹','唐','唐诗','tang','','[]','近來章奏小年詩，一種成空盡可悲。',64,'全唐诗/poet.tang.21000.json','["近來章奏小年詩，一種成空盡可悲。", "書得眼昏朱似碧，用來心破髮如絲。", "催身易老緣多事，報主深恩在幾時。", "天遣兩家無嗣子，欲將文集與它誰。"]'),
('8b7d60fa-dba6-420f-be59-4173a745e571','酬樂天餘思不盡加爲六韻之作','元稹','唐','唐诗','tang','','[]','律呂同聲我爾身，文章君是一伶倫。',96,'全唐诗/poet.tang.21000.json','["律呂同聲我爾身，文章君是一伶倫。", "衆推賈誼爲才子，帝喜相如作侍臣。", "次韻千言曾報荅，直詞三道共經綸。", "元詩駮雜真難辨，白樸流傳用轉新。", "蔡女圖書雖在口，于公門戶豈生塵。", "商瞿未老猶希冀，莫把籝金便付人。"]'),
('e4663cd7-5c90-4af8-9fc7-e1af158dffa8','寄樂天','元稹','唐','唐诗','tang','','[]','莫嗟虛老海壖西，天下風光數會稽。',64,'全唐诗/poet.tang.21000.json','["莫嗟虛老海壖西，天下風光數會稽。", "靈氾橋前百里鏡，石帆山崦五雲溪。", "冰銷田地蘆錐短，春入枝條柳眼低。", "安得故人生羽翼，飛來相伴醉如泥。"]'),
('207b2dcf-2f03-4fe2-8a1d-47e4f41f9325','酬樂天雪中見寄','元稹','唐','唐诗','tang','','["\u897f\u6e56"]','知君夜聽風蕭索，曉望林亭雪半糊。',160,'全唐诗/poet.tang.21000.json','["知君夜聽風蕭索，曉望林亭雪半糊。", "撼落不教封柳眼，埽來偏盡附梅株。", "敲扶密竹枝猶亞，煦暖寒禽氣漸蘇。", "坐覺湖聲迷遠浪，回驚雲路在長途。", "錢塘湖上蘋先合，梳洗樓前粉暗鋪。", "石立玉童披鶴氅，臺施瑤席換龍鬚。", "滿空飛舞應爲瑞，寡和高歌只自娛。", "莫遣擁簾傷思婦，且將盈尺慰農夫。", "稱觴彼此情何異，對景東西事有殊。", "鏡水遶山山盡白，琉璃雲母世間無。"]'),
('342875c5-a2ee-41a4-a8a7-46b5c228a8c4','和樂天早春見寄','元稹','唐','唐诗','tang','','[]','雨香雲澹覺微和，誰送春聲入櫂歌。',64,'全唐诗/poet.tang.21000.json','["雨香雲澹覺微和，誰送春聲入櫂歌。", "萱近北堂穿土早，柳偏東面受風多。", "湖添水色消殘雪，江送潮頭湧漫波。", "同受新年不同賞，無由縮地欲如何。"]'),
('3955fe87-c138-42aa-95f3-018520621eb6','酬復言長慶四年元日郡齋感懷見寄','元稹','唐','唐诗','tang','','[]','臘盡殘銷春又歸，逢新別故欲沾衣。',128,'全唐诗/poet.tang.21000.json','["臘盡殘銷春又歸，逢新別故欲沾衣。", "自驚身上添年紀，休繫心中小是非。", "富貴祝來何所遂，聰明鞭得轉無機。", "羞看稚子先拈酒，悵望平生舊採薇。", "去日漸加餘日少，賀人雖鬧故人稀。", "椒花麗句閑重檢，艾髮衰容惜寸輝。", "苦思正旦酬白雪，閑觀風色動青旂。", "千官仗下爐煙裏，東海西頭意獨違。"]'),
('15bd12b8-915d-4bdd-acec-477448457968','代郡齋神荅樂天','元稹','唐','唐诗','tang','','[]','虛白堂神傳好語，二年長伴獨吟時。',48,'全唐诗/poet.tang.21000.json','["虛白堂神傳好語，二年長伴獨吟時。", "夜憐星月多離燭，日滉波濤一下帷。", "爲報何人償酒債，引看牆上使君詩。"]'),
('c1809840-a969-4554-9220-76cc32b786ee','酬樂天重寄別','元稹','唐','唐诗','tang','','[]','却報君侯聽苦辭，老頭拋我欲何之。',32,'全唐诗/poet.tang.21000.json','["却報君侯聽苦辭，老頭拋我欲何之。", "武牢關外雖分手，不似如今衰白時。"]'),
('98f20cf9-073d-4149-b69f-9b71ee348944','和樂天重題別東樓','元稹','唐','唐诗','tang','','[]','山容水態使君知，樓上從容萬狀移。',96,'全唐诗/poet.tang.21000.json','["山容水態使君知，樓上從容萬狀移。", "日映文章霞細麗，風驅鱗甲浪參差。", "鼓催潮戶凌晨擊，笛賽婆官徹夜吹。", "喚客潛揮遠紅袖，賣壚高掛小青旗。", "賸鋪牀席春眠處，乍捲簾帷月上時。", "光景無因將得去，爲郎抄在和郎詩。"]'),
('48540e70-9d79-4ea9-9970-518b84ce4d63','餘杭周從事以十章見寄詞調清婉難於遍酬聊和詩首篇以荅來貺','元稹','唐','唐诗','tang','','[]','擾擾紛紛旦暮間，經營閑事不曾閑。',64,'全唐诗/poet.tang.21000.json','["擾擾紛紛旦暮間，經營閑事不曾閑。", "多緣老病推辭酒，少有功夫久羨山。", "清夜笙歌喧四郭，黃昏鐘漏下重關。", "何由得似周從事，醉入人家醒始還。"]'),
('3c46fc5d-743c-4b72-b064-d0c6219f4e0f','寄浙西李大夫四首 一','元稹','唐','唐诗','tang','','[]','柳眼梅心漸欲春，白頭西望憶何人。',32,'全唐诗/poet.tang.21000.json','["柳眼梅心漸欲春，白頭西望憶何人。", "金陵太守曾相伴，共蹋銀臺一路塵。"]'),
('ba915b96-e7a5-4465-ba13-f6b76ac87751','寄浙西李大夫四首 二','元稹','唐','唐诗','tang','','[]','蘂珠深處少人知，網索西臨太液池。',32,'全唐诗/poet.tang.21000.json','["蘂珠深處少人知，網索西臨太液池。", "浴殿曉聞天語後，步廊騎馬笑相隨。"]'),
('f089f679-1db3-4825-af74-a490c9c81d0f','寄浙西李大夫四首 三','元稹','唐','唐诗','tang','','[]','禁林同直話交情，無夜無曾不到明。',32,'全唐诗/poet.tang.21000.json','["禁林同直話交情，無夜無曾不到明。", "最憶西樓人靜夜，玉晨鐘磬兩三聲。"]'),
('f8e5d653-7cb2-4121-acbf-7eb016500211','寄浙西李大夫四首 四','元稹','唐','唐诗','tang','','[]','由來鵬化便圖南，浙右雖雄我未甘。',32,'全唐诗/poet.tang.21000.json','["由來鵬化便圖南，浙右雖雄我未甘。", "早渡西江好歸去，莫拋舟楫滯春潭。"]'),
('da8f662d-c8d7-47f2-ba1c-90344883a422','初除浙東妻有阻色因以四韻曉之','元稹','唐','唐诗','tang','','[]','嫁時五月歸巴地，今日雙旌上越州。',64,'全唐诗/poet.tang.21000.json','["嫁時五月歸巴地，今日雙旌上越州。", "興慶首行千命婦，會稽旁帶六諸侯。", "海樓翡翠閑相逐，鏡水鴛鴦煖共遊。", "我有主恩羞未報，君於此外更何求。"]'),
('ca4f708a-296c-49e6-b2c4-a4e465b6b535','爲樂天自勘詩集因思頃年城南醉歸馬上遞唱豔曲十餘里不絕長慶初俱以制誥侍宿南郊齋宮夜後偶吟數十篇兩掖諸公洎翰林學士三十餘人驚起就聽逮至卒吏莫不衆觀羣公直至侍從行禮之時不復聚寐予與樂天吟哦竟亦不絕因書於樂天卷後越中冬夜風雨不覺將曉諸門互啓關鎖即事成篇','元稹','唐','唐诗','tang','','[]','春野醉吟十里程，齋宮潛詠萬人驚。',32,'全唐诗/poet.tang.21000.json','["春野醉吟十里程，齋宮潛詠萬人驚。", "今宵不寐到明讀，風雨曉聞開鎖聲。"]'),
('6919bbf0-1e19-47d1-9247-9ac9b0503af9','題長慶四年曆日尾','元稹','唐','唐诗','tang','','[]','殘曆半張餘十四，灰心雪鬢兩悽然。',32,'全唐诗/poet.tang.21000.json','["殘曆半張餘十四，灰心雪鬢兩悽然。", "定知新歲御樓後，從此不名長慶年。"]'),
('4908de78-1c45-4507-af50-6c370faca309','樂府古題序 夢上天','元稹','唐','唐诗','tang','','[]','夢上高高天，高高蒼蒼高不極。',158,'全唐诗/poet.tang.21000.json','["夢上高高天，高高蒼蒼高不極。", "下視五嶽塊纍纍，仰天依舊蒼蒼色。", "蹋雲聳身身更上，攀天上天攀未得。", "西瞻若水兔輪低，東望蟠桃海波黑。", "日月之光不到此，非暗非明煙塞塞。", "天悠地遠身跨風，下無階梯上無力。", "來時畏有他人上，截斷龍胡斬鵬翼。", "茫茫漫漫方自悲，哭向青雲椎素臆。", "哭聲厭咽旁人惡，喚起驚悲淚飄露。", "千慙萬謝喚厭人，向使無君終不寤。"]'),
('12bfaef5-8d1a-4b71-bc00-cee246d124ce','樂府古題序 冬白紵','元稹','唐','唐诗','tang','','[]','吳宮夜長宮漏款，簾幕四垂燈燄煖。',112,'全唐诗/poet.tang.21000.json','["吳宮夜長宮漏款，簾幕四垂燈燄煖。", "西施自舞王自管，雪紵翻翻鶴翎散。", "促節牽繁舞腰嬾，舞腰嬾，王罷飲。", "蓋覆西施鳳花錦，身作匡牀臂爲枕。", "朝珮樅玉王晏寢，寢醒閽報門無事。", "子胥死後言爲諱，近王之臣諭王意。", "共笑越王窮惴惴，夜夜抱冰寒不睡。"]'),
('42a6f605-8339-44ef-9208-af90b6e4e9ec','樂府古題序 將進酒','元稹','唐','唐诗','tang','','[]','將進酒，將進酒。',148,'全唐诗/poet.tang.21000.json','["將進酒，將進酒。", "酒中有毒酖主父，言之主父傷主母。", "母爲妾地父妾天，仰天俯地不忍言。", "陽爲僵踣主父前，主父不知加妾鞭。", "旁人知妾爲主說，主將淚洗鞭頭血。", "推椎主母牽下堂，扶妾遣升堂上牀。", "將進酒，酒中無毒令主壽。", "願主廻恩歸主母，遣妾如此由主父。", "妾爲此事人偶知，自慙不密方自悲。", "主今顛倒安置妾，貪天僭地誰不爲。"]'),
('b23b9487-ac91-4800-9aa7-b1bc09a3344c','樂府古題序 採珠行','元稹','唐','唐诗','tang','','[]','海波無底珠沈海，採珠之人判死採。',80,'全唐诗/poet.tang.21000.json','["海波無底珠沈海，採珠之人判死採。", "萬人判死一得珠，斛量買婢人何在。", "年年採珠珠避人，今年採珠由海神。", "海神採珠珠盡死，死盡明珠空海水。", "珠爲海物海屬神，神今自採何況人。"]'),
('e01dc2d3-9313-48b5-b358-c3a08d9da808','樂府古題序 董逃行','元稹','唐','唐诗','tang','','[]','董逃董逃董卓逃，揩鏗戈甲聲勞嘈。',132,'全唐诗/poet.tang.21000.json','["董逃董逃董卓逃，揩鏗戈甲聲勞嘈。", "剜剜深臍脂燄燄，人皆數歎曰。", "爾獨不憶年年取我身上膏，膏銷骨盡煙火死。", "長安城中賊毛起，城門四走公卿士。", "走勸劉虞作天子，劉虞不敢作天子。", "曹瞞篡亂從此始，董逃董逃人莫喜。", "勝負相環相枕倚，縫綴難成裁破易。", "何況曲鍼不能伸巧指，欲學裁縫須準擬。"]'),
('2cb57d9e-adaf-4a08-aff4-240a23a7d088','樂府古題序 憶遠曲','元稹','唐','唐诗','tang','','[]','憶遠曲，郎身不遠郎心遠。',149,'全唐诗/poet.tang.21000.json','["憶遠曲，郎身不遠郎心遠。", "沙隨郎飯俱在匙，郎意看沙那比飯。", "水中書字無字痕，君心暗畫誰會君。", "況妾事姑姑進止，身去門前同萬里。", "一家盡是郎腹心，妾似生來無兩耳。", "妾身何足言，聽妾私勸君。", "君今夜夜醉何處？姑來伴妾自閉門。", "嫁夫恨不早，養兒將備老。", "妾自嫁郎身骨立，老姑爲郎求娶妾。", "妾不忍見姑郎忍見，爲郎忍耐看姑面。"]'),
('10ca127f-b941-4689-8217-99a5e09c79b4','樂府古題序 夫遠征','元稹','唐','唐诗','tang','','[]','趙卒四十萬，盡爲坑中鬼。',114,'全唐诗/poet.tang.21000.json','["趙卒四十萬，盡爲坑中鬼。", "趙王未信趙母言，猶點新兵更填死。", "填死之兵兵氣索，秦強趙破括敵起。", "括雖專命起尚輕，何況牽肘之人牽不已。", "坑中之鬼妻在營，髽麻戴絰鵝雁鳴。", "送夫之婦又行哭，哭聲送死非送行。", "夫遠征，遠征不必戍長城，出門便不知死生。"]'),
('19a9273b-3081-4575-a9f1-bb6ad27cd93f','樂府古題序 織婦詞','元稹','唐','唐诗','tang','','["\u5987\u5973", "\u6292\u6000", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','織夫何太忙，蠶經三臥行欲老。',126,'全唐诗/poet.tang.21000.json','["織夫何太忙，蠶經三臥行欲老。", "蠶神女聖早成絲，今年絲稅抽徵早。", "早徵非是官人惡，去歲官家事戎索。", "征人戰苦束刀瘡，主將勳高換羅幕。", "繅絲織帛猶努力，變緝撩機苦難織。", "東家頭白雙女兒，爲解挑紋嫁不得。", "檐前嫋嫋游絲上，上有蜘蛛巧來往。", "羨他蟲豸解緣天，能向虛空織羅網。"]'),
('3ebfbcd5-a4e9-4e05-9396-82b390c73091','樂府古題序 田家詞','元稹','唐','唐诗','tang','','["\u53d9\u4e8b", "\u6218\u4e89", "\u6292\u6000", "\u4e50\u5e9c", "\u519c\u6c11", "\u65b0\u4e50\u5e9c\u8f9e"]','牛吒吒，田确确。',113,'全唐诗/poet.tang.21000.json','["牛吒吒，田确确。", "旱塊敲牛蹄趵趵，種得官倉珠顆穀。", "六十年來兵蔟蔟，月月食糧車轆轆。", "一日官軍收海服，驅牛駕車食牛肉。", "歸來攸得牛兩角，重鑄鋤犂作斤劚。", "姑舂婦擔去輸官，輸官不足歸賣屋。", "願官早勝讎早覆，農死有兒牛有犢，誓不遣官軍糧不足。"]'),
('446bec5f-c3ab-4caa-af4f-66ce21a8f2bd','樂府古題序 俠客行','元稹','唐','唐诗','tang','','[]','俠客不怕死，怕在事不成。',92,'全唐诗/poet.tang.21000.json','["俠客不怕死，怕在事不成。", "事成不肯藏姓名，我非竊賊誰夜行。", "白日堂堂殺袁盎，九衢草草人面青。", "此客此心師海鯨，海鯨露背橫滄溟。", "海波分作兩處生，分海減海刀，俠客有謀。", "人不識測，三尺鐵蛇延二國。"]'),
('0d4bd083-3717-434d-9284-b0c34dde5475','樂府古題序 君莫非','元稹','唐','唐诗','tang','','[]','鳥不解走，獸不解飛。',100,'全唐诗/poet.tang.21000.json','["鳥不解走，獸不解飛。", "兩不相解，那得相譏。", "犬不飲露，蟬不噉肥。", "以蟬易犬，蟬死犬飢。", "燕在梁棟，鼠在階基。", "各自窠窟，人不能移。", "婦好鍼縷，夫讀書詩。", "男翁女嫁，卒不相知。", "懼聾摘耳，效痛嚬眉。", "我不非爾，爾無我非。"]'),
('ab89c83e-a4ac-4ec9-9a21-186019ef8a03','樂府古題序 田野狐兔行','元稹','唐','唐诗','tang','','[]','種豆耘鋤，種禾溝甽。',70,'全唐诗/poet.tang.21000.json','["種豆耘鋤，種禾溝甽。", "禾苗豆甲，狐榾兔翦。", "割鵠餧鷹，烹麟噉犬。", "鷹怕兔毫，犬被狐引。", "狐兔相須，鷹犬相盡。", "日暗天寒，禾稀豆損。", "鷹犬就烹，狐兔俱哂。"]'),
('e9450f35-87bb-4295-9de7-34914fadc24d','樂府古題序 當來日大難行','元稹','唐','唐诗','tang','','[]','當來日大難行，前有阪，後有坑。',98,'全唐诗/poet.tang.21000.json','["當來日大難行，前有阪，後有坑。", "大梁側，小梁傾。", "兩軸相絞，兩輪相撐。", "大牛豎，小牛橫。", "烏啄牛背，足趺力儜，當來日大難行。", "太行雖險，險可使平。", "輪軸自撓，牽制不停。", "泥潦漸久，荆棘旋生。", "行必不得，不如不行。"]'),
('dec1d0c4-b4b3-430e-9d82-40946c67b108','樂府古題序 人道短','元稹','唐','唐诗','tang','','[]','古道天道長人道短，我道天道短人道長。',323,'全唐诗/poet.tang.21000.json','["古道天道長人道短，我道天道短人道長。", "天道晝夜廻轉不曾住，春秋冬夏忙，顛風暴雨電雷狂。", "晴被陰暗，月奪日光。", "往往星宿，日亦堂堂。", "天既職性命，道德人自強。", "堯舜有聖德，天不能遣。", "壽命永昌，泥金刻玉。", "與秦始皇，周公傅說。", "何不長宰相，老耼仲尼。", "何事栖遑，莽卓恭顯。", "皆數十年富貴，梁冀夫婦。", "車馬煌煌，若此顛倒事。", "豈非天道短，豈非人道長。", "堯舜留得神聖事，百代天子有典章。", "仲尼留得孝順語，千年萬歲父子不敢相滅亡。", "歿後千餘載，唐家天子封作文宣王。", "老君留得五千字，子孫萬萬稱聖唐。", "諡作玄元帝，魂魄坐天堂。", "周公周禮二十卷，有能行者知紀綱。", "傅說說命三四紙，有能師者稱祖宗。", "天能夭人命，人使道無窮。", "若此神聖事，誰道人道短。", "豈非人道長，天能種百草。", "蕕得十年有氣息，蕣纔一日芳。"]'),
('a6326b33-4250-4766-ac58-d742b6cb4ebe','樂府古題序 苦樂相倚曲','元稹','唐','唐诗','tang','','[]','古來苦樂之相倚，近於掌上之十指。',192,'全唐诗/poet.tang.21000.json','["古來苦樂之相倚，近於掌上之十指。", "君心半夜猜恨生，荆棘滿懷天未明。", "漢成眼瞥飛燕時，可憐班女恩已衰。", "未有因由相決絕，猶得半年佯暖熱。", "轉將深意諭旁人，緝綴瑕疵遣潛說。", "一朝詔下辭金屋，班姬自痛何倉卒。", "呼天撫地將自明，不悟尋時暗銷骨。", "白首宮人前再拜，願將日月相輝解。", "苦樂相尋晝夜間，燈光那有天明在。", "主今被奪心應苦，妾奪深恩初爲主。", "欲知妾意恨主時，主今爲妾思量取。", "班姬收淚抱妾身，我曾排擯無限人。"]'),
('d1ddef83-d86f-4f00-8f98-1cedc22cf519','樂府古題序 出門行','元稹','唐','唐诗','tang','','[]','兄弟同出門，同行不同志。',288,'全唐诗/poet.tang.21000.json','["兄弟同出門，同行不同志。", "悽悽分岐路，各各營所爲。", "兄上荆山巔，翻石辨虹氣。", "弟沈滄海底，偷珠待龍睡。", "出門不數年，同歸亦同遂。", "俱用私所珍，升沈自茲異。", "獻珠龍王宮，值龍覓珠次。", "但喜復得珠，不求珠所自。", "酬客雙龍女，授客六龍轡。", "遣充行雨神，雨澤隨客意。", "雩夏鐘鼓繁，禜秋玉帛積。", "彩色畫廊廟，奴僮被珠翠。", "驥騄千萬雙，鴛鴦七十二。", "言者未搖舌，無人敢輕議。", "其兄因獻璞，再刖不履地。", "門戶親戚疎，匡牀妻妾棄。", "銘心有所待，視足無所愧。", "持璞自枕頭，淚痕雙血漬。", "一朝龍醒寤，本問偷珠事。", "因知行雨偏，妻子五刑備。", "仁兄捧尸哭，勢友掉頭諱。", "喪車黔首葬，弔客青蠅至。", "楚有望氣人，王前忽長跪。", "賀王得貴寶，不遠王所莅。"]'),
('6d5fff46-32e1-4118-98f5-120146079b6a','樂府古題序 捉捕歌','元稹','唐','唐诗','tang','','[]','捉捕復捉捕，莫捉狐與兔。',288,'全唐诗/poet.tang.21000.json','["捉捕復捉捕，莫捉狐與兔。", "狐兔藏窟穴，豺狼妨道路。", "道路非不妨，最憂螻蟻聚。", "豺狼不陷穽，螻蟻潛幽蠹。", "切切主人窗，主人輕細故。", "延緣蝕𣡵櫨，漸入棟梁柱。", "梁棟盡空虛，攻穿痕不露。", "主人坦然意，晝夜安寢寤。", "網羅布參差，鷹犬走回互。", "盡力窮窟穴，無心自還顧。", "客來歌捉捕，歌竟淚如雨。", "豈是惜狐兔，畏君先後誤。", "願君埽梁棟，莫遣螻蟻附。", "次及清道塗，盡滅豺狼步。", "主人堂上坐，行客門前度。", "然後巡野田，徧張畋獵具。", "外無梟獍援，內有熊羆驅。", "狡兔掘荒榛，妖狐熏古墓。", "用力不足多，得禽自無數。", "畏君聽未詳，聽客有明喻。", "蟣蝨誰不輕，鯨鯢誰不惡。", "在海尚幽遐，在懷交穢汚。", "歌此勸主人，主人那不悟。", "不悟還更歌，誰能恐違忤。"]'),
('fe9f4c9e-c71e-458f-b18c-44ce2036869c','樂府古題序 古築城曲五解 一','元稹','唐','唐诗','tang','','[]','年年塞下丁，長作出塞兵。',24,'全唐诗/poet.tang.21000.json','["年年塞下丁，長作出塞兵。", "自從冒頓強，官築遮虜城。"]'),
('3c3c9603-68ed-44fe-92f1-01e84616a974','樂府古題序 古築城曲五解 二','元稹','唐','唐诗','tang','','[]','築城須努力，城高遮得賊。',24,'全唐诗/poet.tang.21000.json','["築城須努力，城高遮得賊。", "但恐賊路多，有城遮不得。"]'),
('e92bbc7a-2373-492a-9ba7-0b146391cf8e','樂府古題序 古築城曲五解 三','元稹','唐','唐诗','tang','','[]','丁口傳父言，莫問城堅不。',24,'全唐诗/poet.tang.21000.json','["丁口傳父言，莫問城堅不。", "平城被虜圍，漢劚城牆走。"]'),
('48a9c53a-4441-4160-b19a-e8bfca566cc9','樂府古題序 古築城曲五解 四','元稹','唐','唐诗','tang','','[]','因茲請休和，虜往騎來過。',24,'全唐诗/poet.tang.21000.json','["因茲請休和，虜往騎來過。", "半疑兼半信，築城猶嵯峨。"]'),
('c85e8697-9e78-40cb-8f8e-5d4a9bf772b4','樂府古題序 古築城曲五解 五','元稹','唐','唐诗','tang','','[]','築城安敢煩，願聽丁一言。',24,'全唐诗/poet.tang.21000.json','["築城安敢煩，願聽丁一言。", "請築鴻臚寺，兼愁虜出關。"]'),
('16e8df55-02ae-4e52-b8c9-f72a27cd99fe','樂府古題序 估客樂','元稹','唐','唐诗','tang','','[]','估客無住著，有利身則行。',288,'全唐诗/poet.tang.21000.json','["估客無住著，有利身則行。", "出門求火伴，入戶辭父兄。", "父兄相教示，求利莫求名。", "求名有所避，求利無不營。", "火伴相勒縛，賣假莫賣誠。", "交關但交假，本生得失輕。", "自茲相將去，誓死意不更。", "亦解市頭語，便無鄰里情。", "鍮石打臂釧，糯米吹項瓔。", "歸來邨中賣，敲作金石聲。", "邨中田舍娘，貴賤不敢爭。", "所費百錢本，已得十倍贏。", "顏色轉光淨，飲食亦甘馨。", "子本頻蕃息，貨販日兼幷。", "求珠駕滄海，採玉上荆衡。", "北買党項馬，西擒吐蕃鸚。", "炎洲布火浣，蜀地錦織成。", "越婢脂肉滑，奚僮眉眼明。", "通算衣食費，不計遠近程。", "經遊天下徧，却到長安城。", "城中東西市，聞客次第迎。", "迎客兼說客，多財爲勢傾。", "客心本明黠，聞語心已驚。", "先問十常侍，次求百公卿。"]'),
('8f19c587-32cc-47b4-9671-d1129116d9c2','連昌宮詞','元稹','唐','唐诗','tang','','[]','連昌宮中滿宮竹，歲久無人森似束。',384,'全唐诗/poet.tang.21000.json','["連昌宮中滿宮竹，歲久無人森似束。", "又有牆頭千葉桃，風動落花紅蔌蔌。", "宮邊老翁爲余泣，小年進食曾因入。", "上皇正在望仙樓，太真同凭闌干立。", "樓上樓前盡珠翠，炫轉熒煌照天地。", "歸來如夢復如癡，何暇備言宮裏事。", "初過寒食一百六，店舍無煙宮樹綠。", "夜半月高弦索鳴，賀老琵琶定場屋。", "力士傳呼覓念奴，念奴潛伴諸郎宿。", "須臾覓得又連催，特敕街中許然燭。", "春嬌滿眼睡紅綃，掠削雲鬟旋裝束。", "飛上九天歌一聲，二十五郎吹管逐。", "逡巡大徧涼州徹，色色龜茲轟錄續。", "李謩擪笛傍宮牆，偷得新翻數般曲。", "平明大駕發行宮，萬人歌舞塗路中。", "百官隊仗避岐薛，楊氏諸姨車鬬風。", "明年十月東都破，御路猶存祿山過。", "驅令供頓不敢藏，萬姓無聲淚潛墮。", "兩京定後六七年，却尋家舍行宮前。", "莊園燒盡有枯井，行宮門閉樹宛然。", "爾後相傳六皇帝，不到離宮門久閉。", "往來年少說長安，玄武樓成花萼廢。", "去年敕使因斫竹，偶值門開暫相逐。", "荆榛櫛比塞池塘，狐兔驕癡緣樹木。"]'),
('84eaa5b6-6ea8-4904-acf8-7f7f8b100932','望雲騅馬歌','元稹','唐','唐诗','tang','','[]','憶昔先皇幸蜀時，八馬入谷七馬疲。',386,'全唐诗/poet.tang.21000.json','["憶昔先皇幸蜀時，八馬入谷七馬疲。", "肉綻筋攣四蹄脫，七馬死盡無馬騎。", "天子蒙塵天雨泣，巉巖道路淋漓濕。", "崢嶸白草眇難期，謥洞黃泉安可入。", "朱泚圍兵抽未盡，懷光寇騎追行及。", "嬪娥相顧倚樹啼，鵷鷺無聲仰天立。", "圉人初進望雲騅，彩色顦顇衆馬欺。", "上前噴吼如有意，耳尖卓立節踠奇。", "君王試遣廻胸臆，撮骨鋸牙駢兩肋。", "蹄懸四跼腦顆方，胯聳三山尾株直。", "圉人畏誚仍相惑，此馬無良空有力。", "頻頻囓掣轡難施，往往跳趫鞍不得。", "色沮聲悲仰天訴，天不遣言君未識。", "亞身受取白玉羈，開口銜將紫金勒。", "君王自此方敢騎，似遇良臣久悽惻。", "龍騰魚鼈啅然驚，驥朌驢騾少顏色。", "七聖心迷運方厄，五丁力盡路猶窄。", "橐它山上斧刃堆，望秦嶺下錐頭石。", "五六百里真符縣，八十四盤青山驛。", "掣開流電有輝光，突過浮雲無朕跡。", "地平險盡施黃屋，九九屬車十二纛。", "齊暎前導引騅頭，嚴震迎號抱騅足。", "路傍垂白天寶民，望騅禮拜見騅哭。", "皆言玄宗當時無此馬，不免騎騾來幸蜀。"]'),
('1819e9db-aa89-4523-8662-783a06dfac6e','和李校書新題樂府十二首 上陽白髮人','元稹','唐','唐诗','tang','','[]','天寶年中花鳥使，撩花狎鳥含春思。',256,'全唐诗/poet.tang.21000.json','["天寶年中花鳥使，撩花狎鳥含春思。", "滿懷墨詔求嬪御，走上高樓半酣醉。", "醉酣直入卿士家，閨闈不得偷廻避。", "良人顧妾心死別，小女呼爺血垂淚。", "十中有一得更衣，永配深宮作宮婢。", "御馬南奔胡馬蹙，宮女三千合宮棄。", "宮門一閉不復開，上陽花草青苔地。", "月夜閑聞洛水聲，秋池暗度風荷氣。", "日日長看提衆門，終身不見門前事。", "近年又送數人來，自言興慶南宮至。", "我悲此曲將徹骨，更想深冤復酸鼻。", "此輩賤嬪何足言，帝子天孫古稱貴。", "諸王在閤四十年，七宅六宮門戶閟。", "隋煬枝條襲封邑，肅宗血胤無官位。", "王無妃媵主無壻，陽亢陰淫結災累。", "何如決壅順衆流，女遣從夫男作吏。"]'),
('ebdc03e3-3b42-42a0-ac94-42efd22f537c','和李校書新題樂府十二首 華原磬','元稹','唐','唐诗','tang','','[]','泗濱浮石裁爲磬，古樂疎音少人聽。',192,'全唐诗/poet.tang.21000.json','["泗濱浮石裁爲磬，古樂疎音少人聽。", "工師小賤牙曠稀，不辨邪聲嫌雅正。", "正聲不屈古調高，鍾律參差管絃病。", "鏗金戛瑟徒相雜，投玉敲冰杳然零。", "華原輭石易追琢，高下隨人無雅鄭。", "棄舊美新由樂胥，自此黃鍾不能競。", "玄宗愛樂愛新樂，梨園弟子承恩橫。", "霓裳纔徹胡騎來，雲門未得蒙親定。", "我藏古磬藏在心，有時激作南風詠。", "伯夔曾撫野獸馴，仲尼暫叩春雷盛。", "何時得向筍簴懸，爲君一吼君心醒。", "願君每聽念封疆，不遣豺狼勦人命。"]'),
('1d20399f-aebe-402c-9c30-f048a7010313','和李校書新題樂府十二首 五弦彈','元稹','唐','唐诗','tang','','[]','趙璧五弦彈徵調，徵聲巉絕何清峭。',240,'全唐诗/poet.tang.21000.json','["趙璧五弦彈徵調，徵聲巉絕何清峭。", "辭雄皓鶴警露啼，失子哀猿繞林嘯。", "風入春松正凌亂，鶯含曉舌憐嬌妙。", "嗚嗚暗溜咽冰泉，殺殺霜刀澀寒鞘。", "促節頻催漸繁撥，珠幢斗絕金鈴掉。", "千靫鳴鏑發胡弓，萬片清球擊虞廟。", "衆樂雖同第一部，德宗皇帝常偏召。", "旬休節假暫歸來，一聲狂殺長安少。", "主第侯家最難見，挼歌按曲皆承詔。", "水精簾外教貴嬪，瑇瑁筵心伴中要。", "臣有五賢非此弦，或在拘囚或屠釣。", "一賢得進勝累百，兩賢得進同周召。", "三賢事漢滅暴彊，四賢鎮岳寧邊徼。", "五賢竝用調五常，五常既敘三光耀。", "趙璧五弦非此賢，九九何勞設庭燎。"]'),
('e3dbf3c4-e30a-4d37-bfbf-5697282f3c97','和李校書新題樂府十二首 西涼伎','元稹','唐','唐诗','tang','','[]','吾聞昔日西涼州，人煙撲地桑柘稠。',204,'全唐诗/poet.tang.21000.json','["吾聞昔日西涼州，人煙撲地桑柘稠。", "蒲萄酒熟恣行樂，紅豔青旗朱粉樓。", "樓下當壚稱卓女，樓頭伴客名莫愁。", "鄉人不識離別苦，更卒多爲沈滯遊。", "哥舒開府設高宴，八珍九醞當前頭。", "前頭百戲競撩亂，丸劒跳躑霜雪浮。", "獅子搖光毛彩豎，胡騰醉舞筋骨柔。", "大宛來獻赤汗馬，贊普亦奉翠茸裘。", "一朝燕賊亂中國，河湟沒盡空遺丘。", "開遠門前萬里堠，今來蹙到行原州。", "去京五百而近何其逼，天子縣內半沒爲荒陬。", "西涼之道爾阻脩，連城邊將但高會，每聽此曲能不羞。"]'),
('68711ded-7564-4b9b-afd3-711d0bcc78cd','和李校書新題樂府十二首 法曲','元稹','唐','唐诗','tang','','[]','吾聞黃帝鼓清角，弭伏熊羆舞玄鶴。',192,'全唐诗/poet.tang.21000.json','["吾聞黃帝鼓清角，弭伏熊羆舞玄鶴。", "舜持干羽苗革心，堯用咸池鳳巢閣。", "大夏濩武皆象功，功多已訝玄功薄。", "漢祖過沛亦有歌，秦王破陣非無作。", "作之宗廟見艱難，作之軍旅傳糟粕。", "明皇度曲多新態，宛轉侵淫易沈著。", "赤白桃李取花名，霓裳羽衣號天落。", "雅弄雖云已變亂，夷音未得相參錯。", "自從胡騎起煙塵，毛毳腥羶滿咸洛。", "女爲胡婦學胡妝，伎進胡音務胡樂。", "火鳳聲沈多咽絕，春鶯囀罷長蕭索。", "胡音胡騎與胡妝，五十年來競紛泊。"]'),
('5663eff3-c9cf-4a2f-beec-36e3616ceaf2','和李校書新題樂府十二首 馴犀','元稹','唐','唐诗','tang','','[]','建中之初放馴象，遠歸林邑近交廣。',192,'全唐诗/poet.tang.21000.json','["建中之初放馴象，遠歸林邑近交廣。", "獸返深山鳥搆巢，鷹鵰鷂鶻無羈鞅。", "貞元之歲貢馴犀，上林置圈官司養。", "玉盆金棧非不珍，虎噉狴牢魚食網。", "渡江之橘踰汶貉，反時易性安能長。", "臘月北風霜雪深，踡跼鱗身遂長往。", "行地無疆費傳驛，通天異物罹幽枉。", "乃知養獸如養人，不必人人自敦獎。", "不擾則得之於理，不奪有以多於賞。", "脫衣推食衣食之，不若男耕女令紡。", "堯民不自知有堯，但見安閑聊擊壤。", "前觀馴象後馴犀，理國其如指諸掌。"]'),
('227fbb31-176f-4e56-aa43-f33b3eef917d','和李校書新題樂府十二首 立部伎','元稹','唐','唐诗','tang','','[]','胡部新聲錦筵坐，中庭漢振高音播。',255,'全唐诗/poet.tang.21000.json','["胡部新聲錦筵坐，中庭漢振高音播。", "太宗廟樂傳子孫，取類羣兇陣初破。", "戢戢攢槍霜雪耀，騰騰擊鼓雲雷磨。", "初疑遇敵身啓行，終象由文士憲左。", "昔日高宗常立聽，曲終然後臨玉座。", "如今節將一掉頭，電卷風收盡摧挫。", "宋晉鄭女歌聲發，滿堂會客齊喧㰤。", "珊珊珮玉動腰身，一一貫珠隨咳唾。", "頃向圜丘見郊祀，亦曾正旦親朝賀。", "太常雅樂備宮懸，九奏未終百寮惰。", "惉滯難令季札辨，遲廻但恐文侯臥。", "工師盡取聾昧人，豈是先王作之過。", "宋沇嘗傳天寶季，法曲胡音忽相和。", "明年十月燕寇來，九廟千門虜塵涴我聞此語歎復泣，古來邪正將誰奈。", "奸聲入耳佞入心，侏儒飽飯夷齊餓。"]'),
('5deb4404-3d22-4019-95c9-b0c23dbb91cc','和李校書新題樂府十二首 驃國樂','元稹','唐','唐诗','tang','','[]','驃之樂器頭象駝，音聲不合十二和。',256,'全唐诗/poet.tang.21000.json','["驃之樂器頭象駝，音聲不合十二和。", "促舞跳趫筋節硬，繁辭變亂名字訛。", "千彈萬唱皆咽咽，左旋右轉空傞傞。", "俯地呼天終不會，曲成調變當如何。", "德宗深意在柔遠，笙鏞不御停嬌娥。", "史館書爲朝貢傳，太常編入鞮靺科。", "古時陶堯作天子，遜遁親聽康衢歌。", "又遣遒人持木鐸，徧采謳謠天下過。", "萬人有意皆洞達，四岳不敢施煩苛。", "盡令區中擊壤塊，燕及海外覃恩波。", "秦霸周衰古官廢，下堙上塞王道頗。", "共矜異俗同聲教，不念齊民方薦瘥。", "傳稱魚鼈亦咸若，苟能效此誠足多。", "借如牛馬未蒙澤，豈在抱甕滋黿鼉。", "教化從來有源委，必將泳海先泳河。", "是非倒置自古有，驃兮驃兮誰爾訶。"]'),
('e7b809cc-caa8-4dcc-8c46-f0ae914e7ca9','和李校書新題樂府十二首 胡旋女','元稹','唐','唐诗','tang','','[]','天寶欲末胡欲亂，胡人獻女能胡旋。',255,'全唐诗/poet.tang.21000.json','["天寶欲末胡欲亂，胡人獻女能胡旋。", "旋得明王不覺迷，妖胡奄到長生殿。", "胡旋之義世莫知，胡旋之容我能傳。", "蓬斷霜根羊角疾，竿戴朱盤火輪炫。", "驪珠迸珥逐飛星，虹暈輕巾掣流電。", "潛鯨暗噏笡波海，回風亂舞當空霰。", "萬過其誰辨終始，四座安能分背面。", "才人觀者相爲言，承奉君恩在圜變。", "是非好惡隨君口，南北東西逐君眄。", "柔輭依身著佩帶，裴回繞指同環釧。", "佞臣聞此心計回，熒惑君心君眼眩。", "君言似曲屈爲鉤，君言好直舒爲箭。", "巧隨清影觸處行，妙學春鶯百般囀。", "傾天側地用君力，抑塞周遮恐君見。", "翠華南幸萬里橋，玄宗始悟坤維轉寄言旋目與旋心，有國有家當共譴。"]'),
('fc24eec5-132f-42af-9c19-01108dd28c44','和李校書新題樂府十二首 蠻子朝','元稹','唐','唐诗','tang','','[]','西南六詔有遺種，僻在荒陬路尋壅。',224,'全唐诗/poet.tang.21000.json','["西南六詔有遺種，僻在荒陬路尋壅。", "部落支離君長賤，比諸夷狄爲幽冗。", "犬戎彊盛頻侵削，降有憤心戰無勇。", "夜防抄盜保深山，朝望煙塵上高冢。", "鳥道繩橋來款附，非因慕化因危悚。", "清平官繫金呿嵯，求天叩地持雙珙。", "益州大將韋令公，頃實遭時定汧隴。", "自居劇鎮無他績，幸得蠻來固恩寵。", "爲蠻開道引蠻朝，迎蠻送蠻常繼踵。", "天子臨軒四方賀，朝廷無事唯端拱。", "漏天走馬春雨寒，瀘水飛蛇瘴煙重。", "椎頭醜類除憂患，瘇足役夫勞洶湧。", "匈奴互市歲不供，雲蠻通好轡長駷。", "戎王養馬漸多年，南人耗顇西人恐。"]'),
('f925f98a-ddf0-4c1e-a5e6-25b624ac1e12','和李校書新題樂府十二首 縛戎人','元稹','唐','唐诗','tang','','[]','邊頭大將差健卒，入抄禽生快於鶻。',384,'全唐诗/poet.tang.21000.json','["邊頭大將差健卒，入抄禽生快於鶻。", "但逢赬面即捉來，半是邊人半戎羯。", "大將論功重多級，捷書飛奏何超忽。", "聖朝不殺諧至仁，遠送炎方示微罰。", "萬里虛勞肉食費，連頭盡被氈裘暍。", "華裀重席臥腥臊，病犬愁鴣聲咽嗢。", "中有一人能漢語，自言家本長城窟。", "少年隨父戍安西，河渭瓜沙眼看沒。", "天寶未亂猶數載，狼星四角光蓬勃。", "中原禍作邊防危，果有豺狼四來伐。", "蕃馬臕成正翹健，蕃兵肉飽爭唐突。", "煙塵亂起無亭燧，主帥驚跳棄旄鉞。", "半夜城摧鵝雁鳴，妻啼子叫曾不歇。", "陰森神廟未敢依，脆薄河冰安可越。", "荆棘深處共潛身，前困蒺藜後臲卼。", "平明蕃騎四面走，古墓深林盡株榾。", "少壯爲俘頭被髠，老翁留居足多刖。", "烏鳶滿野尸狼藉，樓榭成灰牆突兀。", "暗水濺濺入舊池，平沙漫漫鋪明月。", "戎王遣將來安慰，口不敢言心咄咄。", "供進腋腋御叱般，豈料穹廬揀肥腯。", "五六十年消息絕，中間盟會又猖獗。", "眼穿東日望堯雲，腸斷正朝梳漢髮。", "近年如此思漢者，半爲老病半埋骨。"]'),
('8d8487d4-8d9f-41ed-8455-14af95c78bd4','和李校書新題樂府十二首 陰山道','元稹','唐','唐诗','tang','','[]','年年買馬陰山道，馬死陰山帛空耗。',258,'全唐诗/poet.tang.21000.json','["年年買馬陰山道，馬死陰山帛空耗。", "元和天子念女工，內出金銀代酬犒。", "臣有一言昧死進，死生甘分荅恩燾。", "費財爲馬不獨生，耗帛傷工有他盜。", "臣聞平時七十萬匹馬，關中不省聞嘶噪。", "四十八監選龍媒，時貢天庭付良造。", "如今坰野十無一，盡在飛龍相踐暴。", "萬束芻茭供旦暮，千鍾菽粟長牽漕。", "屯軍郡國百餘鎮，縑緗歲奉春冬勞。", "稅戶逋逃例攤配，官司折納仍貪冒。", "挑紋變䌰力倍費，棄舊從新人所好。", "越縠繚綾織一端，十匹素縑功未到。", "豪家富賈踰常制，令族清班無雅操。", "從騎愛奴絲布衫，臂鷹小兒雲錦韜。", "羣臣利己要差僭，天子深衷空憫悼。", "綽立花塼鵷鳳行，雨露恩波幾時報。"]'),
('10552516-d84b-43d1-afea-a3b5aa7a8581','有鳥二十章 一','元稹','唐','唐诗','tang','','[]','有鳥有鳥名老鴟，鴟張貪很老不衰。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥名老鴟，鴟張貪很老不衰。", "似鷹指爪唯攫肉，戾天羽翮徒翰飛。", "朝偷暮竊恣昏飽，後顧前瞻高樹枝。", "珠丸彈射死不去，意在護巢兼護兒。"]'),
('3bf3ae6b-1a13-4b55-a429-65f57f4b0c29','有鳥二十章 二','元稹','唐','唐诗','tang','','[]','有鳥有鳥毛似鶴，行步雖遲性靈惡。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥毛似鶴，行步雖遲性靈惡。", "主人但見閑慢容，許占蓬萊最高閣。", "弱羽長憂俊鶻拳，疽腸暗著鵷雛啄。", "千年不死伴靈龜，梟心鶴貌何人覺。"]'),
('65247e61-4db8-432a-a236-cf36329605ce','有鳥二十章 三','元稹','唐','唐诗','tang','','[]','有鳥有鳥如鸛雀，食蛇抱礐天姿惡。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥如鸛雀，食蛇抱礐天姿惡。", "行經水滸爲毒流，羽拂酒杯爲死藥。", "漢后忍渴天豈知，驪姬墳地君寧覺。", "嗚呼爲有白色毛，亦得乘軒謬稱鶴。"]'),
('ad8858a8-53aa-4d5d-9e02-63d622229ee0','有鳥二十章 四','元稹','唐','唐诗','tang','','[]','有鳥有鳥名爲鳩，毛衣輭毳心性柔。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥名爲鳩，毛衣輭毳心性柔。", "鶻緣暖足憐不喫，鷂爲同科曾共游。", "飛飛漸上高高閣，百鳥不猜稱好逑。", "佳人許伴鵷雛食，望爾化爲張氏鉤。"]'),
('4da427a5-0339-4a15-9443-6a9ff8456b00','有鳥二十章 五','元稹','唐','唐诗','tang','','[]','有鳥有鳥名野雞，天姿耿介行步齊。',96,'全唐诗/poet.tang.21000.json','["有鳥有鳥名野雞，天姿耿介行步齊。", "主人偏養憐整頓，玉粟充腸瑤樹栖。", "池塘潛狎不鳴雁，津梁暗引無用鵜。", "秋鷹迸逐霜鶻遠，鵩鳥護巢當晝啼。", "主人頻問遣妖術，力盡計窮音響悽。", "當時何不早量分，莫遣輝光深照泥。"]'),
('f29c90a2-a21d-4f31-9da3-480022d62c12','有鳥二十章 六','元稹','唐','唐诗','tang','','[]','有鳥有鳥羣翠碧，毛羽短長心竝窄。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥羣翠碧，毛羽短長心竝窄。", "皆曾偷食淥池魚，前去後來更逼迫。", "食魚滿腹各自飛，池上見人長似客。", "飛飛競占嘉樹林，百鳥不爭緣鳳惜。"]'),
('14418c40-8711-4298-8d39-83728bc95484','有鳥二十章 七','元稹','唐','唐诗','tang','','[]','有鳥有鳥羣紙鳶，因風假勢童子牽。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥羣紙鳶，因風假勢童子牽。", "去地漸高人眼亂，世人爲爾羽毛全。", "風吹繩斷童子走，餘勢尚存猶在天。", "愁爾一朝還到地，落在深泥誰復憐。"]'),
('4a787853-f034-4a5e-8e02-bc5f3a95cd1c','有鳥二十章 八','元稹','唐','唐诗','tang','','[]','有鳥有鳥名啄木，木中求食常不足。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥名啄木，木中求食常不足。", "偏啄鄧林求一蟲，蟲孔未穿長觜禿。", "木皮已穴蟲在信，蟲蝕木心根柢覆。", "可憐樹上百鳥兒，有時飛向新林宿。"]'),
('9343276f-7c83-4e34-b6ec-f222da7af8ee','有鳥二十章 九','元稹','唐','唐诗','tang','','[]','有鳥有鳥衆蝙蝠，長伴佳人占華屋。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥衆蝙蝠，長伴佳人占華屋。", "妖鼠多年羽翮生，不辨雌雄無本族。", "穿墉伺隙善潛身，晝伏宵飛惡明燭。", "大廈雖存柱石傾，暗齧棟梁成蠹木。"]'),
('b1a7813b-5020-4970-9d89-4ac4cafb7ca4','有鳥二十章 十','元稹','唐','唐诗','tang','','[]','有鳥有鳥名爲鴞，深藏孔穴難動搖。',48,'全唐诗/poet.tang.21000.json','["有鳥有鳥名爲鴞，深藏孔穴難動搖。", "鷹鸇繞樹探不得，隨珠彈盡聲轉嬌。", "主人煩惑罷擒取，許占神林爲物妖。"]'),
('b71f5e31-bd8b-42ab-89e5-73f7b5c21342','有鳥二十章 十一','元稹','唐','唐诗','tang','','[]','有鳥有鳥名燕子，口中未省無泥滓。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥名燕子，口中未省無泥滓。", "春風吹送廊廡間，秋社驅將嵌孔裏。", "雷驚雨灑一時蘇，雲壓霜摧半年死。", "驅去驅來長信風，暫託棟梁何用喜。"]'),
('1d212155-6f49-43cf-aa4f-45c9ca08f944','有鳥二十章 十二','元稹','唐','唐诗','tang','','[]','有鳥有鳥名老烏，貪癡突誖天下無。',96,'全唐诗/poet.tang.21000.json','["有鳥有鳥名老烏，貪癡突誖天下無。", "田中攫肉吞不足，偏入諸巢探衆雛。", "歸來仍占主人樹，腹飽巢高聲響麤。", "山鵶野鵲閑受肉，鳳皇不得聞罪辜。", "秋鷹掣斷架上索，利爪一揮毛血落。", "可憐鵶鵲慕腥羶，猶向巢邊競紛泊。"]'),
('c0726816-032e-4b36-9c6f-8e5eb382064d','有鳥二十章 十三','元稹','唐','唐诗','tang','','[]','有鳥有鳥謂白鷴，雪毛皓白紅觜殷。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥謂白鷴，雪毛皓白紅觜殷。", "貴人妾婦愛光彩，行提坐臂怡朱顏。", "妖姬謝寵辭金屋，雕籠又伴新人宿。", "無心爲主擬銜花，空長白毛映紅肉。"]'),
('9f903c49-7695-4505-89da-b2710b250e4a','有鳥二十章 十四','元稹','唐','唐诗','tang','','[]','有鳥有鳥羣雀兒，中庭啄粟籬上飛。',96,'全唐诗/poet.tang.21000.json','["有鳥有鳥羣雀兒，中庭啄粟籬上飛。", "秋鷹欺小嫌不食，鳳皇容衆從爾隨。", "大鵬忽起遮白日，餘風簸蕩山岳移。", "翩翾百萬徒驚噪，扶搖勢遠何由知。", "古來妄說銜花報，縱解銜花何所爲。", "可惜官倉無限粟，伯夷餓死黃口肥。"]'),
('7fe4f4b5-8251-41f7-b2c9-c8f6fe3f37c2','有鳥二十章 十五','元稹','唐','唐诗','tang','','[]','有鳥有鳥皆百舌，舌端百囀聲咄㗌。',96,'全唐诗/poet.tang.21000.json','["有鳥有鳥皆百舌，舌端百囀聲咄㗌。", "先春盡學百鳥啼，真僞不分聽者悅。", "伶倫鳳律亂宮商，盤木天雞誤時節。", "朝朝暮暮主人耳，桃李無言管弦咽。", "五月炎光朱火盛，陽燄燒陰幽響絕。", "安知不是卷舌星，化作剛刀一時截。"]'),
('8477519a-d221-4ee5-b8aa-8c88558b4368','有鳥二十章 十六','元稹','唐','唐诗','tang','','[]','有鳥有鳥毛羽黃，雄者爲鴛雌者鴦。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥毛羽黃，雄者爲鴛雌者鴦。", "主人幷養七十二，羅列雕籠開洞房。", "雄鳴一聲雌鼓翼，夜不得栖朝不食。", "氣息榻然雙翅垂，猶入籠中就顏色。"]'),
('50923de2-a14a-4bdf-a02e-67afaf8d122a','有鳥二十章 十七','元稹','唐','唐诗','tang','','[]','有鳥有鳥名鷂雛，鈴子眼睛蒼錦襦。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥名鷂雛，鈴子眼睛蒼錦襦。", "貴人腕輭憐易臂，奮肘一揮前後呼。", "俊鶻無由拳狡兔，金雕不得擒魅狐。", "文王長在苑中獵，何日非熊休賣屠。"]'),
('1147622f-41a8-4111-8d0f-440cd9ef98c6','有鳥二十章 十八','元稹','唐','唐诗','tang','','[]','有鳥有鳥名鸚鵡，養在雕籠解人語。',161,'全唐诗/poet.tang.21000.json','["有鳥有鳥名鸚鵡，養在雕籠解人語。", "主人曾問私所聞，因說妖姬暗欺主。", "主人方惑翻見疑，趁歸隴底雙翅垂。", "山鵶野雀怪鸚語，競噪爭窺無已時。", "君不見隋朝隴頭姥，嬌養雙鸚囑新婦。", "一鸚曾說婦無儀，悍婦殺鸚欺主母。", "一鸚閉口不復言，母問不言何太久。", "鸚言悍婦殺鸚由，母爲逐之鄉里醜。", "當時主母信爾言，顧爾微禽命何有。", "今之主人翻爾疑，何事籠中漫開口。"]'),
('2744b904-f72e-49b5-badf-0d8180e22f82','有鳥二十章 十九','元稹','唐','唐诗','tang','','[]','有鳥有鳥名俊鶻，鷂小鵰癡俊無匹。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥名俊鶻，鷂小鵰癡俊無匹。", "雛鴨拂爪血迸天，狡兔中拳頭粉骨。", "平明度海朝未食，拔上秋空雲影沒。", "瞥然飛下人不知，攪碎荒城魅狐窟。"]'),
('cb7bd301-b8bd-4683-ba3e-bfc014cb4064','有鳥二十章 二十','元稹','唐','唐诗','tang','','[]','有鳥有鳥真白鶴，飛上九霄雲漠漠。',64,'全唐诗/poet.tang.21000.json','["有鳥有鳥真白鶴，飛上九霄雲漠漠。", "司晨守夜悲雞犬，啄腐吞腥笑鵰鶚。", "堯年值雪度關山，晉室聞琴下寥廓。", "遼東盡爾千歲人，悵望橋邊舊城郭。"]'),
('6acceec3-68d6-4e33-8386-901930cb01fe','有酒十章 一','元稹','唐','唐诗','tang','','[]','有酒有酒雞初鳴，夜長睡足神慮清。',95,'全唐诗/poet.tang.21000.json','["有酒有酒雞初鳴，夜長睡足神慮清。", "悄然危坐心不平，浩思一氣初彭亨。", "澒洞浩汗真無名，胡不終渾成。", "胡爲沈濁以升清，矗然分畫高下程。", "天蒸地鬱羣動萌，毛鱗裸介如鬇鬡。", "嗚呼萬物紛已生，我可奈何兮杯一傾。"]'),
('3cae9a98-ea56-45b1-8853-db959cd6f414','有酒十章 二','元稹','唐','唐诗','tang','','[]','有酒有酒東方明，一杯既進吞元精。',96,'全唐诗/poet.tang.21000.json','["有酒有酒東方明，一杯既進吞元精。", "尚思天地之始名，一元既二分濁清。", "地居方直天體明，胡不八荒圢圢如砥平。", "胡山高屹崪海泓澄，胡不日車杲杲晝夜行。", "胡爲月輪滅缺星𥋝盯，嗚呼不得真宰情，我可奈何兮杯再傾。"]'),
('e230b2c3-83cd-43a1-ac7c-0c76fd7a60d5','有酒十章 三','元稹','唐','唐诗','tang','','[]','有酒有酒兮湛淥波，飲將愉兮氣彌和。',267,'全唐诗/poet.tang.21000.json','["有酒有酒兮湛淥波，飲將愉兮氣彌和。", "念萬古之紛羅，我獨慨然而浩歌。", "歌曰：天耶，地耶。", "肇萬物耶，儲胥大庭之君耶。", "恍耶，忽耶。", "有耶，傳而信耶。", "久而謬耶，文字生而羲農作耶。", "仁義別而聖賢出耶，炎始暴耶。", "蚩尤熾耶，軒轅戰耶。", "不得已耶，仁耶。", "聖耶，愍人之毒耶。", "天蕩蕩耶，堯穆穆耶。", "豈其讓耶，歸有德耶。", "舜其貪耶，德能嗣耶。", "豈其讓耶，授有功耶。", "禹功大耶，人戴之耶。", "益不逮耶，啓能德耶。", "家天下耶，榮後嗣耶。", "於後嗣之榮則可耶，於天下之榮其可耶。", "嗚呼遠堯舜之日耶，何棄舜之速耶。", "辛癸虐耶，湯武革耶。", "順天意耶，公天下耶。", "踵夏榮嗣，私其公耶。", "竝建萬國，均其私耶。"]'),
('164aa318-3aae-4fd5-a15c-f278cb50f744','有酒十章 四','元稹','唐','唐诗','tang','','[]','有酒有酒兮黯兮溟，仰天大呼兮。',209,'全唐诗/poet.tang.21000.json','["有酒有酒兮黯兮溟，仰天大呼兮。", "天漫漫兮高兮青，高兮漫兮吾孰知天否與靈。", "取人之仰者，無乃在乎昭昭乎曰與夫日星。", "何三光之竝照兮，奄雲雨之冥冥。", "幽妖倏忽兮水怪族形，黿鼉岸走兮海若鬬鯨。", "河潰潰兮愈濁，濟翻翻兮不寧。", "蛇噴雲而出穴，虎嘯風兮屢鳴。", "汙高巢而鳳去兮，溺厚地而芝蘭以之不生。", "葵心傾兮何向，松影直而孰明。", "人懼愁兮戴榮，天寂默兮無聲。", "嗚呼！天在雲之上兮，人在雲之下兮。", "又安能決雲而上征，嗚呼。", "既上征之不可兮，我奈何兮杯復傾。"]'),
('b80c69cc-cdcb-461a-a0e7-2f228baff17b','有酒十章 五','元稹','唐','唐诗','tang','','[]','有酒有酒香滿尊，君寧不飲開君顏。',154,'全唐诗/poet.tang.21000.json','["有酒有酒香滿尊，君寧不飲開君顏。", "豈不知君飲此心恨，君今獨醒誰與言。", "君寧不見颶風翻海火燎原，巨鼇唐突高燄延。", "精衛銜蘆塞海溢，枯魚噴沫救池燔。", "筋疲力竭波更大，鰭燋甲裂身已乾。", "有翼勸爾升九天，有鱗勸爾登龍門。", "九天下視日月轉，龍門上激雷雨奔。", "螗蜋雖怒誰爾懼，鶡旦雖啼誰爾憐。", "摶空意遠風來壯，我可奈何兮一杯又進消我煩。"]'),
('06276d06-ff4a-4f9b-b867-d83d17fbcb7e','有酒十章 六','元稹','唐','唐诗','tang','','[]','有酒有酒歌且哀，江春例早多早梅。',199,'全唐诗/poet.tang.21000.json','["有酒有酒歌且哀，江春例早多早梅。", "櫻桃桃李相續開，間以木蘭之秀香裴回。", "東風吹盡南風來，鶯聲漸澀花摧隤。", "四月清和豔殘卉，芍藥翻紅蒲映水。", "夏龍痡毒雷雨多，蒲葉離披豔紅死。", "紅豔猶存榴樹花，紫苞欲綻高筍牙。", "筍牙成竹冒霜雪，榴花落地還銷歇。", "萬古盈虧相逐行，君看夜夜當窗月。", "榮落虧盈可奈何，生成未徧霜霰過。", "霜霰過兮復奈何，靈芝敻絕荆棘多。", "荆棘多兮可奈何，可奈何兮終奈何。", "秦皇堯舜俱腐骨，我可奈何兮又進一杯歌復歌。"]'),
('2a61f06f-f695-484b-af4c-670de001ab5b','有酒十章 七','元稹','唐','唐诗','tang','','[]','有酒有酒方爛漫，飲酣拔劒心眼亂。',96,'全唐诗/poet.tang.21000.json','["有酒有酒方爛漫，飲酣拔劒心眼亂。", "聲若雷砰目流電，醉舞翻環身眩轉。", "乾綱倒軋坤維旋，白日橫空星宿見，一夫心醉萬物變。", "何況蚩尤之蹴蹋，安得不以熊羆戰。", "嗚呼！風后力牧得親見，我可奈何兮又進一杯除健羨。"]'),
('f7956f1c-64bd-4a54-b3b8-364eb1c4aae9','有酒十章 八','元稹','唐','唐诗','tang','','[]','有酒有酒兮告臨江，風漫漫兮波長。',158,'全唐诗/poet.tang.21000.json','["有酒有酒兮告臨江，風漫漫兮波長。", "渺渺兮注海，海蒼蒼兮路茫茫。", "彼萬流之混入兮，又安能分若畎澮淮河與夫岷吳之巨江。", "味作鹹而若一，雖甘淡兮誰謂爾爲良。", "濟涓涓而縷貫，將奈何兮萬里之渾黃。", "鯨歸穴兮渤溢，鼇載山兮低昂。", "陰火然兮衆族沸渭，颶風作兮晝夜猖狂。", "顧千珍與萬怪兮，皆委潤而深藏。", "信天地之瀦蓄兮，我可奈何兮一杯又進兮包大荒。"]'),
('ed87f022-102c-44ad-9e41-45b0d46aa7fc','有酒十章 九','元稹','唐','唐诗','tang','','[]','有酒有酒兮日將落，餘光委照在林薄。',69,'全唐诗/poet.tang.21000.json','["有酒有酒兮日將落，餘光委照在林薄。", "陽烏撩亂兮屋上栖，陰怪跳趫兮水中躍。", "月爭光兮星又繁，燒橫空兮燄仍爍。", "我可奈何兮時既昏，一杯又進兮聊處廓。"]'),
('ba6a6549-70ea-4296-ad36-63ce8a93b5d6','有酒十章 十','元稹','唐','唐诗','tang','','[]','有酒有酒兮再祝，祝予心兮何欲。',85,'全唐诗/poet.tang.21000.json','["有酒有酒兮再祝，祝予心兮何欲。", "欲天泰而地寧，欲人康而歲熟。", "欲鳳翥而鵷隨兮，欲龍亨而驥逐。", "欲日盛而星微兮，欲滋蘭而殲毒。", "欲人欲而天從，苟天未從兮，我可奈何兮一杯又進聊自足。"]'),
('16147bf3-1a81-4699-ad1b-fa25fd1bfcb2','華之巫','元稹','唐','唐诗','tang','','[]','有一人兮神之側，廟森森兮神默默。',233,'全唐诗/poet.tang.21000.json','["有一人兮神之側，廟森森兮神默默。", "神默默兮可奈何，願一見神兮何可得。", "女巫索我何所有，神之開閉予之手。", "我能進若神之前，神不自言寄予口。", "爾欲見神安爾身，買我神錢沽我酒。", "我家又有神之盤，爾進此盤神爾安。", "此盤不進行路難，陸有摧車舟有瀾。", "我聞此語長太息，豈有神明欺正直。", "爾居大道誰南北，恣矯神言假神力。", "假神力兮神未悟，行道之人不得度。", "我欲見神誅爾巫，豈是因巫假神祜。", "爾巫，爾巫。", "爾獨不聞乎？", "與其媚於奧，不若媚於竈。", "使我傾心事爾巫，吾寧驅車守吾道。", "爾巫爾巫且相保，吾心自有丘之禱。"]'),
('276771ed-6210-4d63-b145-80d27a03091c','廟之神','元稹','唐','唐诗','tang','','[]','我馬煩兮釋我車，神之廟兮山之阿。',139,'全唐诗/poet.tang.21000.json','["我馬煩兮釋我車，神之廟兮山之阿。", "予一拜而一祝，祝予心之無涯。", "涕汍瀾而零落，神寂默而無譁。", "神兮，神兮。", "奈神之寂默而不言何，復再拜而再祝。", "鼓吾腹兮歌吾歌，歌曰。", "今耶，古耶。", "有耶，無耶。", "福不自神耶，神不福人耶。", "巫爾惑耶，稔而誅耶。", "謁不得耶，終不可謁耶。", "返吾駕而遵吾道，廟之木兮山之花。"]'),
('4c92f93b-48e5-40bf-b4c9-78c84d0e987c','村花晚','元稹','唐','唐诗','tang','','[]','三春已暮桃李傷，棠梨花白蔓菁黃。',82,'全唐诗/poet.tang.21000.json','["三春已暮桃李傷，棠梨花白蔓菁黃。", "村中女兒爭摘將，插刺頭鬢相誇張。", "田翁蠶老迷臭香，曬暴𢽱𣀳熏衣裳。", "非無後秀與孤芳，奈爾千株萬頃之茫茫。", "天公此意何可量，長教爾輩時節長。"]'),
('a77e8de6-b1d1-478a-b0d1-f610c95b1f5e','紫躑躅','元稹','唐','唐诗','tang','','[]','紫躑躅，滅紫攏帬倚山腹。',136,'全唐诗/poet.tang.21000.json','["紫躑躅，滅紫攏帬倚山腹。", "文君新寡乍歸來，羞怨春風不能哭。", "我從相識便相憐，但是花叢不迴目。", "去年春別湘水頭，今年夏見青山曲。", "迢迢遠在青山上，山高水闊難容足。", "願爲朝日早相暾，願作輕風暗相觸。", "爾躑躅，我向通州爾幽獨。", "可憐今夜宿青山，何年卻向青山宿。", "山花漸暗月漸明，月照空山滿山綠。"]'),
('faffa10f-f063-4447-a22a-569815771787','山枇杷','元稹','唐','唐诗','tang','','[]','山枇杷，花似牡丹殷潑血。',248,'全唐诗/poet.tang.21000.json','["山枇杷，花似牡丹殷潑血。", "往年乘傳過青山，正值山花好時節。", "壓枝凝豔已全開，映葉香苞纔半裂。", "緊搏紅袖欲支頤，慢解絳囊初破結。", "金線叢飄繁蘂亂，珊瑚朵重纖莖折。", "因風旋落帬片飛，帶日斜看目精熱。", "亞水依巖半傾側，籠雲隱霧多愁絕。", "綠珠語盡身欲投，漢武眼穿神漸滅。", "穠姿秀色人皆愛，怨媚羞容我偏別。", "說向閑人人不聽，曾向樂天時一說。", "昨來谷口先相問，及到山前已消歇。", "左降通州十日遲，又與幽花一年別。", "山枇杷，爾託深山何太拙。", "天高萬里看不精，帝在九重聲不徹。", "園中杏樹良人醉，陌上柳枝年少折。", "因爾幽芳喻昔賢，磻谿冷坐權門咽。"]'),
('0bad57ac-1f5f-41b9-af2e-ae1bb1a35834','樹上烏','元稹','唐','唐诗','tang','','[]','樹上烏，洲中有樹巢若鋪。',103,'全唐诗/poet.tang.21000.json','["樹上烏，洲中有樹巢若鋪。", "百巢一樹知幾烏，一烏不下三四雛。", "雛又生雛知幾雛，老烏未死雛已烏。", "散向人間何處無，攫麑啄卵方可食。", "男女羣強最多力，靈蛇萬古唯一珠。", "豈可抨彈千萬億，吾不會天教爾輩多子孫，告訴天公天不言。"]'),
('fa144363-256e-4951-b960-ba406800555e','琵琶歌','元稹','唐','唐诗','tang','','[]','琵琶宮調八十一，旋宮三調彈不出。',384,'全唐诗/poet.tang.21000.json','["琵琶宮調八十一，旋宮三調彈不出。", "玄宗偏許賀懷智，段師此藝還相匹。", "自後流傳指撥衰，崑崙善才徒爾爲。", "澒聲少得似雷吼，纏弦不敢彈羊皮。", "人間奇事會相續，但有卞和無有玉。", "段師弟子數十人，李家管兒稱上足。", "管兒不作供奉兒，拋在東都雙鬢絲。", "逢人便請送杯盞，著盡工夫人不知。", "李家兄弟皆愛酒，我是酒徒爲密友。", "著作曾邀連夜宿，中碾春溪華新綠。", "平明船載管兒行，盡日聽彈無限曲。", "曲名無限知者鮮，霓裳羽衣偏宛轉。", "涼州大徧最豪嘈，六么散序多籠撚。", "我聞此曲深賞奇，賞著奇處驚管兒。", "管兒爲我雙淚垂，自彈此曲長自悲。", "淚垂捍撥朱弦濕，冰泉嗚咽流鶯澀。", "因茲彈作雨霖鈴，風雨蕭條鬼神泣。", "一彈既罷又一彈，珠幢夜靜風珊珊。", "低回慢弄關山思，坐對燕然秋月寒。", "月寒一聲深殿磬，驟彈曲破音繁併。", "百萬金鈴旋玉盤，醉客滿船皆暫醒。", "自茲聽後六七年，管兒在洛我朝天。", "游想慈恩杏園裏，夢寐仁風花樹前。", "去年御史留東臺，公私蹙促顏不開。"]'),
('d104a8e7-e89c-40c2-98e2-7b708f5b7186','小胡笳引','元稹','唐','唐诗','tang','','[]','雷氏金徽琴，王君寶重輕千金。',190,'全唐诗/poet.tang.21000.json','["雷氏金徽琴，王君寶重輕千金。", "三峽流中將得來，明窗拂席幽匣開。", "朱弦宛轉盤鳳足，驟擊數聲風雨迴。", "哀笳慢指董家本，姜生得之妙思忖。", "泛徽胡雁咽蕭蕭，繞指轆轤圓衮衮。", "吞恨緘情乍輕激，故國關山心歷歷。", "潺湲疑是雁鸊鵜，砉騞如聞發鳴鏑。", "流宮變徵漸幽咽，別鶴欲飛猿欲絕。", "秋霜滿樹葉辭風，寒雛墜地烏啼血。", "哀弦已罷春恨長，恨長何恨懷我鄉。", "我鄉安在長城窟，聞君虜奏心飄忽。", "何時窄袖短貂裘，臙脂山下彎明月。"]'),
('7bc83be6-9f75-4612-af7d-f4fa66548049','去杭州','元稹','唐','唐诗','tang','','[]','房杜王魏之子孫，雖及百代爲清門。',384,'全唐诗/poet.tang.21000.json','["房杜王魏之子孫，雖及百代爲清門。", "駿骨鳳毛真可貴，岡頭澤底何足論。", "去年江上識君面，愛君風貌情已敦。", "與君言語見君性，靈府坦蕩消塵煩。", "自茲心洽跡亦洽，居常並榻游竝軒。", "柳陰覆岸鄭監水，李花壓樹韋公園。", "每出新詩共聯綴，閑因醉舞相牽援。", "時尋沙尾楓林夕，夜摘蘭叢衣露繁。", "今君別我欲何去，自言遠結迢迢婚。", "簡書五府已再至，波濤萬里酬一言。", "爲君再拜贈君語，願君靜聽君勿喧。", "君名師範欲何範，君之烈祖遺範存。", "永寧昔在掄鑒表，沙汰沈濁澄浚源。", "君今取友由取士，得不別白清與渾。", "昔公事主盡忠讜，雖及死諫誓不諼。", "今君佐藩如佐主，得不陳露詶所恩。", "昔公爲善日不足，假寐待旦朝至尊。", "今君三十朝未與，得不寸晷倍璵璠。", "昔公令子尚貴主，公執舅禮婦執笲。", "返拜之儀自此絕，關雎之化皎不昏。", "君今遠娉奉明祀，得不齊勵親蘋蘩。", "斯言皆爲書佩帶，然後別袂乃可捫。", "別袂可捫不可解，解袂開帆悽別魂。", "魂搖江樹鳥飛沒，帆挂檣竿鳥尾翻。"]'),
('efb8e0c4-59ad-4806-9df7-31ce2b642c11','南家桃','元稹','唐','唐诗','tang','','[]','南家桃樹深紅色，日照露光看不得。',64,'全唐诗/poet.tang.21000.json','["南家桃樹深紅色，日照露光看不得。", "樹小花狂風易吹，一夜風吹滿牆北。", "離人自有經時別，眼前落花心歎息。", "更待明年花滿枝，一年迢遞空相憶。"]'),
('ed42547e-1f69-409f-b280-00bfcb7a4cc5','志堅師','元稹','唐','唐诗','tang','','[]','嵩山老僧披破衲，七十八年三十臘。',64,'全唐诗/poet.tang.21000.json','["嵩山老僧披破衲，七十八年三十臘。", "靈武朝天遼海征，宇宙曾行三四匝。", "初因怏怏薙却頭，便繞嵩山寂師墖。", "淮西未返半年前，已見淮西陣雲合。"]'),
('097b5cbc-da79-44a4-ae48-1995d118b647','答子蒙','元稹','唐','唐诗','tang','','[]','報盧君，門外雪紛紛。',38,'全唐诗/poet.tang.21000.json','["報盧君，門外雪紛紛。", "紛紛門外雪，城中鼓聲絕。", "強梁御史人覰步，安得夜開沽酒戶。"]'),
('ff94bdfc-9a2b-4d39-aad2-a0639e3d9e73','辛夷花','元稹','唐','唐诗','tang','','[]','問君辛夷花，君言已斑駮。',92,'全唐诗/poet.tang.21000.json','["問君辛夷花，君言已斑駮。", "不畏辛夷不爛開，顧我筋骸官束縛。", "縛遣推囚名御史，狼藉囚徒滿田地。", "明日不推緣國忌，依前不得花前醉。", "韓員外家好辛夷，開時乞取三兩枝。", "折枝爲贈君莫惜，縱君不折風亦吹。"]'),
('c026ee76-45ed-450d-96d7-9a4434d909ed','廳前柏','元稹','唐','唐诗','tang','','[]','廳前柏，知君曾對羅希奭。',56,'全唐诗/poet.tang.21000.json','["廳前柏，知君曾對羅希奭。", "我本癲狂耽酒人，何事與君爲對敵。", "爲對敵，洛陽城中花赤白。", "花赤白，囚漸多，花之赤白奈爾何。"]'),
('b91a878f-7e6b-415a-ac3d-80abbb0040ac','夜別筵','元稹','唐','唐诗','tang','','[]','夜長酒闌燈花長，燈花落地復落牀。',48,'全唐诗/poet.tang.21000.json','["夜長酒闌燈花長，燈花落地復落牀。", "似我別淚三四行，滴君滿坐之衣裳。", "與君別後淚痕在，年年著衣心莫改。"]'),
('dfe5427c-1d71-4e93-8166-2119a9280caa','三泉驛','元稹','唐','唐诗','tang','','[]','三泉驛內逢上巳，新葉趨塵花落地。',48,'全唐诗/poet.tang.21000.json','["三泉驛內逢上巳，新葉趨塵花落地。", "勸君滿盞君莫辭，別後無人共君醉。", "洛陽城中無限人，貴人自貴貧自貧。"]'),
('94c0d9f6-88c4-48ed-b3ea-8d9ebc5262e6','何滿子歌','元稹','唐','唐诗','tang','','[]','何滿能歌能宛轉，天寶年中世稱罕。',320,'全唐诗/poet.tang.21000.json','["何滿能歌能宛轉，天寶年中世稱罕。", "嬰刑擊在囹圄間，水調哀音歌憤懣。", "梨園弟子奏玄宗，一唱承恩羈網緩。", "便將何滿爲曲名，御譜親題樂府纂。", "魚家入內本領絕，葉氏有年聲氣短。", "自外徒煩記得詞，點拍纔成已夸誕。", "我來湖外拜君侯，正值灰飛仲春琯。", "廣宴江亭爲我開，紅妝逼坐花枝暖。", "此時有態蹋華筵，未吐芳詞貌夷坦。", "翠蛾轉盼搖雀釵，碧袖歌垂翻鶴卵。", "定面凝眸一聲發，雲停塵下何勞算。", "迢迢擊磬遠玲玲，一一貫珠勻款款。", "犯羽含商移調態，留情度意拋弦管。", "湘妃寶瑟水上來，秦女玉簫空外滿。", "纏緜疊破最慇懃，整頓衣裳頗閒散。", "冰含遠溜咽還通，鶯泥晚花啼漸嬾。", "斂黛吞聲若自冤，鄭袖見捐西子浣。", "陰山鳴雁曉斷行，巫峽哀猿夜呼伴。", "古者諸侯饗外賓，鹿鳴三奏陳圭瓚。", "何如有態一曲終，牙籌記令紅螺盌。"]'),
('5f53f3fb-6dd3-4d61-ba88-a085232c5c58','通州丁溪館夜別李景信三首 一','元稹','唐','唐诗','tang','','[]','月濛濛兮山掩掩，束束別魂眉歛歛。',48,'全唐诗/poet.tang.21000.json','["月濛濛兮山掩掩，束束別魂眉歛歛。", "蠡琖覆時天欲明，碧幌青燈風灩灩。", "淚消語盡還暫眠，唯夢千山萬山險。"]'),
('181fb69e-a875-4573-9bc9-efb8d2212068','通州丁溪館夜別李景信三首 二','元稹','唐','唐诗','tang','','[]','水環環兮山簇簇，啼鳥聲聲婦人哭。',48,'全唐诗/poet.tang.21000.json','["水環環兮山簇簇，啼鳥聲聲婦人哭。", "離牀別臉睡還開，燈灺暗飄珠蔌蔌。", "山深虎橫館無門，夜集巴兒扣空木。"]'),
('adc63c29-7a3f-4262-b7c5-4494f4104602','通州丁溪館夜別李景信三首 三','元稹','唐','唐诗','tang','','[]','雨瀟瀟兮鵑咽咽，傾冠倒枕燈臨滅。',48,'全唐诗/poet.tang.21000.json','["雨瀟瀟兮鵑咽咽，傾冠倒枕燈臨滅。", "倦僮呼喚譍復眠，啼雞拍翅三聲絕。", "握手相看其奈何，奈何其奈天明別。"]'),
('82c9f4d8-8aa0-483d-ab65-94ed3b4197fb','酬鄭從事四年九月宴望海亭次用舊韻','元稹','唐','唐诗','tang','','[]','海亭樹木何蘢蔥，寒光透坼秋玲瓏。',272,'全唐诗/poet.tang.21000.json','["海亭樹木何蘢蔥，寒光透坼秋玲瓏。", "湖山四面爭氣色，曠望不與人間同。", "一拳墺伏東武小，兩山鬬構秦望雄。", "嵌空古墓失文種，突兀怪石疑防風。", "舟船駢比有宗侶，水雲滃泱無始終。", "雪花布徧稻隴白，日脚插入秋波紅。", "興餘望劇酒四坐，歌聲舞豔煙霞中。", "酒酣從事歌送我，歌云此樂難再逢。", "良時年少猶健羨，使君況是頭白翁。", "我聞此曲深歎息，唧唧不異秋草蟲。", "憶年十五學構廈，有意蓋覆天下窮。", "安知四十虛富貴，朱紫束縛心志空。", "妝梳伎女上樓榭，止欲歡樂微茫躬。", "雖無趣尚慕賢聖，幸有心目知西東。", "欲將滑甘柔藏府，已被鬱噎衝喉嚨。", "君今勸我酒太醉，醉語不復能沖融。", "勸君莫學虛富貴，不是賢人難變通。"]'),
('49449ba6-fe7f-4b59-9d78-586fe5aa13ab','夢遊春七十韻','元稹','唐','唐诗','tang','','[]','昔歲夢遊春，夢遊何所遇。',288,'全唐诗/poet.tang.21000.json','["昔歲夢遊春，夢遊何所遇。", "夢入深洞中，果遂平生趣。", "清泠淺漫流，畫舫蘭篙渡。", "過盡萬株桃，盤旋竹林路。", "長廊抱小樓，門牖相回互。", "樓下雜花叢，叢邊繞鴛鷺。", "池光漾霞影，曉日初明煦。", "未敢上階行，頻移曲池步。", "烏龍不作聲，碧玉曾相慕。", "漸到簾幕間，裴回意猶懼。", "閑窺東西閤，奇玩參差布。", "隔子碧油糊，駝鉤紫金鍍。", "逡巡日漸高，影響人將寤。", "鸚鵡饑亂鳴，嬌娃睡猶怒。", "簾開侍兒起，見我遙相諭。", "鋪設繡紅茵，施張鈿妝具。", "潛褰翡翠帷，瞥見珊瑚樹。", "不辨花貌人，空驚香若霧。", "身回夜合偏，態斂晨霞聚。", "睡臉桃破風，汗妝蓮委露。", "叢梳百葉髻，金蹙重臺屨。", "紕輭鈿頭帬，玲瓏合歡袴。", "鮮妍脂粉薄，闇澹衣裳故。", "最似紅牡丹，雨來春欲暮。"]'),
('a6d2314a-5458-462b-9010-d551f91b7e68','桐花落','元稹','唐','唐诗','tang','','[]','莎草徧桐陰，桐花滿莎落。',144,'全唐诗/poet.tang.21000.json','["莎草徧桐陰，桐花滿莎落。", "蓋覆相團圓，可憐無厚薄。", "昔歲幽院中，深堂下簾幕。", "同在後門前，因論花好惡。", "君誇沈檀樣，云是指撝作。", "暗澹滅紫花，句連蹙金萼。", "都繡六七枝，鬬成雙孔雀。", "尾上稠疊花，又將金解絡。", "我愛看不已，君煩睡先著。", "我作繡桐詩，繫君帬帶著。", "別來苦修道，此意都蕭索。", "今日竟相牽，思量偶然錯。"]'),
('57417914-bb35-4c53-a597-ab9cdde6bfa1','夢昔時','元稹','唐','唐诗','tang','','[]','閒窗結幽夢，此夢誰人知。',48,'全唐诗/poet.tang.21000.json','["閒窗結幽夢，此夢誰人知。", "夜半初得處，天明臨去時。", "山川已久隔，雲雨兩無期。", "何事來相感，又成新別離。"]'),
('8032953f-2666-462f-a170-59051b654a4d','恨妝成','元稹','唐','唐诗','tang','','[]','曉日穿隙明，開帷理妝點。',72,'全唐诗/poet.tang.21000.json','["曉日穿隙明，開帷理妝點。", "傅粉貴重重，施朱憐冉冉。", "柔鬟背額垂，叢鬢隨釵斂。", "凝翠暈蛾眉，輕紅拂花臉。", "滿頭行小梳，當面施圓靨。", "最恨落花時，妝成獨披掩。"]'),
('c7fa54f9-3cfe-4358-b253-74ae88687171','古決絶詞 一','元稹','唐','唐诗','tang','','[]','乍可爲天上牽牛織女星，不願爲庭前紅槿枝。',128,'全唐诗/poet.tang.21000.json','["乍可爲天上牽牛織女星，不願爲庭前紅槿枝。", "七月七日一相見，相見故心終不移。", "那能朝開暮飛去，一任東西南北吹。", "分不兩相守，恨不兩相思。", "對面且如此，背面當可知。", "春風撩亂伯勞語，況是此時拋去時。", "握手苦相問，竟不言後期。", "君情既決絕，妾意已參差。", "借如死生別，安得長苦悲。"]'),
('9bb19a4c-df65-4ba6-8263-af14c3b30cab','古決絶詞 二','元稹','唐','唐诗','tang','','[]','噫春冰之將泮，何予懷之獨結。',156,'全唐诗/poet.tang.21000.json','["噫春冰之將泮，何予懷之獨結。", "有美一人，於焉曠絕。", "一日不見，比一日於三年。", "況三年之曠別，水得風兮小而已波。", "筍在苞兮高不見節，矧桃李之當春。", "競衆人而攀折，我自顧悠悠而若雲。", "又安能保君皚皚之如雪，感破鏡之分明，覩淚痕之餘血。", "幸他人之既不我先，又安能使他人之終不我奪？", "已焉哉！織女別黃姑，一年一度暫相見，彼此隔河何事無。"]'),
('76dca650-59bc-4a93-a326-26dca72e3037','古決絶詞 三','元稹','唐','唐诗','tang','','[]','夜夜相抱眠，幽懷尚沈結。',100,'全唐诗/poet.tang.21000.json','["夜夜相抱眠，幽懷尚沈結。", "那堪一年事，長遣一宵說。", "但感久相思，何暇暫相悅。", "虹橋薄夜成，龍駕侵晨列。", "生憎野鶴性遲迴，死恨天雞識時節。", "曙色漸曈曈，華星欲明滅。", "一去又一年，一年何可徹。", "有此迢遞期，不如死生別。"]'),
('d720e147-9ffc-44e0-a11a-49198cbce2b7','櫻桃花','元稹','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u82b1", "\u548f\u7269", "\u5199\u82b1"]','櫻桃花，一枝兩枝千萬朵。',28,'全唐诗/poet.tang.21000.json','["櫻桃花，一枝兩枝千萬朵。", "花塼曾立摘花人，窣破羅帬紅似火。"]'),
('f9a6adf8-3d32-480c-ba91-aea612bab31e','曹十九舞綠鈿','元稹','唐','唐诗','tang','','[]','急管清弄頻，舞衣纔攬結。',48,'全唐诗/poet.tang.21000.json','["急管清弄頻，舞衣纔攬結。", "含情獨搖手，雙袖參差列。", "騕褭柳牽絲，炫轉風回雪。", "凝眄嬌不移，往往度繁節。"]'),
('52212981-df92-48e1-9a72-1b17d6c7714e','閨晚','元稹','唐','唐诗','tang','','[]','紅帬委塼堦，玉爪剺朱橘。',48,'全唐诗/poet.tang.21000.json','["紅帬委塼堦，玉爪剺朱橘。", "素臆光如砑，明瞳豔凝溢。", "調弦不成曲，學書徒弄筆。", "夜色侵洞房，春煙透簾出。"]'),
('61da7798-6b7f-404b-acad-82e4fa4d6680','曉將別','元稹','唐','唐诗','tang','','[]','風露曉淒淒，月下西牆西。',48,'全唐诗/poet.tang.21000.json','["風露曉淒淒，月下西牆西。", "行人帳中起，思婦枕前啼。", "屑屑命僮御，晨裝儼已齊。", "將去復攜手，日高方解攜。"]'),
('b9efdaf5-c077-45ee-8d8b-d123a4e4686e','薔薇架','元稹','唐','唐诗','tang','','[]','五色階前架，一張籠上被。',48,'全唐诗/poet.tang.21000.json','["五色階前架，一張籠上被。", "殷紅稠疊花，半綠鮮明地。", "風蔓羅帬帶，露英蓮臉淚。", "多逢走馬郎，可惜簾邊思。"]'),
('c9350186-8d14-40b7-b1b3-cd887acf5209','月暗','元稹','唐','唐诗','tang','','[]','月暗燈殘面牆泣，羅纓斗重知啼濕。',64,'全唐诗/poet.tang.21000.json','["月暗燈殘面牆泣，羅纓斗重知啼濕。", "真珠簾斷蝙蝠飛，燕子巢空螢火入。", "深殿門重夜漏嚴，柔□□□□年急。", "君王掌上容一人，更有輕身何處立。"]'),
('de9d45bd-3b00-4a08-bd62-f156e006b1e0','新秋','元稹','唐','唐诗','tang','','[]','旦暮已淒涼，離人遠思忙。',48,'全唐诗/poet.tang.21000.json','["旦暮已淒涼，離人遠思忙。", "夏衣臨曉薄，秋影入檐長。", "前事風隨扇，歸心燕在梁。", "殷勤寄牛女，河漢正相望。"]'),
('1c0a2555-7e81-4da1-bc82-ab3cbaf88248','贈雙文','元稹','唐','唐诗','tang','','[]','豔極翻含怨，憐多轉自嬌。',48,'全唐诗/poet.tang.21000.json','["豔極翻含怨，憐多轉自嬌。", "有時還暫笑，閑坐愛無憀。", "曉月行看墮，春酥見欲消。", "何因肯垂手，不敢望回腰。"]'),
('25fba788-7700-48d4-815c-9a164c06fd8d','春別','元稹','唐','唐诗','tang','','[]','幽芳本未闌，君去蕙花殘。',48,'全唐诗/poet.tang.21000.json','["幽芳本未闌，君去蕙花殘。", "河漢秋期遠，關山世路難。", "雲屏留粉絮，風幌引香蘭。", "腸斷迴文錦，春深獨自看。"]'),
('b9db9fb0-eea2-4266-8edf-d0f099b12989','和樂天示楊瓊','元稹','唐','唐诗','tang','','[]','我在江陵少年日，知有楊瓊初喚出。',160,'全唐诗/poet.tang.21000.json','["我在江陵少年日，知有楊瓊初喚出。", "腰身瘦小歌圓緊，依約年應十六七。", "去年十月過蘇州，瓊來拜問郎不識。", "青衫玉貌何處去，安得紅旗遮頭白。", "我語楊瓊瓊莫語，汝雖笑我我笑汝。", "汝今無復小腰身，不似江陵時好女。", "楊瓊爲我歌送酒，爾憶江陵縣中否。", "江陵王令骨爲灰，車來嫁作尚書婦。", "盧戡及第嚴澗在，其餘死者十八九。", "我今賀爾亦自多，爾得老成余白首。"]'),
('03c8d269-c926-4e73-9957-40d2fc0cc512','魚中素','元稹','唐','唐诗','tang','','[]','重疊魚中素，幽緘手自開。',24,'全唐诗/poet.tang.21000.json','["重疊魚中素，幽緘手自開。", "斜紅餘淚蹟，知著臉邊來。"]'),
('d9b26a58-c9cb-4a98-8980-32df48b58348','代九九','元稹','唐','唐诗','tang','','[]','昔年桃李月，顏色共花宜。',240,'全唐诗/poet.tang.21000.json','["昔年桃李月，顏色共花宜。", "廻臉蓮初破，低蛾柳竝垂。", "望山多倚樹，弄水愛臨池。", "遠被登樓識，潛因倒影窺。", "隔林徒想像，上砌轉逶迤。", "謾擲庭中果，虛攀牆外枝。", "強持文玉佩，求結麝香縭。", "阿母憐金重，親兄要馬騎。", "把將嬌小女，嫁與冶遊兒。", "自隱勤勤索，相要事事隨。", "每常同坐臥，不省暫參差。", "纔學羞兼妒，何言寵便移。", "青春來易皎，白日誓先虧。", "僻性嗔來見，邪行醉後知。", "別牀鋪枕席，當面指瑕疵。", "妾貌應猶在，君情遽若斯。", "的成終世恨，焉用此宵爲。", "鸞鏡燈前撲，鴛衾手下隳。", "參商半夜起，琴瑟一聲離。", "努力新叢豔，狂風次第吹。"]'),
('a2af1c24-204c-47bf-801d-e9b9ba68857c','盧十九子蒙吟盧七員外洛川懷古六韻命余和','元稹','唐','唐诗','tang','','[]','聞道盧明府，閑行詠洛神。',72,'全唐诗/poet.tang.21000.json','["聞道盧明府，閑行詠洛神。", "浪圓疑靨笑，波鬬憶眉嚬。", "蹀躞橋頭馬，空濛水上塵。", "草芽猶犯雪，冰岸欲消春。", "寓目終無限，通辭未有因。", "子蒙將此曲，吟似獨眠人。"]'),
('5c26e26e-a157-4137-9bc5-24b8ec2f57cd','劉阮妻二首 一','元稹','唐','唐诗','tang','','[]','仙洞千年一度開，等閑偷入又偷廻。',32,'全唐诗/poet.tang.21000.json','["仙洞千年一度開，等閑偷入又偷廻。", "桃花飛盡東風起，何處消沈去不來。"]'),
('f26b620f-ed26-4d21-9a14-ad7b34e9e55a','劉阮妻二首 二','元稹','唐','唐诗','tang','','[]','芙蓉脂肉綠雲鬟，罨畫樓臺青黛山。',32,'全唐诗/poet.tang.21000.json','["芙蓉脂肉綠雲鬟，罨畫樓臺青黛山。", "千樹桃花萬年藥，不知何事憶人間。"]'),
('496955eb-549a-4176-84d3-ab6460eaa70f','桃花','元稹','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u6000", "\u82b1", "\u5199\u82b1", "\u6843\u82b1"]','桃花淺深處，似勻深淺妝。',24,'全唐诗/poet.tang.21000.json','["桃花淺深處，似勻深淺妝。", "春風助腸斷，吹落白衣裳。"]'),
('1ba56a50-65aa-40e2-9aa7-92968d1d44d4','暮秋','元稹','唐','唐诗','tang','','[]','看著牆西日又沈，步廊廻合戟門深。',32,'全唐诗/poet.tang.21000.json','["看著牆西日又沈，步廊廻合戟門深。", "栖烏滿樹聲聲絕，小玉上牀鋪夜衾。"]'),
('9ed1832b-2c8b-4a26-a5e3-75ffe21934d9','壓牆花','元稹','唐','唐诗','tang','','[]','野性大都迷里巷，愛將高樹記人家。',32,'全唐诗/poet.tang.21000.json','["野性大都迷里巷，愛將高樹記人家。", "春來偏認平陽宅，爲見牆頭拂面花。"]'),
('87f6a3f4-2794-4bbf-a3f9-ca1cf1c55ea6','舞腰','元稹','唐','唐诗','tang','','[]','帬裾旋旋手迢迢，不趁音聲自趁嬌。',32,'全唐诗/poet.tang.21000.json','["帬裾旋旋手迢迢，不趁音聲自趁嬌。", "未必諸郎知曲誤，一時偷眼爲廻腰。"]'),
('f0ef9ca9-c45c-48c9-892f-9c010ef044c8','白衣裳二首 一','元稹','唐','唐诗','tang','','[]','雨濕輕塵隔院香，玉人初著白衣裳。',32,'全唐诗/poet.tang.21000.json','["雨濕輕塵隔院香，玉人初著白衣裳。", "半含惆悵閑看繡，一朵棃花壓象牀。"]'),
('c3a44a44-f364-4b68-b465-7f4686aa418f','白衣裳二首 二','元稹','唐','唐诗','tang','','[]','藕絲衫子柳花帬，空著沈香慢火熏。',32,'全唐诗/poet.tang.21000.json','["藕絲衫子柳花帬，空著沈香慢火熏。", "閑倚屏風笑周昉，枉拋心力畫朝雲。"]'),
('5bb71085-da80-4dc8-86c0-9afc6cc551fe','憶事','元稹','唐','唐诗','tang','','[]','夜深閑到戟門邊，却繞行廊又獨眠。',32,'全唐诗/poet.tang.21000.json','["夜深閑到戟門邊，却繞行廊又獨眠。", "明月滿庭池水淥，桐花垂在翠簾前。"]'),
('41743123-f8db-4bc6-936f-76e33c0d235a','寄舊詩與薛濤因成長句','元稹','唐','唐诗','tang','','[]','詩篇調態人皆有，細膩風光我獨知。',64,'全唐诗/poet.tang.21000.json','["詩篇調態人皆有，細膩風光我獨知。", "月夜詠花憐暗澹，雨朝題柳爲敧垂。", "長教碧玉藏深處，總向紅牋寫自隨。", "老大不能收拾得，與君閑似好男兒。"]'),
('aed8b3b5-a77f-494e-8e76-e1d555680de1','友封體','元稹','唐','唐诗','tang','','[]','雨送浮涼夏簟清，小樓腰褥怕單輕。',64,'全唐诗/poet.tang.21000.json','["雨送浮涼夏簟清，小樓腰褥怕單輕。", "微風暗度香囊轉，朧月斜穿隔子明。", "樺燭燄高黃耳吠，柳堤風靜紫騮聲。", "頻頻聞動中門鎖，桃葉知嗔未敢迎。"]'),
('3edd1e3b-097c-4583-8508-7ad621c58327','看花','元稹','唐','唐诗','tang','','[]','努力少年求好官，好花須是少年看。',32,'全唐诗/poet.tang.21000.json','["努力少年求好官，好花須是少年看。", "君看老大逢花樹，未折一枝心已闌。"]'),
('8a413ed7-6711-44b2-ad6a-b47450108b1d','斑竹','元稹','唐','唐诗','tang','','[]','一枝斑竹渡湘沅，萬里行人感別魂。',32,'全唐诗/poet.tang.21000.json','["一枝斑竹渡湘沅，萬里行人感別魂。", "知是娥皇廟前物，遠隨風雨送啼痕。"]'),
('d98eb31f-b3ee-4260-92f9-8cb8ea41ea6b','箏','元稹','唐','唐诗','tang','','[]','莫愁私地愛王昌，夜夜箏聲怨隔牆。',64,'全唐诗/poet.tang.21000.json','["莫愁私地愛王昌，夜夜箏聲怨隔牆。", "火鳳有凰求不得，春鶯無伴囀空長。", "急揮舞破催飛燕，慢逐歌詞弄小娘。", "死恨相如新索婦，枉將心力爲他狂。"]'),
('4c27e1d9-2475-4e73-b738-7a55dfb45fc9','春曉','元稹','唐','唐诗','tang','','[]','半欲天明半未明，醉聞花氣睡聞鶯。',32,'全唐诗/poet.tang.21000.json','["半欲天明半未明，醉聞花氣睡聞鶯。", "𤞇兒撼起鐘聲動，二十年前曉寺情。"]'),
('b097335d-ca08-4438-9510-e6096fc017b8','所思二首 一','元稹','唐','唐诗','tang','','[]','庾亮樓中初見時，武昌春柳似腰肢。',32,'全唐诗/poet.tang.21000.json','["庾亮樓中初見時，武昌春柳似腰肢。", "相逢相失還如夢，爲雨爲雲今不知。"]'),
('38efdf17-955d-49a2-b653-943a241b1a51','所思二首 二','元稹','唐','唐诗','tang','','[]','鄂渚濛濛煙雨微，女郎魂逐暮雲歸。',32,'全唐诗/poet.tang.21000.json','["鄂渚濛濛煙雨微，女郎魂逐暮雲歸。", "只應長在漢陽渡，化作鴛鴦一隻飛。"]'),
('c9ef6401-b33c-4077-89bc-f01fc3279dce','鶯鶯詩','元稹','唐','唐诗','tang','','[]','殷紅淺碧舊衣裳，取次梳頭闇澹妝。',64,'全唐诗/poet.tang.21000.json','["殷紅淺碧舊衣裳，取次梳頭闇澹妝。", "夜合帶煙籠曉日，牡丹經雨泣殘陽。", "低迷隱笑原非笑，散漫清香不似香。", "頻動橫波嗔阿母，等閑教見小兒郎。"]'),
('93b76dba-03fa-4474-ab05-fde7a29b212b','離思五首 一','元稹','唐','唐诗','tang','','[]','自愛殘妝曉鏡中，環釵謾篸綠絲叢。',32,'全唐诗/poet.tang.21000.json','["自愛殘妝曉鏡中，環釵謾篸綠絲叢。", "須臾日射燕脂頰，一朵紅蘇旋欲融。"]'),
('77854aa8-a4df-45d4-8954-3bdfabae4e7a','離思五首 二','元稹','唐','唐诗','tang','','[]','山泉散漫繞階流，萬樹桃花暎小樓。',32,'全唐诗/poet.tang.21000.json','["山泉散漫繞階流，萬樹桃花暎小樓。", "閑讀道書慵未起，水晶簾下看梳頭。"]'),
('cefcc178-b5f8-4e84-acb2-7426d40d7a60','離思五首 三','元稹','唐','唐诗','tang','','[]','紅羅著壓逐時新，吉了花紗嫩麴塵。',32,'全唐诗/poet.tang.21000.json','["紅羅著壓逐時新，吉了花紗嫩麴塵。", "第一莫嫌材地弱，些些紕縵最宜人。"]'),
('de747326-60b6-4d83-9a80-ea9dc9faec13','離思五首 四','元稹','唐','唐诗','tang','','["\u54f2\u7406", "\u7231\u60c5", "\u60bc\u4ea1"]','曾經滄海難爲水，除却巫山不是雲。',32,'全唐诗/poet.tang.21000.json','["曾經滄海難爲水，除却巫山不是雲。", "取次花叢嬾迴顧，半緣修道半緣君。"]'),
('ff039b04-41f7-4bee-9ab1-5706ad5098f4','離思五首 五','元稹','唐','唐诗','tang','','[]','尋常百種花齊發，偏摘棃花與白人。',32,'全唐诗/poet.tang.21000.json','["尋常百種花齊發，偏摘棃花與白人。", "今日江頭兩三樹，可憐和葉度殘春。"]'),
('d3395d4d-0a3a-4f21-8bbe-df008a886d51','雜憶五首 一','元稹','唐','唐诗','tang','','[]','今年寒食月無光，夜色纔侵已上牀。',32,'全唐诗/poet.tang.21000.json','["今年寒食月無光，夜色纔侵已上牀。", "憶得雙文通內裏，玉櫳深處暗聞香。"]'),
('d0c42d02-eead-460c-93d1-11a04736d246','雜憶五首 二','元稹','唐','唐诗','tang','','[]','花籠微月竹籠煙，百尺絲繩拂地懸。',32,'全唐诗/poet.tang.21000.json','["花籠微月竹籠煙，百尺絲繩拂地懸。", "憶得雙文人靜後，潛教桃葉送鞦韆。"]'),
('1012eab2-7f98-4ed7-a813-e7a8a15579a7','雜憶五首 三','元稹','唐','唐诗','tang','','[]','寒輕夜淺繞回廊，不辨花叢暗辨香。',32,'全唐诗/poet.tang.21000.json','["寒輕夜淺繞回廊，不辨花叢暗辨香。", "憶得雙文朧月下，小樓前後捉迷藏。"]'),
('99fc571b-24a4-4520-bff8-ee677f323b54','雜憶五首 四','元稹','唐','唐诗','tang','','[]','山榴似火葉相兼，亞拂塼階半拂檐。',32,'全唐诗/poet.tang.21000.json','["山榴似火葉相兼，亞拂塼階半拂檐。", "憶得雙文獨披掩，滿頭花草倚新簾。"]'),
('dfe67598-78d6-4a90-b68b-7a32e2c2a468','雜憶五首 五','元稹','唐','唐诗','tang','','[]','春冰消盡碧波湖，漾影殘霞似有無。',32,'全唐诗/poet.tang.21000.json','["春冰消盡碧波湖，漾影殘霞似有無。", "憶得雙文衫子薄，鈿頭雲暎褪紅酥。"]'),
('6fc66dae-9544-419e-ad13-bef2f0f0eb00','有所教','元稹','唐','唐诗','tang','','[]','莫畫長眉畫短眉，斜紅傷豎莫傷垂。',32,'全唐诗/poet.tang.21000.json','["莫畫長眉畫短眉，斜紅傷豎莫傷垂。", "人人總解爭時勢，都大須看各自宜。"]'),
('11b2a981-689c-4ab8-843f-bdfbe7e15669','襄陽爲盧竇紀事 一','元稹','唐','唐诗','tang','','[]','帝下真符召玉真，偶逢遊女暫相親。',32,'全唐诗/poet.tang.21000.json','["帝下真符召玉真，偶逢遊女暫相親。", "素書三卷留爲贈，從向人間說向人。"]'),
('37e40ad1-9efa-4c05-909c-cd2e7d01b735','襄陽爲盧竇紀事 二','元稹','唐','唐诗','tang','','[]','風弄花枝月照階，醉和春睡倚香懷。',32,'全唐诗/poet.tang.21000.json','["風弄花枝月照階，醉和春睡倚香懷。", "依稀似覺雙環動，潛被蕭郎卸玉釵。"]'),
('eaa8f109-244f-4aa0-8d48-0530a4b47bcb','襄陽爲盧竇紀事 三','元稹','唐','唐诗','tang','','[]','鶯聲撩亂曙燈殘，暗覓金釵動曉寒。',32,'全唐诗/poet.tang.21000.json','["鶯聲撩亂曙燈殘，暗覓金釵動曉寒。", "猶帶春酲嬾相送，櫻桃花下隔簾看。"]'),
('c402e39c-6fb4-4dbd-afcf-a3cdc560e697','襄陽爲盧竇紀事 四','元稹','唐','唐诗','tang','','[]','琉璃波面月籠煙，暫逐蕭郎走上天。',32,'全唐诗/poet.tang.21000.json','["琉璃波面月籠煙，暫逐蕭郎走上天。", "今日歸時最腸斷，回江還是夜來船。"]'),
('86c0f428-44fd-4e96-9058-f5a69df61402','襄陽爲盧竇紀事 五','元稹','唐','唐诗','tang','','[]','花枝臨水復臨堤，閑照江流亦照泥。',32,'全唐诗/poet.tang.21000.json','["花枝臨水復臨堤，閑照江流亦照泥。", "千萬春風好擡舉，夜來曾有鳳皇栖。"]'),
('a0eba22a-3749-4e5b-9fea-1dc7e9910f5d','會真詩三十韻','元稹','唐','唐诗','tang','','[]','微月透簾櫳，螢光度碧空。',288,'全唐诗/poet.tang.21000.json','["微月透簾櫳，螢光度碧空。", "遙天初縹緲，低樹漸蔥蘢。", "龍吹過庭竹，鸞歌拂井桐。", "羅綃垂薄霧，環佩響輕風。", "絳節隨金母，雲心捧玉童。", "更深人悄悄，晨會雨濛濛。", "珠瑩光文履，花明隱繡櫳。", "寶釵行彩鳳，羅帔掩丹虹。", "言自瑤華浦，將朝碧帝宮。", "因遊李城北，偶向宋家東。", "戲調初微拒，柔情已暗通。", "低鬟蟬影動，廻步玉塵蒙。", "轉面流花雪，登牀抱綺叢。", "鴛鴦交頸舞，翡翠合歡籠。", "眉黛羞頻聚，朱脣暖更融。", "氣清蘭蘂馥，膚潤玉肌豐。", "無力慵移腕，多嬌愛斂躬。", "汗光珠點點，髮亂綠鬆鬆。", "方喜千年會，俄聞五夜窮。", "留連時有限，繾綣意難終。", "慢臉含愁態，芳詞誓素衷。", "贈環明運合，留結表心同。", "啼粉流清鏡，殘燈繞暗蟲。", "華光獨冉冉，旭日漸曈曈。"]'),
('5ac17224-0a89-415f-83b0-e942a652d48d','古豔詩二首 一','元稹','唐','唐诗','tang','','[]','春來頻到宋家東，垂袖開懷待好風。',32,'全唐诗/poet.tang.21000.json','["春來頻到宋家東，垂袖開懷待好風。", "鶯藏柳闇無人語，惟有牆花滿樹紅。"]'),
('65076398-9b91-4f22-8f67-4e2981a805aa','古豔詩二首 二','元稹','唐','唐诗','tang','','[]','深院無人草樹光，嬌鶯不語趁陰藏。',32,'全唐诗/poet.tang.21000.json','["深院無人草樹光，嬌鶯不語趁陰藏。", "等閑弄水浮花片，流出門前賺阮郎。"]'),
('c3305dc1-6c72-49a4-a0fe-e356378218f1','奉和浙西大夫李德裕述夢四十韻大夫本題言贈於夢中詩賦以寄一二僚友故今所和者亦止述翰苑舊游而已次本韻','元稹','唐','唐诗','tang','','[]','聞有池塘什，還因夢寐遭。',288,'全唐诗/poet.tang.21000.json','["聞有池塘什，還因夢寐遭。", "攀禾工類蔡，詠豆敏過曹。", "莊蝶玄言祕，羅禽藻思高。", "戈矛排筆陣，貔虎讓文韜。", "綵繢鸞凰頸，權奇驥騄髦。", "神樞千里應，華衮一言褒。", "李廣留飛箭，王祥得佩刀。", "傳乘司隸馬，繼染翰林毫。", "辨穎□超脫，詞鋒豈足櫜。", "金剛錐透玉，鑌鐵劒吹毛。", "顧我曾陪附，思君正鬱陶。", "近酬新樂錄，仍寄續離騷。", "阿閣偏隨鳳，方壺共跨鼇。", "借騎銀杏葉，橫賜錦垂萄。", "冰井分珍果，金瓶貯御醪。", "獨辭珠有戒，廉取玉非叨。", "麥紙侵紅點，蘭燈燄碧高。", "代予言不易，承聖旨偏勞。", "繞月同棲鵲，驚風比夜獒。", "吏傳開鎖契，神撼引鈴絛。", "渥澤深難報，危心過自操。", "犯顏誠懇懇，騰口懼忉忉。", "佩寵雖緺綬，安貧尚葛袍。", "賓親多謝絕，延薦必英豪。"]'),
('ff97354c-8737-4f1b-b828-f5599f0f219b','自述','元稹','唐','唐诗','tang','','[]','延英引對碧衣郎，江硯宣毫各別牀。',32,'全唐诗/poet.tang.21000.json','["延英引對碧衣郎，江硯宣毫各別牀。", "天子下簾親考試，宮人手裏過茶湯。"]'),
('aef14e4f-e564-4e52-a7a8-5db3f45458a6','春分投簡陽明洞天作','元稹','唐','唐诗','tang','','[]','中分春一半，今日半春徂。',288,'全唐诗/poet.tang.21000.json','["中分春一半，今日半春徂。", "老惜光陰甚，慵牽興緒孤。", "偶成投祕簡，聊得泛平湖。", "郡邑移仙界，山川展畫圖。", "旌旗遮嶼浦，士女滿闉闍。", "似木吳兒勁，如花越女姝。", "牛儂驚力直，蠶妾笑睢盱。", "怪我攜章甫，嘲人託鷓鴣。", "閭閻隨地勝，風俗舉華殊。", "跣足沿流婦，丫頭避役奴。", "雕題雖少有，雞卜尚多巫。", "鄉味尤珍蛤，家神愛事烏。", "舟船通海嶠，田種繞城隅。", "櫛比千艘合，袈裟萬頃鋪。", "亥茶闐小市，漁父隔深蘆。", "日脚斜穿浪，雲根遠曳蒲。", "凝風花氣度，新雨草芽蘇。", "粉壞梅辭萼，紅含杏綴珠。", "薅餘秧漸長，燒後葑猶枯。", "綠綟高懸柳，青錢密辮榆。", "馴鷗眠淺瀨，驚雉迸平蕪。", "水靜王餘見，山空謝豹呼。", "燕狂捎蛺蝶，螟挂集蒲盧。", "淺碧鶴新卵，深黃鵝嫩雛。"]'),
('84b5587a-f71a-4b05-a586-9be49cbf6fb6','春遊','元稹','唐','唐诗','tang','','[]','酒戶年年減，山行漸漸難。',72,'全唐诗/poet.tang.21000.json','["酒戶年年減，山行漸漸難。", "欲終心懶慢，轉恐興闌散。", "鏡水波猶冷，稽峰雪尚殘。", "不能辜物色，乍可怯春寒。", "遠目傷千里，新年思萬端。", "無人知此意，閑凭小欄干。"]'),
('2fb3a6f8-8459-47f3-a523-c4207c3c5776','除夜酬樂天','元稹','唐','唐诗','tang','','[]','引儺綏斾亂毿毿，戲罷人歸思不堪。',64,'全唐诗/poet.tang.21000.json','["引儺綏斾亂毿毿，戲罷人歸思不堪。", "虛漲火塵龜浦北，無由阿傘鳳城南。", "休官期限元同約，除夜情懷老共諳。", "莫道明朝始添歲，今年春在歲前三。"]'),
('e9fde5d5-c84d-460a-8642-86813b4068c7','酬樂天初冬早寒見寄','元稹','唐','唐诗','tang','','[]','乍起衣猶冷，微吟帽半敧。',48,'全唐诗/poet.tang.21000.json','["乍起衣猶冷，微吟帽半敧。", "霜凝南屋瓦，雞唱後園枝。", "洛水碧雲曉，吳宮黃葉時。", "兩傳千里意，書札不如詩。"]'),
('44f6fcc0-4709-4d41-8e95-2ba1b851be27','酬白樂天杏花園','元稹','唐','唐诗','tang','','[]','劉郎不用閑惆悵，且作花間共醉人。',32,'全唐诗/poet.tang.21000.json','["劉郎不用閑惆悵，且作花間共醉人。", "算得貞元舊朝士，幾人同見太和春。"]'),
('5786583f-f2e4-4d98-97ae-143d78135231','過東都別樂天二首 一','元稹','唐','唐诗','tang','','[]','君應怪我留連久，我欲與君辭別難。',32,'全唐诗/poet.tang.21000.json','["君應怪我留連久，我欲與君辭別難。", "白頭徒侶漸稀少，明日恐君無此歡。"]'),
('9cd675e1-ee14-4478-8dd0-90f6b9f81c03','過東都別樂天二首 二','元稹','唐','唐诗','tang','','[]','自識君來三度別，這回白盡老髭鬚。',32,'全唐诗/poet.tang.21000.json','["自識君來三度別，這回白盡老髭鬚。", "戀君不去君須會，知得後廻相見無。"]'),
('b34aac3b-ebae-43e8-9ef5-aaee061fc76d','逢白公','元稹','唐','唐诗','tang','','[]','遠路事無限，相逢唯一言。',24,'全唐诗/poet.tang.21000.json','["遠路事無限，相逢唯一言。", "月色照榮辱，長安千萬門。"]'),
('ed2393a3-fef6-4427-b0ce-01bed072df90','酬白太傅','元稹','唐','唐诗','tang','','[]','太空秋色涼，獨鳥下微陽。',48,'全唐诗/poet.tang.21000.json','["太空秋色涼，獨鳥下微陽。", "三徑池塘靜，六街車馬忙。", "漸能高酒戶，始是入詩狂。", "官冷且無事，追陪慎莫忘。"]'),
('41194004-fd0f-4bce-a285-934b17fafed0','和嚴給事聞唐昌觀玉蘂花下有遊仙','元稹','唐','唐诗','tang','','[]','弄玉潛過玉樹時，不教青鳥出花枝。',32,'全唐诗/poet.tang.21000.json','["弄玉潛過玉樹時，不教青鳥出花枝。", "的應未有諸人覺，只是嚴朗不得知。"]'),
('184d0e8b-963f-4f84-bd96-b085329e3ca7','贈毛仙翁','元稹','唐','唐诗','tang','','[]','仙駕初從蓬海來，相逢又說向天台。',64,'全唐诗/poet.tang.21000.json','["仙駕初從蓬海來，相逢又說向天台。", "一言親授希微訣，三夕同傾沆瀣杯。", "此日臨風飄羽衛，他年嘉約指鹽梅。", "花前揮手迢遙去，目斷霓旌不可陪。"]'),
('c574b079-d88b-464f-b53f-bb11bdeb9fe4','八月十四日夜玩月','元稹','唐','唐诗','tang','','[]','猶欠一宵輪未滿，紫霞紅襯碧雲端。',32,'全唐诗/poet.tang.21000.json','["猶欠一宵輪未滿，紫霞紅襯碧雲端。", "誰能喚得姮娥下，引向堂前子細看。"]'),
('1aea459c-509b-4662-98ac-b877f3fd0bb2','寒食夜','元稹','唐','唐诗','tang','','[]','紅染桃花雪壓棃，玲瓏雞子鬬贏時。',32,'全唐诗/poet.tang.21000.json','["紅染桃花雪壓棃，玲瓏雞子鬬贏時。", "今年不是明寒食，暗地鞦韆別有期。"]'),
('95272c8b-caa7-4baa-8ed3-7308b6ebed7a','三月三十日程氏館餞杜十四歸京','元稹','唐','唐诗','tang','','[]','江春今日盡，程館祖筵開。',120,'全唐诗/poet.tang.21000.json','["江春今日盡，程館祖筵開。", "我正南冠縶，君尋北路回。", "謀身誠太拙，從宦苦無媒。", "處困方明命，遭時不在才。", "踰年長倚玉，連夜共銜杯。", "涸溜霑濡沫，餘光照死灰。", "行看鴻欲翥，敢憚酒相催。", "拍逐飛觥絕，香隨舞袖來。", "消棃拋五徧，娑葛𣩄三臺。", "已許尊前倒，臨風淚莫頹。"]'),
('1f231302-d3a1-4341-9543-750b8d2909e2','酬張祕書因寄馬贈詩','元稹','唐','唐诗','tang','','[]','丞相功高厭武名，牽將戰馬寄儒生。',64,'全唐诗/poet.tang.21000.json','["丞相功高厭武名，牽將戰馬寄儒生。", "四蹄荀距藏雖盡，六尺鬚頭見尚驚。", "減粟偷兒憎未飽，騎驢詩客駡先行。", "勸君還却司空著，莫遣衙參傍子城。"]'),
('daf4c0d5-df3a-41b2-83b4-aeb8969078d5','戲酬副使中丞見示四韻','元稹','唐','唐诗','tang','','[]','莫恨暫櫜鞬，交游幾箇全。',48,'全唐诗/poet.tang.21000.json','["莫恨暫櫜鞬，交游幾箇全。", "眼明相見日，肺病欲秋天。", "五馬虛盈櫪，雙蛾浪滿船。", "可憐俱老大，無處用閑錢。"]'),
('e4862a80-d33a-4e84-b851-b3bbb6ce9e0c','贈柔之','元稹','唐','唐诗','tang','','[]','窮冬到鄉國，正歲別京華。',48,'全唐诗/poet.tang.21000.json','["窮冬到鄉國，正歲別京華。", "自恨風塵眼，常看遠地花。", "碧幢還照曜，紅粉莫咨嗟。", "嫁得浮雲壻，相隨即是家。"]'),
('d6f9d1f6-d814-4f29-aaff-577b3f3b338c','修龜山魚池示衆僧','元稹','唐','唐诗','tang','','[]','勸爾諸僧好護持，不須垂釣引青絲。',32,'全唐诗/poet.tang.21000.json','["勸爾諸僧好護持，不須垂釣引青絲。", "雲山莫厭看經坐，便是浮生得道時。"]'),
('2af18de6-d652-4799-9659-ca3b1f491559','寄贈薛濤','元稹','唐','唐诗','tang','','[]','錦江滑膩蛾眉秀，幻出文君與薛濤。',64,'全唐诗/poet.tang.21000.json','["錦江滑膩蛾眉秀，幻出文君與薛濤。", "言語巧偷鸚鵡舌，文章分得鳳皇毛。", "紛紛辭客多停筆，箇箇公卿欲夢刀。", "別後相思隔煙水，菖蒲花發五雲高。"]'),
('036ceb3f-2c41-4208-8b3b-fdf052517667','贈劉採春','元稹','唐','唐诗','tang','','[]','新粧巧樣畫雙蛾，謾裹常州透額羅。',64,'全唐诗/poet.tang.21000.json','["新粧巧樣畫雙蛾，謾裹常州透額羅。", "正面偷勻光滑笏，緩行輕踏破紋波。", "言辭雅措風流足，舉止低迴秀媚多。", "更有惱人腸斷處，選詞能唱望夫歌。"]'),
('9e73c3ca-362f-4c54-9201-2b219df8180c','醉題東武','元稹','唐','唐诗','tang','','[]','役役行人事，紛紛碎簿書。',48,'全唐诗/poet.tang.21000.json','["役役行人事，紛紛碎簿書。", "功夫兩衙盡，留滯七年餘。", "病痛梅天發，親情海岸疎。", "因循未歸得，不是憶鱸魚。"]'),
('875827b7-3e08-4c24-8069-e15b5a3099e1','崔徽歌','元稹','唐','唐诗','tang','','[]','崔徽本不是娼家，教歌按舞娼家長。',64,'全唐诗/poet.tang.21000.json','["崔徽本不是娼家，教歌按舞娼家長。", "使君知有不自由，坐在頭時立在掌。", "有客有客名丘夏，善寫儀容得恣把。", "爲徽持此謝敬中，以死報郎爲□□。"]'),
('22a880cf-50a6-48c2-babd-0a6a19a7fad3','一字至七字詩 茶','元稹','唐','唐诗','tang','','[]','茶，香葉，嫩芽。',68,'全唐诗/poet.tang.21000.json','["茶，香葉，嫩芽。", "慕詩客，愛僧家。", "碾雕白玉，羅織紅紗。", "銚煎黃蘂色，椀轉麴塵花。", "夜後邀陪明月，晨前命對朝霞。", "洗盡古今人不倦，將知醉後豈堪誇。"]'),
('280f1aaf-b380-4080-8d96-cca5b5704548','句','元稹','唐','唐诗','tang','','[]','兒歌楊柳葉，妾拂石榴花。',44,'全唐诗/poet.tang.21000.json','["兒歌楊柳葉，妾拂石榴花。", "松門待制應全遠，藥樹監搜可得知。", "髻鬟峨峨高一尺，門前立地看春風。"]'),
('3c628410-da54-43bd-965c-e4ab548f0519','賀雨','白居易','唐','唐诗','tang','','[]','皇帝嗣寶曆，元和三年冬。',287,'全唐诗/poet.tang.21000.json','["皇帝嗣寶曆，元和三年冬。", "自冬及春暮，不雨旱爞爞。", "上心念下民，懼歲成災凶。", "遂下罪己詔，殷勤告萬邦。", "帝曰予一人，繼天承祖宗。", "憂勤不遑寧，夙夜心忡忡。", "元年誅劉闢，一舉靖巴邛。", "二年戮李錡，不戰安江東。", "顧惟眇眇德，遽有巍巍功。", "或者天降沴，無乃儆予躬。", "上思天戒，下思致時邕。", "莫如率其身，慈和與儉恭。", "乃命罷進獻，乃命賑饑窮。", "宥死降五刑，責己寬三農。", "宮女出宣徽，廐馬減飛龍。", "庶政靡不舉，皆出自宸衷。", "奔騰道路人，傴僂田野翁。", "歡呼相告報，感泣涕霑胸。", "順人人心悅，先天天意從。", "詔下纔七日，和氣生沖融。", "凝爲油油雲，散作習習風。", "晝夜三日雨，淒淒復濛濛。", "萬心春熙熙，百穀青芃芃。", "人變愁爲喜，歲易儉爲豐。"]'),
('bd828f73-1d2b-479f-a8ae-d51f3ebfbe5f','讀張籍古樂府','白居易','唐','唐诗','tang','','[]','張君何爲者，業文三十春。',240,'全唐诗/poet.tang.21000.json','["張君何爲者，業文三十春。", "尤工樂府詩，舉代少其倫。", "爲詩意如何，六義互鋪陳。", "風雅比興外，未嘗著空文。", "讀君學仙詩，可諷放佚君。", "讀君董公詩，可誨貪暴臣。", "讀君商女詩，可感悍婦仁。", "讀君勤齊詩，可勸薄夫敦。", "上可裨教化，舒之濟萬民。", "下可理情性，卷之善一身。", "始從青衿歲，迨此白髮新。", "日夜秉筆吟，心苦力亦勤。", "時無采詩官，委棄如泥塵。", "恐君百歲後，滅沒人不聞。", "願藏中祕書，百代不湮淪。", "願播內樂府，時得聞至尊。", "言者志之苗，行者文之根。", "所以讀君詩，亦知君爲人。", "如何欲五十，官小身賤貧。", "病眼街西住，無人行到門。"]'),
('713ae960-bba3-4038-8d32-ba4f2af5d5d3','哭孔戡','白居易','唐','唐诗','tang','','[]','洛陽誰不死，戡死聞長安。',192,'全唐诗/poet.tang.21000.json','["洛陽誰不死，戡死聞長安。", "我是知戡者，聞之涕泫然。", "戡佐山東軍，非義不可干。", "拂衣向西來，其道直如弦。", "從事得如此，人人以爲難。", "人言明明代，合置在朝端。", "或望居諫司，有事戡必言。", "或望居憲府，有邪戡必彈。", "惜哉兩不諧，沒齒爲閑官。", "竟不得一日，謇謇立君前。", "形骸隨衆人，斂葬北邙山。", "平生剛腸內，直氣歸其間。", "賢者爲生民，生死懸在天。", "謂天不愛人，胡爲生其賢。", "謂天果愛民，胡爲奪其年。", "茫茫元化中，誰執如此權。"]'),
('4ee3b027-85e1-4d47-941f-0a149efa1ee0','凶宅','白居易','唐','唐诗','tang','','[]','長安多大宅，列在街西東。',264,'全唐诗/poet.tang.21000.json','["長安多大宅，列在街西東。", "往往朱門內，房廊相對空。", "梟鳴松桂樹，狐藏蘭菊叢。", "蒼苔黃葉地，日暮多旋風。", "前主爲將相，得罪竄巴庸。", "後主爲公卿，寢疾歿其中。", "連延四五主，殃禍繼相鍾。", "自從十年來，不利主人翁。", "風雨壞檐隙，蛇鼠穿牆墉。", "人凝不敢買，日毀土木功。", "嗟嗟俗人心，甚矣其愚蒙。", "旦恐災將至，不思禍所從。", "我今題此詩，欲悟迷者胸。", "凡爲大官人，年祿多高崇。", "權重持難久，位高勢易窮。", "驕者物之盈，老者數之終。", "四者如寇盜，日夜來相攻。", "假使居吉土，孰能保其躬。", "因小以明大，借家可喻邦。", "周秦宅殽函，其宅非不同。", "一興八百年，一死望夷宮。", "寄語家與國，人凶非宅凶。"]'),
('4e805ce8-041e-42d8-bde7-8e2225219061','夢仙','白居易','唐','唐诗','tang','','[]','人有夢仙者，夢身升上清。',288,'全唐诗/poet.tang.21000.json','["人有夢仙者，夢身升上清。", "坐乘一白鶴，前引雙紅旌。", "羽衣忽飄飄，玉鸞俄錚錚。", "半空直下視，人世塵冥冥。", "漸失鄉國處，纔分山水形。", "東海一片白，列岳五點青。", "須臾羣仙來，相引朝玉京。", "安期羨門輩，列侍如公卿。", "仰謁玉皇帝，稽首前致誠。", "帝言汝仙才，努力勿自輕。", "却後十五年，期汝不死庭。", "再拜受斯言，既寤喜且驚。", "祕之不敢泄，誓志居巖扃。", "恩愛捨骨肉，飲食斷羶腥。", "朝餐雲母散，夜吸沆瀣精。", "空山三十載，日望輜軿迎。", "前期過已久，鸞鶴無來聲。", "齒髮日衰白，耳目減聰明。", "一朝同物化，身與糞壤幷。", "神仙信有之，俗力非可營。", "苟無金骨相，不列丹臺名。", "徒傳辟穀法，虛受燒丹經。", "只自取勤苦，百年終不成。", "悲哉夢仙人，一夢誤一生。"]'),
('554b95f5-9862-4836-b3e0-f445ac850fed','觀刈麥','白居易','唐','唐诗','tang','','["\u751f\u6d3b", "\u590f\u5929", "\u519c\u6c11", "\u4e5d\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u521d\u4e2d\u53e4\u8bd7", "\u8bbd\u55bb"]','田家少閑月，五月人倍忙。',155,'全唐诗/poet.tang.21000.json','["田家少閑月，五月人倍忙。", "夜來南風起，小麥覆隴黃。", "婦姑荷簞食，童穉攜壺漿。", "相隨餉田去，丁壯在南岡。", "足蒸暑土氣，背灼炎天光。", "力盡不知熱，但惜夏日長。", "復有貧婦人，抱子在其傍。", "右手秉遺穗，左臂懸敝筐。", "聽其相顧言，聞者爲悲傷。", "家田輸稅盡，拾此充飢腸。", "今我何功德，曾不事農桑。", "吏祿三百石，歲晏有餘糧。", "念此私自媿盡日不能忘。"]'),
('dbc680d9-dfd3-44f1-b8f1-5e339ad8afae','題海圖屏風','白居易','唐','唐诗','tang','','[]','海水無風時，波濤安悠悠。',156,'全唐诗/poet.tang.21000.json','["海水無風時，波濤安悠悠。", "鱗介無小大，遂性各沈浮。", "突兀海底鼇，首冠三神丘。", "釣網不能制，其來非一秋。", "或者不量力，謂茲鼇可求。", "贔屭牽不動，綸絕沈其鉤。", "一鼇既頓頷，諸鼇齊掉頭。", "白濤與黑浪，呼吸繞咽喉。", "噴風激飛廉，鼓波怒陽侯。", "鯨鯢得其便，張口欲吞舟。", "萬里無活鱗，百川多倒流。", "遂使江漢水，朝宗意亦休。", "蒼然屏風上，此畫良有由。"]'),
('e4aa1b26-6427-485e-b698-a77989f9e567','羸駿','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','驊騮失其主，羸餓無人牧。',96,'全唐诗/poet.tang.21000.json','["驊騮失其主，羸餓無人牧。", "向風嘶一聲，莽蒼黃河曲。", "蹋冰水畔立，臥雪冢間宿。", "歲暮田野空，寒草不滿腹。", "豈無市駿者，盡是凡人目。", "相馬失於瘦，遂遺千里足。", "村中何擾擾，有吏徵芻粟。", "輸彼軍廐中，化作駑駘肉。"]'),
('643e8598-02dc-4b1c-9079-60b9ff28db06','廢琴','白居易','唐','唐诗','tang','','[]','絲桐合爲琴，中有太古聲。',72,'全唐诗/poet.tang.21000.json','["絲桐合爲琴，中有太古聲。", "古聲澹無味，不稱今人情。", "玉徽光彩滅，朱弦塵土生。", "廢棄來已久，遺音尚泠泠。", "不辭爲君彈，縱彈人不聽。", "何物使之然，羌笛與秦箏。"]'),
('c10b6235-6d2c-4d3a-b5a5-6ca89cd0ba1b','李都尉古劒','白居易','唐','唐诗','tang','','["\u5199\u5251", "\u548f\u7269\u8bd7", "\u548f\u7269", "\u8bbd\u55bb"]','古劒寒黯黯，鑄來幾千秋。',108,'全唐诗/poet.tang.21000.json','["古劒寒黯黯，鑄來幾千秋。", "白光納日月，紫氣排斗牛。", "有客借一觀，愛之不敢求。", "湛然玉匣中，秋水澄不流。", "至寶有本性，精剛無與儔。", "可使寸寸折，不能繞指柔。", "願快直士心，將斷佞臣頭。", "不願報小怨，夜半刺私讎。", "勸君慎所用，無作神兵羞。"]'),
('a351f7cb-46e0-4519-b17f-2a812ccf3069','雲居寺孤桐','白居易','唐','唐诗','tang','','[]','一株青玉立，千葉綠雲委。',84,'全唐诗/poet.tang.21000.json','["一株青玉立，千葉綠雲委。", "亭亭五丈餘，高意猶未已。", "山僧年九十，清淨老不死。", "自云手種時，一棵青桐子。", "直從萌芽拔，高自毫末始。", "四面無附枝，中心有通理。", "寄言立身者，孤直當如此。"]'),
('0877cd66-9611-4b76-9fe6-0c6a06e90d48','京兆府新栽蓮','白居易','唐','唐诗','tang','','["\u547d\u8fd0", "\u548f\u7269", "\u8377\u82b1", "\u548f\u7269\u8bd7", "\u611f\u4f24"]','汚溝貯濁水，水上葉田田。',96,'全唐诗/poet.tang.21000.json','["汚溝貯濁水，水上葉田田。", "我來一長歎，知是東溪蓮。", "下有青泥汚，馨香無復全。", "上有紅塵撲，顏色不得鮮。", "物性猶如此，人事亦宜然。", "託根非其所，不如遭棄捐。", "昔在溪中日，花葉媚清漣。", "今來不得地，顦顇府門前。"]'),
('9aba082d-e238-4881-84e1-b15d57d8ad1d','月夜登閣避暑','白居易','唐','唐诗','tang','','[]','旱久炎氣盛，中人若燔燒。',96,'全唐诗/poet.tang.21000.json','["旱久炎氣盛，中人若燔燒。", "青風隱何處，草樹不動搖。", "何以避暑氣，無如出塵囂。", "行行都門外，佛閣正岧嶤。", "清涼近高生，煩熱委靜銷。", "開襟當軒坐，意泰神飄飄。", "迴看歸路傍，禾黍盡枯焦。", "獨善誠有計，將何救旱苗。"]'),
('ed31a7fa-eef3-4b6b-893b-6cac8b1a65ac','初授拾遺','白居易','唐','唐诗','tang','','[]','奉詔登左掖，束帶參朝議。',120,'全唐诗/poet.tang.21000.json','["奉詔登左掖，束帶參朝議。", "何言初命卑，且脫風塵吏。", "杜甫陳子昂，才名括天地。", "當時非不遇，尚無過斯位。", "況余蹇薄者，寵至不自意。", "驚近白日光，慙非青雲器。", "天子方從諫，朝廷無忌諱。", "豈不思匪躬，適遇時無事。", "受命已旬月，飽食隨班次。", "諫紙忽盈箱，對之終自媿。"]'),
('c2e81ae3-9e6d-44ee-a3c9-2a8d49b44bfb','贈元稹','白居易','唐','唐诗','tang','','[]','自我從宦遊，七年在長安。',144,'全唐诗/poet.tang.21000.json','["自我從宦遊，七年在長安。", "所得惟元君，乃知定交難。", "豈無山上苗，徑寸無歲寒。", "豈無要津水，咫尺有波瀾。", "之子異於是，久處誓不諼。", "無波古井水，有節秋竹竿。", "一爲同心友，三及芳歲闌。", "花下鞍馬遊，雪中杯酒歡。", "衡門相逢迎，不具帶與冠。", "春風日高睡，秋月夜深看。", "不爲同登科，不爲同署官。", "所合在方寸，心源無異端。"]'),
('661ef3f3-58b7-46ec-b6d1-57aeec5fd95c','哭劉敦質','白居易','唐','唐诗','tang','','[]','小樹兩株柏，新土三尺墳。',84,'全唐诗/poet.tang.21000.json','["小樹兩株柏，新土三尺墳。", "蒼蒼白露草，此地哭劉君。", "哭君豈無辭，辭云君子人。", "如何天不弔，窮悴至終身。", "愚者多貴壽，賢者獨賤迍。", "龍亢彼無悔，蠖屈此不伸。", "哭罷持此辭，吾將詰羲文。"]'),
('f5b36596-f308-49fc-addc-b70e609fe19b','答友問','白居易','唐','唐诗','tang','','[]','大圭廉不割，利劒用不缺。',60,'全唐诗/poet.tang.21000.json','["大圭廉不割，利劒用不缺。", "當其斬馬時，良玉不如鐵。", "置鐵在洪爐，鐵消易如雪。", "良玉同其中，三日燒不熱。", "君疑才與德，詠此知優劣。"]'),
('fa451140-ea5c-4abe-a2cd-e1f37f0e40f4','雜興三首 一','白居易','唐','唐诗','tang','','[]','楚王多內寵，傾國選嬪妃。',156,'全唐诗/poet.tang.21000.json','["楚王多內寵，傾國選嬪妃。", "又愛從禽樂，馳騁每相隨。", "錦韝臂花隼，羅袂控金羈。", "遂習宮中女，皆如馬上兒。", "色禽合爲荒，刑政兩已衰。", "雲夢春仍獵，章華夜不歸。", "東風二月天，春雁正離離。", "美人挾銀鏑，一發疊雙飛。", "飛鴻驚斷行，斂翅避蛾眉。", "君王顧之笑，弓箭生光輝。", "迴眸語君曰，昔聞莊王時。", "有一愚夫人，其名曰樊姬。", "不有此遊樂，三載斷鮮肥。"]'),
('f7ad936c-1640-4c51-9e56-035c42caf1e2','雜興三首 二','白居易','唐','唐诗','tang','','[]','越國政初荒，越天旱不已。',120,'全唐诗/poet.tang.21000.json','["越國政初荒，越天旱不已。", "風日燥水田，水涸塵飛起。", "國中新下令，官渠禁流水。", "流水不入田，壅入王宮裏。", "餘波養魚鳥，倒影浮樓雉。", "澹灩九折池，縈迴十餘里。", "四月芰荷發，越王日遊嬉。", "左右好風來，香動芙蓉蘂。", "但愛芙蓉香，又種芙蓉子。", "不念閶門外，千里稻苗死。"]'),
('dc5c87a4-7be3-4752-ad17-2c81e3b791e6','雜興三首 三','白居易','唐','唐诗','tang','','[]','吳王心日侈，服玩盡奇瓌。',120,'全唐诗/poet.tang.21000.json','["吳王心日侈，服玩盡奇瓌。", "身臥翠羽帳，手持紅玉杯。", "冠垂明月珠，帶束通天犀。", "行動自矜顧，數步一裴回。", "小人知所好，懷寶四方來。", "奸邪得藉手，從此倖門開。", "古稱國之寶，穀米與賢才。", "今看君王眼，視之如塵灰。", "伍員諫已死，浮屍去不迴。", "姑蘇臺下草，麋鹿暗生麑。"]'),
('3115a223-afb9-44d9-8984-e2ab4dbae3ad','宿紫閣山北村','白居易','唐','唐诗','tang','','[]','晨遊柴閣峰，暮宿山下村。',120,'全唐诗/poet.tang.21000.json','["晨遊柴閣峰，暮宿山下村。", "村老見余喜，爲余開一尊。", "舉杯未及飲，暴卒來入門。", "柴衣挾刀斧，草草十餘人。", "奪我席上酒，掣我盤中飧。", "主人退後立，斂手反如賓。", "中庭有奇樹，種來三十春。", "主人惜不得，持斧斷其根。", "口稱采造家，身屬神策軍。", "主人慎勿語，中尉正承恩。"]'),
('a146cbfd-885c-4744-9f8f-a0b41e9e4d6b','讀漢書','白居易','唐','唐诗','tang','','[]','禾黍與稂莠，雨來同日滋。',156,'全唐诗/poet.tang.21000.json','["禾黍與稂莠，雨來同日滋。", "桃李與荆棘，霜降同夜萎。", "草木既區別，榮枯那等夷。", "茫茫天地意，無乃太無私。", "小人與君子，用置各有宜。", "奈何西漢末，忠邪竝信之。", "不然盡信忠，早絕邪臣窺。", "不然盡信邪，早使忠臣知。", "優游兩不斷，盛業日已衰。", "痛矣蕭京輩，終令陷禍機。", "每讀元成紀，憤憤令人悲。", "寄言爲國者，不得學天時。", "寄言爲臣者，可以鑒於斯。"]'),
('de9e9798-70d0-4432-a198-5936c1262cc5','贈樊著作','白居易','唐','唐诗','tang','','[]','陽城爲諫議，以正事其君。',216,'全唐诗/poet.tang.21000.json','["陽城爲諫議，以正事其君。", "其手如屈軼，舉必指佞臣。", "卒使不仁者，不得秉國鈞。", "元稹爲御史，以直立其身。", "其心如肺石，動必達窮民。", "東川八十家，冤憤一言伸。", "劉闢肆亂心，殺人正紛紛。", "其嫂曰庾氏，棄絕不爲親。", "從史萌逆節，隱心潛負恩。", "其佐曰孔戡，捨去不爲賓。", "凡此士與女，其道天下聞。", "常恐國史上，但記鳳與麟。", "賢者不爲名，名彰教乃敦。", "每惜若人輩，身死名亦淪。", "君爲著作郎，職廢志空存。", "雖有良史才，直筆無所申。", "何不自著書？實錄彼善人。", "編爲一家言，以備史闕文。"]'),
('033c5ceb-150d-4729-8782-da90abfb9938','蜀路石婦','白居易','唐','唐诗','tang','','[]','道旁一石婦，無記復無銘。',168,'全唐诗/poet.tang.21000.json','["道旁一石婦，無記復無銘。", "傳是此鄉女，爲婦孝且貞。", "十五嫁邑人，十六夫征行。", "夫行二十載，婦獨守孤焭。", "其夫有父母，老病不安寧。", "其婦執婦道，一一如禮經。", "晨昏問起居，恭順發心誠。", "藥餌自調節，膳羞必甘馨。", "夫行竟不歸，婦德轉光明。", "後人高其節，刻石像婦形。", "儼然整衣巾，若立在閨庭。", "似見舅姑禮，如聞環珮聲。", "至今爲婦者，見此孝心生。", "不比山頭石，空有望夫名。"]'),
('39232610-67ba-4ec5-9d49-7bdf3db5b7d2','折劒頭','白居易','唐','唐诗','tang','','[]','拾得折劒頭，不知折之由。',72,'全唐诗/poet.tang.21000.json','["拾得折劒頭，不知折之由。", "一握青蛇尾，數寸碧峰頭。", "疑是斬鯨鯢，不然刺蛟虯。", "缺落泥土中，委棄無人收。", "我有鄙介性，好剛不好柔。", "勿輕直折劒，猶勝曲全鉤。"]'),
('b80c6a20-d207-4c2f-98c2-fc06f64968d8','登樂遊園望','白居易','唐','唐诗','tang','','[]','獨上樂遊園，四望天日曛。',96,'全唐诗/poet.tang.21000.json','["獨上樂遊園，四望天日曛。", "東北何靄靄，宮闕入煙雲。", "愛此高處立，忽如遺垢氛。", "耳目暫清曠，懷抱鬱不伸。", "下視十二街，綠樹間紅塵。", "車馬徒滿眼，不見心所親。", "孔生死洛陽，元九謫荆門。", "可憐南北路，高蓋者何人。"]'),
('28749904-b223-425a-bc49-fa96ae2d984e','酬元九對新栽竹有懷見寄','白居易','唐','唐诗','tang','','[]','昔我十年前，與君始相識。',120,'全唐诗/poet.tang.21000.json','["昔我十年前，與君始相識。", "曾將秋竹竿，比君孤且直。", "中心一以合，外事紛無極。", "共保秋竹心，風霜侵不得。", "始嫌梧桐樹，秋至先改色。", "不愛楊柳枝，春來輭無力。", "憐君別我後，見竹長相憶。", "長欲在眼前，故栽庭戶側。", "分首今何處，君南我在北。", "吟我贈君詩，對之心惻惻。"]'),
('e7f1a145-ba1c-4447-8e8b-a478940eb598','感鶴','白居易','唐','唐诗','tang','','[]','鶴有不羣者，飛飛在野田。',120,'全唐诗/poet.tang.21000.json','["鶴有不羣者，飛飛在野田。", "飢不啄腐鼠，渴不飲盜泉。", "貞姿自耿介，雜鳥何翩翾。", "同遊不同志，如此十餘年。", "一興嗜慾念，遂爲矰繳牽。", "委質小池內，爭食羣雞前。", "不惟懷稻粱，兼亦競腥羶。", "不惟戀主人，兼亦狎鳥鳶。", "物心不可知，天性有時遷。", "一飽尚如此，況乘大夫軒。"]'),
('0581caee-7b84-4a76-8f99-5aca00d752f5','春雪','白居易','唐','唐诗','tang','','[]','元和歲在卯，六年春二月。',168,'全唐诗/poet.tang.21000.json','["元和歲在卯，六年春二月。", "月晦寒食天，天陰夜飛雪。", "連宵復竟日，浩浩殊未歇。", "大似落鵝毛，密如飄玉屑。", "寒銷春茫蒼，氣變風凜冽。", "上林草盡沒，曲江水復結。", "紅乾杏花死，綠凍楊枝折。", "所憐物性傷，非惜年芳絕。", "上天有時令，四序平分別。", "寒燠苟反常，物生皆夭閼。", "我觀聖人意，魯史有其說。", "或記水不冰，或書霜不殺。", "上將儆政教，下以防災孽。", "茲雪今如何，信美非時節。"]'),
('7820d8bc-5b50-4d4e-a9e3-f6ea86a8619e','高僕射','白居易','唐','唐诗','tang','','[]','富貴人所愛，聖人去其泰。',144,'全唐诗/poet.tang.21000.json','["富貴人所愛，聖人去其泰。", "所以致仕年，著在禮經內。", "玄元亦有訓，知止則不殆。", "二疏獨能行，遺跡東門外。", "清風久銷歇，迨此向千載。", "斯人古亦稀，何況今之代。", "遑遑名利客，白首千百輩。", "惟有高僕射，七十懸車蓋。", "我年雖未老，歲月亦云邁。", "預恐耄及時，貪榮不能退。", "中心私自儆，何以爲我戒。", "故作僕射詩，書之於大帶。"]'),
('6c3b0506-115f-4a31-9136-1620270ed02e','白牡丹','白居易','唐','唐诗','tang','','[]','城中看花客，旦暮走營營。',168,'全唐诗/poet.tang.21000.json','["城中看花客，旦暮走營營。", "素華人不顧，亦占牡丹名。", "閉在深寺中，車馬無來聲。", "唯有錢學士，盡日繞叢行。", "憐此皓然質，無人自芳馨。", "衆嫌我獨賞，移植在中庭。", "留景夜不暝，迎光曙先明。", "對之心亦靜，虛白相向生。", "唐昌玉蘂花，攀玩衆所爭。", "折來比顏色，一種如瑤瓊。", "彼因稀見貴，此以多爲輕。", "始知無正色，愛惡隨人情。", "豈惟花獨爾，理與人事幷。", "君看入時者，紫豔與紅英。"]'),
('4afb736a-6bee-488d-8748-f3bb270459ac','贈內','白居易','唐','唐诗','tang','','[]','生爲同室親，死爲同穴塵。',180,'全唐诗/poet.tang.21000.json','["生爲同室親，死爲同穴塵。", "他人尚相勉，而況我與君。", "黔婁固窮士，妻賢忘其貧。", "冀缺一農夫，妻敬儼如賓。", "陶潛不營生，翟氏自爨薪。", "梁鴻不肯仕，孟光甘布帬。", "君雖不讀書，此事耳亦聞。", "至此千載後，傳是何如人。", "人生未死間，不能忘其身。", "所須者衣食，不過飽與溫。", "蔬食足充飢，何必膏粱珍。", "繒絮足禦寒，何必錦繡文。", "君家有貽訓，清白遺子孫。", "我亦貞苦士，與君新結婚。", "庶保貧與素，偕老同欣欣。"]'),
('723657d7-cb24-44f4-aa06-4e0bc3ccdbd7','寄唐生','白居易','唐','唐诗','tang','','[]','賈誼哭時事，阮籍哭路岐。',288,'全唐诗/poet.tang.21000.json','["賈誼哭時事，阮籍哭路岐。", "唐生今亦哭，異代同其悲。", "唐生者何人，五十寒且飢。", "不悲口無食，不悲身無衣。", "所悲忠與義，悲甚則哭之。", "太尉擊賊日，尚書叱盜時。", "大夫死兇寇，諫議謫蠻夷。", "每見如此事，聲發涕輒隨。", "往往聞其風，俗士猶或非。", "憐君頭半白，其志竟不衰。", "我亦君之徒，鬱鬱何所爲。", "不能發聲哭，轉作樂府詩。", "篇篇無空文，句句必盡規。", "功高虞人箴，痛甚騷人辭。", "非求宮律高，不務文字奇。", "惟歌生民病，願得天子知。", "未得天子知，甘受時人嗤。", "藥良氣味苦，琴澹音聲稀。", "不懼權豪怒，亦任親朋議。", "人竟無奈何，呼作狂男兒。", "每逢羣盜息，或遇雲霧披。", "但自高聲歌，庶幾天聽卑。", "歌哭雖異名，所感則同歸。", "寄君三十章，與君爲哭詞。"]'),
('0a59fc41-c8e9-42ed-8790-62fdd405ece8','傷唐衢二首 一','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','自我心存道，外物少能逼。',168,'全唐诗/poet.tang.21000.json','["自我心存道，外物少能逼。", "常排傷心事，不爲長歎息。", "忽聞唐衢死，不覺動顏色。", "悲端從東來，觸我心惻惻。", "伊昔未相知，偶遊滑臺側。", "同宿李翺家，一言如舊識。", "酒酣出送我，風雪黃河北。", "日西竝馬頭，語別至昏黑。", "君歸向東鄭，我來遊上國。", "交心不交面，從此重相憶。", "憐君儒家子，不得詩書力。", "五十著青衫，試官無祿食。", "遺文僅千首，六義無差忒。", "散在京洛間，何人爲收拾。"]'),
('cdf28257-4200-41af-9cfa-7cc858b62fef','傷唐衢二首 二','白居易','唐','唐诗','tang','','[]','憶昨元和初，忝備諫官位。',168,'全唐诗/poet.tang.21000.json','["憶昨元和初，忝備諫官位。", "是時兵革後，生民正顦顇。", "但傷民病痛，不識時忌諱。", "遂作秦中吟，一吟悲一事。", "貴人皆怪怒，閑人亦非訾。", "天高未及聞，荆棘生滿地。", "惟有唐衢見，知我平生志。", "一讀興歎嗟，再吟垂涕泗。", "因和三十韻，手題遠緘寄。", "致吾陳杜間，賞愛非常意。", "此人無復見，此詩猶可貴。", "今日開篋看，蠹魚損文字。", "不知何處葬，欲問先歔欷。", "終去哭墳前，還君一掬淚。"]'),
('5ec36535-f0a9-4635-9a2a-ab25a4e5965e','問友','白居易','唐','唐诗','tang','','[]','種蘭不種艾，蘭生艾亦生。',72,'全唐诗/poet.tang.21000.json','["種蘭不種艾，蘭生艾亦生。", "根荄相交長，莖葉相附榮。", "香莖與臭葉，日夜俱長大。", "鋤艾恐傷蘭，溉蘭恐滋艾。", "蘭亦未能溉，艾亦未能除。", "沈吟意不決，問君合何如。"]'),
('de070606-3e25-4100-9b11-4038f0c5a870','悲哉行','白居易','唐','唐诗','tang','','[]','悲哉爲儒者，力學不知疲。',192,'全唐诗/poet.tang.21000.json','["悲哉爲儒者，力學不知疲。", "讀書眼欲暗，秉筆手生胝。", "十上方一第，成名常苦遲。", "縱有宦達者，兩鬢已成絲。", "可憐少壯日，適在窮賤時。", "丈夫老且病，焉用富貴爲。", "沈沈朱門宅，中有乳臭兒。", "狀貌如婦人，光明膏粱肌。", "手不把書卷，身不擐戎衣。", "二十襲封爵，門承勳戚資。", "春來日日出，服御何輕肥。", "朝從博徒飲，暮有倡樓期。", "平封還酒債，堆金選蛾眉。", "聲色狗馬外，其餘一無知。", "山苗與澗松，地勢隨高卑。", "古來無奈何，非君獨傷悲。"]'),
('5091996e-23c3-43ad-8b9e-54ba20c8e529','紫藤','白居易','唐','唐诗','tang','','[]','藤花紫蒙茸，藤葉青扶疎。',156,'全唐诗/poet.tang.21000.json','["藤花紫蒙茸，藤葉青扶疎。", "誰謂好顏色，而爲害有餘。", "下如蛇屈盤，上若繩縈紆。", "可憐中間樹，束縛成枯株。", "柔蔓不自勝，嫋嫋挂空虛。", "豈知纏樹木，千夫力不如。", "先柔後爲害，有似諛佞徒。", "附著君權勢，君迷不肯誅。", "又如妖婦人，綢繆蠱其夫。", "奇邪壞人室，夫惑不能除。", "寄言邦與家，所慎在其初。", "毫末不早辨，滋蔓信難圖。", "願以藤爲戒，銘之于座隅。"]'),
('a06e4034-9520-4474-8068-3624207e846a','放鷹','白居易','唐','唐诗','tang','','[]','十月鷹出籠，草枯雉兔肥。',144,'全唐诗/poet.tang.21000.json','["十月鷹出籠，草枯雉兔肥。", "下韝隨指顧，百擲無一遺。", "鷹翅疾如風，鷹爪利如錐。", "本爲鳥所設，今爲人所資。", "孰能使之然，有術甚易知。", "取其向背性，制在飢飽時。", "不可使長飽，不可使長飢。", "飢則力不足，飽則背人飛。", "乘飢縱搏擊，未飽須縶維。", "所以爪翅功，而人坐收之。", "聖明馭英雄，其術亦如斯。", "鄙語不可棄，吾聞諸獵師。"]'),
('984cabd9-8d66-45aa-8d01-d602de5aea5e','慈烏夜啼','白居易','唐','唐诗','tang','','["\u8bbd\u523a", "\u6bcd\u4eb2", "\u5199\u9e1f", "\u9e1f"]','慈烏失其母，啞啞吐哀音。',108,'全唐诗/poet.tang.21000.json','["慈烏失其母，啞啞吐哀音。", "晝夜不飛去，經年守故林。", "夜夜夜半啼，聞者爲霑襟。", "聲中如告訴，未盡反哺心。", "百鳥豈無母，爾獨哀怨深。", "應是母慈重，使爾悲不任。", "昔有吳起者，母歿喪不臨。", "嗟哉斯徒輩，其心不如禽。", "慈烏復慈烏，鳥中之曾參。"]'),
('76db2d4d-67b9-4819-a586-dee0e28b7046','燕詩示劉叟','白居易','唐','唐诗','tang','','[]','梁上有雙燕，翩翩雄與雌。',180,'全唐诗/poet.tang.21000.json','["梁上有雙燕，翩翩雄與雌。", "銜泥兩椽間，一巢生四兒。", "四兒日夜長，索食聲孜孜。", "青蟲不易捕，黃口無飽期。", "觜爪雖欲敝，心力不知疲。", "須臾十來往，猶恐巢中飢。", "辛勤三十日，母瘦雛漸肥。", "喃喃教言語，一一刷毛衣。", "一旦羽翼成，引上庭樹枝。", "舉翅不回顧，隨風四散飛。", "雌雄空中鳴，聲盡呼不歸。", "却入空巢裏，啁啾終夜悲。", "燕燕爾勿悲，爾當返自思。", "思爾爲雛日，高飛背母時。", "當時父母念，今日爾應知。"]'),
('9a3a88f3-0230-4ebf-8966-f0f8086f725c','采地黃者','白居易','唐','唐诗','tang','','[]','麥死春不雨，禾損秋早霜。',84,'全唐诗/poet.tang.21000.json','["麥死春不雨，禾損秋早霜。", "歲晏無口食，田中采地黃。", "采時將何用，持以易餱糧。", "凌晨荷鋤去，薄暮不盈筐。", "攜來朱門家，賣與白面郎。", "與君噉肥馬，可使照地光。", "願易馬殘粟，救此苦飢腸。"]'),
('aaf65a51-cd9e-45cd-a646-fc5bebbae6df','初入太行路','白居易','唐','唐诗','tang','','[]','天冷日不光，太行峰蒼莽。',48,'全唐诗/poet.tang.21000.json','["天冷日不光，太行峰蒼莽。", "嘗聞此中險，今我方獨往。", "馬蹄凍且滑，羊腸不可上。", "若比世路難，猶自平於掌。"]'),
('2336d910-2309-4e9f-bf77-0756cd8d57e2','鄧魴張徹落第','白居易','唐','唐诗','tang','','[]','古琴無俗韻，奏罷無人聽。',84,'全唐诗/poet.tang.21000.json','["古琴無俗韻，奏罷無人聽。", "寒松無妖花，枝下無人行。", "春風十二街，軒騎不暫停。", "奔車看牡丹，走馬聽秦箏。", "衆目悅芳豔，松獨守其貞。", "衆耳喜鄭衛，琴亦不改聲。", "懷哉二夫子，念此無自輕。"]'),
('3bc21d9c-17f8-48f2-9a6a-a22caa97ccc8','送王處士','白居易','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','王門豈無酒，侯門豈無肉。',96,'全唐诗/poet.tang.21000.json','["王門豈無酒，侯門豈無肉。", "主人貴且驕，待客禮不足。", "望塵而拜者，朝夕走碌碌。", "王生獨拂衣，遐舉如雲鵠。", "寧歸白雲外，飲水臥空谷。", "不能隨衆人，斂手低眉目。", "扣門與我別，酤酒留君宿。", "好去采薇人，終南山正綠。"]'),
('3416a316-b7b3-4ad4-9260-63d0ec9e7af2','村居苦寒','白居易','唐','唐诗','tang','','["\u98ce", "\u5199\u98ce", "\u751f\u6d3b", "\u519c\u6c11"]','八年十二月，五日雪紛紛。',120,'全唐诗/poet.tang.21000.json','["八年十二月，五日雪紛紛。", "竹柏皆凍死，況彼無衣民。", "回觀村閭間，十室八九貧。", "北風利如劒，布絮不蔽身。", "唯燒蒿棘火，愁坐夜待晨。", "乃知大寒歲，農者尤苦辛。", "顧我當此日，草堂深掩門。", "褐裘覆絁被，坐臥有餘溫。", "幸免飢凍苦，又無壠畝勤。", "念彼深可媿，自問是何人。"]'),
('10a06424-0792-49e3-88e0-c388c86f13c7','納粟','白居易','唐','唐诗','tang','','[]','有吏夜叩門，高聲催納粟。',96,'全唐诗/poet.tang.21000.json','["有吏夜叩門，高聲催納粟。", "家人不待曉，場上張燈燭。", "揚簸淨如珠，一車三十斛。", "猶憂納不中，鞭責及僮僕。", "昔余謬從事，內媿才不足。", "連授四命官，坐尸十年祿。", "常聞古人語，損益周必復。", "今日諒甘心，還他太倉穀。"]'),
('034a478a-eefe-4d0c-b15d-5b44cfa71bcf','薛中丞','白居易','唐','唐诗','tang','','[]','百人無一直，百直無一遇。',192,'全唐诗/poet.tang.21000.json','["百人無一直，百直無一遇。", "借問遇者誰，正人行得路。", "中丞薜存誠，守直心甚固。", "皇明燭如日，再使秉王度。", "奸豪與佞巧，非不憎且懼。", "直道漸光明，邪謀難蓋覆。", "每因匪躬節，知有匡時具。", "張爲墜網綱，倚作頹檐柱。", "悠哉上天意，報施紛回互。", "自古已冥茫，從今尤不諭。", "豈與小人意，昏然同好惡。", "不然君子人，何反如朝露。", "裴相昨已夭，薛君今又去。", "以我惜賢心，五年如旦暮。", "況聞善人命，長短繫運數。", "今我一涕零，豈爲中丞故。"]'),
('ead7bf0f-a37e-45b1-ac88-8685b31734dd','秋池二首 一','白居易','唐','唐诗','tang','','[]','前池秋始半，卉物多摧壞。',48,'全唐诗/poet.tang.21000.json','["前池秋始半，卉物多摧壞。", "欲暮槿先萎，未霜荷已敗。", "默然有所感，可以從茲誡。", "本不種松筠，早彫何足怪。"]'),
('6f9d160d-f49d-4237-ab23-0527fd57ec4f','秋池二首 二','白居易','唐','唐诗','tang','','[]','鑿池貯秋水，中有蘋與芰。',48,'全唐诗/poet.tang.21000.json','["鑿池貯秋水，中有蘋與芰。", "天旱水暗消，塌然委空地。", "有似泛泛者，附離權與貴。", "一旦恩勢移，相隨共顦顇。"]'),
('c88a2e2d-77ed-4699-8fa2-7ced4ac3918e','夏旱','白居易','唐','唐诗','tang','','[]','太陰不離畢，太歲仍在午。',96,'全唐诗/poet.tang.21000.json','["太陰不離畢，太歲仍在午。", "旱日與炎風，枯燋我田畝。", "金石欲銷鑠，況茲禾與黍。", "嗸嗸萬族中，唯農最辛苦。", "憫然望歲者，出門何所覩。", "但見棘與茨，羅生徧場圃。", "惡苗承沴氣，欣然得其所。", "感此因問天，可能長不雨。"]'),
('bfca1d70-ebf1-4c0a-be2c-9ecd5ba26192','諭友','白居易','唐','唐诗','tang','','[]','昨夜霜一降，殺君庭中槐。',156,'全唐诗/poet.tang.21000.json','["昨夜霜一降，殺君庭中槐。", "乾葉不待黃，索索飛下來。", "憐君感節物，晨起步前階。", "臨風蹋葉立，半日顏色哀。", "西望長安城，歌鐘十二街。", "何人不歡樂，君獨心悠哉。", "白日頭上走，朱顏鏡中頹。", "平生青雲心，銷化成死灰。", "我今贈一言，勝飲酒千杯。", "其言雖甚鄙，可破悒悒懷。", "朱門有勳貴，陋巷有顏回。", "窮通各問命，不繫才不才。", "推此自豁豁，不必待安排。"]'),
('7f871d40-8c88-44fe-8203-2fdaa77c38b0','丘中有一士二首 一','白居易','唐','唐诗','tang','','[]','丘中有一士，不知其姓名。',96,'全唐诗/poet.tang.21000.json','["丘中有一士，不知其姓名。", "面色不憂苦，血氣常和平。", "每選隙地居，不蹋要路行。", "舉動無尤悔，物莫與之爭。", "藜藿不充腸，布褐不蔽形。", "終歲守窮餓，而無嗟歎聲。", "豈是愛貧賤，深知時俗情。", "勿矜羅弋巧，鸞鶴在冥冥。"]'),
('697f64d7-e6f6-4762-9c52-76b0fc10aa3f','丘中有一士二首 二','白居易','唐','唐诗','tang','','[]','丘中有一士，守道歲月深。',96,'全唐诗/poet.tang.21000.json','["丘中有一士，守道歲月深。", "行披帶索衣，坐拍無弦琴。", "不飲濁泉水，不息曲木陰。", "所逢苟非義，糞土千黃金。", "鄉人化其風，熏如蘭在林。", "智愚與強弱，不忍相欺侵。", "我欲訪其人，將行復沈吟。", "何必見其面，但在學其心。"]'),
('e6ea2741-b818-4e31-8de2-3c4b5057ff91','新製布裘','白居易','唐','唐诗','tang','','[]','桂布白似雪，吳緜輭於雲。',96,'全唐诗/poet.tang.21000.json','["桂布白似雪，吳緜輭於雲。", "布重緜且厚，爲裘有餘溫。", "朝擁坐至暮，夜覆眠達晨。", "誰知嚴冬月，支體暖如春。", "中夕忽有念，撫裘起逡巡。", "丈夫貴兼濟，豈獨善一身。", "安得萬里裘，蓋裹周四垠。", "穩暖皆如我，天下無寒人。"]'),
('6509e378-c9e7-4afa-ba95-5bc4be21114c','杏園中棗樹','白居易','唐','唐诗','tang','','["\u54f2\u7406"]','人言百果中，唯棗凡且鄙。',144,'全唐诗/poet.tang.21000.json','["人言百果中，唯棗凡且鄙。", "皮皴似龜手，葉小如鼠耳。", "胡爲不自知，生花此園裏。", "豈宜遇攀玩，幸免遭傷毀。", "二月曲江頭，雜英紅旖旎。", "棗亦在其間，如嫫對西子。", "東風不擇木，吹喣長未已。", "眼看欲合抱，得盡生生理。", "寄言遊春客，乞君一迴視。", "君愛繞指柔，從君憐柳杞。", "君求悅目豔，不敢爭桃李。", "君若作大車，輪軸材須此。"]'),
('2fa3153c-cbac-4b0c-82e9-679a9dc8907c','蝦蟇','白居易','唐','唐诗','tang','','[]','嘉魚薦宗朝，靈龜貢邦家。',144,'全唐诗/poet.tang.21000.json','["嘉魚薦宗朝，靈龜貢邦家。", "應龍能致雨，潤我百穀芽。", "蠢蠢水族中，無用者蝦蟇。", "形穢肌肉腥，出沒於泥沙。", "六月七月交，時雨正滂沱。", "蝦蟇得其志，快樂無以加。", "地既蕃其生，使之族類多。", "天又與其聲，得以相諠譁。", "豈惟玉池上，汚君清冷波。", "可獨瑤瑟前，亂君鹿鳴歌。", "常恐飛上天，跳躍隨姮娥。", "往往蝕明月，遣君無奈何。"]'),
('bcdaaf94-7746-4dd6-9d48-359d09af6013','寄隱者','白居易','唐','唐诗','tang','','[]','賣藥向都城，行憩青門樹。',120,'全唐诗/poet.tang.21000.json','["賣藥向都城，行憩青門樹。", "道逢馳驛者，色有非常懼。", "親族走相送，欲別不敢住。", "私怪問道旁，何人復何故。", "云是右丞相，當國握樞務。", "祿厚食萬錢，恩深日三顧。", "昨日延英對，今日崖州去。", "由來君臣間，寵辱在朝暮。", "青青東郊草，中有歸山路。", "歸去臥雲人，謀身計非誤。"]'),
('a551b820-311d-4ef5-8def-9b1f4a6c1bdd','放魚','白居易','唐','唐诗','tang','','[]','曉日提竹籃，家僮買春蔬。',156,'全唐诗/poet.tang.21000.json','["曉日提竹籃，家僮買春蔬。", "青青芹蕨下，疊臥雙白魚。", "無聲但呀呀，以氣相喣濡。", "傾籃寫地上，撥刺長尺餘。", "豈唯刀机憂，坐見螻蟻圖。", "脫泉雖已久，得水猶可蘇。", "放之小池中，且用救乾枯。", "水小池窄狹，動尾觸四隅。", "一時幸苟活，久遠將何如。", "憐其不得所，移放於南湖。", "南湖連西江，好去勿踟躕。", "施恩即望報，吾非斯人徒。", "不須泥沙底，辛苦覓明珠。"]'),
('105eb4ed-6526-4794-a6e4-1d58247288cf','文柏牀','白居易','唐','唐诗','tang','','[]','陵上有老柏，柯葉寒蒼蒼。',96,'全唐诗/poet.tang.21000.json','["陵上有老柏，柯葉寒蒼蒼。", "朝爲風煙樹，暮爲宴寢牀。", "以其多奇文，宜升君子堂。", "刮削露節目，拂拭生輝光。", "玄斑狀貍首，素質如截肪。", "雖充悅目玩，終乏周身防。", "華彩誠可愛，生理苦已傷。", "方知自殘者，爲有好文章。"]'),
('50768326-3c0c-47dd-a680-3c99496db4ad','潯陽三題 廬山桂','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','偃蹇月中桂，結根依青天。',108,'全唐诗/poet.tang.21000.json','["偃蹇月中桂，結根依青天。", "天風繞月起，吹子下人間。", "飄零委何處，乃落匡廬山。", "生爲石上桂，葉如翦碧鮮。", "枝幹日長大，根荄日牢堅。", "不歸天上月，空老山中年。", "廬山去咸陽，道里三四千。", "無人爲移植，得入上林園。", "不及紅花樹，長栽溫室前。"]'),
('8a02fed1-83bf-4927-bcac-bbe87e95cc87','潯陽三題 湓浦竹','白居易','唐','唐诗','tang','','[]','潯陽十月天，天氣仍溫燠。',96,'全唐诗/poet.tang.21000.json','["潯陽十月天，天氣仍溫燠。", "有霜不殺草，有風不落木。", "玄冥氣力薄，草木冬猶綠。", "誰肯湓浦頭，回眼看修竹。", "其有顧盼者，持刀斬且束。", "剖劈青琅玕，家家蓋牆屋。", "吾聞汾晉間，竹少重如玉。", "胡爲取輕賤，生此西江曲。"]'),
('823ebceb-6848-442c-918e-5cbfe2a70f93','潯陽三題 東林寺白蓮','白居易','唐','唐诗','tang','','[]','東林北塘水，湛湛見底清。',120,'全唐诗/poet.tang.21000.json','["東林北塘水，湛湛見底清。", "中生白芙蓉，菡萏三百莖。", "白日發光彩，清飆散芳馨。", "洩香銀囊破，瀉露玉盤傾。", "我慙塵垢眼，見此瓊瑤英。", "乃知紅蓮花，虛得清淨名。", "夏萼敷未歇，秋房結纔成。", "夜深衆僧寢，獨起繞池行。", "欲收一顆子，寄向長安城。", "但恐出山去，人間種不生。"]'),
('8ab973dc-252d-4372-a57b-b37b39bd9698','大水','白居易','唐','唐诗','tang','','[]','潯陽郊郭間，大水歲一至。',120,'全唐诗/poet.tang.21000.json','["潯陽郊郭間，大水歲一至。", "閭閻半飄蕩，城堞多傾墜。", "蒼茫生海色，渺漫連空翠。", "風卷白波飜，日煎紅浪沸。", "工商徹屋去，牛馬登山避。", "況當率稅時，頗害農桑事。", "獨有傭舟子，鼓枻生意氣。", "不知萬人災，自覓錐刀利。", "吾無奈爾何，爾非久得志。", "九月霜降後，水涸爲平地。"]'),
('f92bfbe6-80e7-4db6-9b66-94d8c2d57e23','續古詩十首 一','白居易','唐','唐诗','tang','','[]','戚戚復戚戚，送君遠行役。',96,'全唐诗/poet.tang.21000.json','["戚戚復戚戚，送君遠行役。", "行役非中原，海外黃沙磧。", "伶俜獨居妾，迢遰長征客。", "君望功名歸，妾憂生死隔。", "誰家無夫婦，何人不離坼。", "所恨薄命身，嫁遲別日迫。", "妾身有存歿，妾心無改易。", "生作閨中婦，死作山頭石。"]'),
('a36f4666-50ef-4b26-a8ab-afd115dd7897','續古詩十首 二','白居易','唐','唐诗','tang','','[]','掩淚別鄉里，飄颻將遠行。',84,'全唐诗/poet.tang.21000.json','["掩淚別鄉里，飄颻將遠行。", "茫茫綠野中，春盡孤客情。", "驅馬上丘隴，高低路不平。", "風吹棠棃花，啼鳥時一聲。", "古墓何代人，不知姓與名。", "化作路傍土，年年春草生。", "感彼忽自悟，今我何營營。"]'),
('1c0621f3-319f-49b3-87b0-508dd2ddbaac','續古詩十首 三','白居易','唐','唐诗','tang','','[]','朝采山上薇，暮采山上薇。',84,'全唐诗/poet.tang.21000.json','["朝采山上薇，暮采山上薇。", "歲晏薇亦盡，飢來何所爲。", "坐飲白石水，手把青松枝。", "擊節獨長謌，其聲清且悲。", "櫪馬非不肥，所苦常縶維。", "豢豕非不飽，所憂竟爲犧。", "行行歌此曲，以慰常苦飢。"]'),
('befb8898-91d2-4889-a5e7-11d8b5b19dba','續古詩十首 四','白居易','唐','唐诗','tang','','[]','雨露長纖草，山苗高入雲。',60,'全唐诗/poet.tang.21000.json','["雨露長纖草，山苗高入雲。", "風雪折勁木，澗松摧爲薪。", "風摧此何意，雨長彼何因。", "百丈澗底死，寸莖山上春。", "可憐苦節士，感此涕盈巾。"]'),
('0e1e3774-5373-4448-84b6-4c59bd55bee3','續古詩十首 五','白居易','唐','唐诗','tang','','[]','窈窕雙鬟女，容德俱如玉。',96,'全唐诗/poet.tang.21000.json','["窈窕雙鬟女，容德俱如玉。", "晝居不踰閾，夜行常秉燭。", "氣如含露蘭，心如貫霜竹。", "宜當備嬪御，胡爲守幽獨。", "無媒不得選，年忽過三六。", "歲暮望漢宮，誰在黃金屋。", "邯鄲進倡女，能唱黃花曲。", "一曲稱君心，恩榮連九族。"]'),
('b0ab4f70-9cbc-4d3f-93c5-f9a5cd723297','續古詩十首 六','白居易','唐','唐诗','tang','','[]','栖栖遠方士，讀書三十年。',108,'全唐诗/poet.tang.21000.json','["栖栖遠方士，讀書三十年。", "業成無知己，徒步來入關。", "長安多王候，英俊競攀援。", "幸隨衆賓末，得厠門館間。", "東閤有旨酒，中堂有管弦。", "何爲向隅客，對此不開顏。", "富貴無是非，主人終日歡。", "貧賤多悔尤，客子中夜歎。", "歸去復歸去，故鄉貧亦安。"]'),
('b37176b6-1ae4-441f-9295-32a8094995e8','續古詩十首 七','白居易','唐','唐诗','tang','','[]','涼風飄嘉樹，日夜減芳華。',156,'全唐诗/poet.tang.21000.json','["涼風飄嘉樹，日夜減芳華。", "下有感秋婦，攀條苦悲嗟。", "我本幽閑女，結髮事豪家。", "豪家多婢僕，門內頗驕奢。", "良人近封候，出入鳴玉珂。", "自從富貴來，恩薄讒言多。", "冢婦獨守禮，羣妾互奇衺。", "但信言有玷，不察心無瑕。", "容光未銷歇，歡愛忽蹉跎。", "何意掌上玉，化爲眼中砂。", "盈盈一尺水，浩浩千丈河。", "勿言小大異，隨分有風波。", "閨房猶復爾，邦國當如何。"]'),
('63c5d972-21a8-4f8a-98d3-476743028682','續古詩十首 八','白居易','唐','唐诗','tang','','[]','心亦無所迫，身亦無所拘。',72,'全唐诗/poet.tang.21000.json','["心亦無所迫，身亦無所拘。", "何爲腸中氣，鬱鬱不得舒。", "不舒良有以，同心久離居。", "五年不見面，三年不得書。", "念此令人老，抱膝坐長吁。", "豈無盈尊酒，非君誰與娛。"]'),
('5b2ba0b5-f8f6-458a-bf97-a2b555d4f25b','續古詩十首 九','白居易','唐','唐诗','tang','','[]','攬衣出門行，遊觀繞林渠。',84,'全唐诗/poet.tang.21000.json','["攬衣出門行，遊觀繞林渠。", "澹澹春水暖，東風生綠蒲。", "上有和鳴雁，下有掉尾魚。", "飛沈一何樂，鱗羽各有徒。", "而我方獨處，不與之子俱。", "顧彼自傷己，禽魚之不如。", "出遊欲遣憂，孰知憂有餘。"]'),
('e87f60d5-df4f-4786-90c8-f401f0c7bf4c','續古詩十首 十','白居易','唐','唐诗','tang','','[]','春旦日初出，曈曈耀晨輝。',72,'全唐诗/poet.tang.21000.json','["春旦日初出，曈曈耀晨輝。", "草木照未遠，浮雲已蔽之。", "天地黯以晦，當午如昏時。", "雖有東南風，力微不能吹。", "中園何所有，滿地青青葵。", "陽光委雲上，傾心欲何依。"]'),
('468231ca-94eb-4bc2-bd53-2b59457346b9','秦中吟十首 議婚','白居易','唐','唐诗','tang','','[]','天下無正聲，悅耳即爲娛。',180,'全唐诗/poet.tang.21000.json','["天下無正聲，悅耳即爲娛。", "人間無正色，悅目即爲姝。", "顏色非相遠，貧富則有殊。", "貧爲時所棄，富爲時所趨。", "紅樓富家女，金縷繡羅襦。", "見人不斂手，嬌癡二八初。", "母兄未開口，已嫁不須臾。", "綠窗貧家女，寂莫二十餘。", "荆釵不直錢，衣上無真珠。", "幾迴人欲聘，臨日又踟躕。", "主人會良媒，置酒滿玉壺。", "四座且勿飲，聽我歌兩途。", "富家女易嫁，嫁早輕其夫。", "貧家女難嫁，嫁晚孝於姑。", "聞君欲娶婦，娶婦意何如。"]'),
('b9c2ac3e-a037-46f4-bc65-ef37a2e1881f','秦中吟十首 重賦','白居易','唐','唐诗','tang','','[]','厚地植桑麻，所要濟生民。',228,'全唐诗/poet.tang.21000.json','["厚地植桑麻，所要濟生民。", "生民理布帛，所求活一身。", "身外充征賦，上以奉君親。", "國家定兩稅，本意在愛人。", "厥初防其淫，明敕內外臣。", "稅外加一物，皆以枉法論。", "奈何歲月久，貪吏得因循。", "浚我以求寵，斂索無冬春。", "織絹未成匹，繰絲未盈斤。", "里胥迫我納，不許暫逡巡。", "歲暮天地閉，陰風生破村。", "夜深煙火盡，霰雪白紛紛。", "幼者形不蔽，老者體無溫。", "悲喘與寒氣，幷入鼻中辛。", "昨日輸殘稅，因窺官庫門。", "繒帛如山積，絲絮如雲屯。", "號爲羨餘物，隨月獻至尊。", "奪我身上煖，買爾眼前恩。", "進入瓊林庫，歲久化爲塵。"]'),
('9ce5ee95-a94a-4bdc-9cf1-cac8447f93e5','秦中吟十首 傷宅','白居易','唐','唐诗','tang','','[]','誰家起甲第，朱門大道邊。',168,'全唐诗/poet.tang.21000.json','["誰家起甲第，朱門大道邊。", "豐屋中櫛比，高牆外迴環。", "纍纍六七堂，棟宇相連延。", "一堂費百萬，鬱鬱起青煙。", "洞房溫且清，寒暑不能干。", "高堂虛且迥，坐臥見南山。", "繞廊柴藤架，夾砌紅藥欄。", "攀枝摘櫻桃，帶花移牡丹。", "主人此中坐，十載爲大官。", "廚有臭敗肉，庫有貫朽錢。", "誰能將我語，問爾骨肉間。", "豈無窮賤者，忍不救飢寒。", "如何奉一身，直欲保千年。", "不見馬家宅，今作奉誠園。"]'),
('3f8a372b-192c-42ff-93fd-748759d01005','秦中吟十首 傷友','白居易','唐','唐诗','tang','','[]','陋巷孤寒士，出門苦恓恓。',144,'全唐诗/poet.tang.21000.json','["陋巷孤寒士，出門苦恓恓。", "雖云志氣高，豈免顏色低。", "平生同門友，通籍在金閨。", "曩者膠漆契，邇來雲雨睽。", "正逢下朝歸，軒騎五門西。", "是時天久陰，三日雨淒淒。", "蹇驢避路立，肥馬當風嘶。", "迴頭忘相識，占道上沙堤。", "昔年洛陽社，貧賤相提攜。", "今日長安道，對面隔雲泥。", "近日多如此，非君獨慘悽。", "死生不變者，唯聞任與黎。"]'),
('a62438a7-3101-43a8-b9a0-a9104fa95f9d','秦中吟十首 不致仕','白居易','唐','唐诗','tang','','[]','七十而致仕，禮法有明文。',132,'全唐诗/poet.tang.21000.json','["七十而致仕，禮法有明文。", "何乃貪榮者，斯言如不聞。", "可憐八九十，齒墮雙眸昏。", "朝露貪名利，夕陽憂子孫。", "挂冠顧翠緌，懸車惜朱輪。", "金章腰不勝，傴僂入君門。", "誰不愛富貴，誰不戀君恩。", "年高須告老，名遂合退身。", "少時共嗤誚，晚歲多因循。", "賢哉漢二疏，彼獨是何人。", "寂莫東門路，無人繼去塵。"]'),
('eff3368f-d3ef-4efc-8f76-3fc5451498d7','秦中吟十首 立碑','白居易','唐','唐诗','tang','','[]','勳德既下衰，文章亦陵夷。',168,'全唐诗/poet.tang.21000.json','["勳德既下衰，文章亦陵夷。", "但見山中石，立作路旁碑。", "銘勳悉太公，敘德皆仲尼。", "復以多爲貴，千言直萬貲。", "爲文彼何人，想見下筆時。", "但欲愚者悅，不思賢者嗤。", "豈獨賢者嗤，仍傳後代疑。", "古石蒼苔字，安知是媿詞。", "我聞望江縣，麴令撫惸嫠。", "在官有仁政，名不聞京師。", "身歿欲歸葬，百姓遮路岐。", "攀轅不得歸，留葬此江湄。", "至今道其名，男女涕皆垂。", "無人立碑碣，唯有邑人知。"]'),
('7d73a7ee-1ba7-4554-b380-3ecc19cba200','秦中吟十首 輕肥','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','意氣驕滿路，鞍馬光照塵。',96,'全唐诗/poet.tang.21000.json','["意氣驕滿路，鞍馬光照塵。", "借問何爲者，人稱是內臣。", "朱紱皆大夫，紫綬或將軍。", "誇赴軍中宴，走馬去如雲。", "尊罍溢九醞，水陸羅八珍。", "果擘洞庭橘，膾切天池鱗。", "食飽心自若，酒酣氣益振。", "是歲江南旱，衢州人食人。"]'),
('cbb4237d-7ec6-4eeb-ab1f-200accf6954d','秦中吟十首 五弦','白居易','唐','唐诗','tang','','[]','清歌且罷唱，紅袂亦停舞。',120,'全唐诗/poet.tang.21000.json','["清歌且罷唱，紅袂亦停舞。", "趙叟抱五弦，宛轉當胸撫。", "大聲麄若散，颯颯風和雨。", "小聲細欲絕，切切鬼神語。", "又如鵲報喜，轉作猨啼苦。", "十指無定音，顛倒宮徵羽。", "坐客聞此聲，形神若無主。", "行客聞此聲，駐足不能舉。", "嗟嗟俗人耳，好今不好古。", "所以綠窗琴，日日生塵土。"]'),
('9676361e-0b9d-492d-8405-0b8e46a5be84','秦中吟十首 歌舞','白居易','唐','唐诗','tang','','[]','秦中歲云暮，大雪滿皇州。',108,'全唐诗/poet.tang.21000.json','["秦中歲云暮，大雪滿皇州。", "雪中退朝者，朱紫盡公候。", "貴有風雪興，富無飢寒憂。", "所營唯第宅，所務在追遊。", "朱門車馬客，紅燭歌舞樓。", "歡酣促密坐，醉煖脫重裘。", "秋官爲主人，廷尉居上頭。", "日中爲一樂，夜半不能休。", "豈知閿鄉獄，中有凍死囚。"]'),
('cc2eede8-a26c-402f-b4c8-97a2ad1f1207','秦中吟十首 買花','白居易','唐','唐诗','tang','','["\u5199\u82b1", "\u82b1", "\u8bbd\u523a"]','帝城春欲暮，喧喧車馬度。',120,'全唐诗/poet.tang.21000.json','["帝城春欲暮，喧喧車馬度。", "共道牡丹時，相隨買花去。", "貴賤無常價，酬直看花數。", "灼灼百朵紅，戔戔五束素。", "上張幄幕庇，旁織巴籬護。", "水灑復泥封，移來色如故。", "家家習爲俗，人人迷不悟。", "有一田舍翁，偶來買花處。", "低頭獨長歎，此歎無人喻。", "一叢深色花，十戶中人賦。"]'),
('50a07b10-b4b7-4847-b588-d8d622377cc9','贈友五首 一','白居易','唐','唐诗','tang','','[]','一年十二月，每月有常令。',120,'全唐诗/poet.tang.21000.json','["一年十二月，每月有常令。", "君出臣奉行，謂之握金鏡。", "由茲六氣順，以遂萬物性。", "時令一反常，生靈受其病。", "周漢德下衰，王風始不競。", "又從斬鼂錯，諸侯益強盛。", "百里不同禁，四時自爲政。", "盛夏興土功，方春勦人命。", "誰能救其失，待君佐邦柄。", "峨峨象魏門，懸法彝倫正。"]'),
('4ffaba97-f314-4143-9ae0-9fb299c59466','贈友五首 二','白居易','唐','唐诗','tang','','[]','銀生楚山曲，金生鄱谿濱。',144,'全唐诗/poet.tang.21000.json','["銀生楚山曲，金生鄱谿濱。", "南人棄農業，求之多苦辛。", "披砂復鑿石，矻矻無冬春。", "手足盡皴胝，愛利不愛身。", "畬田既慵斫，稻田亦嬾耘。", "相攜作游手，皆道求金銀。", "畢竟金與銀，何殊泥與塵。", "且非衣食物，不濟飢寒人。", "棄本以趨末，日富而歲貧。", "所以先聖王，棄藏不爲珍。", "誰能反古風，待君秉國鈞。", "捐金復抵璧，勿使勞生民。"]'),
('d7004b4a-a7e9-4049-9fe5-24cbf7e1dd1f','贈友五首 三','白居易','唐','唐诗','tang','','[]','私家無錢爐，平地無銅山。',156,'全唐诗/poet.tang.21000.json','["私家無錢爐，平地無銅山。", "胡爲秋夏稅，歲歲輸銅錢。", "錢力日已重，農力日已殫。", "賤糶粟與麥，賤貿絲與緜。", "歲暮衣食盡，焉得無飢寒。", "吾聞國之初，有制垂不刊。", "庸必算丁口，租必計桑田。", "不求土所無，不強人所難。", "量入以爲出，上足下亦安。", "兵興一變法，兵息遂不還。", "使我農桑人，顦顇畎畝間。", "誰能革此弊，待君秉利權。", "復彼租庸法，令如貞觀年。"]'),
('281913e9-6157-4bac-974c-50b53d91b471','贈友五首 四','白居易','唐','唐诗','tang','','[]','京師四方則，王化之本根。',120,'全唐诗/poet.tang.21000.json','["京師四方則，王化之本根。", "長吏久於政，然後風教敦。", "如何尹京者，遷次不逡巡。", "請君屈指數，十年十五人。", "科條日相矯，吏力亦已勤。", "寬猛政不一，民心安得淳。", "九州雍爲首，羣牧之所遵。", "天下率如此，何以安吾民。", "誰能變此法，待君贊彌綸。", "慎擇循良吏，令其長子孫。"]'),
('2bb9559d-27eb-4a42-96c2-c8aa8d5e7126','贈友五首 五','白居易','唐','唐诗','tang','','[]','三十男有室，二十女有歸。',120,'全唐诗/poet.tang.21000.json','["三十男有室，二十女有歸。", "近代多離亂，婚姻多過期。", "嫁娶既不早，生育常苦遲。", "兒女未成人，父母已衰羸。", "凡人貴達日，多在長大時。", "欲報親不待，孝心無所施。", "哀哉三牲養，少得及庭闈。", "惜哉萬鍾粟，多用飽妻兒。", "誰能正婚禮，待君張國維。", "庶使孝子心，皆無風樹悲。"]'),
('879362e7-25be-4db1-9132-fbe542308ad4','寓意詩五首 一','白居易','唐','唐诗','tang','','[]','豫樟生深山，七年而後知。',144,'全唐诗/poet.tang.21000.json','["豫樟生深山，七年而後知。", "挺高二百尺，本末皆十圍。", "天子建明堂，此材獨中規。", "匠人執斤墨，采度將有期。", "孟冬草木枯，烈火燎山陂。", "疾風吹猛燄，從根燒到枝。", "養材三十年，方成棟梁姿。", "一朝爲灰燼，柯葉無孑遺。", "地雖生爾材，天不與爾時。", "不如糞土英，猶有人掇之。", "已矣勿重陳，重陳令人悲。", "不悲焚燒苦，但悲采用遲。"]'),
('ea7d6f3a-4f1d-4b58-96d4-1144ce3b2cf3','寓意詩五首 二','白居易','唐','唐诗','tang','','[]','赫赫京內史，炎炎中書郎。',120,'全唐诗/poet.tang.21000.json','["赫赫京內史，炎炎中書郎。", "昨傳徵拜日，恩賜頗殊常。", "貂冠水蒼玉，紫綬黃金章。", "佩服身未暖，已聞竄遐荒。", "親戚不得別，吞聲泣路旁。", "賓客亦已散，門前雀羅張。", "富貴來不久，倏如瓦溝霜。", "權勢去尤速，瞥若石火光。", "不如守貧賤，貧賤可久長。", "傳語宦遊子，且來歸故鄉。"]'),
('a76290c2-2b24-48b5-94c8-b79a7241bc9d','寓意詩五首 三','白居易','唐','唐诗','tang','','[]','促織不成章，提壺但聞聲。',120,'全唐诗/poet.tang.21000.json','["促織不成章，提壺但聞聲。", "嗟哉蟲與鳥，無實有虛名。", "與君定交日，久要如弟兄。", "何以示誠信，白水指爲盟。", "雲雨一爲別，飛沈兩難幷。", "君爲得風鵬，我爲失水鯨。", "音信日已疎，恩分日已輕。", "窮通尚如此，何況死與生。", "乃知擇交難，須有知人明。", "莫將山上松，結託水上萍。"]'),
('30f3ac8e-0437-4266-8476-6d984757957f','寓意詩五首 四','白居易','唐','唐诗','tang','','[]','翩翩兩玄鳥，本是同巢燕。',84,'全唐诗/poet.tang.22000.json','["翩翩兩玄鳥，本是同巢燕。", "分飛來幾時，秋夏炎涼變。", "一宿蓬篳廬，一栖明光殿。", "偶因銜泥處，復得重相見。", "彼矜杏梁貴，此嗟茅棟賤。", "眼看秋社至，兩處俱難戀。", "所託各暫時，胡爲相歎羨。"]'),
('0415228f-3b68-4682-8da7-4ef9597f5700','寓意詩五首 五','白居易','唐','唐诗','tang','','[]','婆娑園中樹，根株大合圍。',108,'全唐诗/poet.tang.22000.json','["婆娑園中樹，根株大合圍。", "蠢爾樹間蟲，形質一何微。", "孰謂蟲之微，蟲蠹已無期。", "孰謂樹之大，花葉有衰時。", "花衰夏未實，葉病秋先萎。", "樹心半爲土，觀者安得知。", "借問蟲何在，在身不在枝。", "借問蟲何食，食心不食皮。", "豈無啄木鳥，觜長將何爲。"]'),
('f89aa5e5-a703-4956-8fa0-91a512364ee8','讀史五首 一','白居易','唐','唐诗','tang','','[]','楚懷放靈均，國政亦荒淫。',84,'全唐诗/poet.tang.22000.json','["楚懷放靈均，國政亦荒淫。", "彷徨未忍決，繞澤行悲吟。", "漢文疑賈生，謫置湘之陰。", "是時刑方措，此去難爲心。", "士生一代間，誰不有浮沈。", "良時真可惜，亂世何足欽。", "乃知汨羅恨，未抵長沙深。"]'),
('bcf35dca-9704-4f15-8798-92bf36cf6886','讀史五首 二','白居易','唐','唐诗','tang','','[]','禍患如棼絲，其來無端緒。',96,'全唐诗/poet.tang.22000.json','["禍患如棼絲，其來無端緒。", "馬遷下蠶室，嵇康就囹圄。", "抱冤志氣屈，忍恥形神沮。", "當彼戮辱時，奮飛無翅羽。", "商山有黃綺，潁川有巢許。", "何不從之遊？超然離網罟。", "山林少羈鞅，世路多艱阻。", "寄謝伐檀人，慎勿嗟窮處。"]'),
('5d6e2206-6a10-4e9a-9c6f-650cc357e9ba','讀史五首 三','白居易','唐','唐诗','tang','','[]','漢日大江軍，少爲乞食子。',84,'全唐诗/poet.tang.22000.json','["漢日大江軍，少爲乞食子。", "秦時故列侯，老作鋤瓜士。", "春華何暐曄，園中發桃李。", "秋風忽蕭條，堂上生荆杞。", "深谷變爲岸，桑田成海水。", "勢去未須悲，時來何足喜。", "寄言榮枯者，反復殊未已。"]'),
('ec58cff0-5958-4c6a-a487-dfa4900f96af','讀史五首 四','白居易','唐','唐诗','tang','','[]','含沙射人影，雖病人不知。',96,'全唐诗/poet.tang.22000.json','["含沙射人影，雖病人不知。", "巧言搆人罪，至死人不疑。", "掇蠭殺愛子，掩鼻戮寵姬。", "弘恭陷蕭望，趙高謀李斯。", "陰德既必報，陰禍豈虛施。", "人事雖可罔，天道終難欺。", "明則有刑辟，幽則有神祗。", "苟免勿私喜，鬼得而誅之。"]'),
('6b6865e1-7c8f-48e5-b955-e8b76e183d5c','讀史五首 五','白居易','唐','唐诗','tang','','[]','季子顦顇時，婦見不下機。',108,'全唐诗/poet.tang.22000.json','["季子顦顇時，婦見不下機。", "買臣負薪日，妻亦棄如遺。", "一朝黃金多，佩印衣錦歸。", "去妻不敢視，婦嫂強依依。", "富貴家人重，貧賤妻子欺。", "奈何貧富間，可移親愛志。", "遂使中人心，汲汲求富貴。", "又令下人力，各競錐刀利。", "隨分歸舍來，一取妻孥意。"]'),
('a7ba119d-0662-4bce-b1a4-a24f1320dcf3','和荅詩十首 和思歸樂','白居易','唐','唐诗','tang','','[]','山中不栖鳥，夜半聲嚶嚶。',288,'全唐诗/poet.tang.22000.json','["山中不栖鳥，夜半聲嚶嚶。", "似道思歸樂，行人掩泣聽。", "皆疑此山路，遷客多南征。", "憂憤氣不散，結化爲精靈。", "我謂此山鳥，本不因人生。", "人心自懷土，想作思歸鳴。", "孟嘗平居時，娛耳琴泠泠。", "雍門一言感，未奏淚霑纓。", "魏武銅雀妓，日與歡樂幷。", "一旦西陵望，欲歌先涕零。", "峽猨亦何意，隴水復何情。", "爲入愁人耳，皆爲腸斷聲。", "請看元侍御，亦宿此郵亭。", "因聽思歸鳥，神氣獨安寧。", "問君何以然，道勝心自平。", "雖爲南遷客，如在長安城。", "云得此道來，何慮復何營。", "窮達有前定，憂喜無交爭。", "所以事君日，持憲立大庭。", "雖有迴天力，撓之終不傾。", "況始三十餘，年少有直名。", "心中志氣大，眼前爵祿輕。", "君恩若雨露，君威若雷霆。", "退不苟免難，進不曲求榮。"]'),
('51a33228-723f-466c-821e-6bf6ffabb8c9','和荅詩十首 和陽城驛','白居易','唐','唐诗','tang','','[]','商山陽城驛，中有歎者誰。',288,'全唐诗/poet.tang.22000.json','["商山陽城驛，中有歎者誰。", "云是元監察，江陵謫去時。", "忽見此驛名，良久涕欲垂。", "何故陽道州，名姓同於斯。", "憐君一寸心，寵辱誓不移。", "疾惡若巷伯，好賢如緇衣。", "沈吟不能去，意者欲改爲。", "改爲避賢驛，大署於門楣。", "荆人愛羊祜，戶曹改爲辭。", "一字不忍道，況兼姓呼之。", "因題八百言，言直文甚奇。", "詩成寄與我，鏘若金和絲。", "上言陽公行，友悌無等夷。", "骨肉同衾裯，至死不相離。", "次言陽公迹，夏邑始棲遲。", "鄉人化其風，少長皆孝慈。", "次言陽公道，終日對酒巵。", "兄弟笑相顧，醉貌紅怡怡。", "次言陽公節，謇謇居諫司。", "誓心除國蠹，決死犯天威。", "終言陽公命，左遷天一涯。", "道州炎瘴地，身不得生歸。", "一一皆實錄，事事無孑遺。", "凡是爲善者，聞之惻然悲。"]'),
('1255551e-a812-4e50-81a3-ecc29364273e','和荅詩十首 荅桐花','白居易','唐','唐诗','tang','','[]','山木多蓊鬱，茲桐獨亭亭。',288,'全唐诗/poet.tang.22000.json','["山木多蓊鬱，茲桐獨亭亭。", "葉重碧雲片，花簇紫霞英。", "是時三月天，春暖山雨晴。", "夜色向月淺，闇香隨風輕。", "行者多商賈，居者悉黎氓。", "無人解賞愛，有客獨屏營。", "手攀花枝立，足蹋花影行。", "生憐不得所，死欲揚其聲。", "截爲天子琴，刻作古人形。", "云待我成器，薦之於穆清。", "誠是君子心，恐非草木情。", "胡爲愛其華，而反傷其生。", "老龜被刳腸，不如無神靈。", "雄雞自斷尾，不願爲犧牲。", "況此好顏色，花紫葉青青。", "宜遂天地性，忍加刀斧刑。", "我思五丁力，拔入九重城。", "當君正殿栽，花葉生光晶。", "上對月中桂，下覆階前蓂。", "汎拂香爐煙，隱映斧藻屏。", "爲君布綠陰，當暑蔭軒楹。", "沈沈綠滿地，桃李不敢爭。", "爲君發清韻，風來如叩瓊。", "泠泠聲滿耳，鄭衛不足聽。"]'),
('cd55ca70-3513-44dc-9aa1-83ac0c333964','和荅詩十首 和大觜烏','白居易','唐','唐诗','tang','','[]','烏者種有二，名同性不同。',288,'全唐诗/poet.tang.22000.json','["烏者種有二，名同性不同。", "觜小者慈孝，觜大者貪庸。", "觜大命又長，生來十餘冬。", "物老顏色變，頭毛白茸茸。", "飛來庭樹上，初但驚兒童。", "老巫生奸計，與烏意潛通。", "云此非凡鳥，遙見起敬恭。", "千歲乃一出，喜賀主人翁。", "祥瑞來白日，神聖占知風。", "陰作北斗使，能爲人吉凶。", "此烏所止家，家產日夜豐。", "上以致壽考，下可宜田農。", "主人富家子，身老心童蒙。", "隨巫拜復祝，婦姑亦相從。", "殺雞薦其肉，敬若禋六宗。", "烏喜張大觜，飛接在虛空。", "烏既飽羶腥，巫亦饗甘濃。", "烏巫互相利，不復兩西東。", "日日營巢窟，稍稍近房櫳。", "雖生八九子，誰辨其雌雄。", "羣雛又成長，衆觜逞殘兇。", "探巢吞燕卵，入蔟啄蠶蟲。", "豈無乘秋隼，羈絆委高墉。", "但食烏殘肉，無施搏擊功。"]'),
('078b8015-9e4c-4760-a694-778e66ec9113','和荅詩十首 答四皓廟','白居易','唐','唐诗','tang','','[]','天下有道見，無道卷懷之。',288,'全唐诗/poet.tang.22000.json','["天下有道見，無道卷懷之。", "此乃聖人語，吾聞諸仲尼。", "矯矯四先生，同稟希世資。", "隨時有顯晦，秉道無磷緇。", "秦皇肆暴虐，二世遘亂離。", "先生相隨去，商嶺采紫芝。", "君看秦獄中，戮辱者李斯。", "劉項爭天下，謀臣竟悅隨。", "先生如鸞鶴，去入冥冥飛。", "君看齊鼎中，焦爛者酈其。", "子房得沛公，自謂相遇遲。", "八難掉舌樞，三略役心機。", "辛苦十數年，晝夜形神疲。", "竟雜霸者道，徒稱帝者師。", "子房爾則能，此非吾所宜。", "漢高之季年，嬖寵鍾所私。", "冢嫡欲廢奪，骨肉相憂疑。", "豈無子房口，口舌無所施。", "亦有陳平心，心計將何爲。", "皤皤四先生，高冠危映眉。", "從容下南山，顧盼入東闈。", "前瞻惠太子，左右生羽儀。", "却顧戚夫人，楚舞無光輝。", "心不畫一計，口不吐一詞。"]'),
('129c2ddb-caca-4d4b-b9df-697226ecf483','和荅詩十首 和雉媒','白居易','唐','唐诗','tang','','[]','吟君雉媒什，一哂一復歎。',180,'全唐诗/poet.tang.22000.json','["吟君雉媒什，一哂一復歎。", "和之一何晚，今日乃成篇。", "豈唯鳥有之，抑亦人復然。", "張陳刎頸交，竟以勢不完。", "至今不平氣，塞絕泜水源。", "趙襄骨肉親，亦以利相殘。", "至今不善名，高於磨笄山。", "況此籠中雉，志在飲啄間。", "稻粱暫入口，性已隨人遷。", "身苦亦自忘，同族何足言。", "但恨爲媒拙，不足以自全。", "勸君今日後，養鳥養青鸞。", "青鸞一失侶，至死守孤單。", "勸君今日後，結客結任安。", "主人賓客去，獨住在門闌。"]'),
('65140cb9-a979-4aa2-82a7-850f54c9b0a2','和荅詩十首 和松樹','白居易','唐','唐诗','tang','','[]','亭亭山上松，一一生朝陽。',168,'全唐诗/poet.tang.22000.json','["亭亭山上松，一一生朝陽。", "森聳上參天，柯條百尺長。", "漠漠塵中槐，兩兩夾康莊。", "婆娑低覆地，枝幹亦尋常。", "八月白露降，槐葉次第黃。", "歲暮滿山雪，松色鬱青蒼。", "彼如君子心，秉操貫冰霜。", "此如小人面，變態隨炎涼。", "共知松勝槐，誠欲栽道傍。", "糞土種瑤草，瑤草終不芳。", "尚可以斧斤，伐之爲棟梁。", "殺身獲其所，爲君構明堂。", "不然終天年，老死在南岡。", "不願亞枝葉，低隨槐樹行。"]'),
('d4a565e7-0941-4bba-94e0-7a99db5d7a58','和荅詩十首 荅箭鏃','白居易','唐','唐诗','tang','','[]','矢人職司憂，爲箭恐不精。',204,'全唐诗/poet.tang.22000.json','["矢人職司憂，爲箭恐不精。", "精在利其鏃，錯磨鋒鏑成。", "插以青竹簳，羽之赤雁翎。", "勿言分寸鐵，爲用乃長兵。", "聞有狗盜者，晝伏夜潛行。", "摩弓拭箭鏃，夜射不待明。", "一盜既流血，百犬同吠聲。", "狺狺嘷不已，主人爲之驚。", "盜心憎主人，主人不知情。", "反責鏃太利，矢人獲罪名。", "寄言控弦者，願君少留聽。", "何不向西射？西天有狼星。", "何不向東射？東海有長鯨。", "不然學仁貴，三矢平虜庭。", "不然學仲連，一發下燕城。", "胡爲射小盜，此用無乃輕。", "徒霑一點血，虛汚箭頭腥。"]'),
('bec8a3d5-9621-4c48-8a52-74f9cbabfef1','和荅詩十首 和古社','白居易','唐','唐诗','tang','','[]','廢村多年樹，生在古社隈。',180,'全唐诗/poet.tang.22000.json','["廢村多年樹，生在古社隈。", "爲作妖狐窟，心空身未摧。", "妖狐變美女，社樹成樓臺。", "黃昏行人過，見者心裴回。", "飢鵰竟不捉，老犬反爲媒。", "歲媚少年客，十去九不迴。", "昨夜雲雨合，烈風驅迅雷。", "風拔樹根出，雷劈社壇開。", "飛電化爲火，妖狐燒作灰。", "天明至其所，清曠無氛埃。", "舊地葺村落，新田闢荒萊。", "始知天降火，不必常爲災。", "勿謂神默默，勿謂天恢恢。", "勿喜犬不捕，勿誇鵰不猜。", "寄言狐媚者，天火有時來。"]'),
('05c8bb8b-4dc2-4c4b-bec1-a79ee49be091','和荅詩十首 和分水嶺','白居易','唐','唐诗','tang','','[]','高嶺峻稜稜，細泉流亹亹。',168,'全唐诗/poet.tang.22000.json','["高嶺峻稜稜，細泉流亹亹。", "勢分合不得，東西隨所委。", "悠悠草蔓底，濺濺石罅裏。", "分流來幾年，晝夜兩如此。", "朝宗遠不及，去海三千里。", "浸潤小無功，山苗長旱死。", "縈紆用無所，奔迫流不已。", "唯作嗚咽聲，夜入行人耳。", "有源殊不竭，無坎終難止。", "同出而異流，君看何所似。", "有似骨肉親，派別從茲始。", "又似勢利交，波瀾相背起。", "所以贈君詩，將君何所比。", "不比山上泉，比君井中水。"]'),
('21be930e-da09-4b10-ba1d-040dc84b0905','有木詩八首 一','白居易','唐','唐诗','tang','','[]','有木名弱柳，結根近清池。',96,'全唐诗/poet.tang.22000.json','["有木名弱柳，結根近清池。", "風煙借顏色，雨露助華滋。", "峨峨白雪花，嫋嫋青絲枝。", "漸密陰自庇，轉高梢四垂。", "截枝扶爲杖，輭弱不自持。", "折條用樊圃，柔脆非其宜。", "爲樹信可玩，論材何所施。", "可惜金堤地，栽之徒爾爲。"]'),
('10c953de-f7a9-4212-8a4c-4e54f602cdf5','有木詩八首 二','白居易','唐','唐诗','tang','','[]','有木名櫻桃，得地早滋茂。',96,'全唐诗/poet.tang.22000.json','["有木名櫻桃，得地早滋茂。", "葉密獨承日，花繁偏受露。", "迎風闇搖動，引鳥潛來去。", "鳥啄子難成，風來枝莫住。", "低輭易攀玩，佳人屢迴顧。", "色求桃李饒，心向松筠妬。", "好是映牆花，本非當軒樹。", "所以姓蕭人，曾爲伐櫻賦。"]'),
('d1be4366-b686-41ad-8219-913dcc386da6','有木詩八首 三','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','有木秋不凋，青青在江北。',96,'全唐诗/poet.tang.22000.json','["有木秋不凋，青青在江北。", "謂爲洞庭橘，美人自移植。", "上受顧盼恩，下勤澆溉力。", "實成乃是枳，臭苦不堪食。", "物有似是者，真僞何由識。", "美人默無言，對之長歎息。", "中含害物意，外矯凌霜色。", "仍向枝葉間，潛生刺如棘。"]'),
('c51b5f46-e160-4454-96cb-5385b5313062','有木詩八首 四','白居易','唐','唐诗','tang','','[]','有木名杜棃，陰森覆丘壑。',96,'全唐诗/poet.tang.22000.json','["有木名杜棃，陰森覆丘壑。", "心蠹已空朽，根深尚盤薄。", "狐媚言語巧，鳥妖聲音惡。", "憑此爲巢穴，往來互棲託。", "四傍五六本，葉枝相交錯。", "借問因何生，秋風吹子落。", "爲長社壇下，無人敢芟斫。", "幾度野火來，風迴燒不著。"]'),
('664f01dd-6059-47d7-b5ec-2663adf8cdba','有木詩八首 五','白居易','唐','唐诗','tang','','[]','有木香苒苒，山頭生一蕟。',96,'全唐诗/poet.tang.22000.json','["有木香苒苒，山頭生一蕟。", "主人不知名，移種近軒闥。", "愛其有芳味，因以調麴糵。", "前後曾飲者，十人無一活。", "豈徒悔封植，兼亦誤采掇。", "試問識藥人，始知名野葛。", "年深已滋蔓，刀斧不可伐。", "何時猛風來，爲我連根拔。"]'),
('6d6dbe20-917b-4697-af0d-9db71ca52d5c','有木詩八首 六','白居易','唐','唐诗','tang','','[]','有木名水檉，遠望青童童。',96,'全唐诗/poet.tang.22000.json','["有木名水檉，遠望青童童。", "根株非勁挺，柯葉多蒙籠。", "彩翠色如柏，鱗皴皮似松。", "爲同松柏類，得列嘉樹中。", "枝弱不勝雪，勢高常懼風。", "雪壓低還舉，風吹西復東。", "柔芳甚楊柳，早落先梧桐。", "惟有一堪賞，中心無蠹蟲。"]'),
('0fc8d0f9-b6c1-47d0-8d68-7ff816539a51','有木詩八首 七','白居易','唐','唐诗','tang','','[]','有木名凌霄，擢秀非孤標。',96,'全唐诗/poet.tang.22000.json','["有木名凌霄，擢秀非孤標。", "偶依一株樹，遂抽百尺條。", "託根附樹身，開花寄樹梢。", "自謂得其勢，無因有動搖。", "一旦樹摧倒，獨立暫飄颻。", "疾風從東起，吹折不終朝。", "朝爲拂雲花，暮爲委地樵。", "寄言立身者，勿學柔弱苗。"]'),
('b7a4bde8-2642-4caa-84e8-c2d0b92ec6fb','有木詩八首 八','白居易','唐','唐诗','tang','','[]','有木名丹桂，四時香馥馥。',96,'全唐诗/poet.tang.22000.json','["有木名丹桂，四時香馥馥。", "花團夜雪明，葉翦春雲綠。", "風影清似水，霜枝冷如玉。", "獨占小山幽，不容凡鳥宿。", "匠人愛芳直，裁截爲廈屋。", "幹細力未成，用之君自速。", "重任雖大過，直心終不曲。", "縱非梁棟材，猶勝尋常木。"]'),
('4cb1c15d-61ec-48f1-8df4-f465ff7249f0','歎魯二首 一','白居易','唐','唐诗','tang','','[]','季桓心豈忠，其富過周公。',72,'全唐诗/poet.tang.22000.json','["季桓心豈忠，其富過周公。", "陽貨道豈正，其權執國命。", "由來富與權，不繫才與賢。", "所託得其地，雖愚亦獲安。", "彘肥因糞壤，鼠穩依社壇。", "蟲獸尚如是，豈謂無因緣。"]'),
('30150c8b-deff-44b6-ba7a-01561f0a0c30','歎魯二首 二','白居易','唐','唐诗','tang','','[]','展禽胡爲者，直道竟三黜。',72,'全唐诗/poet.tang.22000.json','["展禽胡爲者，直道竟三黜。", "顏子何如人，屢空聊過日。", "皆懷王佐道，不踐陪臣秩。", "自古無奈何，命爲時所屈。", "有如草木分，天各與其一。", "荔枝非名花，牡丹無甘實。"]'),
('642a9151-3608-4484-920b-b5f359f38142','反鮑明遠白頭吟','白居易','唐','唐诗','tang','','[]','炎炎者烈火，營營者小蠅。',120,'全唐诗/poet.tang.22000.json','["炎炎者烈火，營營者小蠅。", "火不熱貞玉，蠅不點清冰。", "此苟無所受，彼莫能相仍。", "乃知物性中，各有能不能。", "古稱怨恨死，則人有所懲。", "懲淫或應可，在道未爲弘。", "譬如蜩鷃徒，啾啾啅龍鵬。", "宜當委之去，寥廓高飛騰。", "豈能泥塵下，區區酬怨憎。", "胡爲坐自苦，吞悲仍撫膺。"]'),
('48d60d89-356a-4a12-b3cf-02dde12b7c6b','青冢','白居易','唐','唐诗','tang','','[]','上有飢鷹號，下有枯蓬走。',192,'全唐诗/poet.tang.22000.json','["上有飢鷹號，下有枯蓬走。", "茫茫邊雪裏，一掬沙培塿。", "傳是昭君墓，埋閉蛾眉久。", "凝脂化爲泥，鉛黛復何有。", "唯有陰怨氣，時生墳左右。", "鬱鬱如苦霧，不隨骨銷朽。", "婦人無他才，榮枯繫妍否。", "何乃明妃命，獨懸畫工手。", "丹青一詿誤，白黑相紛糾。", "遂使君眼中，西施作嫫母。", "同儕傾寵幸，異類爲配偶。", "禍福安可知，美顏不如醜。", "何言一時事，可戒千年後。", "特報後來姝，不須倚眉首。", "無辭插荆釵，嫁作貧家婦。", "不見青冢上，行人爲澆酒。"]'),
('a485e66d-16d3-4b84-8eef-1c19c1f654ea','雜感','白居易','唐','唐诗','tang','','[]','君子防悔尤，賢人戒行藏。',180,'全唐诗/poet.tang.22000.json','["君子防悔尤，賢人戒行藏。", "嫌疑遠瓜李，言動慎毫芒。", "立教固如此，撫事有非常。", "爲君持所感，仰面問蒼蒼。", "犬齧桃樹根，李樹反見傷。", "老龜烹不爛，延禍及枯桑。", "城門自焚爇，池魚罹其殃。", "陽貨肆兇暴，仲尼畏於匡。", "魯酒薄如水，邯鄲開戰場。", "伯禽鞭見血，過失由成王。", "都尉身降虜，宮刑加子長。", "呂安兄不道，都市殺嵇康。", "斯人死已久，其事甚昭彰。", "是非不由己，禍患安可防。", "使我千載後，涕泗滿衣裳。"]'),
('d89a395a-1449-4082-ad16-2d60993387f3','新樂府 七德舞	美撥亂，陳王業也','白居易','唐','唐诗','tang','','[]','七德舞，七德歌，傳自武德至元和。',261,'全唐诗/poet.tang.22000.json','["七德舞，七德歌，傳自武德至元和。", "元和小臣白居易，觀舞聽歌知樂意。", "樂終稽首陳其事，太宗十八舉義兵。", "白旄黃鉞定兩京，擒充戮竇四海清。", "二十有四功業成，二十有九即帝位。", "三十有五致太平，功成理定何神速。", "速在推心置人腹，亡卒遺骸散帛收。", "飢人賣子分金贖，魏徵夢見子夜泣。", "張謹哀聞辰日哭，怨女三千放出宮。", "死囚四百來歸獄，翦鬚燒藥賜功臣。", "李勣嗚咽思殺身含血吮創撫戰士，思摩奮呼乞効死。", "則知不獨善戰善乘時，以心感人人心歸。", "爾來一百九十載，天下至今歌舞之。", "歌七德，舞七德，聖人有作垂無極。", "豈徒耀神武，豈徒誇聖文。", "太宗意在陳王業，王業艱難示子孫。"]'),
('9b6aa0ad-b9af-4efe-8045-28330bb5a227','新樂府 法曲	美列聖，正華聲也','白居易','唐','唐诗','tang','','[]','法曲法曲歌大定，積德重熙有餘慶。',160,'全唐诗/poet.tang.22000.json','["法曲法曲歌大定，積德重熙有餘慶。", "永徽之人舞而詠，法曲法曲舞霓裳。", "政和世理音洋洋，開元之人樂且康。", "法曲法曲歌堂堂，堂堂之慶垂無疆。", "中宗肅宗復鴻業，唐祚中興萬萬葉。", "法曲法曲合夷歌，夷聲邪亂華聲和。", "以亂干和天寶末，明年胡塵犯宮闕。", "乃知法曲本華風，苟能審音與政通。", "一從胡曲相參錯，不辨興衰與哀樂。", "願求牙曠正華音，不令夷夏相交侵。"]'),
('653388ca-159d-4a7a-8e72-8db997377cc9','新樂府 二王後	明祖宗之意也','白居易','唐','唐诗','tang','','[]','二王後，彼何人，介公酅公爲國賓。',132,'全唐诗/poet.tang.22000.json','["二王後，彼何人，介公酅公爲國賓。", "周武隋文之子孫，古人有言天下者，非是一人之天下。", "周亡天下傳於隋，隋人失之唐得之。", "唐興十葉歲二百，介公酅公世爲客。", "明堂太廟朝享時，引居賓位備威儀。", "備威儀，助郊祭，高祖太宗之遺制。", "不獨興滅國，不獨繼絕世。", "欲令嗣位守文君，亡國之孫取爲戒。"]'),
('fbddd4e6-86e1-444f-9e4e-09e473f2a306','新樂府 海漫漫	戒求仙也','白居易','唐','唐诗','tang','','[]','海漫漫，直下無底傍無邊。',168,'全唐诗/poet.tang.22000.json','["海漫漫，直下無底傍無邊。", "雲濤煙浪最深處，人傳中有三神山。", "山上多生不死藥，服之羽化爲天仙。", "秦皇漢武信此語，方士年年采藥去。", "蓬萊今古但聞名，煙水茫茫無覓處。", "海漫漫，風浩浩，眼穿不見蓬萊島。", "不見蓬萊不敢歸，童男丱女舟中老。", "徐福文成多誑誕，上元太一虛祈禱。", "君看驪山頂上茂陵頭，畢竟悲風吹蔓草。", "何況玄元聖祖五千言，不言藥，不言仙，不言白日升青天。"]'),
('318b28a4-48ac-4fd9-9c6c-b478a292fb39','新樂府 立部伎	刺雅樂之替也','白居易','唐','唐诗','tang','','[]','立部伎，鼓笛諠，舞雙劒，跳七丸，嫋巨索，掉長竿。',168,'全唐诗/poet.tang.22000.json','["立部伎，鼓笛諠，舞雙劒，跳七丸，嫋巨索，掉長竿。", "太常部伎有等級，堂上者坐堂下立。", "堂上坐部笙歌清，堂下立部鼓笛鳴。", "笙歌一聲衆側耳，鼓笛萬曲無人聽。", "立部賤，坐部貴，坐部退爲立部伎。", "擊鼓吹笙和雜戲，立部又退何所任。", "始就樂懸操雅音，雅音替壞一至此。", "長令爾輩調宮徵，圓丘后土郊祀時。", "言將此樂感神祇，欲望鳳來百獸舞。", "何異北轅將適楚，工師愚賤安足云。"]'),
('03d52578-b863-4eb7-9517-08c6fc4daea6','新樂府 華原磬	刺樂工非其人也','白居易','唐','唐诗','tang','','[]','華原磬，華原磬，古人不聽今人聽。',176,'全唐诗/poet.tang.22000.json','["華原磬，華原磬，古人不聽今人聽。", "泗濱石，泗濱石，今人不擊古人擊。", "今人古人何不同？用之舍之由樂工。", "樂工雖在耳如壁，不分清濁即爲聾。", "棃園弟子調律呂，知有新聲不如古。", "古稱浮磬出泗濱，立辨致死聲感人。", "宮懸一聽華原石，君心遂忘封疆臣。", "果然胡寇從燕起，武臣少肯封疆死。", "始知樂與時政通，豈聽鏗鏘而已矣。", "磬襄入海去不歸，長安市兒爲樂師。", "華原磬與泗濱石，清濁兩聲誰得知。"]'),
('5fd74af9-88f7-42bd-875f-57a30bd80868','新樂府 上陽白髮人	愍怨曠也','白居易','唐','唐诗','tang','','["\u5bab\u6028", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','上陽人，紅顏闇老白髮新。',310,'全唐诗/poet.tang.22000.json','["上陽人，紅顏闇老白髮新。", "綠衣監使守宮門，一閉上陽多少春。", "玄宗末歲初選入，入時十六今六十。", "同時采擇百餘人，零落年深殘此身。", "憶昔吞悲別親族，扶入車中不教哭。", "皆云入內便承恩，臉似芙蓉胸似玉。", "未容君王得見面，已被楊妃遙側目。", "妬令潛配上陽宮，一生遂向空房宿。", "宿空房，秋夜長，夜長無寐天不明。", "耿耿殘燈背壁影，蕭蕭暗雨打窗聲。", "春日遲，日遲獨坐天難暮。", "宮鶯百囀愁厭聞，梁燕雙栖老休妬。", "鶯歸燕去長悄然，春往秋來不記年。", "唯向深宮望明月，東西四五百迴圓。", "今日宮中年最老，大家遙賜尚書號。", "小頭鞋履窄衣裳，青黛點眉眉細長。", "外人不見見應笑，天寶末年時世妝。", "上陽人，苦最多，少亦苦，老亦苦，少苦老苦兩如何？", "君不見昔時呂向美人賦，又不見今日上陽白髮歌。"]'),
('d29c1368-48c6-474f-b9a4-db596471795e','新樂府 胡旋女	戒近習也','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','胡旋女，胡旋女，心應弦，手應鼓。',224,'全唐诗/poet.tang.22000.json','["胡旋女，胡旋女，心應弦，手應鼓。", "弦鼓一聲雙袖舉，迴雪飄颻轉蓬舞。", "左旋右轉不知疲，千匝萬周無已時。", "人間物類無可比，奔車輪緩旋風遲。", "曲終再拜謝天子，天子爲之微啓齒。", "胡旋女，出康居，徒勞東來萬里餘。", "中原自有胡旋者，鬬妙爭能爾不如。", "天寶季年時欲變，臣妾人人學圜轉。", "中有太真外祿山，二人最道能胡旋。", "棃花園中冊作妃，金雞障下養爲兒。", "祿山胡旋迷君眼，兵過黃河疑未反。", "貴妃胡旋惑君心，死棄馬嵬念更深。", "從茲地軸天維轉，五十年來制不禁。", "胡旋女，莫空舞，數唱此歌悟明主。"]'),
('ece1ff0c-ab25-41df-adb4-836cf2af908f','新樂府 新豐折臂翁	戒邊功也','白居易','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u53d9\u4e8b", "\u5199\u4eba", "\u6124\u61d1", "\u5199\u4eba\u8bd7"]','新豐老翁八十八，頭鬢眉鬚皆似雪。',382,'全唐诗/poet.tang.22000.json','["新豐老翁八十八，頭鬢眉鬚皆似雪。", "玄孫扶向店前行，左臂憑肩右臂折。", "問翁臂折來幾年，兼問致折何因緣。", "翁云貫屬新豐縣，生逢聖代無征戰。", "慣聽棃園歌管聲，不識旗槍與弓箭。", "無何天寶大徵兵，戶有三丁點一丁。", "點得驅將何處去，五月萬里雲南行。", "聞道雲南有瀘水，椒花落時瘴煙起。", "大軍徒涉水如湯，未過十人二三死。", "村南村北哭聲哀，兒別爺娘夫別妻。", "皆云前後征蠻者，千萬人行無一迴。", "是時翁年二十四，兵部牒中有名字。", "夜深不敢使人知，偷將大石搥折臂。", "張弓簸旗俱不堪，從茲始免征雲南。", "骨碎筋傷非不苦，且圖揀退歸鄉土。", "此臂折來六十年，一肢雖廢一身全。", "至今風雨陰寒夜，直到天明痛不眠。", "痛不眠，終不悔，且喜老身今獨在。", "不然當時瀘水頭，身死魂孤骨不收。", "應作雲南望鄉鬼，萬人冢上哭呦呦。", "老人言，君聽取。", "君不聞開元宰相宋開府，不賞邊功防黷武。", "又不聞天寶宰相楊國忠，欲求恩幸立邊功。", "邊功未立生人怨，請問新豐折臂翁。"]'),
('6b822af1-c865-49dc-946d-9740691f330f','新樂府 太行路	借夫婦以諷君臣之不終也','白居易','唐','唐诗','tang','','[]','太行之路能摧車，若比人心是坦途。',215,'全唐诗/poet.tang.22000.json','["太行之路能摧車，若比人心是坦途。", "巫峽之水能覆舟，若比人心是安流。", "人心好惡苦不常，好生毛羽惡生瘡。", "與君結髮未五載，豈期牛女爲參商。", "古稱色衰相棄背，當時美人猶怨悔。", "何況如今鸞鏡中，妾顏未改君心改。", "爲君熏衣裳，君聞蘭麝不馨香。", "爲君盛容飾，君看金翠無顏色。", "行路難，難重陳。", "人生莫作婦人身，百年苦樂由他人。", "行路難，難於山，險於水。", "不獨人間夫與妻，近代君臣亦如此。", "君不見左納言，右納史，朝承恩，暮賜死。", "行路難，不在水，不在山，只在人情反覆間。"]'),
('e1a83087-b1e0-4b1f-b68f-7962982e8abf','新樂府 司天臺	引古以儆今也','白居易','唐','唐诗','tang','','[]','司天臺，仰觀俯察天人際。',136,'全唐诗/poet.tang.22000.json','["司天臺，仰觀俯察天人際。", "羲和死來職事廢，官不求賢空取藝。", "昔聞西漢元成間，上陵下替謫見天。", "北辰微闇少光色，四星煌煌如火赤。", "耀芒動角射三台，上台半滅中台坼。", "是時非無太史官，眼見心知不敢言。", "明朝趨入明光殿，唯奏慶雲壽星見。", "天文時變兩如斯，九重天子不得知。", "不得知，安用臺高百尺爲。"]'),
('2c41f763-148e-4d85-8dce-366037e0d0d3','新樂府 捕蝗		刺長吏也','白居易','唐','唐诗','tang','','[]','捕蝗捕蝗誰家子，天熱日長飢欲死。',180,'全唐诗/poet.tang.22000.json','["捕蝗捕蝗誰家子，天熱日長飢欲死。", "興元兵後傷陰陽，和氣蠱蠹化爲蝗。", "始自兩河及三輔，薦食如蠶飛似雨。", "雨飛蠶食千里間，不見青苗空赤土。", "河南長吏言憂農，課人晝夜捕蝗蟲。", "是時粟斗錢三百，蝗蟲之價與粟同。", "捕蝗捕蝗竟何利，徒使飢人重勞費。", "一蟲雖死百蟲來，豈將人力定天災。", "我聞古之良吏有善政，以政驅蝗蝗出境。", "又聞貞觀之初道欲昌，文皇仰天吞一蝗。", "一人有慶兆民賴，是歲雖蝗不爲害。"]'),
('eb024025-9f9a-498d-af5b-7d8729e741c0','新樂府 昆明春	思王澤之廣被也','白居易','唐','唐诗','tang','','[]','昆明春，昆明春，春池岸古春流新。',232,'全唐诗/poet.tang.22000.json','["昆明春，昆明春，春池岸古春流新。", "影浸南山青滉瀁，波沈西日紅奫淪。", "往年因旱池枯竭，龜尾曳塗魚喣沫。", "詔開八水注恩波，千介萬鱗同日活。", "今來淨綠水照天，游魚鱍鱍蓮田田。", "洲香杜若抽心短，沙暖鴛鴦鋪翅眠。", "動植飛沈皆遂性，皇澤如春無不被。", "漁者仍豐網罟資，貧人久獲菰蒲利。", "詔以昆明近帝城，官家不得收其征。", "菰蒲無租魚無稅，近水之人感君惠。", "感君惠，獨何人。", "吾聞率土皆王民，遠民何疎近何親。", "願推此惠及天下，無遠無近同欣欣。", "吳興山中罷榷茗，鄱陽坑裏休封銀。", "天涯地角無禁利，熙熙同似昆明春。"]'),
('55c4a950-e65f-4b14-b3b5-3fc10aa0c1a1','新樂府 城鹽州	美聖謨而誚邊將也','白居易','唐','唐诗','tang','','[]','城鹽州，城鹽州，城在五原原上頭。',284,'全唐诗/poet.tang.22000.json','["城鹽州，城鹽州，城在五原原上頭。", "蕃東節度鉢闡布，忽見新城當要路。", "金鳥飛傳贊普聞，建牙傳箭集羣臣。", "君臣赬面有憂色，皆言勿謂唐無人。", "自築鹽州十餘載，左衽氈裘不犯塞。", "晝牧牛羊夜捉生，長去新城百里外。", "諸邊急警勞戍人，唯此一道無煙塵。", "靈夏潛安誰復辨，秦原闇通何處見。", "鄜州驛路好馬來，長安藥肆黃蓍賤。", "城鹽州，鹽州未城天子憂。", "德宗按圖自定計，非關將略與廟謀。", "吾聞高宗中宗世，北虜猖狂最難制。", "韓公創築受降城，三城鼎峙屯漢兵。", "東西亙絕數千里，耳冷不聞胡馬聲。", "如今邊將非無策，心笑韓公築城壁。", "相看養寇爲身謀，各握強兵固恩澤。", "願分今日邊將恩，褒贈韓公封子孫。", "誰能將此鹽州曲，飜作歌詞聞至尊。"]'),
('da8402ef-6cf1-4b8b-9a37-feff27fba276','新樂府 道州民	美臣遇明主也','白居易','唐','唐诗','tang','','[]','道州民，多侏儒，長者不過三尺餘。',184,'全唐诗/poet.tang.22000.json','["道州民，多侏儒，長者不過三尺餘。", "市作矮奴年進送，號爲道州任土貢。", "任土貢，寧若斯。", "不聞使人生別離，老翁哭孫母哭兒。", "一自陽城來守郡，不進矮奴頻詔問。", "城云臣按六典書，任土貢有不貢無。", "道州水土所生者，只有矮民無矮奴。", "吾君感悟璽書下，歲貢矮奴宜悉罷。", "道州民，老者幼者何欣欣。", "父兄子弟始相保，從此得作良人身。", "道州民，民到于今受其賜，欲說使君先下淚。", "仍恐兒孫忘使君，生男多以陽爲字。"]'),
('e77ff416-cd6e-4d75-8c2d-098b31872617','新樂府 馴犀		感爲政之難終也','白居易','唐','唐诗','tang','','[]','馴犀馴犀通天犀，軀貌駭人角駭雞。',239,'全唐诗/poet.tang.22000.json','["馴犀馴犀通天犀，軀貌駭人角駭雞。", "海蠻聞有明天子，驅犀乘傳來萬里。", "一朝得謁大明宮，歡呼拜舞自論功。", "五年馴養始堪獻，六譯語言方得通。", "上嘉人獸俱來遠，蠻館四方犀入苑。", "秣以瑤芻鏁以金，故鄉迢遰君門深。", "海鳥不知鐘鼓樂，池魚空結江湖心。", "馴犀生處南方熱，秋無白露冬無雪。", "一入上林三四年，又逢今歲苦寒月。", "飲冰臥霰苦踡跼，角骨凍傷鱗甲蹜。", "馴犀死，蠻兒啼，向闕再拜顏色低。", "奏乞生歸本國去，恐身凍死似馴犀。", "君不見建中初，馴象生還放林邑。", "君不見貞元年末，馴犀凍死蠻兒泣。", "所嗟建中異貞元，象生犀死何足言。"]'),
('c244da49-5540-4485-9184-3680ab1836a6','新樂府 五弦彈	惡鄭之奪雅也','白居易','唐','唐诗','tang','','[]','五弦彈，五弦彈，聽者傾耳心寥寥。',302,'全唐诗/poet.tang.22000.json','["五弦彈，五弦彈，聽者傾耳心寥寥。", "趙璧知君入骨愛，五弦一一爲君調。", "第一第二弦索索，秋風拂松疎韻落。", "第三第四弦泠泠，夜鶴憶子籠中鳴。", "第五弦聲最掩抑，隴水凍咽流不得。", "五弦竝奏君試聽，淒淒切切復錚錚。", "鐵擊珊瑚一兩曲，冰瀉玉盤千萬聲。", "鐵聲殺，冰聲寒。", "殺聲入耳膚血憯，寒氣中人肌骨酸。", "曲終聲盡欲半日，四坐相對愁無言。", "座中有一遠方士，唧唧咨咨聲不已。", "自歎今朝初得聞，始知孤負平生耳。", "唯憂趙璧白髮生，老死人間無此聲。", "遠方士，爾聽五弦信爲美，吾聞正始之音不如是。", "正始之音其若何，朱弦疏越清廟歌。", "一彈一唱再三歎，曲澹節稀聲不多。", "融融曳曳召元氣，聽之不覺心平和。", "人情重今多賤古，古琴有弦人不撫。", "更從趙璧藝成來，二十五弦不如五。"]'),
('ffae9a7f-d8fb-47e3-aee1-1ddca03a7958','新樂府 蠻子朝	刺將驕而相備位也','白居易','唐','唐诗','tang','','[]','蠻子朝，泛皮船兮渡繩橋，來自巂州道路遙。',278,'全唐诗/poet.tang.22000.json','["蠻子朝，泛皮船兮渡繩橋，來自巂州道路遙。", "入界先經蜀川過，蜀將收功先表賀。", "臣聞雲南六詔蠻，東連牂牁西連蕃。", "六詔星居初瑣碎，合爲一詔漸強大。", "開元皇帝雖聖神，唯蠻倔強不來賓。", "鮮于仲通六萬卒，征蠻一陣全軍沒。", "至今西洱河岸邊，箭孔刀痕滿枯骨。", "誰知今日慕華風，不勞一人蠻自通。", "誠由陛下休明德，亦賴微臣誘諭功。", "德宗省表知如此，笑令中使迎蠻子。", "蠻子導從者誰何，摩挲俗羽雙隈伽。", "清平官持赤藤杖，大將軍繫金呿喈。", "異牟尋男尋閤勸，特敕召對延英殿。", "上心貴在懷遠蠻，引臨玉座近天顏。", "冕旒不垂親勞倈，賜衣賜食移時對。", "移時對，不可得，大臣相看有羨色。", "可憐宰相拖紫佩金章，朝日唯聞對一刻。"]'),
('3678b5ab-47f9-4d7e-ac26-688295c2a2a5','新樂府 驃國樂	欲王化之先邇後遠也','白居易','唐','唐诗','tang','','[]','驃國樂，驃國樂，出自大海西南角。',272,'全唐诗/poet.tang.22000.json','["驃國樂，驃國樂，出自大海西南角。", "雍羌之子舒難陀，來獻南音奉正朔。", "德宗立仗御紫庭，黈纊不塞爲爾聽。", "玉螺一吹椎髻聳，銅鼓一擊文身踊。", "珠纓炫轉星宿搖，花鬘斗藪龍蛇動。", "曲終王子啓聖人，臣父願爲唐外臣。", "左右歡呼何翕習，至尊德廣之所及。", "須臾百辟詣閤門，俯伏拜表賀至尊。", "伏見驃人獻新樂，請書國史傳子孫。", "時有擊壤老農父，暗測君心閑獨語。", "聞君政化甚聖明，欲感人心致太平。", "感人在近不在遠，太平由實非由聲。", "觀身理國國可濟，君如心兮民如體。", "體生疾苦心憯悽，民得和平君愷悌。", "貞元之民若未安，驃樂雖聞君不歡。", "貞元之民苟無病，驃樂不來君亦聖。", "驃樂驃樂徒喧喧，不如聞此芻蕘言。"]'),
('8e637621-1c10-4d92-93ac-55e41d15875b','新樂府 縛戎人	達窮民之情也','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','縛戎人，縛戎人，耳穿面破驅入秦。',380,'全唐诗/poet.tang.22000.json','["縛戎人，縛戎人，耳穿面破驅入秦。", "天子矜憐不忍殺，詔徙東南吳與越。", "黃衣小使錄姓名，領出長安乘遞行。", "身被金創面多瘠，扶病徒行日一驛。", "朝餐飢渴費杯盤，夜臥腥臊汚牀席。", "忽逢江水憶交河，垂手齊聲嗚咽歌。", "其中一虜語諸虜，爾苦非多我苦多。", "同伴行人因借問，欲說喉中氣憤憤。", "自云鄉管本涼原，大曆年中沒落蕃。", "一落蕃中四十載，遣著皮裘繫毛帶。", "唯許正朝服漢儀，斂衣整巾潛淚垂。", "誓心密定歸鄉計，不使蕃中妻子知。", "暗思幸有殘筋力，更恐年衰歸不得。", "蕃候嚴兵鳥不飛，脫身冒死奔逃歸。", "晝伏宵行經大漠，雲陰月黑風沙惡。", "驚藏青冢寒草疎，偷渡黃河夜冰薄。", "忽聞漢軍鼙鼓聲，路傍走出再拜迎。", "游騎不聽能漢語，將軍遂縛作蕃生。", "配向東南卑濕地，定無存卹空防備。", "念此吞聲仰訴天，若爲辛苦度殘年。", "涼原鄉井不得見，胡地妻兒虛棄捐。", "沒蕃被囚思漢土，歸漢被劫爲蕃虜。", "早知如此悔歸來，兩地寧如一處苦。", "縛戎人，戎人之中我苦辛。"]'),
('1b4ec8d9-bd6a-499b-9b04-595690b1f548','新樂府 驪宮高	美天子重惜人之財力也','白居易','唐','唐诗','tang','','[]','高高驪山上有宮，朱樓紫殿三四重。',197,'全唐诗/poet.tang.22000.json','["高高驪山上有宮，朱樓紫殿三四重。", "遲遲兮春日，玉甃暖兮溫泉溢。", "嫋嫋兮秋風，山蟬鳴兮宮樹紅。", "翠華不來歲月久，牆有衣兮瓦有松。", "吾君在位已五載，何不一幸乎其中？", "西去都門幾多地，吾君不遊有深意。", "一人出兮不容易，六宮從兮百司備。", "八十一車千萬騎，朝有宴飫暮有賜。", "中人之產數百家，未足充君一日費。", "吾君修己人不知，不自逸兮不自嬉。", "吾君愛人人不識，不傷財兮不傷力。", "驪宮高兮高入雲，君之來兮爲一身，君之不來兮爲萬人。"]'),
('fa557ad1-5a6f-420a-a22d-77f5bd85d565','新樂府 百鍊鏡	辨皇王鑒也','白居易','唐','唐诗','tang','','[]','百鍊鏡，鎔範非常規，日辰處所靈且祇。',146,'全唐诗/poet.tang.22000.json','["百鍊鏡，鎔範非常規，日辰處所靈且祇。", "江心波上舟中鑄，五月五日日午時。", "瓊粉金膏磨瑩已，化爲一片秋潭水。", "鏡成將獻蓬萊宮，揚州長吏手自封。", "人間臣妾不合照，背有九五飛天龍。", "人人呼爲天子鏡，我有一言聞太宗。", "太宗常以人爲鏡，鑒古鑒今不鑒容。", "四海安危居掌內，百王治亂懸心中。", "乃知天子別有鏡，不是揚州百鍊銅。"]'),
('5df437ca-32ec-4efe-872b-0b836f0ab42f','新樂府 青石		激忠烈也','白居易','唐','唐诗','tang','','[]','青石出自藍田山，兼車運載來長安。',190,'全唐诗/poet.tang.22000.json','["青石出自藍田山，兼車運載來長安。", "工人磨琢欲何用，石不能言我代言。", "不願作人家墓前神道碣，墳土未乾名已滅。", "不願作官家道旁德政碑，不鐫實錄鐫虛辭。", "願爲顏氏段氏碑，雕鏤太尉與太師。", "刻此兩片堅貞質，狀彼二人忠烈姿。", "義心如石屹不轉，死節如石確不移。", "如觀奮擊朱泚日，似見叱訶希烈時。", "各於其上題名諡，一置高山一沈水。", "陵谷雖遷碑獨存，骨化爲塵名不死。", "長使不忠不烈臣，觀碑改節慕爲人。", "慕爲人，勸事君。"]'),
('ec6b6d12-1312-470c-b4ea-4eed7386a04d','新樂府 兩朱閣	刺佛寺寖多也','白居易','唐','唐诗','tang','','[]','兩朱閣，南北相對起。',150,'全唐诗/poet.tang.22000.json','["兩朱閣，南北相對起。", "借問何人家，貞元雙帝子。", "帝子吹簫雙得仙，五雲飄颻飛上天。", "第宅亭臺不將去，化爲佛寺在人間。", "妝閤伎樓何寂靜，柳似舞腰池似鏡。", "花落黃昏悄悄時，不聞歌吹聞鐘磬。", "寺門敕牓金字書，尼院佛庭寬有餘。", "青苔明月多閑地，比屋疲人無處居。", "憶昨平陽宅初置，吞幷平人幾家地。", "仙去雙雙作梵宮，漸恐人間盡爲寺。"]'),
('c0504d98-1a16-4054-a991-ef932f59d7a6','新樂府 西涼伎	刺封疆之臣也','白居易','唐','唐诗','tang','','[]','西涼伎，假面胡人假獅子。',316,'全唐诗/poet.tang.22000.json','["西涼伎，假面胡人假獅子。", "刻木爲頭絲作尾，金鍍眼睛銀帖齒。", "奮迅毛衣擺雙耳，如從流沙來萬里。", "紫髯深目兩胡兒，鼓舞跳梁前致辭。", "應似涼州未陷日，安西都護進來時。", "須臾云得新消息，安西路絕歸不得。", "泣向獅子涕雙垂，涼州陷沒知不知。", "獅子回頭向西望，哀吼一聲觀者悲。", "貞元邊將愛此曲，醉坐笑看看不足。", "娛賓犒士宴監軍，獅子胡兒長在目。", "有一征夫年七十，見弄涼州低面泣。", "泣罷斂手白將軍，主憂臣辱昔所聞。", "自從天寶兵戈起，犬戎日夜吞西鄙。", "涼州陷來四十年，河隴侵將七千里。", "平時安西萬里疆，今日邊防在鳳翔。", "緣邊空屯十萬卒，飽食溫衣閑過日。", "遺民腸斷在涼州，將卒相看無意收。", "天子每思長痛惜，將軍欲說合慙羞。", "奈何仍看西涼伎，取笑資歡無所媿。", "縱無智力未能收，忍取西涼弄爲戲。"]'),
('4e798517-f37f-47cb-b1f4-6b9d3ab3f180','新樂府 八駿圖	戒奇物懲佚遊也','白居易','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4", "\u8bbd\u523a"]','穆王八駿天馬駒，後人愛之寫爲圖。',234,'全唐诗/poet.tang.22000.json','["穆王八駿天馬駒，後人愛之寫爲圖。", "背如龍兮頸如象，骨聳筋高脂肉壯。", "日行萬里疾如飛，穆王獨乘何所之。", "四荒八極蹋欲徧，三十二蹄無歇時。", "屬車軸折趁不及，黃屋草生棄若遺。", "瑤池西赴王母宴，七廟經年不親薦。", "璧臺南與盛姬遊，明堂不復朝諸侯。", "白雲黃竹歌聲動，一人荒樂萬人愁。", "周從后稷至文武，積德累功世勤苦。", "豈知纔及四代孫，心輕王業如灰土。", "由來尤物不在大，能蕩君心則爲害。", "文帝却之不肯乘，千里馬去漢道興。", "穆王得之不爲戒，八駿駒來周室壞。", "至今此物尚稱珍，不知房星之精下爲怪。", "八駿圖，君莫愛。"]'),
('20261028-0474-4ce0-b069-2b1c50c57035','新樂府 澗底松	念寒儁也','白居易','唐','唐诗','tang','','[]','有松百尺大十圍，生在澗底寒且卑。',123,'全唐诗/poet.tang.22000.json','["有松百尺大十圍，生在澗底寒且卑。", "澗深山險人路絕，老死不逢工度之。", "天子明堂欠梁木，此求彼有兩不知。", "誰喻蒼蒼造物意，但與之材不與地。", "金張世祿原憲貧，牛衣寒賤貂蟬貴。", "貂蟬與牛衣，高下雖有殊。", "高者未必賢，下者未必愚。", "君不見沈沈海底生珊瑚，歷歷天上種白榆。"]'),
('1c7b03ca-fd0c-463e-816f-aba337f2ae1a','新樂府 牡丹芳	美天子憂農也','白居易','唐','唐诗','tang','','["\u7261\u4e39", "\u548f\u7269\u8bd7", "\u4e50\u5e9c", "\u548f\u7269"]','牡丹芳，牡丹芳，黃金蘂綻紅玉房。',376,'全唐诗/poet.tang.22000.json','["牡丹芳，牡丹芳，黃金蘂綻紅玉房。", "千片赤英霞爛爛，百枝絳點燈煌煌。", "照地初開錦繡段，當風不結蘭麝囊。", "仙人琪樹白無色，王母桃花小不香。", "宿露輕盈泛紫豔，朝陽照耀生紅光。", "紅紫二色間深淺，向背萬態隨低昂。", "映葉多情隱羞面，臥叢無力含醉妝。", "低嬌笑容疑掩口，凝思怨人如斷腸。", "穠姿貴彩信奇絕，雜卉亂花無比方。", "石竹金錢何細碎，芙蓉芍藥苦尋常。", "遂使王公與鄉士，遊花冠蓋日相望。", "庳車輭轝貴公主，香衫細馬豪家郎。", "衛公宅靜閉東院，西明寺深開北廊。", "戲蝶雙舞看人久，殘鶯一聲春日長。", "共愁日照芳難駐，仍張帷幕垂陰涼。", "花開花落二十日，一城之人皆若狂。", "三代以還文勝質，人心重華不重實。", "重華直至牡丹芳，其來有漸非今日。", "元和天子憂農桑，卹下動天天降祥。", "去歲嘉禾生九穗，田中寂莫無人至。", "今年瑞麥分兩岐，君心獨喜無人知。", "無人知，可歎息，我願暫求造化力。", "減却牡丹妖豔色，少迴鄉士愛花心，同似吾君憂稼穡。"]'),
('0732c4d9-21fc-4c0a-8e4a-2c44e5df8833','新樂府 紅線毯	憂蠶桑之費也','白居易','唐','唐诗','tang','','["\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e", "\u8bbd\u523a"]','紅線毯，擇蠒繰絲清水煮。',180,'全唐诗/poet.tang.22000.json','["紅線毯，擇蠒繰絲清水煮。", "揀絲練線紅藍染，染爲紅線紅於藍。", "織作披香殿上毯，披香殿廣十丈餘。", "紅線織成可殿鋪，綵絲茸茸香拂拂。", "線輭花虛不勝物，美人蹋上歌舞來。", "羅韤繡鞋隨步沒，太原毯澀毳縷硬。", "蜀都褥薄錦花冷，不如此毯溫且柔。", "年年十月來宣州，宣城太守加樣織。", "自謂爲臣能竭力，百夫同擔進宮中。", "線厚絲多卷不得，宣城太守知不知。", "一丈毯，千兩絲，地不知寒人要暖，少奪人衣作地衣。"]'),
('6447c346-b037-46bd-b16f-11b772c1e811','新樂府 杜陵叟	傷農夫之困也','白居易','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u751f\u6d3b", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e", "\u519c\u6c11"]','杜陵叟，杜陵居，歲種薄田一頃餘。',174,'全唐诗/poet.tang.22000.json','["杜陵叟，杜陵居，歲種薄田一頃餘。", "三月無雨旱風起，麥苗不秀多黃死。", "九月降霜秋早寒，禾穗未熟皆青乾。", "長吏明知不申破，急斂暴徵求考課。", "典桑賣地納官租，明年衣食將何如。", "剝我身上帛，奪我口中粟。", "虐人害物即豺狼，何必鉤爪鋸牙食人肉。", "不知何人奏皇帝，帝心惻隱知人弊。", "白麻紙上書德音，京畿盡放今年稅。", "昨日里胥方到門，手持尺牒牓鄉村。", "十家租稅九家畢，虛受吾君蠲免恩。"]'),
('35f446ec-9bd1-4df3-bb94-7b3b45888f24','新樂府 繚綾		念女工之勞也','白居易','唐','唐诗','tang','','[]','繚綾繚綾何所似，不似羅綃與紈綺。',210,'全唐诗/poet.tang.22000.json','["繚綾繚綾何所似，不似羅綃與紈綺。", "應似天台山上月明前，四十五尺瀑布泉。", "中有文章又奇絕，地鋪白煙花簇雪。", "織者何人衣者誰，越溪寒女漢宮姬。", "去年中使宣口敕，天上取樣人間織。", "織爲雲外秋雁行，染作江南春水色。", "廣裁衫袖長製帬，金斗熨波刀翦紋。", "異彩奇文相隱映，轉側看花花不定。", "昭陽舞人恩正深，春衣一對直千金。", "汗霑粉汙不再著，曳土蹋泥無惜心。", "繚綾織成費功績，莫比尋常繒與帛。", "絲細繰多女手疼，扎扎千聲不盈尺。", "昭陽殿裏歌舞人，若見織時應也惜。"]'),
('e0677c90-ea54-4de6-94cf-e6af2eea1755','新樂府 賣炭翁	苦官市也','白居易','唐','唐诗','tang','','["\u65b0\u4e50\u5e9c\u8f9e", "\u51ac\u5929", "\u4e50\u5e9c"]','賣炭翁，伐薪燒炭南山中。',156,'全唐诗/poet.tang.22000.json','["賣炭翁，伐薪燒炭南山中。", "滿面塵灰煙火色，兩鬢蒼蒼十指黑。", "賣炭得錢何所營，身上衣裳口中食。", "可憐身上衣正單，心憂炭賤願天寒。", "夜來城上一尺雪，曉駕炭車輾冰轍。", "牛困人飢日已高，市南門外泥中歇。", "翩翩兩騎來是誰，黃衣使者白衫兒。", "手把文書口稱敕，迴車叱牛牽向北。", "一車炭，千餘斤，官使驅將惜不得。", "半匹紅紗一丈綾，繫向牛頭充炭直。"]'),
('572792cc-60ac-4b58-87fa-836f0f7d7b00','新樂府 母別子	刺新間舊也','白居易','唐','唐诗','tang','','["\u79bb\u522b", "\u6bcd\u4eb2"]','母別子，子別母，白日無光哭聲苦。',176,'全唐诗/poet.tang.22000.json','["母別子，子別母，白日無光哭聲苦。", "關西驃騎大將軍，去年破虜新策勳。", "敕賜金錢二百萬，洛陽迎得如花人。", "新人迎來舊人棄，掌上蓮花眼中刺。", "迎新棄舊未足悲，悲在君家留兩兒。", "一始扶行一初坐，坐啼行哭牽人衣。", "以汝夫婦新燕婉，使我母子生別離。", "不如林中烏與鵲，母不失雛雄伴雌。", "應似園中桃李樹，花落隨風子在枝。", "新人新人聽我語，洛陽無限紅樓女。", "但願將軍重立功，更有新人勝於汝。"]'),
('f81bd1e9-faef-44b9-83a4-1066d6e690f8','新樂府 陰山道	疾貪虜也','白居易','唐','唐诗','tang','','[]','陰山道，陰山道，紇邏敦肥水泉好。',208,'全唐诗/poet.tang.22000.json','["陰山道，陰山道，紇邏敦肥水泉好。", "每至戎人送馬時，道旁千里無纖草。", "草盡泉枯馬病羸，飛龍但印骨與皮。", "五十匹縑易一匹，縑去馬來無了日。", "養無所用去非宜，每歲死傷十六七。", "縑絲不足女工苦，疎織短截充匹數。", "藕絲蛛網三丈餘，迴紇訴稱無用處。", "咸安公主號可敦，遠爲可汗頻奏論。", "元和二年下新敕，內出金帛酬馬直。", "仍詔江淮馬價縑，從此不令疎短織。", "合羅將軍呼萬歲，捧授金銀與縑綵。", "誰知黠虜啓貪心，明年馬多來一倍。", "縑漸好，馬漸多，陰山虜，奈爾何。"]'),
('d48559df-00e3-499c-b62a-e78bf137d86a','新樂府 時世妝	儆戎也','白居易','唐','唐诗','tang','','[]','時世妝，時世妝，出自城中傳四方。',112,'全唐诗/poet.tang.22000.json','["時世妝，時世妝，出自城中傳四方。", "時世流行無遠近，顋不施朱面無粉。", "烏膏注脣脣似泥，雙眉畫作八字低。", "妍媸黑白失本態，妝成盡似含悲啼。", "圓鬟無鬢堆髻樣，斜紅不暈赭面狀。", "昔聞被髮伊川中，辛有見之知有戎。", "元和妝梳君記取，髻堆面赭非華風。"]'),
('29be46eb-568b-419f-b5d3-9110e65dea67','新樂府 李夫人	鑒嬖惑也','白居易','唐','唐诗','tang','','[]','漢武帝，初喪李夫人。',286,'全唐诗/poet.tang.22000.json','["漢武帝，初喪李夫人。", "夫人病時不肯別，死後留得生前恩。", "君恩不盡念未已，甘泉殿裏令寫真。", "丹青畫出竟何益，不言不笑愁殺人。", "又令方士合靈藥，玉釜煎鍊金鑪焚。", "九華帳深夜悄悄，反魂香降夫人魂。", "夫人之魂在何許，香煙引到焚香處。", "既來何苦不須臾，縹緲悠揚還滅去。", "去何速兮來何遲，是耶非耶兩不知。", "翠蛾髣髴平生貌，不似昭陽寢疾時。", "魂之不來君心苦，魂之來兮君亦悲。", "背燈隔帳不得語，安用暫來還見違。", "傷心不獨漢武帝，自古及今皆若斯。", "君不見穆王三日哭，重璧臺前傷盛姬。", "又不見泰陵一掬淚，馬嵬坡下念楊妃。", "縱令妍姿豔質化爲土，此恨長在無銷期。", "生亦惑，死亦惑，尤物惑人忘不得。", "人非木石皆有情，不如不遇傾城色。"]'),
('6d47c928-e6dd-4417-a9a5-acb7d4272e84','新樂府 陵園妾	憐幽閉也','白居易','唐','唐诗','tang','','[]','陵園妾，顏色如花命如葉。',248,'全唐诗/poet.tang.22000.json','["陵園妾，顏色如花命如葉。", "命如葉薄將奈何，一奉寢宮年月多。", "年月多，時光換，春愁秋思知何限。", "青絲髮落叢鬢疎，紅玉膚銷繫帬慢。", "憶昔宮中被妬猜，因讒得罪配陵來。", "老母啼呼趁車別，中官監送鏁門迴。", "山宮一閉無開日，未死此身不令出。", "松門到曉月裴回，柏城盡日風蕭瑟。", "松門柏城幽閉深，聞蟬聽燕感光陰。", "眼看菊蘂重陽淚，手把棃花寒食心。", "把花掩淚無人見，綠蕪牆繞青苔院。", "四季徒支妝粉錢，三朝不識君王面。", "遙想六宮奉至尊，宣徽雪夜浴堂春。", "雨露之恩不及者，猶聞不啻三千人。", "三千人，我爾君恩何厚薄。", "願令輪轉直陵園，三歲一來均苦樂。"]'),
('88f00440-4d69-468b-b043-7962fa0cf3d1','新樂府 鹽商婦	惡幸人也','白居易','唐','唐诗','tang','','[]','鹽商婦，多金帛，不事田農與蠶績。',214,'全唐诗/poet.tang.22000.json','["鹽商婦，多金帛，不事田農與蠶績。", "南北東西不失家，風水爲鄉船作宅。", "本是揚州小家女，嫁得西江大商客。", "綠鬟富去金釵多，皓腕肥來銀釧窄。", "前呼蒼頭後叱婢，問爾因何得如此。", "壻作鹽商十五年，不屬州縣屬天子。", "每年鹽利入官時，少入官家多入私。", "官家利薄私家厚，鹽鐵尚書遠不知。", "何況江頭魚米賤，紅膾黃橙香稻飯。", "飽食濃妝倚柁樓，兩朵紅顋花欲綻。", "鹽商婦，有幸嫁鹽商。", "終朝美飯食，終歲好衣裳。", "好衣美食來何處，亦須慙媿桑弘羊。", "桑弘羊，死已久，不獨漢時今亦有。"]'),
('0973992e-aa63-4570-b3be-b0991b326f5c','新樂府 杏爲梁	刺居處僭也','白居易','唐','唐诗','tang','','[]','杏爲梁，桂爲柱，何人堂室李開府。',198,'全唐诗/poet.tang.22000.json','["杏爲梁，桂爲柱，何人堂室李開府。", "碧砌紅軒色未乾，去年身歿今移主。", "高其牆，大其門，誰家第宅盧將軍。", "素泥朱版光未滅，今日官收別賜人。", "開府之堂將軍宅，造未成時頭已白。", "逆旅重居逆旅中，心是主人身是客。", "更有愚夫念身後，心雖甚長計非久。", "窮奢極麗越規模，付子傳孫令保守。", "莫教門外過客聞，撫掌回頭笑殺君。", "君不見馬家宅，尚猶存，宅門題作奉誠園。", "君不見魏家宅，屬他人，詔贖賜還五代孫。", "儉存奢失今在目，安用高牆圍大屋。"]'),
('68553c8b-65c4-43d4-939b-d11b27ffa05f','新樂府 井底引銀缾	止淫奔也','白居易','唐','唐诗','tang','','[]','井底引銀缾，銀缾欲上絲繩絕。',264,'全唐诗/poet.tang.22000.json','["井底引銀缾，銀缾欲上絲繩絕。", "石上磨玉簪，玉簪欲成中央折。", "缾沈簪折知奈何，似妾今朝與君別。", "憶昔在家爲女時，人言舉動有殊姿。", "嬋娟兩鬢秋蟬翼，宛轉雙蛾遠山色。", "笑隨戲伴後園中，此時與君未相識。", "妾弄青梅憑短牆，君騎白馬傍垂楊。", "牆頭馬上遙相顧，一見知君即斷腸。", "知君斷腸共君語，君指南山松柏樹。", "感君松柏化爲心，闇合雙鬟逐君去。", "到君家舍五六年，君家大人頻有言。", "聘則爲妻奔是妾，不堪主祀奉蘋蘩。", "終知君家不可住，其奈出門無去處。", "豈無父母在高堂，亦有親情滿故鄉。", "潛來更不通消息，今日悲羞歸不得。", "爲君一日恩，誤妾百年身。", "寄言癡小人家女，慎勿將身輕許人。"]'),
('a987d989-8c70-482d-becf-a79479ca0f68','新樂府 官牛		諷執政也','白居易','唐','唐诗','tang','','[]','官牛官牛駕官車，滻水岸邊般載沙。',106,'全唐诗/poet.tang.22000.json','["官牛官牛駕官車，滻水岸邊般載沙。", "一石沙，幾斤重，朝載暮載將何用。", "載向五門官道西，綠槐陰下鋪沙堤。", "昨來新拜右丞相，恐怕泥塗汚馬蹄。", "右丞相，馬蹄蹋沙雖淨潔，牛領牽車欲流血。", "右丞相，但能濟人治國調陰陽，官牛領穿亦無妨。"]'),
('88ed338f-17a4-4a27-8f74-fc824b57735b','新樂府 紫毫筆	譏失職也','白居易','唐','唐诗','tang','','[]','紫毫筆，尖如錐兮利如刀。',172,'全唐诗/poet.tang.22000.json','["紫毫筆，尖如錐兮利如刀。", "江南石上有老兔，喫竹飲泉生紫毫。", "宣城之人采爲筆，千萬毛中揀一毫。", "毫雖輕，功甚重，管勒工名充歲貢。", "君兮臣兮勿輕用，勿輕用，將何如。", "願賜東西府御史，願頒左右臺起居。", "搦管趨入黃金闕，抽毫立在白玉除。", "臣有奸邪正衙奏，君有動言直筆書。", "起居郎，侍御史，爾知紫毫不易致。", "每歲宣城進筆時，紫毫之價如金貴。", "慎勿空將彈失儀，慎勿空將錄制詞。"]'),
('ef3c51b2-f0a5-4d9b-8ae3-2a24b342ddee','新樂府 隋堤柳	憫亡國也','白居易','唐','唐诗','tang','','["\u9ec4\u6cb3"]','隋堤柳，歲久年深盡衰朽。',256,'全唐诗/poet.tang.22000.json','["隋堤柳，歲久年深盡衰朽。", "風飄飄兮雨蕭蕭，三株兩株汴河口。", "老枝病葉愁殺人，曾經大業年中春。", "大業年中煬天子，種柳成行夾流水。", "西自黃河東至淮，綠陰一千三百里。", "大業末年春暮月，柳色如煙絮如雪。", "南幸江都恣佚遊，應將此柳繫龍舟。", "紫髯郎將護錦纜，青娥御史直迷樓。", "海內財力此時竭，舟中歌笑何日休。", "上荒下困勢不久，宗社之危如綴旒。", "煬天子，自言福祚長無窮，豈知皇子封酅公。", "龍舟未過彭城閤，義旗已入長安宮。", "蕭牆禍生人事變，晏駕不得歸秦中。", "土墳數尺何處葬，吳公臺下多悲風。", "二百年來汴河路，沙草和煙朝復暮。", "後王何以鑒前王，請看隋堤亡國樹。"]'),
('574d431d-12ab-493d-96d3-41a76871015c','新樂府 草茫茫	懲厚葬也','白居易','唐','唐诗','tang','','[]','草茫茫，土蒼蒼，蒼蒼茫茫在何處，驪山脚下秦皇墓。',136,'全唐诗/poet.tang.22000.json','["草茫茫，土蒼蒼，蒼蒼茫茫在何處，驪山脚下秦皇墓。", "墓中下涸二重泉，當時自以爲深固。", "下流水銀象江海，上綴珠光作烏兔。", "別爲天地於其間，擬將富貴隨身去。", "一朝盜掘墳陵破，龍椁神堂三月火。", "可憐寶玉歸人間，暫借泉中買身禍。", "奢者狼藉儉者安，一凶一吉在眼前。", "憑君回首向南望，漢文葬在霸陵原。"]'),
('3e4acce7-ecde-492c-9935-9a77ea798fdc','新樂府 古冢狐	戒豔色也','白居易','唐','唐诗','tang','','[]','古冢狐，妖且老，化爲婦人顏色好。',178,'全唐诗/poet.tang.22000.json','["古冢狐，妖且老，化爲婦人顏色好。", "頭變雲鬟面變妝，大尾曳作長紅裳。", "徐徐行傍荒村路，日欲暮時人靜處。", "或歌或舞或悲啼，翠眉不舉花顏低。", "忽然一笑千萬態，見者十人八九迷。", "假色迷人猶若是，真色迷人應過此。", "彼真此假俱迷人，人心惡假貴重真。", "狐假女妖害猶淺，一朝一夕迷人眼。", "女爲狐媚害即深，日長月增溺人心。", "何況褒妲之色善蠱惑，能喪人家覆人國。", "君看爲害淺深間，豈將假色同真色。"]'),
('228c557f-cab0-4cff-af64-10bc32fe54cb','新樂府 黑潭龍	疾貪吏也','白居易','唐','唐诗','tang','','[]','黑潭水深黑如墨，傳有神龍人不識。',156,'全唐诗/poet.tang.22000.json','["黑潭水深黑如墨，傳有神龍人不識。", "潭上架屋官立祠，龍不能神人神之。", "豐凶水旱與疾疫，鄉里皆言龍所爲。", "家家養豚漉清酒，朝祈暮賽依巫口。", "神之來兮風飄飄，紙錢動兮錦傘搖。", "神之去兮風亦靜，香火滅兮杯盤冷。", "肉堆潭岸石，酒潑廟前草。", "不知龍神享幾多，林鼠山狐長醉飽。", "狐何幸，豚何辜，年年殺豚將餧狐。", "狐假龍神食豚盡，九重泉底龍知無。"]'),
('d001c677-bd47-4858-8928-5a772268d514','新樂府 天可度	惡詐人也','白居易','唐','唐诗','tang','','[]','天可度，地可量，唯有人心不可防。',132,'全唐诗/poet.tang.22000.json','["天可度，地可量，唯有人心不可防。", "但見丹誠赤如血，誰知僞言巧似簧。", "勸君掩鼻君莫掩，使君夫婦爲參商。", "勸君掇蠭君莫掇，使君父子成豺狼。", "海底魚兮天上鳥，高可射兮深可釣。", "唯有人心相對時，咫尺之間不能料。", "君不見李義府之輩笑欣欣，笑中有刀潛殺人。", "陰陽神變皆可測，不測人間笑是瞋。"]'),
('e732b73e-7503-4d41-a34b-40840a9f157f','新樂府 秦吉了	哀冤民也','白居易','唐','唐诗','tang','','[]','秦吉了，出南中，彩毛青黑花頸紅。',153,'全唐诗/poet.tang.22000.json','["秦吉了，出南中，彩毛青黑花頸紅。", "耳聰心慧舌端巧，鳥語人言無不通。", "昨日長爪鳶，今朝大觜烏。", "鳶捎乳燕一窠覆，烏琢母雞雙眼枯。", "雞號墮地燕驚去，然後拾卵攫其雛。", "豈無鵰與鶚，嗉中肉飽不肯搏。", "亦有鸞鶴羣，閑立高颺如不聞。", "秦吉了，人云爾是能言鳥。", "豈不見雞燕之冤苦，吾聞鳳皇百鳥主。", "爾竟不爲鳳皇之前致一言，安用噪噪閑言語。"]'),
('31b00468-ec56-421b-916d-bafc8bb50ea7','新樂府 鵶九劒	思決壅也','白居易','唐','唐诗','tang','','[]','歐冶子死千年後，精靈闇授張鵶九。',147,'全唐诗/poet.tang.22000.json','["歐冶子死千年後，精靈闇授張鵶九。", "鵶九鑄劒吳山中，天與日時神借功。", "金鐵騰精火飜燄，踴躍求爲鏌鎁劒。", "劒成未試十餘年，有客持金買一觀。", "誰知閉匣長思用，三尺青蛇不肯蟠。", "客有心，劒無口，客代劒言告鵶九。", "君勿矜我玉可切，君勿誇我鐘可刜。", "不如持我決浮雲，無令漫漫蔽白日。", "爲君使無私之光及萬物，蟄蟲昭蘇萌草出。"]'),
('b7bac9ba-9db0-43d4-8647-5f921d7db924','新樂府 采詩官	監前王亂亡之由也','白居易','唐','唐诗','tang','','[]','采詩官，采詩聽歌導人言。',231,'全唐诗/poet.tang.22000.json','["采詩官，采詩聽歌導人言。", "言者無罪聞者誡，下流上通上下泰。", "周滅秦興至隋氏，十代采詩官不置。", "郊廟登歌贊君美，樂府豔詞悅君意。", "若求興諭規刺言，萬句千章無一字。", "不是章句無規刺，漸及朝廷絕諷議。", "諍臣杜口爲冗員，諫鼓高懸作虛器。", "一人負扆常端默，百辟入門兩自媚。", "夕郎所賀皆德音，春官每奏唯祥瑞。", "君之堂兮千里遠，君之門兮九重閟。", "君耳唯聞堂上言，君眼不見門前事。", "貪吏害民無所忌，奸臣蔽君無所畏。", "君不見厲王胡亥之末年，羣臣有利君無利。", "君兮君兮願聽此，欲開壅蔽達人情。", "先向歌詩求諷刺。"]'),
('255ad53f-1091-4dbf-94c5-c6041e2d4d0b','常樂里閑居偶題十六韻兼寄劉十五公輿王十一起呂二炅呂四熲崔十八玄亮元九稹劉三十二敦質張十五仲元時爲校書郎','白居易','唐','唐诗','tang','','[]','帝都名利場，雞鳴無安居。',192,'全唐诗/poet.tang.22000.json','["帝都名利場，雞鳴無安居。", "獨有嬾慢者，日高頭未梳。", "工拙性不同，進退迹遂殊。", "幸逢太平代，天子好文儒。", "小才難大用，典校在祕書。", "三旬兩入省，因得養頑疎。", "茅屋四五間，一馬二僕夫。", "俸錢萬六千，月給亦有餘。", "既無衣食牽，亦少人事拘。", "遂使少年心，日日常晏如。", "勿言無知己，躁靜各有徒。", "蘭臺七八人，出處與之俱。", "旬時阻談笑，旦夕望軒車。", "誰能讎校閑，解帶臥吾廬。", "窗前有竹玩，門外有酒酤。", "何以待君子，數竿對一壺。"]'),
('05ac1119-006a-497b-9e1f-574a85f5af26','荅元八宗簡同遊曲江後明日見贈','白居易','唐','唐诗','tang','','[]','長安千萬人，出門各有營。',120,'全唐诗/poet.tang.22000.json','["長安千萬人，出門各有營。", "唯我與夫子，信馬悠悠行。", "行到曲江頭，反照草樹明。", "南山好顏色，病客有心情。", "水禽飜白羽，風荷嫋翠莖。", "何必滄浪去，即此可濯纓。", "時景不重來，賞心難再幷。", "坐愁紅塵裏，夕鼓鼕鼕聲。", "歸來經一宿，世慮稍復生。", "賴聞瑤華唱，再得塵襟清。"]'),
('41df6ae1-af90-41af-8e4e-ca4920e2fb1c','感時','白居易','唐','唐诗','tang','','[]','朝見日上天，暮見日入地。',156,'全唐诗/poet.tang.22000.json','["朝見日上天，暮見日入地。", "不覺明鏡中，忽年三十四。", "勿言身未老，冉冉行將至。", "白髮雖未生，朱顏已先悴。", "人生詎幾何，在世猶如寄。", "雖有七十期，十人無一二。", "今我猶未悟，往往不適意。", "胡爲方寸間，不貯浩然氣。", "貧賤非不惡，道在何足避。", "富貴非不愛，時來當自致。", "所以達人心，外物不能累。", "唯當飲美酒，終日陶陶醉。", "斯言勝金玉，佩服無失墜。"]'),
('2d904c23-d223-46b7-9b05-7eb22c5227eb','首夏同諸校正遊開元觀因宿玩月','白居易','唐','唐诗','tang','','[]','我與二三子，策名在京師。',144,'全唐诗/poet.tang.22000.json','["我與二三子，策名在京師。", "官小無職事，閑於爲客時。", "沈沈道觀中，心賞期在茲。", "到門車馬迴，入院巾杖隨。", "清和四月初，樹木正華滋。", "風清新葉影，鳥戀殘花枝。", "向夕天又晴，東南餘霞披。", "置酒西廊下，待月杯行遲。", "須臾金魄生，若與吾徒期。", "光華一照耀，殿角相參差。", "終夜清景前，笑歌不知疲。", "長安名利地，此興幾人知。"]'),
('3ea7e704-b9b3-4436-b4a8-2595078dc3e1','永崇里觀居','白居易','唐','唐诗','tang','','[]','季夏中氣侯，煩暑自此收。',144,'全唐诗/poet.tang.22000.json','["季夏中氣侯，煩暑自此收。", "蕭颯風雨天，蟬聲暮啾啾。", "永崇里巷靜，華陽觀院幽。", "軒車不到處，滿地槐花秋。", "年光忽冉冉，世事本悠悠。", "何必待衰老，然後悟浮休。", "真隱豈長遠，至道在冥搜。", "身雖世界住，心與虛無遊。", "朝飢有蔬食，夜寒有布裘。", "幸免凍與餒，此外復何求。", "寡慾雖少病，樂天心不憂。", "何以明吾志，周易在牀頭。"]'),
('4c3a41ad-a522-413d-9c26-31f4b8b1294c','早送舉人入試','白居易','唐','唐诗','tang','','[]','夙駕送舉人，東方猶未明。',96,'全唐诗/poet.tang.22000.json','["夙駕送舉人，東方猶未明。", "自謂出太早，已有車馬行。", "騎火高低影，街鼓參差聲。", "可憐早朝者，相看意氣生。", "日出塵埃飛，羣動互營營。", "營營各何求，無非利與名。", "而我常晏起，虛住長安城。", "春深官又滿，日有歸山情。"]'),
('4325bd07-7a5c-450e-a23d-6cc75932c0a4','招王質夫','白居易','唐','唐诗','tang','','[]','濯足雲水客，折腰簪笏身。',48,'全唐诗/poet.tang.22000.json','["濯足雲水客，折腰簪笏身。", "諠閑跡相背，十里別經旬。", "忽因乘逸興，莫惜訪囂塵。", "窗前故栽竹，與君爲主人。"]'),
('df162a62-3b63-4e9f-8413-9698ff871d48','祗役駱口因與王質夫同遊秋山偶題三韻','白居易','唐','唐诗','tang','','[]','石擁百泉合，雲破千峰開。',36,'全唐诗/poet.tang.22000.json','["石擁百泉合，雲破千峰開。", "平生煙霞侶，此地重裴回。", "今日勤王意，一半爲山來。"]'),
('bc7cff00-1c5e-4afc-9088-e440a3f58fcb','見蕭侍御憶舊山草堂詩因以繼和','白居易','唐','唐诗','tang','','[]','琢玉以爲架，綴珠以爲籠。',144,'全唐诗/poet.tang.22000.json','["琢玉以爲架，綴珠以爲籠。", "玉架絆野鶴，珠籠鏁冥鴻。", "鴻思雲外天，鶴憶松上風。", "珠玉信爲美，鳥不戀其中。", "臺中蕭侍御，心與鴻鶴同。", "晚起慵冠豸，閑行厭避驄。", "昨見憶山詩，詩思浩無窮。", "歸夢杳何處，舊居茫水東。", "秋閑杉桂林，春老芝朮叢。", "自云別山後，離抱常忡忡。", "衣繡非不榮，持憲非不雄。", "所樂不在此，悵望草堂空。"]'),
('c81d9038-2d96-4d80-8634-ef3fbed89449','病假中南亭閑望','白居易','唐','唐诗','tang','','[]','欹沈不視事，兩日門掩關。',60,'全唐诗/poet.tang.22000.json','["欹沈不視事，兩日門掩關。", "始知吏役身，不病不得閑。", "閑意不在遠，小亭方丈間。", "西檐竹梢上，坐見太白山。", "遙媿峰上雲，對此塵中顏。"]'),
('73fde295-039e-4dba-9577-f0e088f1c691','仙遊寺獨宿','白居易','唐','唐诗','tang','','[]','沙鶴上階立，潭月當戶開。',48,'全唐诗/poet.tang.22000.json','["沙鶴上階立，潭月當戶開。", "此中留我宿，兩夜不能迴。", "幸與靜境遇，喜無歸侶催。", "從今獨遊後，不擬共人來。"]'),
('e6330e0b-70e6-49c1-9097-22de0dfb4d63','前庭涼夜','白居易','唐','唐诗','tang','','[]','露簟色似玉，風幌影如波。',24,'全唐诗/poet.tang.22000.json','["露簟色似玉，風幌影如波。", "坐愁樹葉落，中庭明月多。"]'),
('00fa55d3-0e0f-4c12-bf74-1f54703806d6','官舍小亭閑望','白居易','唐','唐诗','tang','','[]','風竹散清韻，煙槐凝綠姿。',96,'全唐诗/poet.tang.22000.json','["風竹散清韻，煙槐凝綠姿。", "日高人吏去，閑坐在茅茨。", "葛衣禦時暑，蔬飯療朝飢。", "持此聊自足，心力少營爲。", "亭上獨吟罷，眼前無事時。", "數峰太白雪，一卷陶潛詩。", "人心各自是，我是良在茲。", "迴謝爭名客，甘從君所嗤。"]'),
('7e941849-9edc-4cad-8f88-d466ee755d58','早秋獨夜','白居易','唐','唐诗','tang','','[]','井梧涼葉動，鄰杵秋聲發。',24,'全唐诗/poet.tang.22000.json','["井梧涼葉動，鄰杵秋聲發。", "獨向檐下眠，覺來半牀月。"]'),
('9cce7b85-d405-4249-a14e-c5327adf9ab8','聽彈古淥水','白居易','唐','唐诗','tang','','[]','聞君古淥水，使我心和平。',36,'全唐诗/poet.tang.22000.json','["聞君古淥水，使我心和平。", "欲識慢流意，爲聽疎泛聲。", "西窗竹陰下，竟日有餘清。"]'),
('3d33b371-389e-45ff-9fd8-3e04d8818b7b','松齋自題','白居易','唐','唐诗','tang','','[]','非老亦非少，年過三紀餘。',120,'全唐诗/poet.tang.22000.json','["非老亦非少，年過三紀餘。", "非賤亦非貴，朝登一命初。", "才小分易足，心寬體長舒。", "充腸皆美食，容膝即安居。", "況此松齋下，一琴數帙書。", "書不求甚解，琴聊以自娛。", "夜直入君門，晚歸臥吾廬。", "形骸委順動，方寸付空虛。", "持此將過日，自然多晏如。", "昏昏復默默，非智亦非愚。"]'),
('ea87aebe-1c09-4911-99dd-02a84078f029','冬夜與錢員外同直禁中','白居易','唐','唐诗','tang','','[]','夜深草詔罷，霜月淒凜凜。',48,'全唐诗/poet.tang.22000.json','["夜深草詔罷，霜月淒凜凜。", "欲臥暖殘杯，燈前相對飲。", "連鋪青縑被，對置通中枕。", "髣髴百餘宵，與君同此寢。"]'),
('3bd8cd7b-ab8c-434a-b442-7df532d10fcf','和錢員外禁中夙興見示','白居易','唐','唐诗','tang','','[]','窗白星漢曙，窗暖燈火餘。',72,'全唐诗/poet.tang.22000.json','["窗白星漢曙，窗暖燈火餘。", "坐卷朱裏幕，看封紫泥書。", "窅窅鐘漏盡，曈曈霞景初。", "樓臺紅照曜，松竹青扶疎。", "君愛此時好，回頭特謂余。", "不知上清界，曉景復何如。"]'),
('39a338a5-71a0-48b5-bbae-cf4a01ae1c5f','夏日獨直寄蕭侍御','白居易','唐','唐诗','tang','','[]','憲臺文法地，翰林清切司。',144,'全唐诗/poet.tang.22000.json','["憲臺文法地，翰林清切司。", "鷹猜課野鶴，驥德責山麋。", "課責雖不同，同歸非所宜。", "是以方寸內，忽忽暗相思。", "夏日獨上直，日長何所爲。", "澹然無他念，虛靜是吾師。", "形委有事牽，心與無事期。", "中臆一以曠，外累都若遺。", "地貴身不覺，意閑境來隨。", "但對松與竹，如在山中時。", "情性聊自適，吟詠偶成詩。", "此意非夫子，餘人多不知。"]'),
('a8df86e6-ec70-4b16-94ca-f7dc05d76110','松聲','白居易','唐','唐诗','tang','','[]','月好好獨坐，雙松在前軒。',96,'全唐诗/poet.tang.22000.json','["月好好獨坐，雙松在前軒。", "西南微風來，潛入枝葉間。", "蕭寥發爲聲，半夜明月前。", "寒山颯颯雨，秋琴泠泠弦。", "一聞滌炎暑，再聽破昏煩。", "竟夕遂不寐，心體俱翛然。", "南陌車馬動，西鄰歌吹繁。", "誰知茲檐下，滿耳不爲喧。"]'),
('ca5b3bd9-c96a-4534-8519-b2e4c45add4d','禁中','白居易','唐','唐诗','tang','','[]','門嚴九重靜，窗幽一室閑。',24,'全唐诗/poet.tang.22000.json','["門嚴九重靜，窗幽一室閑。", "好是修心處，何必在深山。"]'),
('4015ebaa-bed9-46a2-ab5b-af14ded716f2','贈吳丹','白居易','唐','唐诗','tang','','[]','巧者力苦勞，智者心苦憂。',192,'全唐诗/poet.tang.22000.json','["巧者力苦勞，智者心苦憂。", "愛君無巧智，終歲閑悠悠。", "嘗登御史府，亦佐東諸候。", "手操糾謬簡，心運決勝籌。", "宦途似風水，君心如虛舟。", "泛然而不有，進退得自由。", "今來脫豸冠，時往侍龍樓。", "官曹稱心靜，居處隨跡幽。", "冬負南榮日，支體甚溫柔。", "夏臥北窗風，枕席如涼秋。", "南山入舍下，酒甕在牀頭。", "人間有閑地，何必隱林丘。", "顧我愚且昧，勞生殊未休。", "一入金門直，星霜三四周。", "主恩信難報，近地徒久留。", "終當乞閑官，退與夫子遊。"]'),
('71651a11-e22e-4b14-a375-28ef4eb00c83','初除戶曹喜而言志','白居易','唐','唐诗','tang','','[]','詔授戶曹掾，捧詔感君恩。',192,'全唐诗/poet.tang.22000.json','["詔授戶曹掾，捧詔感君恩。", "感恩非爲己，祿養及吾親。", "弟兄俱簪笏，新婦儼衣巾。", "羅列高堂下，拜慶正紛紛。", "俸錢四五萬，月可奉晨昏。", "廩祿二百石，歲可盈倉囷。", "喧喧車馬來，賀客滿我門。", "不以我爲貪，知我家內貧。", "置酒延賀客，客容亦歡欣。", "笑云今日後，不復憂空尊。", "荅云如君言，願君少逡巡。", "我有平生志，醉後爲君陳。", "人生百歲期，七十有幾人。", "浮榮及虛位，皆是身之賓。", "唯有衣與食，此事粗關身。", "苟免飢寒外，餘物盡浮雲。"]'),
('f40117ce-199c-4d90-9dfd-1e2aec8992b7','秋居書懷','白居易','唐','唐诗','tang','','[]','門前少賓客，階下多松竹。',120,'全唐诗/poet.tang.22000.json','["門前少賓客，階下多松竹。", "秋景下西牆，涼風入東屋。", "有琴慵不弄，有書閑不讀。", "盡日方寸中，澹然無所欲。", "何須廣居處，不用多積蓄。", "丈室可容身，斗儲可充腹。", "況無治道術，坐受官家祿。", "不種一株桑，不鋤一壠穀。", "終朝飽飯餐，卒歲豐衣服。", "持此知媿心，自然易爲足。"]'),
('b093a901-f11c-4a34-8ff9-f7a70a7b4a56','禁中曉臥因懷王起居','白居易','唐','唐诗','tang','','[]','遲遲禁漏盡，悄悄暝鵶喧。',48,'全唐诗/poet.tang.22000.json','["遲遲禁漏盡，悄悄暝鵶喧。", "夜雨槐花落，微涼臥北軒。", "曙燈殘未滅，風簾閑自飜。", "每一得靜境，思與故人言。"]'),
('6f1666cc-532f-4fe4-ae3b-8b4b6d4b8bfa','養拙','白居易','唐','唐诗','tang','','[]','鐵柔不爲劒，木曲不爲轅。',96,'全唐诗/poet.tang.22000.json','["鐵柔不爲劒，木曲不爲轅。", "今我亦如此，愚蒙不及門。", "甘心謝名利，滅跡歸丘園。", "坐臥茅茨中，但對琴與尊。", "身去韁鎖累，耳辭朝市喧。", "逍遙無所爲，時窺五千言。", "無憂樂性場，寡欲清心源。", "始知不才者，可以探道根。"]'),
('89bcd8ba-60bf-43b9-9a15-cf3a854e5ab3','寄李十一建','白居易','唐','唐诗','tang','','[]','外事牽我形，外物誘我情。',204,'全唐诗/poet.tang.22000.json','["外事牽我形，外物誘我情。", "李君別來久，褊恡從中生。", "憶昨訪君時，立馬扣柴荆。", "有時君未起，穉子喜先迎。", "連步笑出門，衣飜冠或傾。", "埽階苔紋綠，拂榻藤陰清。", "家醞及春熟，園葵乘露烹。", "看山東亭坐，待月南原行。", "門靜唯鳥語，坊遠少鼓聲。", "相對盡日言，不及利與名。", "分手來幾時，明月三四盈。", "別時殘花落，及此新蟬鳴。", "芳歲忽已晚，離抱悵未平。", "豈不思命駕，吏職坐相縈。", "前時君有期，訪我來山城。", "心賞久云阻，言約無自輕。", "相去幸非遠，走馬一日程。"]'),
('5828171a-17ce-4335-8376-14f047f143d1','旅次華州贈袁右丞','白居易','唐','唐诗','tang','','[]','渭水綠溶溶，華山青崇崇。',120,'全唐诗/poet.tang.22000.json','["渭水綠溶溶，華山青崇崇。", "山水一何麗，君子在其中。", "才與世會合，物隨誠感通。", "德星降人福，時雨助歲功。", "化行人無訟，囹圄千日空。", "政順氣亦和，黍稷三年豐。", "客自帝城來，驅馬出關東。", "愛此一郡人，如見太古風。", "方今天子心，憂人正忡忡。", "安得天下守，盡得如袁公。"]'),
('62308253-40ca-4e67-94ff-dc9a381d9278','酬楊九弘貞長安病中見寄','白居易','唐','唐诗','tang','','[]','伏枕君寂寂，折腰我營營。',120,'全唐诗/poet.tang.22000.json','["伏枕君寂寂，折腰我營營。", "所嗟經時別，相去一宿程。", "攜手昨何時，昆明春水平。", "離郡來幾日，太白夏雲生。", "之子未得意，貧病客帝城。", "貧堅志士節，病長高人情。", "隱几自恬澹，閉門無送迎。", "龍臥心有待，鶴瘦貌彌清。", "清機發爲文，投我如振瓊。", "何以慰飢渴，捧之吟一聲。"]'),
('329e16a3-060d-43ff-9a58-7aefde5c659c','禁中寓直夢遊仙遊寺','白居易','唐','唐诗','tang','','[]','西軒草詔暇，松竹深寂寂。',48,'全唐诗/poet.tang.22000.json','["西軒草詔暇，松竹深寂寂。", "月出清風來，忽似山中夕。", "因成西南夢，夢作遊仙客。", "覺聞宮漏聲，猶謂山泉滴。"]'),
('fc874339-6253-46db-982b-a5de6f778ff0','贈王山人','白居易','唐','唐诗','tang','','[]','聞君減寢食，日聽神仙說。',96,'全唐诗/poet.tang.22000.json','["聞君減寢食，日聽神仙說。", "闇待非常人，潛求長生訣。", "言長本對短，未離生死轍。", "假使得長生，才能勝夭折。", "松樹千年朽，槿花一日歇。", "畢竟共虛空，何須誇歲月。", "彭殤徒自異，生死終無別。", "不如學無生，無生即無滅。"]'),
('755e2c6c-5aa5-4aa7-9b09-6bebb7f9d339','秋山','白居易','唐','唐诗','tang','','[]','久病曠心賞，今朝一登山。',84,'全唐诗/poet.tang.22000.json','["久病曠心賞，今朝一登山。", "山秋雲物冷，稱我清羸顏。", "白石臥可枕，青蘿行可攀。", "意中如有得，盡日不欲還。", "人生無幾何，如寄天地間。", "心有千載憂，身無一日閑。", "何時解塵網，此地來掩關。"]'),
('a153de94-91bc-4ec2-a886-35b4e13c76d9','贈能七倫','白居易','唐','唐诗','tang','','[]','澗松高百尋，四時寒森森。',96,'全唐诗/poet.tang.22000.json','["澗松高百尋，四時寒森森。", "臨風有清韻，向日無曲陰。", "如何時俗人，但賞桃李林。", "豈不知堅貞，芳馨誘其心。", "能生學爲文，氣高功亦深。", "手中一百篇，句句披沙金。", "苦節二十年，無人振陸沈。", "今我尚貧賤，徒爲爾知音。"]'),
('a2fa5c2a-a336-4139-b0d0-b7c1122837ae','題楊穎士西亭','白居易','唐','唐诗','tang','','[]','靜得亭上境，遠諧塵外蹤。',60,'全唐诗/poet.tang.22000.json','["靜得亭上境，遠諧塵外蹤。", "憑軒東南望，鳥滅山重重。", "竹露冷煩襟，杉風清病容。", "曠然宜真趣，道與心相逢。", "即此可遺世，何必蓬壺峰。"]'),
('df44ac30-d450-4f89-8ae9-9b510412d850','題贈鄭祕書徵君石溝溪隱居','白居易','唐','唐诗','tang','','[]','鄭君得自然，虛白生心胸。',180,'全唐诗/poet.tang.22000.json','["鄭君得自然，虛白生心胸。", "吸彼沆瀣精，凝爲冰雪容。", "大君貞元初，求賢致時雍。", "蒲輪入翠微，迎下天台峰。", "赤城別松喬，黃閤交夔龍。", "俛仰受三命，從容辭九重。", "出籠鶴翩翩，歸林鳳雝雝。", "在火辨良玉，經霜識貞松。", "新居寄楚山，山碧溪溶溶。", "丹竈燒煙煴，黃精花丰茸。", "蕙帳夜琴澹，桂尊春酒濃。", "時人不到處，苔石無塵蹤。", "我今何爲者，趨世身龍鍾。", "不向林壑訪，無由朝市逢。", "終當解塵纓，卜築來相從。"]'),
('22287c66-40de-4a2f-865f-678144a99da7','及第後歸覲留別諸同年','白居易','唐','唐诗','tang','','[]','十年常苦學，一上謬成名。',72,'全唐诗/poet.tang.22000.json','["十年常苦學，一上謬成名。", "擢第未爲貴，賀親方始榮。", "時輩六七人，送我出帝城。", "軒車動行色，絲管舉離聲。", "得意減別恨，半酣輕遠程。", "翩翩馬蹄疾，春日歸鄉情。"]'),
('e1ca0c5d-f373-4e84-a5d2-dda077f74303','清夜琴興','白居易','唐','唐诗','tang','','[]','月出鳥栖盡，寂然坐空林。',72,'全唐诗/poet.tang.22000.json','["月出鳥栖盡，寂然坐空林。", "是時心境閑，可以彈素琴。", "清泠由木性，恬澹隨人心。", "心積和平氣，木應正始音。", "響餘羣動息，曲罷秋夜深。", "正聲感元化，天地清沈沈。"]'),
('05d65503-db27-49a6-859f-c276c0040d2a','效陶潛體詩十六首 一','白居易','唐','唐诗','tang','','[]','不動者厚地，不息者高天。',144,'全唐诗/poet.tang.22000.json','["不動者厚地，不息者高天。", "無窮者日月，長在者山川。", "松柏與龜鶴，其壽皆千年。", "嗟嗟羣物中，而人獨不然。", "早出向朝市，暮已歸下泉。", "形質及壽命，危脆若浮煙。", "堯舜與周孔，古來稱聖賢。", "借問今何在，一去亦不還。", "我無不死藥，萬萬隨化遷。", "所未定知者，修短遲速間。", "幸及身健日，當歌一尊前。", "何必待人勸，持此自爲歡。"]'),
('bd942d20-27df-4f9d-9f01-2d541a697281','效陶潛體詩十六首 二','白居易','唐','唐诗','tang','','[]','翳翳踰月陰，沈沈連日雨。',96,'全唐诗/poet.tang.22000.json','["翳翳踰月陰，沈沈連日雨。", "開簾望天色，黃雲暗如土。", "行潦毀我墉，疾風壞我宇。", "蓬莠生庭院，泥塗失場圃。", "村深絕賓客，窗晦無儔侶。", "盡日不下牀，跳蛙時入戶。", "出門無所往，入室還獨處。", "不以酒自娛，塊然與誰語。"]'),
('5eb359a8-212d-4786-a04e-af0f32d99336','效陶潛體詩十六首 三','白居易','唐','唐诗','tang','','[]','朝飲一杯酒，冥心合元化。',108,'全唐诗/poet.tang.22000.json','["朝飲一杯酒，冥心合元化。", "兀然無所思，日高尚閑臥。", "暮讀一卷書，會意如嘉話。", "欣然有所遇，夜深猶獨坐。", "又得琴上趣，安弦有餘暇。", "復多詩中狂，下筆不能罷。", "唯茲三四事，持用度晝夜。", "所以陰雨中，經旬不出舍。", "始悟獨往人，心安時亦過。"]'),
('2ec55f28-85fe-4d72-aa8d-0695bc2657e0','效陶潛體詩十六首 四','白居易','唐','唐诗','tang','','[]','車家采桑婦，雨來苦愁悲。',156,'全唐诗/poet.tang.22000.json','["車家采桑婦，雨來苦愁悲。", "蔟蠶北堂前，雨冷不成絲。", "西家荷鋤叟，雨來亦怨咨。", "種豆南山下，雨多落爲萁。", "而我獨何幸，醞酒本無期。", "及此多雨日，正遇新熟時。", "開缾瀉尊中，玉液黃金脂。", "持玩已可悅，歡嘗有餘滋。", "一酌發好容，再酌開愁眉。", "連延四五酌，酣暢入四肢。", "忽然遺我物，誰復分是非。", "是時連夕雨，酩酊無所知。", "人心苦顛倒，反爲憂者嗤。"]'),
('63247af5-fdaf-4f14-9968-f03c387c6a73','效陶潛體詩十六首 五','白居易','唐','唐诗','tang','','[]','朝亦獨醉歌，暮亦獨醉睡。',108,'全唐诗/poet.tang.22000.json','["朝亦獨醉歌，暮亦獨醉睡。", "未盡一壺酒，已成三獨醉。", "勿嫌飲太少，且喜歡易致。", "一杯復兩杯，多不過三四。", "便得心中適，盡忘身外事。", "更復強一杯，陶然遺萬累。", "一飲一石者，徒以多爲貴。", "及其酩酊時，與我亦無異。", "笑謝多飲者，酒錢徒自費。"]'),
('eb7b663e-731d-41e2-a5ca-0b7341c09775','效陶潛體詩十六首 六','白居易','唐','唐诗','tang','','[]','天秋無片雲，地靜無纖塵。',156,'全唐诗/poet.tang.22000.json','["天秋無片雲，地靜無纖塵。", "團團新晴月，林外生白輪。", "憶昨陰霖天，連連三四旬。", "賴逢家醞熟，不覺過朝昏。", "私言雨霽後，可以罷餘尊。", "及對新月色，不醉亦愁人。", "牀頭殘酒榼，欲盡味彌淳。", "攜置南檐下，舉酌自殷勤。", "清光入杯杓，白露生衣巾。", "乃知陰與晴，安可無此君。", "我有樂府詩，成來人未聞。", "今宵醉有興，狂詠驚四鄰。", "獨賞猶復爾，何況有交親。"]'),
('455c3f96-e76e-4175-89b1-f7db6571c3ed','效陶潛體詩十六首 七','白居易','唐','唐诗','tang','','[]','中秋三五夜，明月在前軒。',132,'全唐诗/poet.tang.22000.json','["中秋三五夜，明月在前軒。", "臨觴忽不飲，憶我平生歡。", "我有同心人，邈邈崔與錢。", "我有忘形友，迢迢李與元。", "或飛青雲上，或落江湖間。", "與我不相見，於今四五年。", "我無縮地術，君非馭風仙。", "安得明月下，四人來晤言。", "良夜信難得，佳期杳無緣。", "明月又不駐，漸下西南天。", "豈無他時會，惜此清景前。"]'),
('2f47c287-251a-4f00-951d-c186f031c95d','效陶潛體詩十六首 八','白居易','唐','唐诗','tang','','[]','家醞飲已盡，村中無酒酤。',110,'全唐诗/poet.tang.22000.json','["家醞飲已盡，村中無酒酤。", "坐愁今夜醒，其奈秋懷何。", "有客忽叩門，言語一何佳。", "云是南村叟，挈榼來相過。", "且喜尊不燥，安問少與多。", "重陽雖已過，籬菊有殘花。", "歡來苦晝短，不覺夕陽斜。", "老人[勿]遽起，且待新月華。", "客去有餘趣，竟夕獨酣歌。"]'),
('778d5c9c-8299-4131-ab9c-b0a242561317','效陶潛體詩十六首 九','白居易','唐','唐诗','tang','','[]','原生衣百結，顏子食一簞。',156,'全唐诗/poet.tang.22000.json','["原生衣百結，顏子食一簞。", "歡然樂其志，有以忘飢寒。", "今我何人哉，德不及先賢。", "衣食幸相屬，胡爲不自安。", "況茲清渭曲，居處安且閑。", "榆柳百餘樹，茅茨十數間。", "寒負檐下日，熱濯澗底泉。", "日出猶未起，日入已復眠。", "西風滿村巷，清涼八月天。", "但有雞犬聲，不聞車馬喧。", "時傾一尊酒，坐望東南山。", "穉姪初學步，牽衣戲我前。", "即此自可樂，庶幾顏與原。"]'),
('f8b6c8d6-515d-4849-9cac-b4dcf377cbac','效陶潛體詩十六首 十','白居易','唐','唐诗','tang','','[]','湛湛尊中酒，有功不自伐。',156,'全唐诗/poet.tang.22000.json','["湛湛尊中酒，有功不自伐。", "不伐人不知，我今代其說。", "良將臨大敵，前驅千萬卒。", "一簞投河飲，赴死心如一。", "壯士磨匕首，勇憤氣咆𠷺。", "一酣忘報讎，四體如無骨。", "東海殺孝婦，天旱踰年月。", "一酌酹其魂，通宵雨不歇。", "咸陽秦獄氣，冤痛結爲物。", "千歲不肯散，一沃亦銷失。", "況茲兒女恨，及彼幽憂疾。", "快飲無不消，如霜得春日。", "方知麴糵靈，萬物無與匹。"]'),
('72a82b99-99c9-4434-80a6-40603ce695c9','效陶潛體詩十六首 十一','白居易','唐','唐诗','tang','','[]','煙霞隔懸圃，風波限瀛州。',156,'全唐诗/poet.tang.22000.json','["煙霞隔懸圃，風波限瀛州。", "我豈不欲往，大海路阻修。", "神仙但聞說，靈藥不可求。", "長生無得者，舉世如蜉蝣。", "逝者不重迴，存者難久留。", "踟躕未死間，何苦懷百憂。", "念此忽內熱，坐看成白頭。", "舉杯還獨飲，顧影自獻酬。", "心與口相約，未醉勿言休。", "今朝不盡醉，知有明朝不。", "不見郭門外，纍纍墳與丘。", "月明愁殺人，黃蒿風颼颼。", "死者若有知，悔不秉燭遊。"]'),
('0cc2c275-b879-4096-8b49-14016ce9f08b','效陶潛體詩十六首 十二','白居易','唐','唐诗','tang','','[]','吾聞潯陽郡，昔有陶徵君。',144,'全唐诗/poet.tang.22000.json','["吾聞潯陽郡，昔有陶徵君。", "愛酒不愛名，憂醒不憂貧。", "嘗爲彭澤令，在官纔八旬。", "愀然忽不樂，挂印著公門。", "口吟歸去來，頭戴漉酒巾。", "人吏留不得，直入故山雲。", "歸來五柳下，還以酒養真。", "人間榮與利，擺落如泥塵。", "先生去已久，紙墨有遺文。", "篇篇勸我飲，此外無所云。", "我從老大來，竊慕其爲人。", "其他不可及，且傚醉昏昏。"]'),
('bf60488c-4043-4cf3-893a-b26755c0596e','效陶潛體詩十六首 十三','白居易','唐','唐诗','tang','','[]','楚王疑忠臣，江南放屈平。',96,'全唐诗/poet.tang.22000.json','["楚王疑忠臣，江南放屈平。", "晉朝輕高士，林下棄劉伶。", "一人常獨醉，一人常獨醒。", "醒者多苦志，醉者多歡情。", "歡情信獨善，苦志竟何成。", "兀傲甕間臥，顦顇澤畔行。", "彼憂而此樂，道理甚分明。", "願君且飲酒，勿思身後名。"]'),
('e09f4a35-1c1b-41f4-a038-6919770c3d22','效陶潛體詩十六首 十四','白居易','唐','唐诗','tang','','[]','有一燕趙士，言貌甚奇瓌。',144,'全唐诗/poet.tang.22000.json','["有一燕趙士，言貌甚奇瓌。", "日日酒家去，脫衣典數杯。", "問君何落拓，云僕生草萊。", "地寒命且薄，徒抱王佐才。", "豈無濟時策，君門乏良媒。", "三獻寢不報，遲遲空手迴。", "亦有同門生，先升青雲梯。", "貴賤交道絕，朱門叩不開。", "及歸種禾黍，三歲旱爲災。", "入山燒黃白，一旦化爲灰。", "蹉跎五十餘，生世苦不諧。", "處處去不得，却歸酒中來。"]'),
('3d208efd-9a44-40e6-9bbe-748626c5a00c','效陶潛體詩十六首 十五','白居易','唐','唐诗','tang','','[]','南巷有貴人，高蓋駟馬車。',204,'全唐诗/poet.tang.22000.json','["南巷有貴人，高蓋駟馬車。", "我問何所苦，四十垂白鬚。", "荅云君不知，位重多憂虞。", "北里有寒士，甕牖繩爲樞。", "出扶桑棗杖，入臥蝸牛廬。", "散賤無憂患，心安體亦舒。", "東鄰有富翁，藏貨徧五都。", "東京收粟帛，西市鬻金珠。", "朝營暮計算，晝夜不安居。", "西舍有貧者，匹婦配匹夫。", "布帬行賃舂，裋褐坐傭書。", "以此求口食，一飽欣有餘。", "貴賤與貧富，高下雖有殊。", "憂樂與利害，彼此不相踰。", "是以達人觀，萬化同一途。", "但未知生死，勝負兩何如。", "遲疑未知間，且以酒爲娛。"]'),
('9c3699db-7445-416d-8c1f-2baecbe4654a','效陶潛體詩十六首 十六','白居易','唐','唐诗','tang','','[]','濟水澄而潔，河水渾而黃。',156,'全唐诗/poet.tang.22000.json','["濟水澄而潔，河水渾而黃。", "交流列四瀆，清濁不相傷。", "太公戰牧野，伯夷餓首陽。", "同時號賢聖，進退不相妨。", "謂天不愛民，胡爲生稻粱。", "謂天果愛民，胡爲生豺狼。", "謂神福善人，孔聖竟栖遑。", "謂神禍淫人，暴秦終霸王。", "顏回與黃憲，何辜早夭亡。", "蝮蛇與鴆鳥，何得壽延長。", "物理不可測，神道亦難量。", "舉頭仰問天，天色但蒼蒼。", "唯當多種黍，日醉手中觴。"]'),
('3b25301f-0040-41ae-a94c-58ca372eb88d','自題寫真','白居易','唐','唐诗','tang','','[]','我貌不自識，李放寫我真。',84,'全唐诗/poet.tang.22000.json','["我貌不自識，李放寫我真。", "靜觀神與骨，合是山中人。", "蒲柳質易朽，麋鹿心難馴。", "何事赤墀上，五年爲侍臣。", "況多剛狷性，難與世同塵。", "不惟非貴相，但恐生禍因。", "宜當早罷去，收取雲泉身。"]'),
('646f778f-c4ec-44ce-b7f5-adda355d5d82','遣懷','白居易','唐','唐诗','tang','','[]','寓心身體中，寓性方寸內。',96,'全唐诗/poet.tang.22000.json','["寓心身體中，寓性方寸內。", "此身是外物，何足苦憂愛。", "況有假飾者，華簪及高蓋。", "此又疎於身，復在外物外。", "操之多惴慄，失之又悲悔。", "乃知名與器，得喪俱爲害。", "頹然環堵客，蘿蕙爲巾帶。", "自得此道來，身窮心甚泰。"]'),
('89e6c303-aa37-4256-988b-b49a910cf875','渭上偶釣','白居易','唐','唐诗','tang','','[]','渭水如鏡色，中有鯉與魴。',108,'全唐诗/poet.tang.22000.json','["渭水如鏡色，中有鯉與魴。", "偶持一竿竹，懸釣在其傍。", "微風吹釣絲，嫋嫋十尺長。", "誰知對魚坐，心在無何鄉。", "昔有白頭人，亦釣此渭陽。", "釣人不釣魚，七十得文王。", "況我垂釣意，人魚又兼忘。", "無機兩不得，但弄秋水光。", "興盡釣亦罷，歸來飲我觴。"]'),
('f4c24922-4611-4d65-a3d5-fd3c8afb0bfa','隱几','白居易','唐','唐诗','tang','','[]','身適忘四支，心適忘是非。',84,'全唐诗/poet.tang.22000.json','["身適忘四支，心適忘是非。", "既適又忘適，不知吾是誰。", "百體如槁木，兀然無所知。", "方寸如死灰，寂然無所思。", "今日復明日，身心忽兩遺。", "行年三十九，歲暮日斜時。", "四十心不動，吾今其庶幾。"]'),
('100d4d7b-b17d-4349-af23-b77217a27792','春眠','白居易','唐','唐诗','tang','','[]','新浴肢體暢，獨寢神魂安。',96,'全唐诗/poet.tang.22000.json','["新浴肢體暢，獨寢神魂安。", "況因夜深坐，遂成日高眠。", "春被薄亦暖，朝窗深更閑。", "却忘人間事，似得枕上仙。", "至適無夢想，大和難名言。", "全勝彭澤醉，欲敵曹溪禪。", "何物呼我覺，伯勞聲關關。", "起來妻子笑，生計春茫然。"]'),
('9599cedd-119a-4144-bcb6-efc36492bdf7','閑居','白居易','唐','唐诗','tang','','[]','空腹一醆粥，飢食有餘味。',108,'全唐诗/poet.tang.22000.json','["空腹一醆粥，飢食有餘味。", "南檐半牀日，暖臥因成睡。", "緜袍擁兩膝，竹几支雙臂。", "從旦直至昏，身心一無事。", "心足即爲富，身閑乃當貴。", "富貴在此中，何必居高位。", "君看裴相國，金紫光照地。", "心苦頭盡白，纔年四十四。", "乃知高蓋車，乘者多憂畏。"]'),
('c71310ad-4a41-4943-8b6e-fc6ca3a0232a','夏日','白居易','唐','唐诗','tang','','[]','東窗晚無熱，北戶涼有風。',36,'全唐诗/poet.tang.22000.json','["東窗晚無熱，北戶涼有風。", "盡日坐復臥，不離一室中。", "中心本無繫，亦與出門同。"]'),
('9e2c7980-5c28-43ed-9cf1-eb5a9486dc51','適意二首 一','白居易','唐','唐诗','tang','','[]','十年爲旅客，常有飢寒愁。',120,'全唐诗/poet.tang.22000.json','["十年爲旅客，常有飢寒愁。", "三年作諫官，復多尸素羞。", "有酒不暇飲，有山不得遊。", "豈無平生志，拘牽不自由。", "一朝歸渭上，泛如不繫舟。", "置心世事外，無喜亦無憂。", "終日一蔬食，終年一布裘。", "寒來彌嬾放，數日一梳頭。", "朝睡足始起，夜酌醉即休。", "人心不過適，適外復何求。"]'),
('9a20cfc9-c169-4fd9-a3a0-259c0f13915c','適意二首 二','白居易','唐','唐诗','tang','','[]','早歲從旅遊，頗諳時俗意。',108,'全唐诗/poet.tang.22000.json','["早歲從旅遊，頗諳時俗意。", "中年忝班列，備見朝廷事。", "作客誠已難，爲臣尤不易。", "況余方且介，舉動多忤累。", "直道速我尤，詭遇非吾志。", "胸中十年內，消盡浩然氣。", "自從返田畝，頓覺無憂媿。", "蟠木用難施，浮雲心易遂。", "悠悠身與世，從此兩相棄。"]'),
('b852ffda-f2fc-490b-8744-f4048c17e7ca','首夏病間','白居易','唐','唐诗','tang','','[]','我生來幾時，萬有四千日。',108,'全唐诗/poet.tang.22000.json','["我生來幾時，萬有四千日。", "自省於其間，非憂即有疾。", "老去慮漸息，年來病初愈。", "忽喜身與心，泰然兩無苦。", "況茲孟夏月，清和好時節。", "微風吹裌衣，不寒復不熱。", "移榻樹陰下，竟日何所爲。", "或飲一甌茗，或吟兩句詩。", "內無憂患迫，外無職役羈。"]'),
('c720ef6c-cdc2-41e5-ad2a-6edffff34ea2','晚春酤酒','白居易','唐','唐诗','tang','','[]','百花落如雪，兩鬢垂作絲。',96,'全唐诗/poet.tang.22000.json','["百花落如雪，兩鬢垂作絲。", "春去有來日，我老無少時。", "人生待富貴，爲樂常苦遲。", "不如貧賤日，隨分開愁眉。", "賣我所乘馬，典我舊朝衣。", "盡將酤酒飲，酩酊步行歸。", "名姓日隱晦，形骸日變衰。", "醉臥黃公肆，人知我是誰。"]'),
('b5e4b04e-04c3-467e-877c-8d3b7ab5e567','蘭若寓居','白居易','唐','唐诗','tang','','[]','名宦老慵求，退身安草野。',72,'全唐诗/poet.tang.22000.json','["名宦老慵求，退身安草野。", "家園病嬾歸，寄居在蘭若。", "薜衣換簪組，藜杖代車馬。", "行止輒自由，甚覺身瀟灑。", "晨遊南塢上，夜息東庵下。", "人間千萬事，無有關心者。"]'),
('b634dfac-b739-4132-87cb-5f342f75d83a','麴生訪宿','白居易','唐','唐诗','tang','','[]','西齋寂已暮，叩門聲樀樀。',60,'全唐诗/poet.tang.22000.json','["西齋寂已暮，叩門聲樀樀。", "知是君宿來，自拂塵埃席。", "村家何所有，茶果迎來客。", "貧靜似僧居，竹林依四壁。", "廚燈斜影出，檐雨餘聲滴。"]'),
('d3db5fae-efc6-4076-a30b-f5844c9fcfee','聞庾七左降因詠所懷','白居易','唐','唐诗','tang','','[]','我病臥渭北，君老謫巴東。',120,'全唐诗/poet.tang.22000.json','["我病臥渭北，君老謫巴東。", "相悲一長歎，薄命與君同。", "既歎還自哂，哂歎兩未終。", "後心誚前意，所見何迷蒙。", "人生大塊間，如鴻毛在風。", "或飄青雲上，或落泥塗中。", "衮服相天下，儻來非我通。", "布衣委草莽，偶去非吾窮。", "外物不可必，中懷須自空。", "無令怏怏氣，留滯在心胸。"]'),
('bdf08941-65a2-4477-845b-61bdd13c9040','荅卜者','白居易','唐','唐诗','tang','','[]','病眼昏似夜，衰鬢颯如秋。',48,'全唐诗/poet.tang.22000.json','["病眼昏似夜，衰鬢颯如秋。", "除却須衣食，平生百事休。", "知君善易者，問我決疑不。", "不卜非他故，人間無所求。"]'),
('e2fb4f68-8944-47f0-8ffe-2f8bfc0c874c','歸田三首 一','白居易','唐','唐诗','tang','','[]','人生何所欲，所欲唯兩端。',84,'全唐诗/poet.tang.22000.json','["人生何所欲，所欲唯兩端。", "中人愛富貴，高士慕神仙。", "神仙須有籍，富貴亦在天。", "莫戀長安道，莫尋方丈山。", "西京塵浩浩，東海浪漫漫。", "金門不可入，琪樹何由攀。", "不如歸山下，如法種春田。"]'),
('c73c782a-3f4f-4466-a766-95e6fcd903aa','歸田三首 二','白居易','唐','唐诗','tang','','[]','種田意已決，決意復何如。',120,'全唐诗/poet.tang.22000.json','["種田意已決，決意復何如。", "賣馬買犢使，徒步歸田廬。", "迎春治耒耜，候雨闢菑畬。", "策杖田頭立，躬親課僕夫。", "吾聞老農言，爲稼慎在初。", "所施不鹵莽，其報必有餘。", "上求奉王稅，下望備家儲。", "安得放慵惰，拱手而曳裾。", "學農未爲鄙，親友勿笑余。", "更待明年後，自擬執犂鋤。"]'),
('ea9c4952-d7e9-4507-8d16-06a6a450c62c','歸田三首 三','白居易','唐','唐诗','tang','','[]','三十爲近臣，腰間鳴佩玉。',144,'全唐诗/poet.tang.22000.json','["三十爲近臣，腰間鳴佩玉。", "四十爲野夫，田中學鋤穀。", "何言十年內，變化如此速。", "此理固是常，窮通相倚伏。", "爲魚有深水，爲鳥有高木。", "何必守一方，窘然自牽束。", "化吾足爲馬，吾因以行陸。", "化吾手爲彈，吾因以求肉。", "形骸爲異物，委順心猶足。", "幸得且歸農，安知不爲福。", "況吾行欲老，瞥若風前燭。", "孰能俄頃間，將心繫榮辱。"]'),
('850812cc-ff9b-4b70-b64b-c2252ff1b460','秋遊原上','白居易','唐','唐诗','tang','','[]','七月行已半，早涼天氣清。',132,'全唐诗/poet.tang.22000.json','["七月行已半，早涼天氣清。", "清晨起巾櫛，徐步出柴荆。", "露杖筇竹冷，風襟越蕉輕。", "閑攜弟姪輩，同上秋原行。", "新棗未全赤，晚瓜有餘馨。", "依依田家叟，設此相逢迎。", "自我到此村，往來白髮生。", "村中相識久，老幼皆有情。", "留連向暮歸，樹樹風蟬聲。", "是時新雨足，禾黍夾道青。", "見此令人飽，何必待西成。"]'),
('a8ce0e24-c5d4-4029-9b42-0bc01ef0692a','九日登西原宴望','白居易','唐','唐诗','tang','','[]','病愛枕席涼，日高眠未輟。',132,'全唐诗/poet.tang.22000.json','["病愛枕席涼，日高眠未輟。", "弟兄呼我起，今日重陽節。", "起登西原望，懷抱同一豁。", "移座就菊叢，餻酒前羅列。", "雖無絲與管，歌笑隨情發。", "白日未及傾，顏酡耳已熱。", "酒酣四向望，六合何空闊。", "天地自久長，斯人幾時活。", "請看原下村，村人死不歇。", "一村四十家，哭葬無虛月。", "指此各相勉，良辰且歡悅。"]'),
('e6244ff7-d8a1-42a3-93d7-db4efc6e08c7','寄同病者','白居易','唐','唐诗','tang','','[]','三十生二毛，早衰爲沈疴。',120,'全唐诗/poet.tang.22000.json','["三十生二毛，早衰爲沈疴。", "四十官七品，拙宦非由他。", "年顏日枯槁，時命日蹉跎。", "豈獨我如此，聖賢無奈何。", "迴觀親舊中，舉目尤可嗟。", "或有終老者，沈賤如泥沙。", "或有始壯者，飄忽如風花。", "窮餓與夭促，不如我者多。", "以此反自慰，常得心平和。", "寄言同病者，迴歎且爲歌。"]'),
('52624350-b963-4cd2-85de-22327c0d4f7d','遊藍田山卜居','白居易','唐','唐诗','tang','','[]','脫置腰下組，擺落心中塵。',60,'全唐诗/poet.tang.22000.json','["脫置腰下組，擺落心中塵。", "行歌望山去，意似歸鄉人。", "朝蹋玉峰下，暮尋藍水濱。", "擬求幽僻地，安置疎慵身。", "本性便山寺，應須旁悟真。"]'),
('ca89fae6-22a5-48aa-a3fc-a580694efb0d','村雪夜坐','白居易','唐','唐诗','tang','','[]','南窗背燈坐，風霰暗紛紛。',24,'全唐诗/poet.tang.22000.json','["南窗背燈坐，風霰暗紛紛。", "寂莫深村夜，殘雁雪中聞。"]'),
('0f0fc2c7-01ca-4d6b-93b9-f41de3efca31','東園玩菊','白居易','唐','唐诗','tang','','[]','少年昨已去，芳歲今又闌。',144,'全唐诗/poet.tang.22000.json','["少年昨已去，芳歲今又闌。", "如何寂莫意，復此荒涼園。", "園中獨立久，日澹風露寒。", "秋蔬盡蕪沒，好樹亦凋殘。", "唯有數叢菊，新開籬落間。", "攜觴聊就酌，爲爾一留連。", "憶我少小日，易爲興所牽。", "見酒無時節，未飲已欣然。", "近從年長來，漸覺取樂難。", "常恐更衰老，強飲亦無歡。", "顧謂爾菊花，後時何獨鮮。", "誠知不爲我，借爾暫開顏。"]'),
('7da9ea30-865f-4949-b053-7e5d29392c74','觀稼','白居易','唐','唐诗','tang','','[]','世役不我牽，身心常自若。',144,'全唐诗/poet.tang.22000.json','["世役不我牽，身心常自若。", "晚出看田畝，閑行旁村落。", "纍纍繞場稼，嘖嘖羣飛雀。", "年豐豈獨人，禽鳥聲亦樂。", "田翁逢我喜，默起具尊杓。", "斂手笑相延，社酒有殘酌。", "媿茲勤且敬，藜杖爲淹泊。", "言動任天真，未覺農人惡。", "停杯問生事，夫種妻兒穫。", "筋力苦疲勞，衣食常單薄。", "自慙祿仕者，曾不營農作。", "飽食無所勞，何殊衛人鶴。"]'),
('590e105b-be7e-42d6-98a5-e206ce7a1dc0','聞哭者','白居易','唐','唐诗','tang','','[]','昨日南鄰哭，哭聲一何苦。',96,'全唐诗/poet.tang.22000.json','["昨日南鄰哭，哭聲一何苦。", "云是妻哭夫，夫年二十五。", "今朝北里哭，哭聲又何切。", "云是母哭兒，兒年十七八。", "四鄰尚如此，天下多夭折。", "乃知浮世人，少得垂白髮。", "余今過四十，念彼聊自悅。", "從此明鏡中，不嫌頭似雪。"]'),
('2ea52501-9638-4dae-be7a-02b8f8010973','新構亭臺示諸弟姪','白居易','唐','唐诗','tang','','[]','平臺高數尺，臺上結茅茨。',132,'全唐诗/poet.tang.22000.json','["平臺高數尺，臺上結茅茨。", "東西疏二牖，南北開兩扉。", "蘆簾前後卷，竹簟當中施。", "清泠白石枕，疏涼黃葛衣。", "開襟向風坐，夏日如秋時。", "嘯傲頗有趣，窺臨不知疲。", "東窗對華山，三峰碧參差。", "南檐當渭水，臥見雲帆飛。", "仰摘枝上果，俯折畦中葵。", "足以充飢渴，何必慕甘肥。", "況有好羣從，旦夕相追隨。"]'),
('c8872c66-d342-4afc-8833-8ad72889f26d','自吟拙什因有所懷','白居易','唐','唐诗','tang','','[]','嬾病每多暇，暇來何所爲。',108,'全唐诗/poet.tang.22000.json','["嬾病每多暇，暇來何所爲。", "未能拋筆研，時作一篇詩。", "詩成澹無味，多被衆人嗤。", "上怪落聲韻，下嫌拙言詞。", "時時自吟詠，吟罷有所思。", "蘇州及彭澤，與我不同時。", "此外復誰愛，唯有元微之。", "謫向江陵府，三年作判司。", "向去二千里，詩成遠不知。"]'),
('a69536ea-c876-479a-8bfe-b49b07559f56','東坡秋意寄元八','白居易','唐','唐诗','tang','','[]','寥落野陂畔，獨行思有餘。',96,'全唐诗/poet.tang.22000.json','["寥落野陂畔，獨行思有餘。", "秋荷病葉上，白露大如珠。", "忽憶同賞地，曲江東北隅。", "秋池少遊客，唯我與君俱。", "啼蛩隱紅蓼，瘦馬蹋青蕪。", "當時與今日，俱是暮秋初。", "節物苦相似，時景亦無餘。", "唯有人分散，經年不得書。"]'),
('6d4e9331-73c1-41c1-955e-99136a295d1e','閑居','白居易','唐','唐诗','tang','','[]','深閉竹間扉，靜埽松下地。',48,'全唐诗/poet.tang.22000.json','["深閉竹間扉，靜埽松下地。", "獨嘯晚風前，何人知此意。", "看山盡日坐，枕帙移時睡。", "誰能從我遊，使君心無事。"]'),
('4436f0c3-1c8a-4ba7-9d81-8a63ebc85eda','詠拙','白居易','唐','唐诗','tang','','[]','所稟有巧拙，不可改者性。',192,'全唐诗/poet.tang.22000.json','["所稟有巧拙，不可改者性。", "所賦有厚薄，不可移者命。", "我性愚且惷，我命薄且屯。", "問我何以知，所知良有因。", "亦曾舉兩足，學人蹋紅塵。", "從茲知性拙，不解轉如輪。", "亦曾奮六翮，高飛到青雲。", "從茲知命薄，摧落不逡巡。", "慕貴而厭賤，樂富而惡貧。", "同此天地間，我豈異於人。", "性命苟如此，反則成苦辛。", "以此自安分，雖窮每欣欣。", "葺茅爲我廬，編蓬爲我門。", "縫布作袍被，種穀充盤飧。", "靜讀古人書，閑釣清渭濱。", "優哉復游哉，聊以終吾身。"]'),
('5a17f6c9-15bb-408e-b948-e2b80b5bff85','詠慵','白居易','唐','唐诗','tang','','[]','有官慵不選，有田慵不農。',96,'全唐诗/poet.tang.22000.json','["有官慵不選，有田慵不農。", "屋穿慵不葺，衣裂慵不縫。", "有酒慵不酌，無異尊常空。", "有琴慵不彈，亦與無弦同。", "家人告飯盡，欲炊慵不舂。", "親朋寄書至，欲讀慵開封。", "嘗聞嵇叔夜，一生在慵中。", "彈琴復鍛鐵，比我未爲慵。"]'),
('d045d20d-d445-4a36-9d64-e5caa4f44f82','冬夜','白居易','唐','唐诗','tang','','[]','家貧親愛散，身病交遊罷。',96,'全唐诗/poet.tang.22000.json','["家貧親愛散，身病交遊罷。", "眼前無一人，獨掩村齋臥。", "冷落燈火闇，離披簾幕破。", "策策窗戶前，又聞新雪下。", "長年漸省睡，夜半起端坐。", "不學坐忘心，寂莫安可過。", "兀然身寄世，浩然心委化。", "如此來四年，一千三百夜。"]'),
('1721e2a0-689e-4ddc-aaf2-8dbefdae6bf7','村中留李三固言宿','白居易','唐','唐诗','tang','','[]','平生早遊宦，不道無親故。',108,'全唐诗/poet.tang.22000.json','["平生早遊宦，不道無親故。", "如我與君心，相知應有數。", "春明門前別，金氏陂中遇。", "村酒兩三杯，相留寒日暮。", "勿嫌村酒薄，聊酌論心素。", "請君少踟躕，繫馬門前樹。", "明年身若健，便擬江湖去。", "他日縱相思，知君無覓處。", "後會既茫茫，今宵君且住。"]'),
('cd0249f0-c511-4987-8d76-acccc27683bd','友人夜訪','白居易','唐','唐诗','tang','','[]','檐間清風簟，松下明月杯。',24,'全唐诗/poet.tang.22000.json','["檐間清風簟，松下明月杯。", "幽意正如此，況乃故人來。"]'),
('51f54a42-2690-4866-bb3e-82299e0f5595','遊悟真寺詩','白居易','唐','唐诗','tang','','[]','元和九年秋，八月月上弦。',288,'全唐诗/poet.tang.22000.json','["元和九年秋，八月月上弦。", "我遊悟真寺，寺在王順山。", "去山四五里，先聞水潺湲。", "自茲舍車馬，始涉藍溪灣。", "手拄青竹杖，足蹋白石灘。", "漸怪耳目曠，不聞人世喧。", "山下望山上，初疑不可攀。", "誰知中有路，盤折通巖巔。", "一息幡竿下，再休石龕邊。", "龕間長丈餘，門戶無扃關。", "仰窺不見人，石髮垂若鬟。", "驚出白蝙蝠，雙飛如雪飜。", "回首寺門望，青崖夾朱軒。", "如擘山腹開，置寺於其間。", "入門無平地，地窄虛空寬。", "房廊與臺殿，高下隨峰巒。", "巖崿無撮土，樹木多瘦堅。", "根株抱石長，屈曲蟲蛇蟠。", "松桂亂無行，四時鬱芊芊。", "枝梢嫋青翠，韻若風中弦。", "日月光不透，綠陰相交延。", "幽鳥時一聲，聞之似寒蟬。", "首憩賓位亭，就坐未及安。", "須臾開北戶，萬里明豁然。"]'),
('637abf28-c2e0-4168-a2a0-001c56c9a175','酬張十八訪宿見贈','白居易','唐','唐诗','tang','','[]','昔我爲近臣，君常稀到門。',192,'全唐诗/poet.tang.22000.json','["昔我爲近臣，君常稀到門。", "今我官職冷，君君來往頻。", "我受狷介性，立爲頑拙身。", "平生雖寡合，合即無緇磷。", "況君秉高義，富貴視如雲。", "五侯三相家，眼冷不見君。", "問其所與游，獨言韓舍人。", "其次即及我，我媿非其倫。", "胡爲謬相愛，歲晚逾勤勤。", "落然頹檐下，一話夜達晨。", "牀單食味薄，亦不嫌我貧。", "日高上馬去，相顧猶逡巡。", "長安久無雨，日赤風昏昏。", "憐君將病眼，爲我犯埃塵。", "遠從延康里，來訪曲江濱。", "所重君子道，不獨媿相親。"]'),
('1d0ed699-ddb4-47da-81da-a2e7a645dd87','朝歸書寄元八','白居易','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','進入閤前拜，退就廊下餐。',192,'全唐诗/poet.tang.22000.json','["進入閤前拜，退就廊下餐。", "歸來昭國里，人臥馬歇鞍。", "却睡至日午，起坐心浩然。", "況當好時節，雨後清和天。", "柿樹綠陰合，王家庭院寬。", "缾中鄠縣酒，牆上終南山。", "獨眠仍獨坐，開襟當風前。", "禪師與詩客，次第來相看。", "要語連夜語，須眠終日眠。", "除非奉朝謁，此外無別牽。", "年長身且健，官貧心甚安。", "幸無急病痛，不至苦飢寒。", "自此聊以適，外緣不能干。", "唯應靜者信，難爲動者言。", "臺中元侍御，早晚作郎官。", "未作郎官際，無人相伴閑。"]'),
('50ea363e-57d7-4b60-9e1b-b1e46814f74f','酬吳七見寄','白居易','唐','唐诗','tang','','[]','曲江有病客，尋常多掩關。',192,'全唐诗/poet.tang.22000.json','["曲江有病客，尋常多掩關。", "又聞馬死來，不出身更閑。", "聞有送書者，自起出門看。", "素緘署丹字，中有瓊瑤篇。", "口吟耳自聽，當暑忽翛然。", "似漱寒玉冰，如聞商風弦。", "首章歎時節，末句思笑言。", "嬾慢不相訪，隔街如隔山。", "嘗聞陶潛語，心遠地自偏。", "君住安邑里，左右車徒喧。", "竹藥閉深院，琴尊開小軒。", "誰知市南地，轉作壺中天。", "君本上清人，名在石堂間。", "不知有何過，謫作人間仙。", "常恐歲月滿，飄然歸紫煙。", "莫忘蜉蝣內，進士有同年。"]'),
('407150e0-898d-4cb8-8f4e-e6567efa2586','昭國閑居','白居易','唐','唐诗','tang','','[]','貧閑日高起，門巷晝寂寂。',96,'全唐诗/poet.tang.22000.json','["貧閑日高起，門巷晝寂寂。", "時暑放朝參，天陰少人客。", "槐花滿田地，僅絕人行跡。", "獨在一牀眠，清涼風雨夕。", "勿嫌坊曲遠，近即多牽役。", "勿嫌祿俸薄，厚即多憂責。", "平生尚恬曠，老大宜安適。", "何以養吾真，官閑居處僻。"]'),
('f58de238-d31a-4ab6-a268-6e05878ef617','喜陳兄至','白居易','唐','唐诗','tang','','[]','黃鳥啼欲歇，青梅結半成。',72,'全唐诗/poet.tang.22000.json','["黃鳥啼欲歇，青梅結半成。", "坐憐春物盡，起入東園行。", "攜觴嬾獨酌，忽聞叩門聲。", "閑人猶喜至，何況是陳兄。", "從容盡日語，稠疊長年情。", "勿輕一醆酒，可以話平生。"]'),
('b49143d9-0789-4ece-a092-3dbb25d23c98','贈杓直','白居易','唐','唐诗','tang','','[]','世路重祿位，栖栖者孔宣。',216,'全唐诗/poet.tang.22000.json','["世路重祿位，栖栖者孔宣。", "人情愛年壽，夭死者顏淵。", "二人如何人，不奈命與天。", "我今信多幸，撫己媿前賢。", "已年四十四，又爲五品官。", "況茲知足外，別有所安焉。", "早年以身代，直赴逍遙篇。", "近歲將心地，迴向南宗禪。", "外順世間法，內脫區中緣。", "進不厭朝市，退不戀人寰。", "自吾得此心，投足無不安。", "體非導引適，意無江湖閑。", "有興或飲酒，無事多掩關。", "寂靜夜深坐，安穩日高眠。", "秋不苦長夜，春不惜流年。", "委形老小外，忘懷生死間。", "昨日共君語，與余心膂然。", "此道不可道，因君聊強言。"]'),
('ffe26ceb-c8c1-4d4f-856c-cebc412e2eab','寄張十八','白居易','唐','唐诗','tang','','[]','飢止一簞食，渴止一壺漿。',132,'全唐诗/poet.tang.22000.json','["飢止一簞食，渴止一壺漿。", "出入止一馬，寢興止一牀。", "此外無長物，於我有若亡。", "胡然不知足，名利心遑遑。", "念茲彌嬾放，積習遂爲常。", "經旬不出門，竟日不下堂。", "同病者張生，貧僻住延康。", "慵中每相憶，此意未能忘。", "迢迢青槐街，相去八九坊。", "秋來未相見，應有新詩章。", "早晚來同宿，天氣轉清涼。"]'),
('e2245b36-4dc5-40d4-ac78-41c8548a5c7d','題玉泉寺','白居易','唐','唐诗','tang','','[]','湛湛玉泉色，悠悠浮雲身。',48,'全唐诗/poet.tang.22000.json','["湛湛玉泉色，悠悠浮雲身。", "閑心對定水，清靜兩無塵。", "手把青筇杖，頭戴白綸巾。", "興盡下山去，知我是誰人。"]'),
('8d98a0d7-6ea0-4fea-84ec-f01f8e34c966','朝回遊城南','白居易','唐','唐诗','tang','','[]','朝退馬未困，秋初日猶長。',108,'全唐诗/poet.tang.22000.json','["朝退馬未困，秋初日猶長。", "回轡城南去，郊野正清涼。", "水竹夾小徑，縈迴繞川岡。", "仰看晚山色，俯弄秋泉光。", "青松繫我馬，白石爲我牀。", "常時簪組累，此日和身忘。", "旦隨鵷鷺末，暮遊鷗鶴旁。", "機心一以盡，兩處不亂行。", "誰辨心與跡，非行亦非藏。"]'),
('dfefb484-4847-4b96-9fa6-b2f6a28b5dbc','舟行','白居易','唐','唐诗','tang','','[]','帆影日漸高，閑眠猶未起。',72,'全唐诗/poet.tang.22000.json','["帆影日漸高，閑眠猶未起。", "起問鼓枻人，已行三十里。", "船頭有行竈，炊稻烹紅鯉。", "飽食起婆娑，盥漱秋江水。", "平生滄浪意，一旦來遊此。", "何況不失家，舟中載妻子。"]'),
('be181d5d-0535-4760-a414-9759a37af389','湓浦早冬','白居易','唐','唐诗','tang','','[]','潯陽孟冬月，草木未全衰。',60,'全唐诗/poet.tang.22000.json','["潯陽孟冬月，草木未全衰。", "祗抵長安陌，涼風八月時。", "日西湓水曲，獨行吟舊詩。", "蓼花始零落，蒲葉稍離披。", "但作城中想，何異曲江池。"]'),
('09ddfae1-4bba-405e-a69d-665bfcb5ca4d','江州雪','白居易','唐','唐诗','tang','','[]','新雪滿前山，初晴好天氣。',72,'全唐诗/poet.tang.22000.json','["新雪滿前山，初晴好天氣。", "日西騎馬出，忽有京都意。", "城柳方綴花，檐冰纔結穗。", "須臾風日暖，處處皆飄墜。", "行吟賞未足，坐歎銷何易。", "猶勝嶺南看，雰雰不到地。"]'),
('c80dbc4d-f1d2-4dc2-99ef-505b078a766f','題潯陽樓','白居易','唐','唐诗','tang','','["\u5e90\u5c71"]','常愛陶彭澤，文思何高玄。',96,'全唐诗/poet.tang.22000.json','["常愛陶彭澤，文思何高玄。", "又怪韋江州，詩情亦清閑。", "今朝登此樓，有以知其然。", "大江寒見底，匡山青倚天。", "深夜湓浦月，平旦鑪峰煙。", "清輝與靈氣，日夕供文篇。", "我無二人才，孰爲來其間。", "因高偶成句，俯仰媿江山。"]'),
('5e861c2e-3d2d-4c3c-a1ae-a781b642c36d','訪陶公舊宅','白居易','唐','唐诗','tang','','[]','垢塵不汚玉，靈鳳不啄羶。',216,'全唐诗/poet.tang.22000.json','["垢塵不汚玉，靈鳳不啄羶。", "嗚呼陶靖節，生彼晉宋間。", "心實有所守，口終不能言。", "永惟孤竹子，拂衣首陽山。", "夷齊各一身，窮餓未爲難。", "先生有五男，與之同飢寒。", "腸中食不充，身上衣不完。", "連徵竟不起，斯可謂真賢。", "我生君之後，相去五百年。", "每讀五柳傳，目想心拳拳。", "昔常詠遺風，著爲十六篇。", "今來訪故宅，森若君在前。", "不慕尊有酒，不慕琴無弦。", "慕君遺榮利，老死此丘園。", "柴桑古村落，栗里舊山川。", "不見籬下菊，但餘墟中煙。", "子孫雖無聞，族氏猶未遷。", "每逢姓陶人，使我心依然。"]'),
('9528a395-de70-461f-82ed-20328bc69eed','北亭','白居易','唐','唐诗','tang','','[]','廬宮山下州，湓浦沙邊宅。',144,'全唐诗/poet.tang.22000.json','["廬宮山下州，湓浦沙邊宅。", "宅北倚高岡，迢迢數千尺。", "上有青青竹，竹間多白石。", "茅亭居上頭，豁達門四闢。", "前楹卷簾箔，北牖施牀席。", "江風萬里來，吹我涼淅淅。", "日高公府歸，巾笏隨手擲。", "脫衣恣搔首，坐臥任所適。", "時傾一杯酒，曠望湖天夕。", "口詠獨酌謠，目送歸飛翮。", "慙無出塵操，未免折腰役。", "偶獲此閑居，謬似高人跡。"]'),
('c4842e43-b558-4948-bdce-7a46083a6392','泛湓水','白居易','唐','唐诗','tang','','[]','四月未全熱，麥涼江氣秋。',180,'全唐诗/poet.tang.22000.json','["四月未全熱，麥涼江氣秋。", "湖山處處好，最愛湓水頭。", "湓水從東來，一派入江流。", "可憐似縈帶，中有隨風舟。", "命酒一臨泛，舍鞍揚櫂謳。", "放迴岸傍馬，去逐波間鷗。", "煙浪始渺渺，風襟亦悠悠。", "初疑上河漢，中若尋瀛洲。", "汀樹綠拂地，沙草芳未休。", "青蘿與紫葛，枝蔓垂相樛。", "繫纜步平岸，迴頭望江州。", "城雉映水見，隱隱如蜃樓。", "日入意未盡，將歸復少留。", "到官行半歲，今日方一遊。", "此地來何暮，可以寫吾憂。"]'),
('d9f3dbae-fce4-47bb-9086-ae7e978312f5','荅故人','白居易','唐','唐诗','tang','','[]','故人對酒歎，歎我在天涯。',132,'全唐诗/poet.tang.22000.json','["故人對酒歎，歎我在天涯。", "見我昔榮遇，念我今蹉跎。", "問我爲司馬，官意復如何。", "荅云且勿歎，聽我爲君歌。", "我本蓬蓽人，鄙賤劇泥沙。", "讀書未百卷，信口嘲風花。", "自從筮仕來，六命三登科。", "顧慙虛劣姿，所得亦已多。", "散員足庇身，薄俸可資家。", "省分輒自媿，豈爲不遇耶。", "煩君對杯酒，爲我一咨蹉。"]'),
('15e9c922-a0dd-4edf-9d85-99c2d1357473','官舍內新鑿小池','白居易','唐','唐诗','tang','','[]','簾下開小池，盈盈水方積。',96,'全唐诗/poet.tang.22000.json','["簾下開小池，盈盈水方積。", "中底鋪白沙，四隅甃青石。", "勿言不深廣，但取幽人適。", "泛灩微雨朝，泓澄明月夕。", "豈無大江水，波浪連天白。", "未如牀席間，方丈深盈尺。", "清淺可狎弄，昏煩聊漱滌。", "最愛曉暝時，一片秋天碧。"]'),
('11f9fa17-394b-4c7d-8908-a5728e6a71bc','宿簡寂觀','白居易','唐','唐诗','tang','','[]','巖白雲尚屯，林紅葉初隕。',72,'全唐诗/poet.tang.22000.json','["巖白雲尚屯，林紅葉初隕。", "秋光引閑步，不知身遠近。", "夕投靈洞宿，臥覺塵機泯。", "名利心既忘，市朝夢亦盡。", "暫來尚如此，況乃終身隱。", "何以療夜飢，一匙雲母粉。"]'),
('9e40d9e8-6894-423e-a22e-41f78c97937a','讀謝靈運詩','白居易','唐','唐诗','tang','','[]','吾聞達士道，窮通順冥數。',108,'全唐诗/poet.tang.22000.json','["吾聞達士道，窮通順冥數。", "通乃朝廷來，窮即江湖去。", "謝公才廓落，與世不相遇。", "壯志鬱不用，須有所洩處。", "洩爲山水詩，逸韻諧奇趣。", "大必籠天海，細不遺草樹。", "豈惟玩景物，亦欲攄心素。", "往往即事中，未能忘興諭。", "因知康樂作，不獨在章句。"]'),
('d5165733-096a-420f-a9de-0c11ff563256','北亭獨宿','白居易','唐','唐诗','tang','','[]','悄悄壁下牀，紗籠耿殘燭。',24,'全唐诗/poet.tang.22000.json','["悄悄壁下牀，紗籠耿殘燭。", "夜半獨眠覺，疑在僧房宿。"]'),
('f9339ffc-bd7f-4feb-a534-a006afcc1e3c','約心','白居易','唐','唐诗','tang','','[]','黑鬢絲雪侵，青袍塵土涴。',60,'全唐诗/poet.tang.22000.json','["黑鬢絲雪侵，青袍塵土涴。", "兀兀復騰騰，江城一上佐。", "朝就高齋上，熏然負暄臥。", "晚下小池前，澹然臨水坐。", "已約終身心，長如今日過。"]'),
('659307c0-68f1-4fbe-b743-99caeccb3712','晚望','白居易','唐','唐诗','tang','','[]','江城寒角動，沙洲夕鳥還。',24,'全唐诗/poet.tang.22000.json','["江城寒角動，沙洲夕鳥還。", "獨在高亭上，西南望遠山。"]'),
('226203b3-4d27-49f0-9dea-ffb469c6f364','早春','白居易','唐','唐诗','tang','','[]','雪消冰又釋，景和風復暄。',48,'全唐诗/poet.tang.22000.json','["雪消冰又釋，景和風復暄。", "滿庭田地濕，薺葉生牆根。", "官舍悄無事，日西斜掩門。", "不開莊老卷，欲與何人言。"]');
